/// Standalone Windows-only security validation. Skips the Linux fleet entirely
/// and runs the Windows orchestration stages (bootstrap + the W1.2/W2.2/W2.4/
/// W2.1 security verifiers) against a single Windows UTM guest. Useful for
/// iterating on Windows-side security checks without spinning up the full
/// 5-Linux + 1-Windows live-lab.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct VmLabValidateWindowsSecurityConfig {
    pub inventory_path: PathBuf,
    pub windows_vm: String,
    pub ssh_identity_file: PathBuf,
    pub known_hosts_path: Option<PathBuf>,
    pub ssh_port: u16,
    pub utm_documents_root: Option<PathBuf>,
    pub utmctl_path: Option<PathBuf>,
    pub report_dir: PathBuf,
    pub dry_run: bool,
    pub skip_access_bootstrap: bool,
    pub skip_install: bool,
    /// When true, a failed `validate_windows_authenticode` stage is
    /// recorded as a waived pass rather than a hard failure so that
    /// subsequent stages (including `validate_windows_mesh_join`) still
    /// run. Use for dev/lab builds that are not yet Authenticode-signed.
    pub no_fail_on_authenticode: bool,
    /// Local signed-bundle paths for the W4.5 orchestrator-side
    /// distribution stages. `None` skips the corresponding stage with
    /// reason "no local bundle path provided".
    pub distribute_windows_membership_bundle: Option<PathBuf>,
    pub distribute_windows_assignment_bundle: Option<PathBuf>,
    pub distribute_windows_traversal_bundle: Option<PathBuf>,
    pub distribute_windows_dns_zone_bundle: Option<PathBuf>,
}

pub fn run_validate_windows_security(
    config: &VmLabValidateWindowsSecurityConfig,
) -> Result<String, String> {
    std::fs::create_dir_all(&config.report_dir).map_err(|err| {
        format!(
            "create report dir {} failed: {err}",
            config.report_dir.display()
        )
    })?;
    let outcomes = run_windows_orchestration_stages_with_options(
        config.windows_vm.as_str(),
        config.inventory_path.as_path(),
        config.ssh_identity_file.as_path(),
        config.known_hosts_path.as_deref(),
        config.ssh_port,
        config.utm_documents_root.as_deref(),
        config.utmctl_path.as_deref(),
        config.dry_run,
        config.report_dir.as_path(),
        WindowsOrchestrationOptions {
            skip_access_bootstrap: config.skip_access_bootstrap,
            skip_install: config.skip_install,
            no_fail_on_authenticode: config.no_fail_on_authenticode,
            distribute_windows_membership_bundle: config
                .distribute_windows_membership_bundle
                .clone(),
            distribute_windows_assignment_bundle: config
                .distribute_windows_assignment_bundle
                .clone(),
            distribute_windows_traversal_bundle: config.distribute_windows_traversal_bundle.clone(),
            distribute_windows_dns_zone_bundle: config.distribute_windows_dns_zone_bundle.clone(),
            // Verifier-key distribution opts in via the orchestrate-live-lab
            // path (which auto-populates them from the local report state
            // dir). vm-lab-validate-windows-security has not yet grown CLI
            // flags for these; default to None so the verifier-key stages
            // emit Skipped with "no local bundle path provided".
            ..Default::default()
        },
    );
    let summary_path = config.report_dir.join("windows_security_validation.json");
    let payload = serde_json::json!({
        "schema_version": 1,
        "windows_vm": config.windows_vm,
        "dry_run": config.dry_run,
        "stages": outcomes
            .iter()
            .map(|o| {
                serde_json::json!({
                    "stage": o.stage,
                    "status": format!("{:?}", o.status).to_ascii_lowercase(),
                    "summary": o.summary,
                    "artifacts": o.artifacts.clone(),
                })
            })
            .collect::<Vec<_>>(),
    });
    let serialized = serde_json::to_string_pretty(&payload)
        .map_err(|err| format!("serialize Windows security validation report failed: {err}"))?;
    std::fs::write(summary_path.as_path(), serialized.as_str()).map_err(|err| {
        format!(
            "write Windows security validation report to {} failed: {err}",
            summary_path.display()
        )
    })?;
    println!("{serialized}");
    let any_failed = outcomes.iter().any(|o| o.status == VmLabStageStatus::Fail);
    if any_failed {
        return Err(format!(
            "Windows security validation reported one or more stage failures; report at {}",
            summary_path.display()
        ));
    }
    Ok(format!(
        "Windows security validation passed for {}; report at {}",
        config.windows_vm,
        summary_path.display()
    ))
}

/// Operator-facing config for the `vm-lab-distribute-windows-state`
/// subcommand: pure distribution path. Pushes one or more pre-built
/// signed bundles to a reviewed Windows guest without running the
/// security validators. Use when the security validators have already
/// passed in a prior run and you only want to refresh trust state.
///
/// At least one of the four bundle paths must be `Some`. The
/// validator path
/// (`vm-lab-validate-windows-security --distribute-windows-*-bundle`)
/// is the right call when validators + distribution should run in the
/// same invocation.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct VmLabDistributeWindowsStateConfig {
    pub inventory_path: PathBuf,
    pub windows_vm: String,
    pub ssh_identity_file: PathBuf,
    pub known_hosts_path: Option<PathBuf>,
    pub report_dir: PathBuf,
    pub dry_run: bool,
    pub membership_bundle: Option<PathBuf>,
    pub assignment_bundle: Option<PathBuf>,
    pub traversal_bundle: Option<PathBuf>,
    pub dns_zone_bundle: Option<PathBuf>,
}

/// Pure-distribution dispatch: walks the four optional bundle paths
/// and calls the corresponding `run_distribute_windows_*_stage`
/// wrapper for each one provided. Writes a typed JSON report under
/// `<report_dir>/windows_state_distribution.json` mirroring the
/// validate-windows-security report shape so downstream tooling can
/// consume both with one parser.
pub fn run_distribute_windows_state(
    config: &VmLabDistributeWindowsStateConfig,
) -> Result<String, String> {
    let any_bundle = config.membership_bundle.is_some()
        || config.assignment_bundle.is_some()
        || config.traversal_bundle.is_some()
        || config.dns_zone_bundle.is_some();
    if !any_bundle {
        return Err(
            "at least one of --membership-bundle, --assignment-bundle, --traversal-bundle, --dns-zone-bundle is required".to_owned(),
        );
    }

    std::fs::create_dir_all(&config.report_dir).map_err(|err| {
        format!(
            "create report dir {} failed: {err}",
            config.report_dir.display()
        )
    })?;
    let logs_dir = config.report_dir.join("logs");
    let _ = std::fs::create_dir_all(&logs_dir);

    type DistributeFn =
        fn(&str, &Path, &Path, Option<&Path>, &Path) -> Result<(String, String), (String, String)>;

    let dispatch_one = |stage_name: &'static str,
                        log_filename: &str,
                        bundle: Option<&Path>,
                        dispatch: DistributeFn|
     -> VmLabStageOutcome {
        let log_path = logs_dir.join(log_filename);
        if config.dry_run {
            return stage_outcome(
                stage_name,
                VmLabStageStatus::Skipped,
                format!(
                    "dry-run: would distribute {stage_name} bundle to {}",
                    config.windows_vm
                ),
                vec![],
            );
        }
        let Some(bundle_path) = bundle else {
            return stage_outcome(
                stage_name,
                VmLabStageStatus::Skipped,
                format!("skipped: no local bundle path provided for {stage_name}"),
                vec![],
            );
        };
        match dispatch(
            config.windows_vm.as_str(),
            config.inventory_path.as_path(),
            config.ssh_identity_file.as_path(),
            config.known_hosts_path.as_deref(),
            bundle_path,
        ) {
            Ok((summary, raw_report)) => {
                let log_body = if raw_report.is_empty() {
                    summary.clone()
                } else {
                    format!("{summary}\n--- raw report ---\n{raw_report}")
                };
                let _ = std::fs::write(log_path.as_path(), log_body.as_str());
                stage_outcome(stage_name, VmLabStageStatus::Pass, summary, vec![log_path])
            }
            Err((reason, raw_report)) => {
                let log_body = if raw_report.is_empty() {
                    reason.clone()
                } else {
                    format!("{reason}\n--- raw report ---\n{raw_report}")
                };
                let _ = std::fs::write(log_path.as_path(), log_body.as_str());
                stage_outcome(
                    stage_name,
                    VmLabStageStatus::Fail,
                    format!(
                        "{stage_name} distribution failed for {}: {reason}",
                        config.windows_vm
                    ),
                    vec![log_path],
                )
            }
        }
    };

    let outcomes: Vec<VmLabStageOutcome> = [
        dispatch_one(
            "distribute_windows_membership",
            "distribute_windows_membership.log",
            config.membership_bundle.as_deref(),
            run_distribute_windows_membership_stage,
        ),
        dispatch_one(
            "distribute_windows_assignment",
            "distribute_windows_assignment.log",
            config.assignment_bundle.as_deref(),
            run_distribute_windows_assignment_stage,
        ),
        dispatch_one(
            "distribute_windows_traversal",
            "distribute_windows_traversal.log",
            config.traversal_bundle.as_deref(),
            run_distribute_windows_traversal_stage,
        ),
        dispatch_one(
            "distribute_windows_dns_zone",
            "distribute_windows_dns_zone.log",
            config.dns_zone_bundle.as_deref(),
            run_distribute_windows_dns_zone_stage,
        ),
    ]
    .to_vec();

    let summary_path = config.report_dir.join("windows_state_distribution.json");
    let payload = serde_json::json!({
        "schema_version": 1,
        "windows_vm": config.windows_vm,
        "dry_run": config.dry_run,
        "stages": outcomes
            .iter()
            .map(|o| {
                serde_json::json!({
                    "stage": o.stage,
                    "status": format!("{:?}", o.status).to_ascii_lowercase(),
                    "summary": o.summary,
                    "artifacts": o.artifacts.clone(),
                })
            })
            .collect::<Vec<_>>(),
    });
    let serialized = serde_json::to_string_pretty(&payload)
        .map_err(|err| format!("serialize Windows state distribution report failed: {err}"))?;
    std::fs::write(summary_path.as_path(), serialized.as_str()).map_err(|err| {
        format!(
            "write Windows state distribution report to {} failed: {err}",
            summary_path.display()
        )
    })?;
    println!("{serialized}");
    let any_failed = outcomes.iter().any(|o| o.status == VmLabStageStatus::Fail);
    if any_failed {
        return Err(format!(
            "Windows state distribution reported one or more stage failures; report at {}",
            summary_path.display()
        ));
    }
    Ok(format!(
        "Windows state distribution completed for {}; report at {}",
        config.windows_vm,
        summary_path.display()
    ))
}

/// Reviewed source paths on the Linux exit guest. Match the
/// `RUSTYNET_*_BUNDLE` environment variables baked into the
/// `scripts/systemd/rustynetd.service` unit file.
pub const LINUX_EXIT_MEMBERSHIP_SNAPSHOT_PATH: &str = "/var/lib/rustynet/membership.snapshot";
pub const LINUX_EXIT_ASSIGNMENT_BUNDLE_PATH: &str = "/var/lib/rustynet/rustynetd.assignment";
pub const LINUX_EXIT_TRAVERSAL_BUNDLE_PATH: &str = "/var/lib/rustynet/rustynetd.traversal";
pub const LINUX_EXIT_DNS_ZONE_BUNDLE_PATH: &str = "/var/lib/rustynet/rustynetd.dns-zone";

/// Operator-facing config for the
/// `vm-lab-pull-windows-state-from-linux-exit` subcommand.
///
/// Pulls the four signed bundles from the canonical Linux exit
/// locations down to a local staging directory. The output paths can
/// then be fed straight into
/// `vm-lab-distribute-windows-state --membership-bundle … --assignment-bundle …`
/// to push them onto a Windows guest, closing the heterogeneous
/// (Linux exit → orchestrator host → Windows peer) loop end-to-end.
///
/// The pull step is read-only on the Linux exit: the daemon's
/// canonical bundle paths are owned by the `rustynetd` group with
/// `0640` perms, but the SCP probe runs as a non-root user (the
/// inventory's configured `ssh_user` if any, otherwise the SSH
/// default). Operators must ensure their SSH user has read access to
/// `/var/lib/rustynet/` on the Linux exit (typically by adding the
/// user to the `rustynetd` group); the helper surfaces SCP exit
/// codes so a permission failure is honest, not silent.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct VmLabPullWindowsStateFromLinuxExitConfig {
    pub inventory_path: PathBuf,
    pub linux_exit_alias: String,
    pub ssh_identity_file: PathBuf,
    pub known_hosts_path: Option<PathBuf>,
    pub dest_dir: PathBuf,
    pub report_dir: PathBuf,
    pub dry_run: bool,
}

/// Output paths after a successful
/// `run_pull_windows_state_from_linux_exit`. Each field is the local
/// path of the pulled bundle, suitable for feeding into
/// `VmLabDistributeWindowsStateConfig`.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct PulledLinuxExitBundles {
    pub membership_snapshot: PathBuf,
    pub assignment_bundle: PathBuf,
    pub traversal_bundle: PathBuf,
    pub dns_zone_bundle: PathBuf,
}

/// Pull the four signed bundles from a Linux exit guest down to a
/// local staging directory. Writes a typed JSON report under
/// `<report_dir>/windows_state_pull_from_linux_exit.json` with one
/// entry per bundle (name + status + `local_path` + summary). On Pass
/// the local paths are returned in `PulledLinuxExitBundles`. On Fail
/// the function returns an `Err` with the report path so operators
/// can see exactly which bundle's SCP failed and why.
pub fn run_pull_windows_state_from_linux_exit(
    config: &VmLabPullWindowsStateFromLinuxExitConfig,
) -> Result<(String, PulledLinuxExitBundles), String> {
    std::fs::create_dir_all(&config.report_dir).map_err(|err| {
        format!(
            "create report dir {} failed: {err}",
            config.report_dir.display()
        )
    })?;
    std::fs::create_dir_all(&config.dest_dir).map_err(|err| {
        format!(
            "create dest dir {} failed: {err}",
            config.dest_dir.display()
        )
    })?;

    let membership_local = config.dest_dir.join("membership.snapshot");
    let assignment_local = config.dest_dir.join("rustynetd.assignment");
    let traversal_local = config.dest_dir.join("rustynetd.traversal");
    let dns_zone_local = config.dest_dir.join("rustynetd.dns-zone");

    let bundles: [(&str, &str, &Path); 4] = [
        (
            "membership_snapshot",
            LINUX_EXIT_MEMBERSHIP_SNAPSHOT_PATH,
            membership_local.as_path(),
        ),
        (
            "assignment_bundle",
            LINUX_EXIT_ASSIGNMENT_BUNDLE_PATH,
            assignment_local.as_path(),
        ),
        (
            "traversal_bundle",
            LINUX_EXIT_TRAVERSAL_BUNDLE_PATH,
            traversal_local.as_path(),
        ),
        (
            "dns_zone_bundle",
            LINUX_EXIT_DNS_ZONE_BUNDLE_PATH,
            dns_zone_local.as_path(),
        ),
    ];

    let mut outcomes: Vec<VmLabStageOutcome> = Vec::new();

    if config.dry_run {
        for (label, src, dst) in bundles.iter() {
            outcomes.push(stage_outcome(
                label,
                VmLabStageStatus::Skipped,
                format!(
                    "dry-run: would scp {src} from {} to {}",
                    config.linux_exit_alias,
                    dst.display()
                ),
                vec![],
            ));
        }
    } else {
        let targets = resolve_remote_targets(
            config.inventory_path.as_path(),
            std::slice::from_ref(&config.linux_exit_alias),
            false,
            &[],
        )?;
        let target = targets
            .into_iter()
            .next()
            .ok_or_else(|| format!("no target resolved for alias {}", config.linux_exit_alias))?;
        if target.platform_profile.platform != VmGuestPlatform::Linux {
            return Err(format!(
                "alias {} resolved to non-Linux platform: {} (pull source must be a Linux exit)",
                config.linux_exit_alias,
                target.platform_profile.platform.as_str()
            ));
        }
        let timeout = timeout_or_default(0, DEFAULT_RUN_TIMEOUT_SECS);

        for (label, src, dst) in bundles.iter() {
            let result = scp_from_remote(
                &target,
                None,
                Some(config.ssh_identity_file.as_path()),
                config.known_hosts_path.as_deref(),
                src,
                dst,
                timeout,
            );
            let outcome = match result {
                Ok(status) if status.success() => {
                    if !dst.is_file() {
                        stage_outcome(
                            label,
                            VmLabStageStatus::Fail,
                            format!(
                                "scp reported success but local destination is missing: {}",
                                dst.display()
                            ),
                            vec![],
                        )
                    } else {
                        stage_outcome(
                            label,
                            VmLabStageStatus::Pass,
                            format!(
                                "pulled {src} from {} to {}",
                                config.linux_exit_alias,
                                dst.display()
                            ),
                            vec![dst.to_path_buf()],
                        )
                    }
                }
                Ok(status) => stage_outcome(
                    label,
                    VmLabStageStatus::Fail,
                    format!(
                        "scp of {src} from {} exited non-zero: {}",
                        config.linux_exit_alias,
                        status_code(status)
                    ),
                    vec![],
                ),
                Err(err) => stage_outcome(
                    label,
                    VmLabStageStatus::Fail,
                    format!(
                        "scp of {src} from {} failed: {err}",
                        config.linux_exit_alias
                    ),
                    vec![],
                ),
            };
            outcomes.push(outcome);
        }
    }

    let summary_path = config
        .report_dir
        .join("windows_state_pull_from_linux_exit.json");
    let payload = serde_json::json!({
        "schema_version": 1,
        "linux_exit_alias": config.linux_exit_alias,
        "dest_dir": config.dest_dir.display().to_string(),
        "dry_run": config.dry_run,
        "stages": outcomes
            .iter()
            .map(|o| {
                serde_json::json!({
                    "stage": o.stage,
                    "status": format!("{:?}", o.status).to_ascii_lowercase(),
                    "summary": o.summary,
                    "artifacts": o.artifacts.clone(),
                })
            })
            .collect::<Vec<_>>(),
    });
    let serialized = serde_json::to_string_pretty(&payload)
        .map_err(|err| format!("serialize Windows state pull report failed: {err}"))?;
    std::fs::write(summary_path.as_path(), serialized.as_str()).map_err(|err| {
        format!(
            "write Windows state pull report to {} failed: {err}",
            summary_path.display()
        )
    })?;
    println!("{serialized}");

    let any_failed = outcomes.iter().any(|o| o.status == VmLabStageStatus::Fail);
    if any_failed {
        return Err(format!(
            "Windows state pull from Linux exit reported one or more bundle failures; report at {}",
            summary_path.display()
        ));
    }

    Ok((
        format!(
            "Windows state pulled from Linux exit {}; report at {}",
            config.linux_exit_alias,
            summary_path.display()
        ),
        PulledLinuxExitBundles {
            membership_snapshot: membership_local,
            assignment_bundle: assignment_local,
            traversal_bundle: traversal_local,
            dns_zone_bundle: dns_zone_local,
        },
    ))
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct VmLabOrchestrateLiveLabConfig {
    pub inventory_path: PathBuf,
    pub profile_path: Option<PathBuf>,
    pub profile_output_path: Option<PathBuf>,
    pub exit_vm: Option<String>,
    pub client_vm: Option<String>,
    pub entry_vm: Option<String>,
    pub aux_vm: Option<String>,
    pub extra_vm: Option<String>,
    pub fifth_client_vm: Option<String>,
    pub relay_vm: Option<String>,
    pub ssh_identity_file: PathBuf,
    pub known_hosts_path: Option<PathBuf>,
    pub require_same_network: bool,
    pub script_path: PathBuf,
    pub report_dir: PathBuf,
    pub source_mode: Option<String>,
    pub repo_ref: Option<String>,
    /// D1 — `--rebuild-nodes <alias[,alias]>`: when `Some`, only these aliases
    /// rebuild their daemon in `bootstrap_hosts` (Rust-native `--node` path);
    /// every other node reuses its already-installed daemon. `None` (the
    /// default) rebuilds all nodes. Lets a single-node daemon fix be retested
    /// without a full multi-node rebuild.
    pub rebuild_nodes: Option<Vec<String>>,
    pub max_parallel_node_workers: Option<usize>,
    pub skip_gates: bool,
    pub skip_soak: bool,
    pub skip_cross_network: bool,
    pub utm_documents_root: Option<PathBuf>,
    pub utmctl_path: Option<PathBuf>,
    pub ssh_port: u16,
    pub discovery_timeout_secs: u64,
    pub ready_timeout_secs: u64,
    pub timeout_secs: u64,
    pub collect_artifacts_on_failure: bool,
    pub skip_diagnose_on_failure: bool,
    /// Rust-native `--node` mode: run through validate_baseline_runtime, persist
    /// orchestration context, then stop with the mesh left up.
    pub setup_only: bool,
    /// Rust-native `--node` mode: load persisted orchestration context and run
    /// only the live validation suite against the already-up mesh.
    pub run_only: bool,
    pub stop_after_ready: bool,
    pub dry_run: bool,
    /// `--resume-from <stage>`: resume a failed Rust `--node` run from a
    /// specific stage; all earlier stages are skipped-as-passed. Mutually
    /// exclusive with `--rerun-stage` and `--run-only`.
    pub resume_from: Option<String>,
    /// `--rerun-stage <stage>`: re-run a single Rust-native stage; all other
    /// stages are skipped-as-passed. Mutually exclusive with `--resume-from`
    /// and `--run-only`.
    pub rerun_stage: Option<String>,
    /// `--trust-inventory-ready`: skip the pre-run restart-unready gate.
    ///
    /// The readiness gate keys off `probe_tcp_port_status`, a raw `TcpStream`
    /// connect to `:22` that can be BLIND in a sandboxed / odd-routing context
    /// (e.g. an MCP-launched process that cannot reach the bridged lab subnet
    /// with an unbound socket) even though the `ssh` binary the real bootstrap
    /// uses reaches the same nodes fine. When that happens the gate reboots
    /// every (healthy) VM and aborts. With this flag set the orchestrator emits
    /// a warning + a `restart_unready_vms = Skipped` outcome and proceeds to
    /// bootstrap, letting the real bootstrap SSH be the source of truth — a
    /// genuinely unreachable node then fails bootstrap loudly instead of
    /// silently triggering a destructive restart-all. Off by default; the gate
    /// stays strict unless the operator opts out.
    pub trust_inventory_ready: bool,
    /// Alias of an optional Windows 11 UTM VM to bootstrap and validate as a client node.
    /// When set, the orchestrator includes this VM in UTM discovery/restart, then runs
    /// Windows-specific bootstrap and validation stages after all Linux stages pass.
    pub windows_vm: Option<String>,
    /// Alias of an optional macOS UTM VM to bootstrap and validate as a client node.
    /// When set, the orchestrator includes this VM in UTM discovery/restart, then runs
    /// macOS-specific bootstrap and validation stages after all Linux stages pass.
    pub macos_vm: Option<String>,
    /// Skip all Linux stages and run only the Windows bootstrap and validation stages.
    /// Requires `--windows-vm`. Use when the Linux lab is already known-good and only
    /// the Windows client path needs to be exercised.
    pub windows_only: bool,
    /// When true, a failed `validate_windows_authenticode` stage is
    /// recorded as a waived pass rather than a hard failure, allowing
    /// `validate_windows_mesh_join` to proceed. Use for dev/lab builds
    /// that are not yet Authenticode-signed.
    pub no_fail_on_authenticode: bool,
    /// When true, after the live-lab install + 5-node test path completes,
    /// dispatch the new `rustynetd linux-*-check` daemon-side validator
    /// chainer against every selected Linux alias. Adds 6 stages × N peers
    /// to the orchestration report. Off by default to keep existing
    /// orchestrate-live-lab latency unchanged; flip on when the operator
    /// wants live-evidence proof that each Linux peer's daemon-side state
    /// matches the reviewed posture (W3.2-followup-7 verifier set).
    pub validate_linux_daemon_state: bool,
    /// When non-empty, route to the Rust-native `NodeAdapter` pipeline
    /// instead of the bash orchestrator. Each entry is parsed from a
    /// `--node <alias>:<role>` CLI flag. (W5.1 opt-in; W5.6 wires the
    /// translation + routing surface; default flips to Rust path once
    /// W5.5 cross-orchestrator parity evidence is captured.)
    pub node_assignments: Vec<orchestrator::role_assignment::NodeRoleAssignment>,
    /// Transitional escape hatch (W5.6, removed in W5.7). When set, force
    /// the bash orchestrator path even if other flags would otherwise
    /// route to the Rust orchestrator. Mutually exclusive with `--node`
    /// because the bash orchestrator does not consume `<alias>:<role>`
    /// pairs and would silently ignore them.
    pub legacy_bash_orchestrator: bool,
    /// CIDR list (comma-separated, e.g. `192.168.64.0/24`) propagated to
    /// the Linux bootstrap script as `SSH_ALLOW_CIDRS`. The Rust path
    /// pipes it into `rustynet ops e2e-bootstrap-host --ssh-allow-cidrs`,
    /// which rejects an empty value, so the flag is effectively required
    /// for `--node`-driven live lab runs.
    pub orchestrate_ssh_allow_cidrs: Option<String>,
    /// Track B Step 1 — optional `--topology-profile <path>` JSON
    /// document mapping `exit` / `relay` / `anchor` / `blind_exit`
    /// roles onto inventory aliases. Empty / unset = the orchestrator
    /// uses today's Linux-exit defaults and the explicit per-role
    /// `--exit-vm` etc flags. See `crates/rustynet-cli/src/vm_lab/topology.rs`.
    pub topology_profile: Option<PathBuf>,
    /// Track B Step 1 — convenience `--exit-platform <linux|macos|windows>`
    /// selector that picks the first inventory entry whose platform
    /// matches the requested value. Mutually exclusive with
    /// `--exit-vm` and with a topology-profile `exit` entry; the
    /// resolver enforces fail-closed in
    /// [`topology::resolve_topology`].
    pub exit_platform: Option<String>,
    /// Counterpart of [`Self::exit_platform`] for the relay role
    /// slot. The relay alias is propagated to the bash orchestrator
    /// via `RELAY_VM` / `RELAY_PLATFORM` profile env entries when set;
    /// unset leaves today's implicit behaviour intact.
    pub relay_platform: Option<String>,
    /// Counterpart of [`Self::exit_platform`] for the anchor role
    /// slot. Anchor live-lab capability tests live in Track A, but
    /// the topology layer needs to accept the selector now so the
    /// orchestrator can stamp `ANCHOR_VM` / `ANCHOR_PLATFORM` in the
    /// profile env without a follow-up flag-plumbing churn.
    pub anchor_platform: Option<String>,
    /// Counterpart of [`Self::exit_platform`] for the admin role slot.
    /// admin is a config-only role (it advertises no routes), so it is
    /// deliberately NOT threaded into `topology::resolve_topology`; it
    /// only elects the macOS admin live-issue stage. `Some("macos")`
    /// runs that stage; unset/other Skips it.
    pub admin_platform: Option<String>,
    /// Counterpart of [`Self::exit_platform`] for the blind_exit role slot.
    /// blind_exit is the irreversible exit variant (destructive `* ->
    /// blind_exit`, factory-reset-only exit path). Like admin it is NOT
    /// threaded into `topology::resolve_topology`; it only elects the macOS
    /// blind_exit live stage, which runs LAST because it wipes node identity.
    /// `Some("macos")` runs that stage; unset/other Skips it.
    pub blind_exit_platform: Option<String>,
    /// Counterpart of [`Self::exit_platform`] for the live role-transition
    /// cell (`CrossOsRoleSwitchPlan_2026-06-24.md`). Like admin/blind_exit it
    /// is NOT threaded into `topology::resolve_topology`; it only elects the
    /// macOS live role-transition stage, which drives a real
    /// `TransitionKind::LocalOnly` admin<->client flip via `rustynet role
    /// set` + the launchd reload and asserts the new role + mesh
    /// connectivity post-restart. `Some("macos")` runs that stage;
    /// unset/other Skips it.
    pub role_switch_platform: Option<String>,
    /// Promote the macOS node to a SECONDARY regular (NATing) exit while a
    /// Linux node remains the PRIMARY exit and the membership/assignment
    /// authority. Unlike `--exit-platform macos` (which would make the macOS
    /// node the primary exit = the authority, whose genesis/membership stages
    /// are Linux-path-only and fail on macOS), this is a config-only election
    /// NOT threaded into `topology::resolve_topology`: the Linux exit stays the
    /// authority (membership_setup et al. run on it) and the macOS node joins
    /// via `run_macos_orchestration_stages` and is transitioned
    /// client->admin->exit by `activate_macos_exit_role`. This matches the
    /// realistic deployment (an exit joins a mesh; it is not the authority) and
    /// mirrors how the relay/anchor roles are elected by a flag rather than a
    /// topology rewrite.
    pub macos_promote_exit: bool,
    pub enable_chaos_suite: bool,
    /// Per-stage watchdog timeout in seconds, forwarded to the bash
    /// orchestrator as `--stage-timeout-secs <N>` when greater than zero.
    /// `0` (the default) disables the watchdog and preserves the historical
    /// "run until the outer `--timeout-secs` fires" behaviour. A non-zero
    /// value caps any single stage so a hung node-setup step (e.g. an ssh
    /// probe wedged against a Windows guest) fails the stage instead of
    /// stalling the whole run for hours.
    pub stage_timeout_secs: u64,
    /// Skip the Linux LIVE-VALIDATION SUITE (the `execute_ops_vm_lab_run_live_lab`
    /// call: anchor / role-switch / exit-handoff / relay / two-hop / managed-dns /
    /// network-flap / reboot-recovery / key-custody / secrets / chaos stages — the
    /// ~30-45 min time sink) while STILL running setup (bootstrap + membership +
    /// signed-bundle distribution + baseline) and then the mac/win role stages.
    /// Use ONLY to iterate a macOS/Windows role cell against a freshly-set-up
    /// mesh; the mac/win stages gate on setup's `distribute_*` outcomes, not on
    /// the Linux live suite, so skipping the suite leaves them fully exercised.
    /// A full Linux live suite still runs when this is `false` (the default).
    pub skip_linux_live_suite: bool,
}

/// Validate cross-flag invariants for `vm-lab-orchestrate-live-lab`.
///
/// Currently:
/// - `--legacy-bash-orchestrator` is mutually exclusive with `--node`
///   (the bash path cannot consume role assignments; silently ignoring
///   them would mask operator intent).
pub fn validate_orchestrate_live_lab_config(
    config: &VmLabOrchestrateLiveLabConfig,
) -> Result<(), String> {
    if config.setup_only && config.run_only {
        return Err("--setup-only and --run-only are mutually exclusive".to_owned());
    }
    if config.run_only && config.skip_linux_live_suite {
        return Err("--run-only cannot be combined with --skip-linux-live-suite".to_owned());
    }
    if config.stop_after_ready && (config.setup_only || config.run_only) {
        return Err(
            "--stop-after-ready cannot be combined with --setup-only or --run-only".to_owned(),
        );
    }
    if config.legacy_bash_orchestrator && !config.node_assignments.is_empty() {
        return Err(
            "--legacy-bash-orchestrator is mutually exclusive with --node; \
             pass either the legacy --*-vm flag set or --node assignments, not both"
                .to_owned(),
        );
    }
    if config.legacy_bash_orchestrator && (config.setup_only || config.run_only) {
        return Err(
            "--legacy-bash-orchestrator is mutually exclusive with --setup-only/--run-only; \
             those modes are Rust --node only"
                .to_owned(),
        );
    }
    if config.setup_only && config.node_assignments.is_empty() {
        return Err("--setup-only requires at least one --node <alias>:<role>".to_owned());
    }
    if config.resume_from.is_some() && config.rerun_stage.is_some() {
        return Err("--resume-from and --rerun-stage are mutually exclusive".to_owned());
    }
    if config.resume_from.is_some() {
        let name = config.resume_from.as_deref().unwrap_or("");
        if StageId::try_from(name).is_err() {
            return Err(format!(
                "--resume-from '{}' is not a recognized Rust-native stage; choose from: {:?}",
                name,
                StageId::ALL.iter().map(|s| s.as_str()).collect::<Vec<_>>()
            ));
        }
    }
    if config.rerun_stage.is_some() {
        let name = config.rerun_stage.as_deref().unwrap_or("");
        if StageId::try_from(name).is_err() {
            return Err(format!(
                "--rerun-stage '{}' is not a recognized Rust-native stage; choose from: {:?}",
                name,
                StageId::ALL.iter().map(|s| s.as_str()).collect::<Vec<_>>()
            ));
        }
    }
    Ok(())
}

/// Configuration for `vm-lab-diff-orchestrator-parity`. The subcommand is
/// the W5.5 evidence harness: takes two `parity_input.json` snapshots
/// (one bash, one Rust), emits a machine-readable parity diff to
/// `--output`, and exits non-zero on any drift.
/// Which parity comparison `vm-lab-diff-orchestrator-parity` runs.
///
/// `Strict` (default) requires byte-identical stage-ID sets — correct for
/// same-dialect regression (e.g. Rust-vs-Rust determinism). `Functional`
/// normalizes the bash/Rust stage-ID dialects via
/// `orchestrator::parity::canonical_stage_id` and compares the shared logical
/// work + overall status + node count. Strict is UNSATISFIABLE across dialects
/// (bash and Rust name their stages differently by design); Functional is the
/// satisfiable cross-dialect (bash-vs-Rust) gate.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub enum ParityMode {
    #[default]
    Strict,
    Functional,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct VmLabDiffOrchestratorParityConfig {
    pub left_path: PathBuf,
    pub right_path: PathBuf,
    pub output_path: PathBuf,
    pub mode: ParityMode,
}

pub fn execute_ops_vm_lab_diff_orchestrator_parity(
    config: VmLabDiffOrchestratorParityConfig,
) -> Result<String, String> {
    let left_bytes = fs::read(&config.left_path).map_err(|err| {
        format!(
            "read left parity input '{}': {err}",
            config.left_path.display()
        )
    })?;
    let right_bytes = fs::read(&config.right_path).map_err(|err| {
        format!(
            "read right parity input '{}': {err}",
            config.right_path.display()
        )
    })?;
    let left: orchestrator::report::LiveLabRunReport = serde_json::from_slice(&left_bytes)
        .map_err(|err| {
            format!(
                "parse left parity input '{}': {err}",
                config.left_path.display()
            )
        })?;
    let right: orchestrator::report::LiveLabRunReport = serde_json::from_slice(&right_bytes)
        .map_err(|err| {
            format!(
                "parse right parity input '{}': {err}",
                config.right_path.display()
            )
        })?;
    // Create the output directory once (shared by both modes).
    if let Some(parent) = config.output_path.parent()
        && !parent.as_os_str().is_empty()
    {
        fs::create_dir_all(parent).map_err(|err| {
            format!(
                "create parity diff output directory '{}': {err}",
                parent.display()
            )
        })?;
    }

    match config.mode {
        // Strict: byte-identical stage-ID sets required. Output shape is
        // unchanged from before `--mode` existed (a bare `ParityDiff`), so
        // existing evidence consumers keep working. Unsatisfiable across
        // dialects; correct for same-dialect (Rust-vs-Rust) regression.
        ParityMode::Strict => {
            let diff = orchestrator::parity::diff_live_lab_reports(&left, &right);
            let body = serde_json::to_vec_pretty(&diff)
                .map_err(|err| format!("serialize parity diff: {err}"))?;
            fs::write(&config.output_path, &body).map_err(|err| {
                format!(
                    "write parity diff to '{}': {err}",
                    config.output_path.display()
                )
            })?;
            let summary = format!(
                "parity_diff[strict]: pass={} stages={} stages_only_left={} \
                 stages_only_right={} node_count_left={} node_count_right={}",
                diff.overall_parity_pass,
                diff.stages.len(),
                diff.stages_only_in_left.len(),
                diff.stages_only_in_right.len(),
                diff.node_count_left,
                diff.node_count_right,
            );
            if diff.overall_parity_pass {
                Ok(summary)
            } else {
                Err(summary)
            }
        }
        // Functional: the satisfiable cross-dialect gate. Normalizes the
        // bash/Rust stage-ID vocabularies and compares the shared logical
        // work + overall status + node count. Fail-closed on zero overlap.
        ParityMode::Functional => {
            let diff = orchestrator::parity::diff_live_lab_reports_functional(&left, &right);
            let body = serde_json::to_vec_pretty(&diff)
                .map_err(|err| format!("serialize functional parity diff: {err}"))?;
            fs::write(&config.output_path, &body).map_err(|err| {
                format!(
                    "write parity diff to '{}': {err}",
                    config.output_path.display()
                )
            })?;
            let summary = format!(
                "parity_diff[functional]: pass={} shared_stages={} only_left={} \
                 only_right={} overall_status_match={} node_count_match={}",
                diff.overall_functional_parity_pass,
                diff.shared_stage_count,
                diff.stages_only_in_left.len(),
                diff.stages_only_in_right.len(),
                diff.overall_status_match,
                diff.node_count_match,
            );
            if diff.overall_functional_parity_pass {
                Ok(summary)
            } else {
                Err(summary)
            }
        }
    }
}

/// Configuration for `vm-lab-emit-parity-input`: reconstruct a
/// `parity_input.json` (`LiveLabRunReport`) from a completed run's on-disk
/// evidence (`state/stages.tsv` + `state/nodes.tsv`), regardless of which
/// orchestrator produced it.
///
/// The Rust `--node` path already writes `parity_input.json` directly, but the
/// bash orchestrator never did — this subcommand is the Bucket-7 bridge that
/// lets a bash run be fed to `vm-lab-diff-orchestrator-parity --mode
/// functional` (the redefined W5.6 flip gate). Emitting BOTH sides through this
/// one converter also makes the comparison apples-to-apples (same construction
/// logic), so a diff reflects a real run difference, not a report-building one.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct VmLabEmitParityInputConfig {
    pub report_dir: PathBuf,
    pub output_path: PathBuf,
}

pub fn execute_ops_vm_lab_emit_parity_input(
    config: VmLabEmitParityInputConfig,
) -> Result<String, String> {
    let report = orchestrator::parity::live_lab_run_report_from_report_dir(&config.report_dir)?;
    if let Some(parent) = config.output_path.parent()
        && !parent.as_os_str().is_empty()
    {
        fs::create_dir_all(parent).map_err(|err| {
            format!(
                "create parity input output directory '{}': {err}",
                parent.display()
            )
        })?;
    }
    let body = serde_json::to_vec_pretty(&report)
        .map_err(|err| format!("serialize parity input: {err}"))?;
    fs::write(&config.output_path, &body).map_err(|err| {
        format!(
            "write parity input to '{}': {err}",
            config.output_path.display()
        )
    })?;
    Ok(format!(
        "parity_input: report_dir='{}' overall={:?} stages={} nodes={} -> {}",
        config.report_dir.display(),
        report.overall_status,
        report.stages.len(),
        report.node_statuses.len(),
        config.output_path.display(),
    ))
}

/// Build the deprecation-warning lines (newline-free, one per item) that
/// callers should emit on stderr when the operator invoked
/// `vm-lab-orchestrate-live-lab` with the legacy `--*-vm` flag set but
/// without `--node` and without `--legacy-bash-orchestrator`.
///
/// The warning is informational only: routing is unchanged for now (the
/// bash orchestrator stays default until W5.5 parity is proven). Once
/// proven, the default flips and the warning escalates the operator's
/// migration path.
/// Track B Step 1 — emit a single stderr line per role whose alias was
/// resolved by the topology layer FROM A NON-EXPLICIT source (i.e.
/// `--topology-profile` or `--exit-platform / --relay-platform /
/// --anchor-platform`). Roles resolved from the existing explicit
/// `--exit-vm` etc flags stay silent so default Linux-exit runs
/// produce byte-identical stderr output.
fn log_topology_resolution_overrides(resolution: &topology::TopologyResolution) {
    for resolved in [
        resolution.exit.as_ref(),
        resolution.relay.as_ref(),
        resolution.anchor.as_ref(),
        resolution.blind_exit.as_ref(),
    ]
    .into_iter()
    .flatten()
    {
        if resolved.source == topology::TopologySource::ExplicitCliAlias {
            continue;
        }
        eprintln!(
            "topology: {} alias resolved to {:?} (source: {:?})",
            resolved.role.as_str(),
            resolved.alias,
            resolved.source
        );
    }
}

pub fn legacy_role_flags_deprecation_warnings(
    config: &VmLabOrchestrateLiveLabConfig,
) -> Vec<String> {
    if config.legacy_bash_orchestrator || !config.node_assignments.is_empty() {
        return Vec::new();
    }
    let any_legacy_role_flag_set = config.exit_vm.is_some()
        || config.client_vm.is_some()
        || config.entry_vm.is_some()
        || config.aux_vm.is_some()
        || config.extra_vm.is_some()
        || config.fifth_client_vm.is_some()
        || config.windows_vm.is_some();
    if !any_legacy_role_flag_set {
        return Vec::new();
    }
    vec![
        "deprecated: --exit-vm/--client-vm/--entry-vm/--aux-vm/--extra-vm/\
         --fifth-client-vm/--windows-vm are transitional aliases; prefer \
         repeated --node <alias>:<role> flags for the same role assignment."
            .to_owned(),
        "the bash orchestrator remains the default execution path; once \
         W5.5 cross-orchestrator parity evidence is captured the Rust \
         orchestrator becomes default and the legacy flags will translate \
         to --node automatically. Pass --legacy-bash-orchestrator to lock \
         in the bash path explicitly."
            .to_owned(),
    ]
}

