/// Build the `PowerShell` script body that invokes one of the security-check
/// subcommands on the live Windows guest. Centralizes argv-only discipline so
/// every stage helper goes through the same audited path: the binary path and
/// every additional argument is quoted via `powershell_quote`, the subcommand
/// name and well-formed flags pass through unquoted, and any value carrying a
/// `PowerShell` metacharacter or control byte is rejected at construction.
fn build_windows_security_check_invocation(
    subcommand: &str,
    extra_args: &[String],
) -> Result<String, String> {
    build_windows_exe_check_invocation(
        WINDOWS_RUSTYNETD_EXE_PATH,
        "Windows security-check",
        subcommand,
        extra_args,
    )
}

fn build_windows_relay_check_invocation(
    subcommand: &str,
    extra_args: &[String],
) -> Result<String, String> {
    build_windows_exe_check_invocation(
        WINDOWS_RUSTYNET_RELAY_EXE_PATH,
        "Windows relay-check",
        subcommand,
        extra_args,
    )
}

fn build_windows_exe_check_invocation(
    exe_path: &str,
    label: &str,
    subcommand: &str,
    extra_args: &[String],
) -> Result<String, String> {
    ensure_no_control_chars("Windows check executable path", exe_path)?;
    ensure_no_control_chars(format!("{label} subcommand").as_str(), subcommand)?;
    if subcommand.is_empty()
        || !subcommand
            .chars()
            .all(|ch| ch.is_ascii_alphanumeric() || ch == '-')
    {
        return Err(format!(
            "{label} subcommand must be ASCII-alphanumeric+hyphen: {subcommand:?}"
        ));
    }
    let mut script = format!(
        "& {exe} {subcommand} --no-fail-on-drift",
        exe = powershell_quote(exe_path)?,
    );
    for arg in extra_args {
        ensure_no_control_chars(format!("{label} arg").as_str(), arg.as_str())?;
        script.push(' ');
        if arg.starts_with("--")
            && arg
                .chars()
                .skip(2)
                .all(|ch| ch.is_ascii_alphanumeric() || ch == '-')
        {
            // Well-formed long-flag: alphanumeric/hyphen only after `--`.
            // Safe to emit unquoted (PowerShell parser treats these as tokens).
            script.push_str(arg.as_str());
        } else {
            script.push_str(powershell_quote(arg.as_str())?.as_str());
        }
    }
    Ok(script)
}

fn build_windows_exit_evidence_inventory_script() -> Result<String, String> {
    let mut entries = Vec::new();
    for spec in windows_exit_evidence_artifact_specs() {
        let remote_path =
            windows_guest_path_join(WINDOWS_EXIT_EVIDENCE_REMOTE_ROOT, spec.remote_relative_path)?;
        entries.push(format!(
            "[pscustomobject]@{{ label = {}; exists = (Test-Path -LiteralPath {} -PathType Leaf) }}",
            powershell_quote(spec.label)?,
            powershell_quote(remote_path.as_str())?
        ));
    }
    Ok(format!(
        "Set-StrictMode -Version Latest; \
         $ErrorActionPreference = 'Stop'; \
         $ProgressPreference = 'SilentlyContinue'; \
         @({}) | ConvertTo-Json -Depth 4",
        entries.join("; ")
    ))
}

fn parse_windows_exit_evidence_inventory(raw_json: &str) -> Result<HashSet<String>, String> {
    let parsed: Value = serde_json::from_str(raw_json)
        .map_err(|err| format!("parse Windows Exit evidence inventory failed: {err}"))?;
    let entries = parsed
        .as_array()
        .ok_or_else(|| "Windows Exit evidence inventory must be a JSON array".to_owned())?;
    let allowed_labels = windows_exit_evidence_artifact_specs()
        .iter()
        .map(|spec| spec.label)
        .collect::<HashSet<_>>();
    let mut found = HashSet::new();
    for entry in entries {
        let label = require_json_str(entry, "label")?;
        if !allowed_labels.contains(label) {
            return Err(format!(
                "Windows Exit evidence inventory returned unexpected label {label:?}"
            ));
        }
        if require_json_bool(entry, "exists")? {
            found.insert(label.to_owned());
        }
    }
    Ok(found)
}

fn build_windows_exit_evidence_capture_script() -> Result<String, String> {
    let root = powershell_quote(WINDOWS_EXIT_EVIDENCE_REMOTE_ROOT)?;
    let marker = powershell_quote(WINDOWS_EXIT_KILLSWITCH_PROBE_MARKER)?;
    let daemon = powershell_quote(WINDOWS_RUSTYNETD_EXE_PATH)?;
    let template = r#"
Set-StrictMode -Version Latest;
$ErrorActionPreference = 'Stop';
$ProgressPreference = 'SilentlyContinue';
$ArtifactRoot = __ROOT__;
$DnsDir = Join-Path -Path $ArtifactRoot -ChildPath 'dns_leak_proof';
$DaemonPath = __DAEMON__;
$KillswitchProbeMarker = __MARKER__;
$TunnelAlias = 'rustynet0';
$MeshCidr = '100.64.0.0/10';
$NatName = 'RustyNetExit-rustynet0';
$ServiceName = 'RustyNet';
$script:WrittenLabels = @();
$script:SkippedReasons = @();
function Add-WrittenLabel {
    param([string]$Label)
    $script:WrittenLabels += $Label
}
function Add-SkippedReason {
    param([string]$Reason)
    $script:SkippedReasons += $Reason
}
function Write-JsonFile {
    param([string]$Path, [object]$Value)
    $parent = Split-Path -Parent $Path;
    New-Item -ItemType Directory -Force -Path $parent | Out-Null;
    $Value | ConvertTo-Json -Depth 12 | Set-Content -LiteralPath $Path -Encoding UTF8;
}
function Get-ForwardingState {
    param([string]$Alias)
    try {
        return [string]((Get-NetIPInterface -InterfaceAlias $Alias -AddressFamily IPv4 -ErrorAction Stop).Forwarding)
    } catch {
        return ('Error: ' + $_.Exception.Message)
    }
}
function Get-DefaultEgressAlias {
    try {
        return [string](Get-NetRoute -DestinationPrefix '0.0.0.0/0' -ErrorAction Stop |
            Where-Object { $_.InterfaceAlias -ne $TunnelAlias } |
            Sort-Object -Property RouteMetric,InterfaceMetric |
            Select-Object -First 1 -ExpandProperty InterfaceAlias)
    } catch {
        return ''
    }
}
function Test-NetNatAbsent {
    # Fail-closed NAT presence (mirrors the RSA-0031 daemon merge in
    # crates/rustynetd/src/windows_exit_nat_lifecycle.rs): only a query that
    # SUCCEEDS and returns no matching NetNat proves the NAT was torn down.
    # `Get-NetNat -ErrorAction SilentlyContinue` conflates "absent" with
    # "provider/WMI query failed" — both return $null — which would let a query
    # error be read as a successful teardown (fail-open). The MSFT_NetNat
    # provider throws a CimException "No MSFT_NetNat objects found ..." for a
    # genuinely-absent named NAT; that single message is the only error that
    # counts as absent. Any other failure is indeterminate → treated as PRESENT
    # (not torn down) so teardown can never be claimed from an error.
    param([string]$Name)
    try {
        $existing = Get-NetNat -Name $Name -ErrorAction Stop;
        return ($null -eq $existing);
    } catch {
        if ($_.Exception.Message -match 'No MSFT_NetNat') {
            return $true;
        }
        return $false;
    }
}

New-Item -ItemType Directory -Force -Path $ArtifactRoot | Out-Null;

$egressAlias = Get-DefaultEgressAlias;
$nat = Get-NetNat -Name $NatName -ErrorAction SilentlyContinue;
if ($null -eq $nat) {
    Add-SkippedReason 'NAT lifecycle proof skipped: reviewed NetNat was not present; Windows host is not currently serving exit traffic';
} elseif ([string]::IsNullOrWhiteSpace($egressAlias)) {
    Add-SkippedReason 'NAT lifecycle proof skipped: no non-tunnel default egress interface was detected';
} else {
    $duringTunnelForwarding = Get-ForwardingState -Alias $TunnelAlias;
    $duringEgressForwarding = Get-ForwardingState -Alias $egressAlias;
    $stopError = '';
    try {
        Stop-Service -Name $ServiceName -Force -ErrorAction Stop;
        Start-Sleep -Seconds 4;
    } catch {
        $stopError = $_.Exception.Message;
    }
    # Fail-closed teardown evaluation (mirror of the RSA-0031 daemon merge):
    # restoration is proven ONLY when the NAT query succeeds and shows it gone
    # AND both interfaces report the literal 'Disabled'. A NetNat query error
    # counts as still-present; a forwarding query error ('Error: ...') is not
    # 'Disabled' and so cannot be read as restored.
    $afterNatAbsent = Test-NetNatAbsent -Name $NatName;
    $afterTunnelForwarding = Get-ForwardingState -Alias $TunnelAlias;
    $afterEgressForwarding = Get-ForwardingState -Alias $egressAlias;
    $forwardingRestored = $afterNatAbsent -and
        ($afterTunnelForwarding -eq 'Disabled') -and
        ($afterEgressForwarding -eq 'Disabled');
    # The host WAS serving exit (NAT present during run), so a clean teardown is
    # MANDATORY. Always emit the lifecycle artifact with the real measured
    # after-stop state — never skip on a non-restoration. Writing the artifact
    # only on success would let a genuine residual NAT (a release-blocking open
    # relay) be masked as a Skip, because the validate stage maps an ABSENT
    # artifact to Skipped. With the artifact always present, the validator
    # FAILS on netnat_present=true or forwarding_restored=false.
    Write-JsonFile -Path (Join-Path -Path $ArtifactRoot -ChildPath 'scm_context_nat_lifecycle.json') -Value ([pscustomobject]@{
        schema_version = 1;
        nat_name = $NatName;
        mesh_cidr = $MeshCidr;
        during_run = [pscustomobject]@{
            netnat_present = $true;
            internal_prefix = [string]$nat.InternalIPInterfaceAddressPrefix;
            tunnel_forwarding = $duringTunnelForwarding;
            egress_forwarding = $duringEgressForwarding;
            egress_alias = $egressAlias;
        };
        after_stop = [pscustomobject]@{
            netnat_present = (-not $afterNatAbsent);
            forwarding_restored = $forwardingRestored;
            tunnel_forwarding = $afterTunnelForwarding;
            egress_forwarding = $afterEgressForwarding;
            stop_error = $stopError;
        };
    });
    Add-WrittenLabel 'scm_context_nat_lifecycle';
    if (-not $forwardingRestored) {
        Add-SkippedReason ('NAT lifecycle teardown did NOT prove restoration (artifact emitted for fail-closed validation); stop_error=' + $stopError + '; after_nat_absent=' + $afterNatAbsent + '; after_tunnel=' + $afterTunnelForwarding + '; after_egress=' + $afterEgressForwarding);
    }
    try {
        Start-Service -Name $ServiceName -ErrorAction Stop;
        Start-Sleep -Seconds 8;
    } catch {
        Add-SkippedReason ('service restart after NAT lifecycle probe failed: ' + $_.Exception.Message);
    }
}

$dnsRuleNames = @('RustyNetDNS-BlockLanUdp', 'RustyNetDNS-BlockLanTcp');
$dnsRules = @();
foreach ($ruleName in $dnsRuleNames) {
    $rule = Get-NetFirewallRule -Name $ruleName -ErrorAction SilentlyContinue;
    if ($null -ne $rule) {
        $dnsRules += [pscustomobject]@{
            name = [string]$rule.Name;
            action = [string]$rule.Action;
            direction = [string]$rule.Direction;
            enabled = [string]$rule.Enabled;
            profile = [string]$rule.Profile;
        };
    }
}
$dnsRulesOk = ($dnsRules.Count -eq 2) -and
    (($dnsRules | Where-Object { $_.action -eq 'Block' -and $_.direction -eq 'Outbound' -and $_.enabled -eq 'True' }).Count -eq 2);
if ($dnsRulesOk) {
    New-Item -ItemType Directory -Force -Path $DnsDir | Out-Null;
    Write-JsonFile -Path (Join-Path -Path $DnsDir -ChildPath 'firewall_block_rules.json') -Value ([pscustomobject]@{
        schema_version = 1;
        overall_ok = $true;
        rules = $dnsRules;
    });
    Add-WrittenLabel 'dns_firewall_block_rules';
    $dnsCheckRaw = (& $DaemonPath windows-dns-failclosed-check --no-fail-on-drift 2>&1) -join [Environment]::NewLine;
    if ($LASTEXITCODE -eq 0) {
        Set-Content -LiteralPath (Join-Path -Path $DnsDir -ChildPath 'windows_dns_failclosed_check.json') -Value $dnsCheckRaw -Encoding UTF8;
        Add-WrittenLabel 'dns_failclosed_check';
    } else {
        Add-SkippedReason ('windows-dns-failclosed-check did not exit cleanly: ' + $dnsCheckRaw);
    }
} else {
    Add-SkippedReason 'DNS packet proof precheck skipped: reviewed RustyNet DNS block firewall rules were not both present/enforced';
}

if (Test-Path -LiteralPath $KillswitchProbeMarker -PathType Leaf) {
    $baselineRaw = (& $DaemonPath windows-killswitch-assert --no-fail-on-drift 2>&1) -join [Environment]::NewLine;
    $baselineCode = [int]$LASTEXITCODE;
    $baselineOk = $false;
    try {
        $baselineJson = $baselineRaw | ConvertFrom-Json -ErrorAction Stop;
        $baselineOk = [bool]$baselineJson.overall_ok;
    } catch {
        Add-SkippedReason ('killswitch precedence proof skipped: baseline JSON parse failed: ' + $_.Exception.Message);
    }
    if ($baselineCode -eq 0 -and $baselineOk) {
        $tamperedRaw = '';
        $tamperedCode = 0;
        try {
            Set-NetFirewallProfile -Profile Domain,Private,Public -DefaultOutboundAction Allow -ErrorAction Stop;
            $tamperedRaw = (& $DaemonPath windows-killswitch-assert 2>&1) -join [Environment]::NewLine;
            $tamperedCode = [int]$LASTEXITCODE;
        } finally {
            try {
                Set-NetFirewallProfile -Profile Domain,Private,Public -DefaultOutboundAction Block -ErrorAction SilentlyContinue;
            } catch {
            }
            try {
                Start-Service -Name $ServiceName -ErrorAction SilentlyContinue;
                Start-Sleep -Seconds 8;
            } catch {
            }
        }
        if ($tamperedCode -ne 0) {
            Write-JsonFile -Path (Join-Path -Path $ArtifactRoot -ChildPath 'killswitch_precedence.json') -Value ([pscustomobject]@{
                schema_version = 1;
                baseline_assert = [pscustomobject]@{
                    overall_ok = $true;
                };
                tampered_assert = [pscustomobject]@{
                    overall_ok = $false;
                    exit_code = $tamperedCode;
                    reason = $tamperedRaw.Trim();
                };
            });
            Add-WrittenLabel 'killswitch_precedence';
        } else {
            Add-SkippedReason 'killswitch precedence proof skipped: tampered assertion exited zero';
        }
    } elseif ($baselineCode -ne 0) {
        Add-SkippedReason ('killswitch precedence proof skipped: baseline assertion failed: ' + $baselineRaw);
    }
} else {
    Add-SkippedReason ('killswitch precedence proof skipped: marker file not present at ' + $KillswitchProbeMarker);
}

[pscustomobject]@{
    schema_version = 1;
    artifact_root = $ArtifactRoot;
    written_labels = $script:WrittenLabels;
    skipped_reasons = $script:SkippedReasons;
} | ConvertTo-Json -Depth 12
"#;
    Ok(template
        .replace("__ROOT__", root.as_str())
        .replace("__DAEMON__", daemon.as_str())
        .replace("__MARKER__", marker.as_str()))
}

fn parse_windows_exit_evidence_capture_summary(raw_json: &str) -> Result<(usize, String), String> {
    let report: Value = serde_json::from_str(raw_json)
        .map_err(|err| format!("parse Windows Exit evidence capture summary failed: {err}"))?;
    if require_json_u64(&report, "schema_version")? != 1 {
        return Err(
            "Windows Exit evidence capture summary returned unsupported schema_version".to_owned(),
        );
    }
    let allowed_labels = windows_exit_evidence_artifact_specs()
        .iter()
        .map(|spec| spec.label)
        .collect::<HashSet<_>>();
    let written = require_json_array(&report, "written_labels")?;
    for label in written {
        let label = label
            .as_str()
            .ok_or_else(|| "written_labels entries must be strings".to_owned())?;
        if !allowed_labels.contains(label) {
            return Err(format!(
                "Windows Exit evidence capture returned unexpected label {label:?}"
            ));
        }
    }
    let skipped_count = report
        .get("skipped_reasons")
        .and_then(Value::as_array)
        .map_or(0, std::vec::Vec::len);
    Ok((written.len(), format!("{skipped_count} skipped reason(s)")))
}

/// Track B Step 4 (W1) — promote a Windows host to the active mesh
/// exit by:
///
/// 1. Running the reviewed `Install-RustyNetWindowsExitService.ps1`
///    preflight on the Windows host (enables IPv4 forwarding on every
///    interface and writes a reviewed install-evidence JSON).
/// 2. Polling Windows SCM + the daemon-owned
///    `rustynetd.exe windows-mesh-status-check` probe until the
///    daemon is Running, has the reviewed admin env-file posture, and
///    publishes a fresh runtime mesh snapshot. This avoids
///    `rustynet.exe status` on Windows because that binary can be the
///    trust CLI and is not a daemon-control surface.
///
/// The host-interface egress evidence is captured by the existing
/// `validate_windows_exit_nat_lifecycle` stage, which inspects the
/// `internal_prefix` and `tunnel_forwarding`/`egress_forwarding`
/// fields of the NAT lifecycle artefact — the spec's "source IP
/// field" evidence.
fn promote_windows_to_active_exit(
    windows_alias: &str,
    inventory_path: &Path,
    ssh_identity_file: &Path,
    known_hosts_path: Option<&Path>,
) -> Result<String, String> {
    let targets = resolve_remote_targets(inventory_path, &[windows_alias.to_owned()], false, &[])?;
    let target = targets
        .into_iter()
        .next()
        .ok_or_else(|| format!("no target resolved for alias {windows_alias}"))?;
    if target.platform_profile.platform != VmGuestPlatform::Windows {
        return Err(format!(
            "alias {windows_alias} resolved to non-Windows platform: {}",
            target.platform_profile.platform.as_str()
        ));
    }
    let timeout = timeout_or_default(0, DEFAULT_RUN_TIMEOUT_SECS);

    // Step 1: run the reviewed exit preflight installer via PowerShell.
    // The script writes a structured install-evidence JSON and exits
    // non-zero on per-interface failures, so success implies forwarding
    // was enabled on every IPv4 interface.
    let install_script = format!(
        "& {exe} ops install-windows-exit-service",
        exe = powershell_quote(WINDOWS_RUSTYNETD_CLI_PATH)?,
    );
    let install_invocation = build_ssh_powershell_encoded_invocation(install_script.as_str())?;
    let install_output = capture_remote_shell_command_for_target(
        &target,
        None,
        Some(ssh_identity_file),
        known_hosts_path,
        install_invocation.as_str(),
        timeout,
    )
    .map_err(|err| format!("install-windows-exit-service on {windows_alias} failed: {err}"))?;
    let install_trimmed = install_output.trim().to_owned();

    // Step 2: poll daemon-owned readiness. Never call
    // `rustynet.exe status`: on Windows that binary may be the trust
    // CLI, not a daemon-control CLI. Active-exit NAT/DNS/killswitch
    // stages provide the exit-serving proof after this gate.
    let poll_script = build_windows_active_exit_readiness_script(
        windows_alias,
        WINDOWS_ACTIVE_EXIT_PROMOTE_TIMEOUT_SECS,
    )?;
    let poll_invocation = build_ssh_powershell_encoded_invocation(poll_script.as_str())?;
    let poll_output = capture_remote_shell_command_for_target(
        &target,
        None,
        Some(ssh_identity_file),
        known_hosts_path,
        poll_invocation.as_str(),
        timeout_or_default(
            WINDOWS_ACTIVE_EXIT_PROMOTE_TIMEOUT_SECS + 30,
            DEFAULT_RUN_TIMEOUT_SECS,
        ),
    )
    .map_err(|err| {
        if windows_trust_cli_status_output(err.as_str()) {
            return classify_windows_active_exit_readiness_output(windows_alias, err.as_str())
                .expect_err("trust CLI status output must classify as readiness error");
        }
        format!("polling Windows daemon readiness for {windows_alias} failed: {err}")
    })?;
    let poll_trimmed = poll_output.trim().to_owned();
    classify_windows_active_exit_readiness_output(windows_alias, poll_trimmed.as_str())?;
    Ok(format!(
        "Windows host {windows_alias} promoted to active mesh exit; preflight: {install_trimmed}; daemon readiness: {poll_trimmed}"
    ))
}

/// Cap on the Windows active-exit promotion IPC poll. Long enough to
/// absorb a daemon restart on the Windows host (Set-NetIPInterface +
/// SCM service reload typically settles in <30s), short enough that a
/// wedged daemon fails the stage instead of stalling the live lab.
const WINDOWS_ACTIVE_EXIT_PROMOTE_TIMEOUT_SECS: u64 = 60;

/// Path of the installed `rustynet.exe` (CLI) on Windows guests. This is
/// only valid for reviewed `rustynet ops ...` invocations; it must not be
/// used as a daemon status/readiness CLI on Windows.
const WINDOWS_RUSTYNETD_CLI_PATH: &str = r"C:\Program Files\RustyNet\rustynet.exe";

const WINDOWS_RUSTYNETD_ENV_PATH: &str = r"C:\ProgramData\RustyNet\config\rustynetd.env";
const WINDOWS_WIREGUARD_PUBLIC_KEY_PATH: &str = r"C:\ProgramData\RustyNet\keys\wireguard.pub";

fn build_windows_active_exit_readiness_script(
    windows_alias: &str,
    timeout_secs: u64,
) -> Result<String, String> {
    ensure_no_control_chars("Windows alias", windows_alias)?;
    let alias_q = powershell_quote(windows_alias)?;
    let daemon_q = powershell_quote(WINDOWS_RUSTYNETD_EXE_PATH)?;
    let env_q = powershell_quote(WINDOWS_RUSTYNETD_ENV_PATH)?;
    let key_q = powershell_quote(WINDOWS_WIREGUARD_PUBLIC_KEY_PATH)?;
    Ok(format!(
        "Set-StrictMode -Version Latest; \
         $ErrorActionPreference = 'Stop'; \
         $TargetAlias = {alias_q}; \
         $DaemonPath = {daemon_q}; \
         $EnvPath = {env_q}; \
         $KeyPath = {key_q}; \
         $deadline = (Get-Date).AddSeconds({timeout_secs}); \
         $last = 'not-started'; \
         while ((Get-Date) -lt $deadline) {{ \
           $svc = Get-Service -Name RustyNet -ErrorAction SilentlyContinue; \
           $svcStatus = if ($null -eq $svc) {{ 'missing' }} else {{ [string]$svc.Status }}; \
           $envContent = ''; \
           if (Test-Path -LiteralPath $EnvPath -PathType Leaf) {{ \
             $envContent = Get-Content -LiteralPath $EnvPath -Raw -ErrorAction Stop \
           }}; \
           $nodeMatch = [regex]::Match($envContent, '\"--node-id\",\"([^\"]+)\"'); \
           $roleMatch = [regex]::Match($envContent, '\"--node-role\",\"([^\"]+)\"'); \
           $nodeId = if ($nodeMatch.Success) {{ $nodeMatch.Groups[1].Value.Trim() }} else {{ '' }}; \
           $role = if ($roleMatch.Success) {{ $roleMatch.Groups[1].Value.Trim() }} else {{ '' }}; \
           $daemonPresent = Test-Path -LiteralPath $DaemonPath -PathType Leaf; \
           $keyPresent = Test-Path -LiteralPath $KeyPath -PathType Leaf; \
           if ($svcStatus -eq 'Running' -and $daemonPresent -and $nodeId.Length -gt 0 -and $role -eq 'admin' -and $keyPresent) {{ \
             $probeOut = & $DaemonPath windows-mesh-status-check --max-age-seconds 120 2>&1; \
             $probeExit = $LASTEXITCODE; \
             $probeText = [string]::Join(\"`n\", @($probeOut)); \
             if ($probeExit -eq 0) {{ \
               $probeJson = $probeText | ConvertFrom-Json -ErrorAction Stop; \
               if ($probeJson.overall_ok -eq $true) {{ \
                 Write-Output ('PROMOTED node_id=' + $nodeId + ' service=Running role=admin mesh_status=ok'); \
                 exit 0 \
               }} \
             }}; \
             $last = 'service=' + $svcStatus + ' node_id=' + $nodeId + ' role=' + $role + ' probe_exit=' + $probeExit + ' probe=' + $probeText \
           }} else {{ \
             $last = 'service=' + $svcStatus + ' daemon_present=' + $daemonPresent + ' env_present=' + ($envContent.Length -gt 0) + ' node_id_present=' + ($nodeId.Length -gt 0) + ' role=' + $role + ' wireguard_pub_present=' + $keyPresent \
           }}; \
           Start-Sleep -Seconds 2 \
         }}; \
         Write-Error ('timed out waiting for Windows daemon readiness on ' + $TargetAlias + '; last=' + $last); \
         exit 1"
    ))
}

fn windows_trust_cli_status_output(raw_output: &str) -> bool {
    let lower = raw_output.to_ascii_lowercase();
    lower.contains("unknown rustynet-windows-trust-cli command: status")
        || lower.contains("usage: rustynet trust")
}

fn classify_windows_active_exit_readiness_output(
    windows_alias: &str,
    raw_output: &str,
) -> Result<(), String> {
    if raw_output.contains("PROMOTED") {
        return Ok(());
    }
    if windows_trust_cli_status_output(raw_output) {
        return Err(format!(
            "Windows daemon readiness for {windows_alias} received trust-CLI status output; rustynet.exe is not a daemon status CLI. Expected SCM Running plus rustynetd.exe windows-mesh-status-check readiness."
        ));
    }
    Err(format!(
        "Windows daemon on {windows_alias} did not reach SCM/env/probe readiness within {WINDOWS_ACTIVE_EXIT_PROMOTE_TIMEOUT_SECS}s: {raw_output}"
    ))
}

fn capture_windows_exit_evidence_artifacts(
    windows_alias: &str,
    inventory_path: &Path,
    ssh_identity_file: &Path,
    known_hosts_path: Option<&Path>,
) -> Result<(String, String, bool), (String, String)> {
    let targets = resolve_remote_targets(inventory_path, &[windows_alias.to_owned()], false, &[])
        .map_err(|err| (err, String::new()))?;
    let target = targets.into_iter().next().ok_or_else(|| {
        (
            format!("no target resolved for alias {windows_alias}"),
            String::new(),
        )
    })?;
    if target.platform_profile.platform != VmGuestPlatform::Windows {
        return Err((
            format!(
                "alias {windows_alias} resolved to non-Windows platform: {}",
                target.platform_profile.platform.as_str()
            ),
            String::new(),
        ));
    }
    let timeout = timeout_or_default(0, DEFAULT_RUN_TIMEOUT_SECS);
    let script =
        build_windows_exit_evidence_capture_script().map_err(|err| (err, String::new()))?;
    let raw_output = capture_remote_shell_command_for_target(
        &target,
        None,
        Some(ssh_identity_file),
        known_hosts_path,
        script.as_str(),
        timeout,
    )
    .map_err(|err| {
        (
            format!("remote Windows Exit evidence capture failed: {err}"),
            String::new(),
        )
    })?;
    let raw_trimmed = raw_output.trim().to_owned();
    let (written_count, skipped_summary) =
        parse_windows_exit_evidence_capture_summary(raw_trimmed.as_str())
            .map_err(|err| (err, raw_trimmed.clone()))?;
    let wrote_any = written_count > 0;
    let summary = if wrote_any {
        format!(
            "captured {written_count} Windows Exit evidence artifact(s) on {windows_alias} under {WINDOWS_EXIT_EVIDENCE_REMOTE_ROOT}; {skipped_summary}"
        )
    } else {
        format!(
            "skipped: no Windows Exit evidence artifacts captured on {windows_alias}; {skipped_summary}"
        )
    };
    Ok((summary, raw_trimmed, wrote_any))
}

fn pull_windows_exit_evidence_artifacts(
    windows_alias: &str,
    inventory_path: &Path,
    ssh_identity_file: &Path,
    known_hosts_path: Option<&Path>,
    local_artifact_root: &Path,
) -> Result<(String, String, Vec<PathBuf>), (String, String)> {
    let targets = resolve_remote_targets(inventory_path, &[windows_alias.to_owned()], false, &[])
        .map_err(|err| (err, String::new()))?;
    let target = targets.into_iter().next().ok_or_else(|| {
        (
            format!("no target resolved for alias {windows_alias}"),
            String::new(),
        )
    })?;
    if target.platform_profile.platform != VmGuestPlatform::Windows {
        return Err((
            format!(
                "alias {windows_alias} resolved to non-Windows platform: {}",
                target.platform_profile.platform.as_str()
            ),
            String::new(),
        ));
    }

    fs::create_dir_all(local_artifact_root).map_err(|err| {
        (
            format!(
                "create Windows Exit local artifact root failed ({}): {err}",
                local_artifact_root.display()
            ),
            String::new(),
        )
    })?;

    let timeout = timeout_or_default(0, DEFAULT_RUN_TIMEOUT_SECS);
    let script =
        build_windows_exit_evidence_inventory_script().map_err(|err| (err, String::new()))?;
    let raw_inventory = capture_remote_shell_command_for_target(
        &target,
        None,
        Some(ssh_identity_file),
        known_hosts_path,
        script.as_str(),
        timeout,
    )
    .map_err(|err| {
        (
            format!("remote Windows Exit evidence inventory failed: {err}"),
            String::new(),
        )
    })?;
    let raw_inventory = raw_inventory.trim().to_owned();
    let available = parse_windows_exit_evidence_inventory(raw_inventory.as_str())
        .map_err(|err| (err, raw_inventory.clone()))?;
    if available.is_empty() {
        return Ok((
            format!(
                "skipped: no Windows Exit evidence artifacts found under {WINDOWS_EXIT_EVIDENCE_REMOTE_ROOT} on {windows_alias}"
            ),
            raw_inventory,
            Vec::new(),
        ));
    }

    let mut copied_paths = Vec::new();
    for spec in windows_exit_evidence_artifact_specs() {
        if !available.contains(spec.label) {
            continue;
        }
        let remote_path =
            windows_guest_path_join(WINDOWS_EXIT_EVIDENCE_REMOTE_ROOT, spec.remote_relative_path)
                .map_err(|err| (err, raw_inventory.clone()))?;
        let local_path = local_artifact_root.join(Path::new(spec.local_relative_path));
        let status = scp_from_remote(
            &target,
            None,
            Some(ssh_identity_file),
            known_hosts_path,
            remote_path.as_str(),
            local_path.as_path(),
            timeout,
        )
        .map_err(|err| {
            (
                format!(
                    "copy Windows Exit evidence artifact {} from {} failed: {err}",
                    spec.label, remote_path
                ),
                raw_inventory.clone(),
            )
        })?;
        if !status.success() {
            return Err((
                format!(
                    "copy Windows Exit evidence artifact {} from {} exited non-zero: {}",
                    spec.label,
                    remote_path,
                    status_code(status)
                ),
                raw_inventory,
            ));
        }
        if !local_path.is_file() {
            return Err((
                format!(
                    "copy Windows Exit evidence artifact {} reported success but local file is missing: {}",
                    spec.label,
                    local_path.display()
                ),
                raw_inventory,
            ));
        }
        copied_paths.push(local_path);
    }

    Ok((
        format!(
            "pulled {} Windows Exit evidence artifact(s) from {windows_alias} into {}",
            copied_paths.len(),
            local_artifact_root.display()
        ),
        raw_inventory,
        copied_paths,
    ))
}

