/// Pure evaluator for the JSON output of `rustynetd policy-default-deny-audit`.
/// The daemon-side audit drives the REAL `rustynet_policy` evaluator with a
/// default-deny truth table (`SecurityMinimumBar.md` §3.6). Fail-closed:
///   - empty corpus, or no ALLOW case passed (the vacuous deny-all pass),
///   - any case whose decision did not match expectation.
pub(crate) fn evaluate_policy_default_deny_report(
    linux_alias: &str,
    raw_json: &str,
) -> Result<String, String> {
    let report: rustynetd::policy_default_deny_audit::PolicyDefaultDenyAuditReport =
        serde_json::from_str(raw_json)
            .map_err(|err| format!("parse policy-default-deny-audit JSON output failed: {err}"))?;
    if report.schema_version != 1 {
        return Err(format!(
            "policy-default-deny-audit returned unsupported schema_version={}",
            report.schema_version
        ));
    }
    if report.total_cases == 0 {
        return Err(
            "policy-default-deny-audit returned an empty corpus; the truth table is missing"
                .to_owned(),
        );
    }
    if report.allow_cases_passed == 0 {
        return Err(
            "policy-default-deny-audit passed no ALLOW case; the audit is vacuous (a broken deny-all evaluator would pass) and proves nothing"
                .to_owned(),
        );
    }
    if !report.overall_ok {
        let summary = if report.violations.is_empty() {
            "report set overall_ok=false but listed no violations; output is inconsistent"
                .to_owned()
        } else {
            report
                .violations
                .iter()
                .map(|v| format!("{} (expected {}, got {})", v.id, v.expected, v.actual))
                .collect::<Vec<_>>()
                .join("; ")
        };
        return Err(format!(
            "policy default-deny truth table drift on {linux_alias}: {summary}"
        ));
    }
    Ok(format!(
        "Policy default-deny truth table verified on {linux_alias}: {} deny + {} allow cases held",
        report.deny_cases_passed, report.allow_cases_passed
    ))
}

/// macOS DNS fail-closed artefact-directory validator. Parallel to the
/// Windows variant. Required files in the artefact directory:
///
/// - `pf_block_rules.json` — pf NAT/quick-block rules covering UDP 53
///   and TCP 53 toward the LAN; overall_ok=true
/// - `udp_block_pcap.txt` / `tcp_block_pcap.txt` — empty (no DNS
///   egress observed on the LAN side while the daemon enforces the
///   killswitch)
/// - `tunnel_path_resolves.json` — positive control: a query routed
///   through the tunnel returned an answer
/// - `macos_dns_failclosed_check.json` — `{ schema_version: 1,
///   overall_ok: bool, drift_reasons: [String] }`, mirrors the
///   Windows-side `windows_dns_failclosed_check.json` contract.
fn evaluate_macos_exit_dns_failclosed_artifact_dir(
    macos_alias: &str,
    artifact_dir: &Path,
) -> Result<String, String> {
    macos_exit_dns_failclosed_artifact_set_complete(artifact_dir)?;
    let pf_rules = fs::read_to_string(artifact_dir.join("pf_block_rules.json"))
        .map_err(|err| format!("read pf_block_rules.json failed: {err}"))?;
    let pf_report: Value = serde_json::from_str(&pf_rules)
        .map_err(|err| format!("parse pf_block_rules.json failed: {err}"))?;
    require_json_u64(&pf_report, "schema_version")?
        .eq(&1)
        .then_some(())
        .ok_or_else(|| "pf_block_rules.json returned unsupported schema_version".to_owned())?;
    if !require_json_bool(&pf_report, "overall_ok")? {
        return Err("pf_block_rules.json did not report overall_ok=true".to_owned());
    }
    let rules = require_json_array(&pf_report, "rules")?;
    require_pf_block_rule(rules, "rustynet-dns-block-lan-udp")?;
    require_pf_block_rule(rules, "rustynet-dns-block-lan-tcp")?;

    let udp_pcap = fs::read_to_string(artifact_dir.join("udp_block_pcap.txt"))
        .map_err(|err| format!("read udp_block_pcap.txt failed: {err}"))?;
    require_empty_dns_pcap("udp_block_pcap.txt", udp_pcap.as_str())?;
    let tcp_pcap = fs::read_to_string(artifact_dir.join("tcp_block_pcap.txt"))
        .map_err(|err| format!("read tcp_block_pcap.txt failed: {err}"))?;
    require_empty_dns_pcap("tcp_block_pcap.txt", tcp_pcap.as_str())?;

    // Anti-vacuous guard: an empty egress pcap only proves the killswitch works
    // if a real off-tunnel DNS query was actively driven during the capture.
    // dns_block_probe.json records that probe; fail closed unless it ran AND no
    // DNS response was observed on either transport.
    let probe = fs::read_to_string(artifact_dir.join("dns_block_probe.json"))
        .map_err(|err| format!("read dns_block_probe.json failed: {err}"))?;
    let probe_report: Value = serde_json::from_str(&probe)
        .map_err(|err| format!("parse dns_block_probe.json failed: {err}"))?;
    require_json_u64(&probe_report, "schema_version")?
        .eq(&1)
        .then_some(())
        .ok_or_else(|| "dns_block_probe.json returned unsupported schema_version".to_owned())?;
    if !require_json_bool(&probe_report, "probe_attempted")? {
        return Err(
            "dns_block_probe.json reports the blocked-path probe never ran; an empty pcap without an active off-tunnel probe is vacuous — failing closed"
                .to_owned(),
        );
    }
    if require_json_bool(&probe_report, "udp_response_received")?
        || require_json_bool(&probe_report, "tcp_response_received")?
    {
        return Err(
            "dns_block_probe.json observed a DNS response on the off-tunnel path: LAN DNS is NOT fail-closed (leak)"
                .to_owned(),
        );
    }
    if !require_json_bool(&probe_report, "overall_ok")? {
        return Err("dns_block_probe.json did not report overall_ok=true".to_owned());
    }

    let positive_control = fs::read_to_string(artifact_dir.join("tunnel_path_resolves.json"))
        .map_err(|err| format!("read tunnel_path_resolves.json failed: {err}"))?;
    let positive_report: Value = serde_json::from_str(&positive_control)
        .map_err(|err| format!("parse tunnel_path_resolves.json failed: {err}"))?;
    if !require_json_bool(&positive_report, "overall_ok")?
        || !require_json_bool(&positive_report, "resolved")?
    {
        return Err(
            "tunnel_path_resolves.json did not prove tunnel DNS positive control".to_owned(),
        );
    }

    let dns_check = fs::read_to_string(artifact_dir.join("macos_dns_failclosed_check.json"))
        .map_err(|err| format!("read macos_dns_failclosed_check.json failed: {err}"))?;
    evaluate_macos_dns_failclosed_report(macos_alias, dns_check.as_str())?;

    Ok(format!(
        "macOS exit DNS leak proof verified on {macos_alias}: off-tunnel probe driven, UDP/TCP egress pcaps empty, no probe response, and tunnel positive control passed"
    ))
}

fn macos_exit_dns_failclosed_artifact_set_complete(artifact_dir: &Path) -> Result<(), String> {
    let required = [
        "pf_block_rules.json",
        "udp_block_pcap.txt",
        "tcp_block_pcap.txt",
        "dns_block_probe.json",
        "tunnel_path_resolves.json",
        "macos_dns_failclosed_check.json",
    ];
    let missing = required
        .iter()
        .filter(|relative| !artifact_dir.join(relative).is_file())
        .copied()
        .collect::<Vec<_>>();
    if missing.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "missing required artifact(s): {}",
            missing.join(", ")
        ))
    }
}

/// Linux exit-mode DNS fail-closed artefact-directory validator.
/// Mirrors the macOS/Windows exit DNS contracts, but reads the Linux
/// nftables producer's `firewall_block_rules.json` and existing
/// `linux_dns_failclosed_check.json` report.
fn evaluate_linux_exit_dns_failclosed_artifact_dir(
    linux_alias: &str,
    artifact_dir: &Path,
) -> Result<String, String> {
    linux_exit_dns_failclosed_artifact_set_complete(artifact_dir)?;
    let firewall_rules = fs::read_to_string(artifact_dir.join("firewall_block_rules.json"))
        .map_err(|err| format!("read firewall_block_rules.json failed: {err}"))?;
    let firewall_report: Value = serde_json::from_str(&firewall_rules)
        .map_err(|err| format!("parse firewall_block_rules.json failed: {err}"))?;
    require_json_u64(&firewall_report, "schema_version")?
        .eq(&1)
        .then_some(())
        .ok_or_else(|| {
            "firewall_block_rules.json returned unsupported schema_version".to_owned()
        })?;
    if !require_json_bool(&firewall_report, "overall_ok")? {
        return Err("firewall_block_rules.json did not report overall_ok=true".to_owned());
    }
    let rules = require_json_array(&firewall_report, "rules")?;
    require_linux_dns_block_rule(rules, "rustynet-dns-block-lan-udp")?;
    require_linux_dns_block_rule(rules, "rustynet-dns-block-lan-tcp")?;

    let udp_pcap = fs::read_to_string(artifact_dir.join("udp_block_pcap.txt"))
        .map_err(|err| format!("read udp_block_pcap.txt failed: {err}"))?;
    require_empty_dns_pcap("udp_block_pcap.txt", udp_pcap.as_str())?;
    let tcp_pcap = fs::read_to_string(artifact_dir.join("tcp_block_pcap.txt"))
        .map_err(|err| format!("read tcp_block_pcap.txt failed: {err}"))?;
    require_empty_dns_pcap("tcp_block_pcap.txt", tcp_pcap.as_str())?;

    // Anti-vacuous guard (mirrors the macOS validator): an empty egress pcap
    // only proves the killswitch works if a real off-tunnel DNS query was
    // actively driven during the capture. dns_block_probe.json records that
    // probe; fail closed unless it ran AND no DNS response was observed on
    // either transport. Without this, the require_empty_dns_pcap checks above
    // pass on "nothing tried DNS" — a vacuous PASS, not a fail-closed proof.
    let probe = fs::read_to_string(artifact_dir.join("dns_block_probe.json"))
        .map_err(|err| format!("read dns_block_probe.json failed: {err}"))?;
    let probe_report: Value = serde_json::from_str(&probe)
        .map_err(|err| format!("parse dns_block_probe.json failed: {err}"))?;
    require_json_u64(&probe_report, "schema_version")?
        .eq(&1)
        .then_some(())
        .ok_or_else(|| "dns_block_probe.json returned unsupported schema_version".to_owned())?;
    if !require_json_bool(&probe_report, "probe_attempted")? {
        return Err(
            "dns_block_probe.json reports the blocked-path probe never ran; an empty pcap without an active off-tunnel probe is vacuous — failing closed"
                .to_owned(),
        );
    }
    if require_json_bool(&probe_report, "udp_response_received")?
        || require_json_bool(&probe_report, "tcp_response_received")?
    {
        return Err(
            "dns_block_probe.json observed a DNS response on the off-tunnel path: LAN DNS is NOT fail-closed (leak)"
                .to_owned(),
        );
    }
    if !require_json_bool(&probe_report, "overall_ok")? {
        return Err("dns_block_probe.json did not report overall_ok=true".to_owned());
    }

    let positive_control = fs::read_to_string(artifact_dir.join("tunnel_path_resolves.json"))
        .map_err(|err| format!("read tunnel_path_resolves.json failed: {err}"))?;
    let positive_report: Value = serde_json::from_str(&positive_control)
        .map_err(|err| format!("parse tunnel_path_resolves.json failed: {err}"))?;
    if !require_json_bool(&positive_report, "overall_ok")?
        || !require_json_bool(&positive_report, "resolved")?
    {
        return Err(
            "tunnel_path_resolves.json did not prove tunnel DNS positive control".to_owned(),
        );
    }

    let dns_check = fs::read_to_string(artifact_dir.join("linux_dns_failclosed_check.json"))
        .map_err(|err| format!("read linux_dns_failclosed_check.json failed: {err}"))?;
    evaluate_linux_dns_failclosed_report(linux_alias, dns_check.as_str())?;

    Ok(format!(
        "Linux exit DNS leak proof verified on {linux_alias}: off-tunnel probe driven, UDP/TCP egress pcaps empty, no probe response, and tunnel positive control passed"
    ))
}

fn linux_exit_dns_failclosed_artifact_set_complete(artifact_dir: &Path) -> Result<(), String> {
    let required = [
        "firewall_block_rules.json",
        "udp_block_pcap.txt",
        "tcp_block_pcap.txt",
        "dns_block_probe.json",
        "tunnel_path_resolves.json",
        "linux_dns_failclosed_check.json",
    ];
    let missing = required
        .iter()
        .filter(|relative| !artifact_dir.join(relative).is_file())
        .copied()
        .collect::<Vec<_>>();
    if missing.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "missing required artifact(s): {}",
            missing.join(", ")
        ))
    }
}

/// macOS exit killswitch precedence artefact validator. Same contract
/// as the Windows variant: baseline assertion must pass, tampered
/// assertion must fail with a non-zero exit code and a non-empty
/// reason string. The tamper itself (e.g. flushing pf or unloading the
/// `com.rustynet.daemon` plist mid-run) is producer-side; the
/// validator only enforces the audit-shape contract.
fn evaluate_macos_exit_killswitch_precedence_artifact(
    macos_alias: &str,
    raw_json: &str,
) -> Result<String, String> {
    let report: Value = serde_json::from_str(raw_json)
        .map_err(|err| format!("parse macos exit killswitch precedence artifact failed: {err}"))?;
    require_json_u64(&report, "schema_version")?
        .eq(&1)
        .then_some(())
        .ok_or_else(|| {
            "macos exit killswitch precedence artifact returned unsupported schema_version"
                .to_owned()
        })?;
    let baseline = require_json_value(&report, "baseline_assert")?;
    if !require_json_bool(baseline, "overall_ok")? {
        return Err("baseline killswitch assertion did not pass before tamper".to_owned());
    }
    let tampered = require_json_value(&report, "tampered_assert")?;
    if require_json_bool(tampered, "overall_ok")? {
        return Err("tampered killswitch assertion reported overall_ok=true".to_owned());
    }
    let exit_code = require_json_i64(tampered, "exit_code")?;
    if exit_code == 0 {
        return Err("tampered killswitch assertion exited zero".to_owned());
    }
    let reason = require_json_str(tampered, "reason")?;
    if reason.trim().is_empty() {
        return Err("tampered killswitch assertion did not record a reason".to_owned());
    }
    Ok(format!(
        "macOS exit killswitch precedence verified on {macos_alias}: tamper rejected with exit_code={exit_code}"
    ))
}

fn evaluate_macos_dns_failclosed_report(
    macos_alias: &str,
    raw_json: &str,
) -> Result<String, String> {
    let report: Value = serde_json::from_str(raw_json)
        .map_err(|err| format!("parse macos-dns-failclosed-check JSON output failed: {err}"))?;
    require_json_u64(&report, "schema_version")?
        .eq(&1)
        .then_some(())
        .ok_or_else(|| {
            format!(
                "macos-dns-failclosed-check returned unsupported schema_version={}",
                require_json_u64(&report, "schema_version").unwrap_or_default()
            )
        })?;
    let overall_ok = require_json_bool(&report, "overall_ok")?;
    let drift_reasons = require_json_array(&report, "drift_reasons")?;
    if !overall_ok {
        let reasons = if drift_reasons.is_empty() {
            "report set overall_ok=false but no drift_reasons recorded; output is inconsistent"
                .to_owned()
        } else {
            drift_reasons
                .iter()
                .filter_map(|v| v.as_str())
                .collect::<Vec<_>>()
                .join("; ")
        };
        return Err(format!("macOS DNS fail-closed drift detected: {reasons}"));
    }
    if !drift_reasons.is_empty() {
        let joined = drift_reasons
            .iter()
            .filter_map(|v| v.as_str())
            .collect::<Vec<_>>()
            .join("; ");
        return Err(format!(
            "report set overall_ok=true but drift_reasons is non-empty: {joined}"
        ));
    }
    Ok(format!("macOS DNS fail-closed verified on {macos_alias}"))
}

fn require_forwarding_enabled_macos(value: &Value, field: &str) -> Result<(), String> {
    let status = require_json_str(value, field)?;
    if status.eq_ignore_ascii_case("enabled") {
        Ok(())
    } else {
        Err(format!(
            "macOS exit forwarding field {field} was {status:?}, expected Enabled"
        ))
    }
}

fn require_pf_block_rule(rules: &[Value], expected_name: &str) -> Result<(), String> {
    let rule = rules
        .iter()
        .find(|rule| {
            rule.get("name")
                .and_then(Value::as_str)
                .is_some_and(|name| name == expected_name)
        })
        .ok_or_else(|| format!("pf_block_rules.json missing {expected_name}"))?;
    for (field, expected) in [
        ("action", "block"),
        ("direction", "out"),
        ("enabled", "true"),
    ] {
        let actual = require_json_str(rule, field)?;
        if !actual.eq_ignore_ascii_case(expected) {
            return Err(format!(
                "pf rule {expected_name} field {field} was {actual:?}, expected {expected}"
            ));
        }
    }
    Ok(())
}

fn require_linux_dns_block_rule(rules: &[Value], expected_name: &str) -> Result<(), String> {
    let rule = rules
        .iter()
        .find(|rule| {
            rule.get("name")
                .and_then(Value::as_str)
                .is_some_and(|name| name == expected_name)
        })
        .ok_or_else(|| format!("firewall_block_rules.json missing {expected_name}"))?;
    for (field, expected) in [
        ("action", "drop"),
        ("direction", "out"),
        ("enabled", "true"),
    ] {
        let actual = require_json_str(rule, field)?;
        if !actual.eq_ignore_ascii_case(expected) {
            return Err(format!(
                "Linux DNS block rule {expected_name} field {field} was {actual:?}, expected {expected}"
            ));
        }
    }
    Ok(())
}

fn require_json_value<'a>(value: &'a Value, field: &str) -> Result<&'a Value, String> {
    value
        .get(field)
        .ok_or_else(|| format!("JSON field {field:?} is missing"))
}

fn require_json_array<'a>(value: &'a Value, field: &str) -> Result<&'a [Value], String> {
    require_json_value(value, field)?
        .as_array()
        .map(Vec::as_slice)
        .ok_or_else(|| format!("JSON field {field:?} must be an array"))
}

fn require_json_str<'a>(value: &'a Value, field: &str) -> Result<&'a str, String> {
    require_json_value(value, field)?
        .as_str()
        .ok_or_else(|| format!("JSON field {field:?} must be a string"))
}

fn require_json_bool(value: &Value, field: &str) -> Result<bool, String> {
    require_json_value(value, field)?
        .as_bool()
        .ok_or_else(|| format!("JSON field {field:?} must be a boolean"))
}

fn require_json_u64(value: &Value, field: &str) -> Result<u64, String> {
    require_json_value(value, field)?
        .as_u64()
        .ok_or_else(|| format!("JSON field {field:?} must be an unsigned integer"))
}

fn require_json_i64(value: &Value, field: &str) -> Result<i64, String> {
    require_json_value(value, field)?
        .as_i64()
        .ok_or_else(|| format!("JSON field {field:?} must be an integer"))
}

fn validate_cidr_like(label: &str, cidr: &str) -> Result<(), String> {
    let (addr, prefix) = cidr
        .split_once('/')
        .ok_or_else(|| format!("{label} must be CIDR-shaped"))?;
    if addr.parse::<IpAddr>().is_err() {
        return Err(format!("{label} has invalid IP address: {addr:?}"));
    }
    let prefix: u8 = prefix
        .parse()
        .map_err(|_| format!("{label} has invalid prefix length"))?;
    if prefix > 128 {
        return Err(format!("{label} prefix length out of range"));
    }
    Ok(())
}

fn require_forwarding_enabled(value: &Value, field: &str) -> Result<(), String> {
    let status = require_json_str(value, field)?;
    if status.eq_ignore_ascii_case("enabled") {
        Ok(())
    } else {
        Err(format!(
            "Windows exit forwarding field {field} was {status:?}, expected Enabled"
        ))
    }
}

fn require_dns_block_rule(rules: &[Value], expected_name: &str) -> Result<(), String> {
    let rule = rules
        .iter()
        .find(|rule| {
            rule.get("name")
                .and_then(Value::as_str)
                .is_some_and(|name| name == expected_name)
        })
        .ok_or_else(|| format!("firewall_block_rules.json missing {expected_name}"))?;
    for (field, expected) in [
        ("action", "Block"),
        ("direction", "Outbound"),
        ("enabled", "True"),
    ] {
        let actual = require_json_str(rule, field)?;
        if !actual.eq_ignore_ascii_case(expected) {
            return Err(format!(
                "firewall rule {expected_name} field {field} was {actual:?}, expected {expected}"
            ));
        }
    }
    Ok(())
}

/// Assert that a blocked-path DNS capture is empty (no DNS/53 egress was seen).
///
/// INVARIANT — this helper proves only HALF the DNS-leak contract and is unsafe
/// on its own. An empty pcap is *vacuous* unless something actively drove an
/// off-tunnel DNS query during the capture window: "no DNS egress observed"
/// could simply mean "no DNS was ever attempted". Every caller MUST therefore
/// pair this with a `probe_attempted` assertion over the producer's
/// `dns_block_probe.json` artifact (probe ran AND no udp/tcp response observed)
/// — see `evaluate_linux_exit_dns_failclosed_artifact_dir` and
/// `evaluate_macos_exit_dns_failclosed_artifact_dir`. Do NOT weaken this helper
/// to accept a non-empty pcap; the empty-pcap check and the active-probe check
/// together form the proof. A future Windows caller MUST stay Skipped until its
/// producer emits the same probe artifact.
fn require_empty_dns_pcap(label: &str, content: &str) -> Result<(), String> {
    let trimmed = content.trim();
    if trimmed.is_empty() || trimmed.contains("0 packets captured") {
        return Ok(());
    }
    Err(format!(
        "{label} contains DNS egress evidence; expected an empty blocked-path capture"
    ))
}

fn run_validate_windows_mesh_join_stage(
    windows_alias: &str,
    inventory_path: &Path,
    ssh_identity_file: &Path,
    known_hosts_path: Option<&Path>,
) -> Result<(String, String), (String, String)> {
    let targets = resolve_remote_targets(inventory_path, &[windows_alias.to_owned()], false, &[])
        .map_err(|err| (err, String::new()))?;
    let target = targets.into_iter().next().ok_or_else(|| {
        (
            format!("no target resolved for alias {windows_alias}"),
            String::new(),
        )
    })?;
    if target.platform_profile.platform != VmGuestPlatform::Windows {
        return Err((
            format!(
                "alias {windows_alias} resolved to non-Windows platform: {}",
                target.platform_profile.platform.as_str()
            ),
            String::new(),
        ));
    }
    let timeout = timeout_or_default(0, DEFAULT_RUN_TIMEOUT_SECS);
    let script = build_windows_security_check_invocation("windows-mesh-status-check", &[])
        .map_err(|err| (err, String::new()))?;
    let invocation = build_ssh_powershell_encoded_invocation(script.as_str())
        .map_err(|err| (err, String::new()))?;
    let raw_output = capture_remote_shell_command_for_target(
        &target,
        None,
        Some(ssh_identity_file),
        known_hosts_path,
        invocation.as_str(),
        timeout,
    )
    .map_err(|err| {
        (
            format!("remote dispatch of windows-mesh-status-check failed: {err}"),
            String::new(),
        )
    })?;
    let raw_trimmed = raw_output.trim().to_owned();
    evaluate_windows_mesh_join_report(windows_alias, raw_trimmed.as_str())
        .map(|summary| (summary, raw_trimmed.clone()))
        .map_err(|reason| (reason, raw_trimmed))
}

/// Pure evaluator for the JSON output of `rustynetd
/// windows-mesh-status-check`. Returns a one-line success summary
/// when the daemon reports a current membership + assignment
/// snapshot, or a precise drift reason. Callable in tests without
/// SSH/IO.
fn evaluate_windows_mesh_join_report(
    windows_alias: &str,
    raw_json: &str,
) -> Result<String, String> {
    let report: rustynetd::windows_mesh_status::WindowsMeshStatusReport =
        serde_json::from_str(raw_json)
            .map_err(|err| format!("parse windows-mesh-status-check JSON output failed: {err}"))?;
    if report.schema_version != 1 {
        return Err(format!(
            "windows-mesh-status-check returned unsupported schema_version={}",
            report.schema_version
        ));
    }
    if !report.overall_ok {
        let reasons = if report.drift_reasons.is_empty() {
            "report set overall_ok=false but no drift_reasons recorded; output is inconsistent"
                .to_owned()
        } else {
            report.drift_reasons.join("; ")
        };
        return Err(format!("Windows mesh-join state drift detected: {reasons}"));
    }
    if !report.drift_reasons.is_empty() {
        return Err(format!(
            "report set overall_ok=true but drift_reasons is non-empty: {}",
            report.drift_reasons.join("; ")
        ));
    }
    let summary_detail = match &report.snapshot {
        rustynetd::windows_mesh_status::WindowsMeshSnapshotLoad::Ok {
            peer_ids,
            age_seconds,
            ..
        } => format!("peers={} age_seconds={}", peer_ids.len(), age_seconds),
        // The variants below would normally be drift cases handled
        // above (overall_ok=false). They appear here only on a
        // self-inconsistent payload — keep the summary informative
        // rather than panicking.
        rustynetd::windows_mesh_status::WindowsMeshSnapshotLoad::Missing { reason } => {
            format!("inconsistent: load_status=missing reason={reason}")
        }
        rustynetd::windows_mesh_status::WindowsMeshSnapshotLoad::IntegrityMismatch { reason } => {
            format!("inconsistent: load_status=integrity-mismatch reason={reason}")
        }
        rustynetd::windows_mesh_status::WindowsMeshSnapshotLoad::InvalidFormat { reason } => {
            format!("inconsistent: load_status=invalid-format reason={reason}")
        }
    };
    Ok(format!(
        "Windows mesh-join state verified on {windows_alias} ({summary_detail})"
    ))
}

