pub fn execute_ops_vm_lab_iterate_live_lab(
    config: VmLabIterateLiveLabConfig,
) -> Result<String, String> {
    if config.validation_steps.is_empty() {
        return Err(
            "specify at least one --validation-step for vm-lab-iterate-live-lab".to_owned(),
        );
    }

    let dirty_worktree = if config.require_clean_tree || config.require_local_head {
        Some(git_worktree_is_dirty()?)
    } else {
        None
    };
    let (resolved_source_mode, resolved_repo_ref) = resolve_iteration_source_selection(
        config.source_mode.as_deref(),
        config.repo_ref.as_deref(),
        config.require_clean_tree,
        config.require_local_head,
        dirty_worktree.unwrap_or(false),
    )?;

    let profile_output_path = config
        .profile_output_path
        .clone()
        .unwrap_or_else(default_live_lab_iteration_profile_path);
    let report_dir = config
        .report_dir
        .clone()
        .unwrap_or_else(default_live_lab_iteration_report_dir);
    let script_path = config.script_path.clone();
    let timeout_secs = config.timeout_secs;

    for step in &config.validation_steps {
        execute_vm_lab_iteration_validation_step(step, timeout_secs)?;
    }

    let profile_result =
        execute_ops_vm_lab_write_live_lab_profile(VmLabWriteLiveLabProfileConfig {
            inventory_path: config.inventory_path.clone(),
            output_path: profile_output_path.clone(),
            exit_vm: config.exit_vm.clone(),
            exit_target: config.exit_target.clone(),
            client_vm: config.client_vm.clone(),
            client_target: config.client_target.clone(),
            entry_vm: config.entry_vm.clone(),
            entry_target: config.entry_target.clone(),
            aux_vm: config.aux_vm.clone(),
            aux_target: config.aux_target.clone(),
            extra_vm: config.extra_vm.clone(),
            extra_target: config.extra_target.clone(),
            fifth_client_vm: config.fifth_client_vm.clone(),
            fifth_client_target: config.fifth_client_target.clone(),
            relay_vm: None,
            relay_target: None,
            linux_blind_exit_vm: None,
            require_same_network: config.require_same_network,
            ssh_identity_file: config.ssh_identity_file.clone(),
            ssh_known_hosts_file: config.ssh_known_hosts_file.clone(),
            ssh_allow_cidrs: config.ssh_allow_cidrs.clone(),
            network_id: config.network_id.clone(),
            traversal_ttl_secs: config.traversal_ttl_secs,
            cross_network_nat_profiles: None,
            cross_network_required_nat_profiles: None,
            cross_network_impairment_profile: None,
            backend: Some(
                config
                    .backend
                    .clone()
                    .unwrap_or_else(|| "linux-wireguard-userspace-shared".to_owned()),
            ),
            source_mode: Some(resolved_source_mode.clone()),
            repo_ref: resolved_repo_ref.clone(),
            report_dir: Some(report_dir.clone()),
        })?;

    let live_lab_result = execute_ops_vm_lab_run_live_lab(VmLabRunLiveLabConfig {
        profile_path: profile_output_path.clone(),
        script_path,
        dry_run: config.dry_run,
        skip_setup: false,
        skip_gates: config.skip_gates,
        skip_soak: config.skip_soak,
        skip_cross_network: config.skip_cross_network,
        enable_chaos_suite: false,
        source_mode: Some(resolved_source_mode),
        repo_ref: resolved_repo_ref,
        report_dir: Some(report_dir.clone()),
        timeout_secs,
        // vm-lab-iterate-live-lab does not expose a per-stage watchdog flag;
        // keep the historical behaviour (0 = watchdog disabled, outer
        // --timeout-secs still bounds the whole run).
        stage_timeout_secs: 0,
        orchestrated: false,
    });

    let summary = summarize_live_lab_report(
        report_dir.as_path(),
        config.collect_failure_diagnostics,
        config.failed_log_tail_lines,
    )?;
    let summary_text = render_live_lab_iteration_summary(
        profile_output_path.as_path(),
        report_dir.as_path(),
        profile_result.as_str(),
        &summary,
    );

    match live_lab_result {
        Ok(_) => Ok(summary_text),
        Err(err) => Err(format!("{summary_text}\nrun_error={err}")),
    }
}

pub fn execute_ops_vm_lab_validate_live_lab_profile(
    config: VmLabValidateLiveLabProfileConfig,
) -> Result<String, String> {
    let profile = load_live_lab_profile(config.profile_path.as_path())?;
    ensure_local_regular_file_path(
        Path::new(profile.required("SSH_IDENTITY_FILE")?.as_str()),
        "SSH identity file",
    )?;
    if let Some(path) = profile.optional("SSH_KNOWN_HOSTS_FILE") {
        ensure_local_regular_file_path(Path::new(path.as_str()), "SSH known_hosts file")?;
    }
    let source_mode = profile.optional("SOURCE_MODE");
    let backend = profile.optional("RUSTYNET_BACKEND");
    if let Some(expected_backend) = config.expected_backend.as_deref()
        && backend.as_deref() != Some(expected_backend)
    {
        return Err(format!(
            "live-lab profile backend mismatch: expected {expected_backend}, got {}",
            backend.as_deref().unwrap_or("none")
        ));
    }
    if let Some(expected_source_mode) = config.expected_source_mode.as_deref()
        && source_mode.as_deref() != Some(expected_source_mode)
    {
        return Err(format!(
            "live-lab profile source mode mismatch: expected {expected_source_mode}, got {}",
            source_mode.as_deref().unwrap_or("none")
        ));
    }
    if let Some(mode) = source_mode.as_deref() {
        validate_live_lab_source_mode(mode)?;
        if mode == "ref" && profile.optional("REPO_REF").is_none() {
            return Err("live-lab profile SOURCE_MODE=ref requires REPO_REF".to_owned());
        }
    }
    if config.require_five_node {
        for key in ["ENTRY_TARGET", "AUX_TARGET", "EXTRA_TARGET"] {
            if profile.optional(key).is_none() {
                return Err(format!(
                    "live-lab profile must define {key} for the reduced five-node topology"
                ));
            }
        }
    }

    ensure_live_lab_profile_platform_metadata(&profile)?;
    ensure_live_lab_profile_desktop_orchestrator_supported(
        &profile,
        "vm-lab-validate-live-lab-profile",
    )?;

    let targets = profile.configured_targets()?;
    let mut lines = vec![
        format!("profile_path={}", config.profile_path.display()),
        format!("target_count={}", targets.len()),
        format!("backend={}", backend.as_deref().unwrap_or("none")),
        format!("source_mode={}", source_mode.as_deref().unwrap_or("none")),
        format!(
            "repo_ref={}",
            profile.optional("REPO_REF").as_deref().unwrap_or("none")
        ),
        format!(
            "report_dir={}",
            profile.optional("REPORT_DIR").as_deref().unwrap_or("none")
        ),
    ];
    for target in &targets {
        lines.push(format!("target.{}={}", target.role, target.target));
    }
    Ok(lines.join("\n"))
}

pub fn execute_ops_vm_lab_diagnose_live_lab_failure(
    config: VmLabDiagnoseLiveLabFailureConfig,
) -> Result<String, String> {
    let report_dir = resolve_absolute_path(config.report_dir.as_path())?;
    let profile = load_live_lab_profile(config.profile_path.as_path())?;
    ensure_live_lab_profile_desktop_orchestrator_supported(
        &profile,
        "vm-lab-diagnose-live-lab-failure",
    )?;
    let summary = summarize_live_lab_report(report_dir.as_path(), false, 1)?;
    let stage = if let Some(stage) = config.stage.as_deref() {
        stage.to_owned()
    } else {
        summary
            .first_failed_stage
            .clone()
            .ok_or_else(|| "live-lab report does not contain a failed stage".to_owned())?
    };
    let stage_records = parse_live_lab_stage_records(report_dir.as_path())?;
    let stage_record = stage_records
        .iter()
        .find(|record| record.name == stage)
        .cloned()
        .or_else(|| infer_live_lab_stage_record(report_dir.as_path(), stage.as_str()).ok())
        .ok_or_else(|| format!("stage {stage} is not present in {}", report_dir.display()))?;
    let diagnostics_dir = config.output_dir.clone().unwrap_or_else(|| {
        report_dir
            .join("diagnostics")
            .join(sanitize_label_for_path(stage.as_str()))
    });
    fs::create_dir_all(diagnostics_dir.as_path()).map_err(|err| {
        format!(
            "create diagnostics dir failed ({}): {err}",
            diagnostics_dir.display()
        )
    })?;

    let targets = resolve_live_lab_profile_targets(config.inventory_path.as_path(), &profile)?;
    let ssh_identity_file = profile.optional("SSH_IDENTITY_FILE").map(PathBuf::from);
    let ssh_known_hosts_file = profile.optional("SSH_KNOWN_HOSTS_FILE").map(PathBuf::from);
    let timeout = timeout_or_default(config.timeout_secs, DEFAULT_COLLECT_TIMEOUT_SECS);
    let mut warnings = Vec::new();
    let status_targets = targets
        .iter()
        .map(|target| target.remote_target.clone())
        .collect::<Vec<_>>();
    let status_output = match execute_vm_lab_status_for_targets(
        status_targets.as_slice(),
        None,
        ssh_identity_file.as_deref(),
        ssh_known_hosts_file.as_deref(),
        timeout,
    ) {
        Ok(output) => output,
        Err(output) => {
            warnings.push(
                "vm-lab-status reported probe failures; inspect vm_lab_status.json for partial results".to_owned(),
            );
            output
        }
    };
    let status_path = diagnostics_dir.join("vm_lab_status.json");
    fs::write(status_path.as_path(), status_output.as_bytes()).map_err(|err| {
        format!(
            "write vm-lab status output failed ({}): {err}",
            status_path.display()
        )
    })?;

    let artifacts_dir = if config.collect_artifacts {
        let artifacts_dir = diagnostics_dir.join("artifacts");
        if let Err(err) = execute_vm_lab_collect_artifacts_for_targets(
            status_targets.as_slice(),
            None,
            ssh_identity_file.as_deref(),
            ssh_known_hosts_file.as_deref(),
            artifacts_dir.as_path(),
            timeout,
        ) {
            warnings.push(
                "artifact collection reported probe failures; inspect artifacts/collection_error.txt for details".to_owned(),
            );
            fs::create_dir_all(artifacts_dir.as_path()).map_err(|create_err| {
                format!(
                    "create artifact diagnostics dir failed ({}): {create_err}",
                    artifacts_dir.display()
                )
            })?;
            let error_path = artifacts_dir.join("collection_error.txt");
            fs::write(error_path.as_path(), err.as_bytes()).map_err(|write_err| {
                format!(
                    "write artifact collection error failed ({}): {write_err}",
                    error_path.display()
                )
            })?;
        }
        Some(artifacts_dir)
    } else {
        None
    };
    let stage_forensics = collect_live_lab_stage_forensics(
        report_dir.as_path(),
        &stage_record,
        &summary,
        diagnostics_dir.as_path(),
        targets.as_slice(),
        timeout,
    )?;
    warnings.extend(stage_forensics.warnings.iter().cloned());

    let targets_json = targets
        .iter()
        .map(|target| {
            json!({
                "role": target.role,
                "target": target.profile_target,
                "ssh_target": target.remote_target.ssh_target,
            })
        })
        .collect::<Vec<_>>();
    let summary_json = json!({
        "report_dir": config.report_dir,
        "profile_path": config.profile_path,
        "stage": stage,
        "stage_description": stage_record.description,
        "key_report_path": summary.key_report_path.clone(),
        "key_log_path": summary.key_log_path.clone(),
        "likely_reason": summary.likely_reason.clone(),
        "target_count": targets.len(),
        "targets": targets_json,
        "status_output_path": status_path.clone(),
        "artifacts_dir": artifacts_dir.clone(),
        "warnings": warnings.clone(),
        "stage_forensics": {
            "strategy": stage_forensics.strategy.clone(),
            "report_context_dir": stage_forensics.report_context_dir.clone(),
            "summary_json_path": stage_forensics.summary_json_path.clone(),
            "review_markdown_path": stage_forensics.review_markdown_path.clone(),
            "remote_probe_dir": stage_forensics.remote_probe_dir.clone(),
            "worker_results_json_path": stage_forensics.worker_results_json_path.clone(),
            "worker_results_markdown_path": stage_forensics.worker_results_markdown_path.clone(),
            "copied_paths": stage_forensics.copied_paths.clone(),
            "notes": stage_forensics.notes.clone(),
        },
    });
    let summary_path = diagnostics_dir.join("diagnostics_summary.json");
    fs::write(
        summary_path.as_path(),
        serde_json::to_vec_pretty(&summary_json)
            .map_err(|err| format!("serialize live-lab diagnostics summary failed: {err}"))?,
    )
    .map_err(|err| {
        format!(
            "write diagnostics summary failed ({}): {err}",
            summary_path.display()
        )
    })?;
    validate_live_lab_diagnostics_artifacts(diagnostics_dir.as_path())?;
    serialize_vm_lab_command_result(&VmLabCommandResult {
        command: "vm-lab-diagnose-live-lab-failure".to_owned(),
        overall_status: VmLabCommandOverallStatus::Pass,
        report_dir: diagnostics_dir.display().to_string(),
        outcomes: vec![VmLabStageOutcome {
            stage: stage_record.name,
            status: VmLabStageStatus::Pass,
            summary: stage_record.description,
            artifacts: vec![
                status_path.display().to_string(),
                summary_path.display().to_string(),
                stage_forensics.summary_json_path.display().to_string(),
                stage_forensics.review_markdown_path.display().to_string(),
            ],
        }],
        warnings,
        next_actions: vec![format!(
            "Inspect {} for the AI-focused review bundle",
            stage_forensics.review_markdown_path.display()
        )],
    })
}

fn infer_live_lab_stage_record(
    report_dir: &Path,
    stage: &str,
) -> Result<LiveLabStageRecord, String> {
    let log_path = report_dir.join("logs").join(format!("{stage}.log"));
    let parallel_stage_dir = report_dir.join("state").join(format!("parallel-{stage}"));
    if !log_path.is_file() && !parallel_stage_dir.is_dir() {
        return Err(format!(
            "stage {stage} is not present in {}",
            report_dir.display()
        ));
    }

    let description_prefix = format!("[stage:{stage}] START ");
    let description = fs::read_to_string(log_path.as_path())
        .ok()
        .and_then(|body| {
            body.lines().find_map(|line| {
                line.trim()
                    .strip_prefix(description_prefix.as_str())
                    .map(|value| value.trim().to_owned())
            })
        })
        .unwrap_or_else(|| stage.replace('_', " "));

    Ok(LiveLabStageRecord {
        name: stage.to_owned(),
        severity: "unknown".to_owned(),
        status: "incomplete".to_owned(),
        rc: String::new(),
        log_path,
        description,
    })
}

fn collect_live_lab_stage_forensics(
    report_dir: &Path,
    stage_record: &LiveLabStageRecord,
    summary: &LiveLabStageSummary,
    diagnostics_dir: &Path,
    targets: &[ResolvedLiveLabTarget],
    timeout: Duration,
) -> Result<LiveLabStageForensicsBundle, String> {
    let strategy = live_lab_stage_forensics_strategy(stage_record.name.as_str()).to_owned();
    let local_bundle =
        collect_live_lab_stage_local_bundle(report_dir, stage_record, summary, diagnostics_dir)?;
    let mut notes = live_lab_stage_forensics_notes(stage_record.name.as_str());
    let mut warnings = Vec::new();
    let remote_probe = match stage_record.name.as_str() {
        "validate_baseline_runtime" => {
            collect_validate_baseline_runtime_remote_probe(diagnostics_dir, targets, timeout)?
        }
        _ => LiveLabStageRemoteProbeSummary {
            remote_probe_dir: None,
            notes: Vec::new(),
            warnings: Vec::new(),
        },
    };
    notes.extend(remote_probe.notes.iter().cloned());
    warnings.extend(remote_probe.warnings.iter().cloned());

    let review_markdown_path = diagnostics_dir.join("stage_forensics_review.md");
    let review_markdown = render_live_lab_stage_forensics_review(LiveLabStageReviewContext {
        report_dir,
        stage_record,
        summary,
        strategy: strategy.as_str(),
        local_bundle: &local_bundle,
        remote_probe_dir: remote_probe.remote_probe_dir.as_deref(),
        notes: notes.as_slice(),
        warnings: warnings.as_slice(),
    });
    fs::write(review_markdown_path.as_path(), review_markdown.as_bytes()).map_err(|err| {
        format!(
            "write stage forensics review failed ({}): {err}",
            review_markdown_path.display()
        )
    })?;

    let summary_json_path = diagnostics_dir.join("stage_forensics_summary.json");
    let summary_json = json!({
        "stage": stage_record.name,
        "strategy": strategy.clone(),
        "report_context_dir": local_bundle.report_context_dir.clone(),
        "copied_paths": local_bundle.copied_paths.clone(),
        "worker_result_count": local_bundle.worker_results.len(),
        "failed_worker_count": local_bundle.worker_results.iter().filter(|result| result.rc != 0).count(),
        "worker_results_json_path": local_bundle.worker_results_json_path.clone(),
        "worker_results_markdown_path": local_bundle.worker_results_markdown_path.clone(),
        "remote_probe_dir": remote_probe.remote_probe_dir.clone(),
        "notes": notes.clone(),
        "warnings": warnings.clone(),
        "review_markdown_path": review_markdown_path.clone(),
    });
    fs::write(
        summary_json_path.as_path(),
        serde_json::to_vec_pretty(&summary_json)
            .map_err(|err| format!("serialize stage forensics summary failed: {err}"))?,
    )
    .map_err(|err| {
        format!(
            "write stage forensics summary failed ({}): {err}",
            summary_json_path.display()
        )
    })?;

    let mut copied_paths = local_bundle.copied_paths.clone();
    copied_paths.push(summary_json_path.clone());
    copied_paths.push(review_markdown_path.clone());

    Ok(LiveLabStageForensicsBundle {
        strategy,
        report_context_dir: local_bundle.report_context_dir,
        summary_json_path,
        review_markdown_path,
        remote_probe_dir: remote_probe.remote_probe_dir,
        copied_paths,
        worker_results_json_path: local_bundle.worker_results_json_path,
        worker_results_markdown_path: local_bundle.worker_results_markdown_path,
        notes,
        warnings,
    })
}

fn collect_live_lab_stage_local_bundle(
    report_dir: &Path,
    stage_record: &LiveLabStageRecord,
    summary: &LiveLabStageSummary,
    diagnostics_dir: &Path,
) -> Result<LiveLabStageLocalBundle, String> {
    let report_context_dir = diagnostics_dir.join("report_context");
    fs::create_dir_all(report_context_dir.as_path()).map_err(|err| {
        format!(
            "create stage report context dir failed ({}): {err}",
            report_context_dir.display()
        )
    })?;

    let mut copied_paths = Vec::new();
    let mut seen_sources = HashSet::new();
    copy_stage_bundle_file(
        summary.key_report_path.as_path(),
        report_context_dir.join("failure_digest.md").as_path(),
        &mut seen_sources,
        &mut copied_paths,
    )?;
    copy_stage_bundle_file(
        report_dir.join("failure_digest.json").as_path(),
        report_context_dir.join("failure_digest.json").as_path(),
        &mut seen_sources,
        &mut copied_paths,
    )?;
    copy_stage_bundle_file(
        report_dir.join("run_summary.md").as_path(),
        report_context_dir.join("run_summary.md").as_path(),
        &mut seen_sources,
        &mut copied_paths,
    )?;
    copy_stage_bundle_file(
        report_dir.join("run_summary.json").as_path(),
        report_context_dir.join("run_summary.json").as_path(),
        &mut seen_sources,
        &mut copied_paths,
    )?;
    copy_stage_bundle_file(
        report_dir.join("state/stages.tsv").as_path(),
        report_context_dir.join("state/stages.tsv").as_path(),
        &mut seen_sources,
        &mut copied_paths,
    )?;
    copy_stage_bundle_file(
        stage_record.log_path.as_path(),
        report_context_dir
            .join("logs")
            .join(
                stage_record
                    .log_path
                    .file_name()
                    .unwrap_or_else(|| std::ffi::OsStr::new("stage.log")),
            )
            .as_path(),
        &mut seen_sources,
        &mut copied_paths,
    )?;

    let parallel_stage_dir = report_dir
        .join("state")
        .join(format!("parallel-{}", stage_record.name));
    let copied_parallel_dir = report_context_dir
        .join("state")
        .join(format!("parallel-{}", stage_record.name));
    if parallel_stage_dir.is_dir() {
        copy_stage_bundle_dir(
            parallel_stage_dir.as_path(),
            copied_parallel_dir.as_path(),
            &mut seen_sources,
            &mut copied_paths,
        )?;
    }

    let worker_results = read_parallel_stage_results(report_dir, stage_record.name.as_str());
    let (worker_results_json_path, worker_results_markdown_path) = if worker_results.is_empty() {
        (None, None)
    } else {
        let json_path = diagnostics_dir.join("stage_worker_results.json");
        let markdown_path = diagnostics_dir.join("stage_worker_results.md");
        write_live_lab_worker_results_summary(
            worker_results.as_slice(),
            json_path.as_path(),
            markdown_path.as_path(),
        )?;
        copied_paths.push(json_path.clone());
        copied_paths.push(markdown_path.clone());
        (Some(json_path), Some(markdown_path))
    };

    Ok(LiveLabStageLocalBundle {
        report_context_dir,
        copied_paths,
        worker_results,
        worker_results_json_path,
        worker_results_markdown_path,
    })
}

fn write_live_lab_worker_results_summary(
    worker_results: &[LiveLabWorkerResult],
    json_path: &Path,
    markdown_path: &Path,
) -> Result<(), String> {
    let results_json = worker_results
        .iter()
        .map(|result| {
            json!({
                "stage_name": result.stage_name,
                "label": result.label,
                "target": result.target,
                "node_id": result.node_id,
                "role": result.role,
                "rc": result.rc,
                "started_at": result.started_at,
                "finished_at": result.finished_at,
                "log_path": result.log_path,
                "snapshot_path": result.snapshot_path,
                "route_policy_path": result.route_policy_path,
                "dns_state_path": result.dns_state_path,
                "primary_failure_reason": result.primary_failure_reason,
            })
        })
        .collect::<Vec<_>>();
    let summary_json = json!({
        "worker_count": worker_results.len(),
        "failed_worker_count": worker_results.iter().filter(|result| result.rc != 0).count(),
        "results": results_json,
    });
    fs::write(
        json_path,
        serde_json::to_vec_pretty(&summary_json)
            .map_err(|err| format!("serialize worker results summary failed: {err}"))?,
    )
    .map_err(|err| {
        format!(
            "write worker results summary failed ({}): {err}",
            json_path.display()
        )
    })?;

    let mut lines = vec![
        "# Live-Lab Worker Results".to_owned(),
        String::new(),
        format!("- worker_count={}", worker_results.len()),
        format!(
            "- failed_worker_count={}",
            worker_results
                .iter()
                .filter(|result| result.rc != 0)
                .count()
        ),
    ];
    for result in worker_results {
        let reason = if result.primary_failure_reason.trim().is_empty() {
            "none"
        } else {
            result.primary_failure_reason.as_str()
        };
        lines.push(format!(
            "- label={} role={} node_id={} rc={} reason={} log_path={} snapshot_path={} route_policy_path={} dns_state_path={}",
            result.label,
            result.role,
            result.node_id,
            result.rc,
            reason,
            result.log_path,
            result.snapshot_path,
            result.route_policy_path,
            result.dns_state_path
        ));
    }
    fs::write(markdown_path, lines.join("\n").as_bytes()).map_err(|err| {
        format!(
            "write worker results markdown failed ({}): {err}",
            markdown_path.display()
        )
    })?;
    Ok(())
}

fn collect_windows_diagnostics_for_target(
    target: &ResolvedLiveLabTarget,
    target_dir: &Path,
    timeout: Duration,
) -> Result<(Vec<String>, Vec<String>), String> {
    let helper_local_path = windows_diagnostics_helper_script_local_path();
    let remote_root = windows_helper_script_remote_path(
        &target.remote_target,
        &format!(
            "diagnostics\\{}",
            sanitize_label_for_path(target.role.as_str())
        ),
    )?;
    let context = RemoteFallbackContext {
        target: &target.remote_target,
        ssh_user_override: None,
        ssh_identity_file: None,
        known_hosts_path: None,
        timeout,
    };
    let output = capture_windows_helper_script_output_from_path(
        &context,
        helper_local_path.as_path(),
        WINDOWS_COLLECT_DIAGNOSTICS_HELPER_FILE,
        &["-OutputRoot".to_owned(), remote_root.clone()],
    )?;
    let helper_output_root = output.trim();
    if helper_output_root.is_empty() {
        return Err(format!(
            "Windows diagnostics helper did not emit an output root for {}",
            target.role
        ));
    }
    if helper_output_root != remote_root {
        return Err(format!(
            "Windows diagnostics helper emitted unexpected output root for {}: expected {}, got {}",
            target.role, remote_root, helper_output_root
        ));
    }

    let output_files = [
        "services.txt",
        "net-ip.txt",
        "routes.txt",
        "dns.txt",
        "firewall.txt",
        "events-system.txt",
        "events-application.txt",
        "tooling.txt",
    ];
    let mut copied_paths = Vec::new();
    for file_name in output_files {
        let remote_file = windows_guest_path_join(helper_output_root, file_name)?;
        let local_file = target_dir.join(file_name);
        let status = if let Some(VmController::LocalUtm { utm_name, .. }) =
            target.remote_target.controller.as_ref()
        {
            utm_pull_raw(
                utm_name.as_str(),
                remote_file.as_str(),
                local_file.as_path(),
                timeout,
            )?
        } else {
            scp_from_remote(
                &target.remote_target,
                None,
                None,
                None,
                remote_file.as_str(),
                local_file.as_path(),
                timeout,
            )?
        };
        ensure_success_status(
            status,
            format!("copy Windows diagnostics file {file_name}").as_str(),
        )?;
        copied_paths.push(local_file);
    }

    let metadata_path = target_dir.join("metadata.json");
    let metadata = json!({
        "role": target.role,
        "target": target.profile_target,
        "ssh_target": target.remote_target.ssh_target,
        "platform": target.remote_target.platform_profile.platform.as_str(),
        "remote_shell": target.remote_target.platform_profile.remote_shell.as_str(),
        "guest_exec_mode": target.remote_target.platform_profile.guest_exec_mode.as_str(),
        "service_manager": target.remote_target.platform_profile.service_manager.as_str(),
        "remote_output_root": helper_output_root,
        "helper_script": WINDOWS_COLLECT_DIAGNOSTICS_HELPER_FILE,
        "copied_paths": copied_paths,
    });
    fs::write(
        metadata_path.as_path(),
        serde_json::to_vec_pretty(&metadata)
            .map_err(|err| format!("serialize Windows diagnostics metadata failed: {err}"))?,
    )
    .map_err(|err| {
        format!(
            "write Windows diagnostics metadata failed ({}): {err}",
            metadata_path.display()
        )
    })?;

    Ok((
        vec![format!(
            "Windows diagnostics helper collected services, network, route, DNS, firewall, event-log, and tooling state for {} via {}",
            target.role, WINDOWS_COLLECT_DIAGNOSTICS_HELPER_FILE
        )],
        Vec::new(),
    ))
}

fn collect_validate_baseline_runtime_remote_probe(
    diagnostics_dir: &Path,
    targets: &[ResolvedLiveLabTarget],
    timeout: Duration,
) -> Result<LiveLabStageRemoteProbeSummary, String> {
    let remote_probe_dir = diagnostics_dir.join("remote_validate_baseline_runtime");
    fs::create_dir_all(remote_probe_dir.as_path()).map_err(|err| {
        format!(
            "create baseline remote probe dir failed ({}): {err}",
            remote_probe_dir.display()
        )
    })?;
    let mut warnings = Vec::new();
    let mut results = Vec::new();
    let mut notes = Vec::new();

    for target in targets {
        let target_dir = remote_probe_dir.join(sanitize_label_for_path(target.role.as_str()));
        fs::create_dir_all(target_dir.as_path()).map_err(|err| {
            format!(
                "create baseline target probe dir failed ({}): {err}",
                target_dir.display()
            )
        })?;
        match target.remote_target.platform_profile.platform {
            VmGuestPlatform::Linux | VmGuestPlatform::Macos => {
                let rustynet_status_script = privileged_rustynet_cli_script("status");
                let rustynet_netcheck_script = privileged_rustynet_cli_script("netcheck");
                let sections = [
                    ("hostname", "hostname"),
                    (
                        "service_active",
                        "if command -v systemctl >/dev/null 2>&1; then systemctl is-active rustynetd.service 2>&1; else echo systemctl-unavailable; fi",
                    ),
                    ("rustynet_status", rustynet_status_script.as_str()),
                    ("rustynet_netcheck", rustynet_netcheck_script.as_str()),
                    (
                        "daemon_socket",
                        "if [ -S /run/rustynet/rustynetd.sock ]; then echo daemon_socket=present; else echo daemon_socket=missing; fi",
                    ),
                    (
                        "route_get_1_1_1_1",
                        "if command -v ip >/dev/null 2>&1; then ip -4 route get 1.1.1.1 2>&1; else echo ip-unavailable; fi",
                    ),
                    (
                        "plaintext_passphrase_check",
                        "if test ! -e /var/lib/rustynet/keys/wireguard.passphrase && test ! -e /etc/rustynet/wireguard.passphrase && test ! -e /etc/rustynet/signing_key_passphrase; then echo no-plaintext-passphrase-files; else echo plaintext-passphrase-files-present; fi",
                    ),
                    (
                        "plaintext_passphrase_paths",
                        "for path in /var/lib/rustynet/keys/wireguard.passphrase /etc/rustynet/wireguard.passphrase /etc/rustynet/signing_key_passphrase; do if [ -e \"$path\" ]; then ls -ld \"$path\" 2>&1; else printf '%s missing\\n' \"$path\"; fi; done",
                    ),
                    (
                        "runtime_state_paths",
                        "for path in /run/rustynet/rustynetd.sock /var/lib/rustynet/rustynetd.assignment /var/lib/rustynet/rustynetd.traversal /var/lib/rustynet/rustynetd.dns-zone /var/lib/rustynet/rustynetd.trust; do if [ -e \"$path\" ] || [ -S \"$path\" ]; then ls -ld \"$path\" 2>&1; else printf '%s missing\\n' \"$path\"; fi; done",
                    ),
                    (
                        "time_state",
                        "if command -v timedatectl >/dev/null 2>&1; then timedatectl status 2>&1; else date -u '+%Y-%m-%dT%H:%M:%SZ'; fi",
                    ),
                    (
                        "journalctl_rustynetd_tail",
                        "if command -v journalctl >/dev/null 2>&1; then if sudo -n true >/dev/null 2>&1; then sudo -n journalctl -u rustynetd.service --no-pager -n 80 2>&1; else journalctl -u rustynetd.service --no-pager -n 80 2>&1; fi; else echo journalctl-unavailable; fi",
                    ),
                ];
                let capture_script = build_section_capture_script(sections.as_slice());
                match capture_remote_shell_command_for_target(
                    &target.remote_target,
                    None,
                    None,
                    None,
                    capture_script.as_str(),
                    timeout,
                ) {
                    Ok(output) => {
                        let sections = parse_section_capture(output.as_str());
                        for (name, body) in &sections {
                            fs::write(target_dir.join(format!("{name}.txt")), body.as_bytes())
                                .map_err(|err| {
                                    format!(
                                        "write baseline stage probe failed ({} {}): {err}",
                                        target.role, name
                                    )
                                })?;
                        }
                        let metadata_path = target_dir.join("metadata.json");
                        let metadata = json!({
                            "role": target.role,
                            "target": target.profile_target,
                            "ssh_target": target.remote_target.ssh_target,
                            "platform": target.remote_target.platform_profile.platform.as_str(),
                            "sections": sections.keys().cloned().collect::<Vec<_>>(),
                        });
                        fs::write(
                            metadata_path.as_path(),
                            serde_json::to_vec_pretty(&metadata).map_err(|err| {
                                format!("serialize baseline probe metadata failed: {err}")
                            })?,
                        )
                        .map_err(|err| {
                            format!(
                                "write baseline probe metadata failed ({}): {err}",
                                metadata_path.display()
                            )
                        })?;
                        results.push(json!({
                            "role": target.role,
                            "target": target.profile_target,
                            "ssh_target": target.remote_target.ssh_target,
                            "platform": target.remote_target.platform_profile.platform.as_str(),
                            "target_dir": target_dir,
                            "error": Value::Null,
                        }));
                    }
                    Err(err) => {
                        warnings.push(format!(
                            "baseline runtime probe failed for {} ({}): {err}",
                            target.role, target.profile_target
                        ));
                        let error_path = target_dir.join("error.txt");
                        fs::write(error_path.as_path(), err.as_bytes()).map_err(|write_err| {
                            format!(
                                "write baseline probe error failed ({}): {write_err}",
                                error_path.display()
                            )
                        })?;
                        results.push(json!({
                            "role": target.role,
                            "target": target.profile_target,
                            "ssh_target": target.remote_target.ssh_target,
                            "platform": target.remote_target.platform_profile.platform.as_str(),
                            "target_dir": target_dir,
                            "error": err,
                        }));
                    }
                }
            }
            VmGuestPlatform::Windows => {
                match collect_windows_diagnostics_for_target(target, target_dir.as_path(), timeout)
                {
                    Ok((target_notes, target_warnings)) => {
                        notes.extend(target_notes);
                        warnings.extend(target_warnings);
                        results.push(json!({
                            "role": target.role,
                            "target": target.profile_target,
                            "ssh_target": target.remote_target.ssh_target,
                            "platform": target.remote_target.platform_profile.platform.as_str(),
                            "target_dir": target_dir,
                            "error": Value::Null,
                        }));
                    }
                    Err(err) => {
                        warnings.push(format!(
                            "Windows baseline runtime diagnostics failed for {} ({}): {err}",
                            target.role, target.profile_target
                        ));
                        let error_path = target_dir.join("error.txt");
                        fs::write(error_path.as_path(), err.as_bytes()).map_err(|write_err| {
                            format!(
                                "write Windows baseline probe error failed ({}): {write_err}",
                                error_path.display()
                            )
                        })?;
                        results.push(json!({
                            "role": target.role,
                            "target": target.profile_target,
                            "ssh_target": target.remote_target.ssh_target,
                            "platform": target.remote_target.platform_profile.platform.as_str(),
                            "target_dir": target_dir,
                            "error": err,
                        }));
                    }
                }
            }
            VmGuestPlatform::Ios | VmGuestPlatform::Android => {
                return Err(format!(
                    "baseline runtime diagnostics are not implemented for platform {} ({})",
                    target.remote_target.platform_profile.platform.as_str(),
                    target.role
                ));
            }
        }
    }

    let summary_path = remote_probe_dir.join("summary.json");
    fs::write(
        summary_path.as_path(),
        serde_json::to_vec_pretty(&json!({
            "target_count": targets.len(),
            "failed_probes": warnings.len(),
            "results": results,
        }))
        .map_err(|err| format!("serialize baseline remote probe summary failed: {err}"))?,
    )
    .map_err(|err| {
        format!(
            "write baseline remote probe summary failed ({}): {err}",
            summary_path.display()
        )
    })?;

    let mut summary_notes = vec![
        "Baseline runtime forensics include focused remote probes for rustynet status, daemon socket presence, route selection, plaintext-passphrase absence, runtime state files, time state, and the last 80 journal lines from rustynetd.".to_owned(),
    ];
    summary_notes.extend(notes);

    Ok(LiveLabStageRemoteProbeSummary {
        remote_probe_dir: Some(remote_probe_dir),
        notes: summary_notes,
        warnings,
    })
}

fn render_live_lab_stage_forensics_review(context: LiveLabStageReviewContext<'_>) -> String {
    let LiveLabStageReviewContext {
        report_dir,
        stage_record,
        summary,
        strategy,
        local_bundle,
        remote_probe_dir,
        notes,
        warnings,
    } = context;
    let mut lines = vec![
        "# Live-Lab Stage Forensics".to_owned(),
        String::new(),
        format!("- report_dir={}", report_dir.display()),
        format!("- stage={}", stage_record.name),
        format!("- stage_description={}", stage_record.description),
        format!("- stage_strategy={strategy}"),
        format!("- stage_status={}", stage_record.status),
        format!("- stage_rc={}", stage_record.rc),
        format!("- key_report_path={}", summary.key_report_path.display()),
        format!("- stage_log_path={}", stage_record.log_path.display()),
        format!(
            "- report_context_dir={}",
            local_bundle.report_context_dir.display()
        ),
        format!("- copied_path_count={}", local_bundle.copied_paths.len()),
    ];
    if let Some(reason) = summary.likely_reason.as_deref() {
        lines.push(format!("- likely_reason={reason}"));
    }
    if let Some(key_log_path) = summary.key_log_path.as_deref() {
        lines.push(format!("- key_log_path={}", key_log_path.display()));
    }
    if let Some(remote_probe_dir) = remote_probe_dir {
        lines.push(format!("- remote_probe_dir={}", remote_probe_dir.display()));
    }
    if let Some(path) = local_bundle.worker_results_json_path.as_deref() {
        lines.push(format!("- worker_results_json_path={}", path.display()));
    }
    if let Some(path) = local_bundle.worker_results_markdown_path.as_deref() {
        lines.push(format!("- worker_results_markdown_path={}", path.display()));
    }

    if !notes.is_empty() {
        lines.push(String::new());
        lines.push("## Notes".to_owned());
        for note in notes {
            lines.push(format!("- {note}"));
        }
    }

    if !warnings.is_empty() {
        lines.push(String::new());
        lines.push("## Warnings".to_owned());
        for warning in warnings {
            lines.push(format!("- {warning}"));
        }
    }

    if !local_bundle.worker_results.is_empty() {
        lines.push(String::new());
        lines.push("## Worker Results".to_owned());
        for result in &local_bundle.worker_results {
            let reason = if result.primary_failure_reason.trim().is_empty() {
                "none"
            } else {
                result.primary_failure_reason.as_str()
            };
            lines.push(format!(
                "- label={} role={} node_id={} rc={} reason={} log_path={} snapshot_path={} route_policy_path={} dns_state_path={}",
                result.label,
                result.role,
                result.node_id,
                result.rc,
                reason,
                result.log_path,
                result.snapshot_path,
                result.route_policy_path,
                result.dns_state_path
            ));
        }
    }

    lines.push(String::new());
    lines.push("## Copied Report Context".to_owned());
    for path in &local_bundle.copied_paths {
        lines.push(format!("- {}", path.display()));
    }

    lines.join("\n")
}

fn live_lab_stage_forensics_strategy(stage_name: &str) -> &'static str {
    match stage_name {
        "validate_baseline_runtime" => "validate-baseline-runtime",
        _ => "generic-stage-context",
    }
}

fn live_lab_stage_forensics_notes(stage_name: &str) -> Vec<String> {
    match stage_name {
        "validate_baseline_runtime" => vec![
            "Expected rustynet status fields: transport_socket_identity_state=authoritative_backend_shared_transport, transport_socket_identity_error=none, encrypted_key_store=true, auto_tunnel_enforce=true, membership_active_nodes=5.".to_owned(),
            "Expected client routing on non-exit nodes: exit_node=exit-1 and `ip -4 route get 1.1.1.1` selects `dev rustynet0`.".to_owned(),
            "Expected plaintext-passphrase hygiene result: no-plaintext-passphrase-files.".to_owned(),
        ],
        _ => vec![
            "The report_context bundle includes the report summary, the failing stage log, and any parallel-stage evidence copied from the original report directory.".to_owned(),
        ],
    }
}

fn copy_stage_bundle_file(
    source: &Path,
    destination: &Path,
    seen_sources: &mut HashSet<PathBuf>,
    copied_paths: &mut Vec<PathBuf>,
) -> Result<(), String> {
    if !source.exists() || !source.is_file() {
        return Ok(());
    }
    if !seen_sources.insert(source.to_path_buf()) {
        return Ok(());
    }
    if let Some(parent) = destination.parent() {
        fs::create_dir_all(parent).map_err(|err| {
            format!(
                "create stage bundle dir failed ({}): {err}",
                parent.display()
            )
        })?;
    }
    fs::copy(source, destination).map_err(|err| {
        format!(
            "copy stage bundle file failed ({} -> {}): {err}",
            source.display(),
            destination.display()
        )
    })?;
    copied_paths.push(destination.to_path_buf());
    Ok(())
}

fn copy_stage_bundle_dir(
    source: &Path,
    destination: &Path,
    seen_sources: &mut HashSet<PathBuf>,
    copied_paths: &mut Vec<PathBuf>,
) -> Result<(), String> {
    if !source.exists() || !source.is_dir() {
        return Ok(());
    }
    if !seen_sources.insert(source.to_path_buf()) {
        return Ok(());
    }
    copy_dir_recursive(source, destination)?;
    copied_paths.push(destination.to_path_buf());
    Ok(())
}

fn copy_dir_recursive(source: &Path, destination: &Path) -> Result<(), String> {
    fs::create_dir_all(destination).map_err(|err| {
        format!(
            "create copied directory failed ({}): {err}",
            destination.display()
        )
    })?;
    for entry in fs::read_dir(source)
        .map_err(|err| format!("read directory failed ({}): {err}", source.display()))?
    {
        let entry = entry
            .map_err(|err| format!("read directory entry failed ({}): {err}", source.display()))?;
        let entry_path = entry.path();
        let destination_path = destination.join(entry.file_name());
        let file_type = entry
            .file_type()
            .map_err(|err| format!("read file type failed ({}): {err}", entry_path.display()))?;
        if file_type.is_dir() {
            copy_dir_recursive(entry_path.as_path(), destination_path.as_path())?;
        } else if file_type.is_file() {
            if let Some(parent) = destination_path.parent() {
                fs::create_dir_all(parent).map_err(|err| {
                    format!(
                        "create copied file parent failed ({}): {err}",
                        parent.display()
                    )
                })?;
            }
            fs::copy(entry_path.as_path(), destination_path.as_path()).map_err(|err| {
                format!(
                    "copy directory entry failed ({} -> {}): {err}",
                    entry_path.display(),
                    destination_path.display()
                )
            })?;
        }
    }
    Ok(())
}

fn resolve_path(path: &Path) -> Result<PathBuf, String> {
    if path.is_absolute() {
        Ok(path.to_path_buf())
    } else {
        std::env::current_dir()
            .map_err(|err| format!("resolve current directory failed: {err}"))
            .map(|cwd| cwd.join(path))
    }
}

fn resolve_absolute_path(path: &Path) -> Result<PathBuf, String> {
    resolve_path(path)
}

fn unix_now() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs()
}

fn collected_at_utc_now() -> String {
    Command::new("date")
        .arg("-u")
        .arg("+%FT%TZ")
        .output()
        .ok()
        .filter(|output| output.status.success())
        .and_then(|output| String::from_utf8(output.stdout).ok())
        .map(|text| text.trim().to_owned())
        .filter(|text| !text.is_empty())
        .unwrap_or_else(|| format!("unix:{}", unix_now()))
}

/// Overlay the run-level verdict from `state/report_state.json` (when
/// present) onto the stage-derived overall status. stages.tsv alone can read
/// all-pass while the run failed in a wrapper stage recorded only at the run
/// level — a diff that then reports "pass → pass, no change" between two
/// failed runs is actively misleading. The overlay only ever tightens toward
/// "fail"; it never upgrades a stage-derived failure.
fn live_lab_overall_status_with_report_state(report_dir: &Path, stage_derived: &str) -> String {
    let path = report_dir.join("state/report_state.json");
    let Ok(body) = fs::read_to_string(&path) else {
        return stage_derived.to_owned();
    };
    let Ok(value) = serde_json::from_str::<Value>(&body) else {
        return stage_derived.to_owned();
    };
    match (
        value.get("run_complete").and_then(Value::as_bool),
        value.get("run_passed").and_then(Value::as_bool),
    ) {
        (Some(true), Some(false)) => "fail".to_owned(),
        // The run never completed (e.g. it died in a wrapper/validator stage
        // after setup): calling the dir "pass" off setup-only stage records
        // is the misleading verdict this overlay exists to prevent.
        (Some(false), _) if stage_derived == "pass" => "incomplete".to_owned(),
        _ => stage_derived.to_owned(),
    }
}

pub fn execute_ops_vm_lab_diff_live_lab_runs(
    config: VmLabDiffLiveLabRunsConfig,
) -> Result<String, String> {
    let old_summary = summarize_live_lab_report(config.old_report_dir.as_path(), false, 1)?;
    let new_summary = summarize_live_lab_report(config.new_report_dir.as_path(), false, 1)?;
    let old_records = parse_live_lab_stage_records(config.old_report_dir.as_path())?;
    let new_records = parse_live_lab_stage_records(config.new_report_dir.as_path())?;
    let old_map = old_records
        .iter()
        .map(|record| (record.name.clone(), record))
        .collect::<BTreeMap<_, _>>();
    let new_map = new_records
        .iter()
        .map(|record| (record.name.clone(), record))
        .collect::<BTreeMap<_, _>>();
    let ordered_names = old_records
        .iter()
        .map(|record| record.name.clone())
        .chain(
            new_records
                .iter()
                .map(|record| record.name.clone())
                .filter(|name| !old_map.contains_key(name)),
        )
        .collect::<Vec<_>>();

    let mut first_divergent_stage = None;
    let mut changes = Vec::new();
    for name in ordered_names {
        let old_status = old_map.get(&name).map(|record| record.status.as_str());
        let new_status = new_map.get(&name).map(|record| record.status.as_str());
        let old_rc = old_map.get(&name).map(|record| record.rc.as_str());
        let new_rc = new_map.get(&name).map(|record| record.rc.as_str());
        if old_status != new_status || old_rc != new_rc {
            if first_divergent_stage.is_none() {
                first_divergent_stage = Some(name.clone());
            }
            changes.push(format!(
                "{}:{}:{} -> {}:{}",
                name,
                old_status.unwrap_or("missing"),
                old_rc.unwrap_or("missing"),
                new_status.unwrap_or("missing"),
                new_rc.unwrap_or("missing")
            ));
        }
    }

    let mut lines = vec![
        format!("old_report_dir={}", config.old_report_dir.display()),
        format!("new_report_dir={}", config.new_report_dir.display()),
        format!(
            "old_overall_status={}",
            live_lab_overall_status_with_report_state(
                config.old_report_dir.as_path(),
                old_summary.overall_status.as_str()
            )
        ),
        format!(
            "new_overall_status={}",
            live_lab_overall_status_with_report_state(
                config.new_report_dir.as_path(),
                new_summary.overall_status.as_str()
            )
        ),
        format!(
            "old_first_failed_stage={}",
            old_summary.first_failed_stage.as_deref().unwrap_or("none")
        ),
        format!(
            "new_first_failed_stage={}",
            new_summary.first_failed_stage.as_deref().unwrap_or("none")
        ),
        format!(
            "first_divergent_stage={}",
            first_divergent_stage.as_deref().unwrap_or("none")
        ),
        format!("changed_stage_count={}", changes.len()),
    ];
    if let Some(reason) = old_summary.likely_reason.as_deref() {
        lines.push(format!("old_likely_reason={reason}"));
    }
    if let Some(reason) = new_summary.likely_reason.as_deref() {
        lines.push(format!("new_likely_reason={reason}"));
    }
    for change in changes {
        lines.push(format!("stage_change={change}"));
    }
    Ok(lines.join("\n"))
}

fn resolve_iteration_source_selection(
    configured_source_mode: Option<&str>,
    configured_repo_ref: Option<&str>,
    require_clean_tree: bool,
    require_local_head: bool,
    dirty_worktree: bool,
) -> Result<(String, Option<String>), String> {
    if (require_clean_tree || require_local_head) && dirty_worktree {
        return Err("git worktree must be clean for this live-lab iteration".to_owned());
    }
    if require_local_head {
        if let Some(source_mode) = configured_source_mode
            && source_mode != "local-head"
        {
            return Err(format!(
                "--require-local-head is incompatible with --source-mode {source_mode}"
            ));
        }
        if let Some(repo_ref) = configured_repo_ref
            && repo_ref != "HEAD"
        {
            return Err(format!(
                "--require-local-head is incompatible with --repo-ref {repo_ref} (expected HEAD)"
            ));
        }
        return Ok(("local-head".to_owned(), None));
    }
    let source_mode = configured_source_mode.unwrap_or("working-tree");
    validate_live_lab_source_mode(source_mode)?;
    let repo_ref = if source_mode == "ref" {
        let value = configured_repo_ref
            .filter(|value| !value.is_empty())
            .ok_or_else(|| "source-mode=ref requires --repo-ref".to_owned())?;
        Some(value.to_owned())
    } else {
        None
    };
    Ok((source_mode.to_owned(), repo_ref))
}

fn git_worktree_is_dirty() -> Result<bool, String> {
    let mut command = Command::new("git");
    command.current_dir(workspace_root_path());
    // The live-lab evidence ledgers are appended to BY THIS ORCHESTRATOR during a
    // run (the run-matrix row and gate-timing telemetry are written by design — see
    // append_live_lab_run_matrix_row). They are documentation/telemetry, not deployed
    // code, so their churn must not count as a dirty worktree for the setup->run git
    // provenance check; otherwise a clean-tree run flips clean->dirty mid-run on the
    // orchestrator's own evidence write and the provenance comparison fails closed on
    // a non-code change. Any real code (or other tracked-file) change still surfaces
    // here and still fails the provenance check.
    command.args([
        "status",
        "--short",
        "--",
        ".",
        ":(exclude)documents/operations/live_lab_run_matrix.csv",
        ":(exclude)documents/operations/gate_timings.csv",
        ":(exclude)documents/operations/live_lab_stage_timings.csv",
    ]);
    let output = run_output_with_timeout(
        &mut command,
        timeout_or_default(30, DEFAULT_RUN_TIMEOUT_SECS),
    )?;
    if !output.status.success() {
        return Err(format!(
            "git status failed with status {}",
            status_code(output.status)
        ));
    }
    let stdout = String::from_utf8(output.stdout)
        .map_err(|err| format!("git status returned non-UTF-8 output: {err}"))?;
    Ok(!stdout.trim().is_empty())
}

impl LiveLabProfile {
    fn required(&self, key: &str) -> Result<String, String> {
        self.values
            .get(key)
            .cloned()
            .ok_or_else(|| format!("live-lab profile is missing required key {key}"))
    }

    fn optional(&self, key: &str) -> Option<String> {
        self.values.get(key).cloned()
    }

    fn configured_targets(&self) -> Result<Vec<LiveLabProfileTarget>, String> {
        let mut targets = vec![
            LiveLabProfileTarget {
                role: "exit".to_owned(),
                target: self.required("EXIT_TARGET")?,
                utm_name: self
                    .optional("EXIT_UTM_NAME")
                    .filter(|value| !value.trim().is_empty()),
            },
            LiveLabProfileTarget {
                role: "client".to_owned(),
                target: self.required("CLIENT_TARGET")?,
                utm_name: self
                    .optional("CLIENT_UTM_NAME")
                    .filter(|value| !value.trim().is_empty()),
            },
        ];
        for (key, utm_key, role) in [
            ("ENTRY_TARGET", "ENTRY_UTM_NAME", "entry"),
            ("AUX_TARGET", "AUX_UTM_NAME", "aux"),
            ("EXTRA_TARGET", "EXTRA_UTM_NAME", "extra"),
            (
                "FIFTH_CLIENT_TARGET",
                "FIFTH_CLIENT_UTM_NAME",
                "fifth_client",
            ),
        ] {
            if let Some(target) = self.optional(key)
                && !target.trim().is_empty()
            {
                targets.push(LiveLabProfileTarget {
                    role: role.to_owned(),
                    target,
                    utm_name: self
                        .optional(utm_key)
                        .filter(|value| !value.trim().is_empty()),
                });
            }
        }
        Ok(targets)
    }
}

fn live_lab_profile_target_platform_profile(
    profile: &LiveLabProfile,
    role: &str,
) -> Result<Option<VmPlatformProfile>, String> {
    let prefix = role.to_ascii_uppercase();
    let target_key = format!("{prefix}_TARGET");
    let Some(target) = profile.optional(target_key.as_str()) else {
        return Ok(None);
    };
    if target.trim().is_empty() {
        return Ok(None);
    }

    let platform = VmGuestPlatform::parse(
        profile
            .required(format!("{prefix}_PLATFORM").as_str())?
            .as_str(),
    )
    .map_err(|err| format!("{prefix}_PLATFORM: {err}"))?;
    let remote_shell = VmRemoteShell::parse(
        profile
            .required(format!("{prefix}_REMOTE_SHELL").as_str())?
            .as_str(),
    )
    .map_err(|err| format!("{prefix}_REMOTE_SHELL: {err}"))?;
    let guest_exec_mode = VmGuestExecMode::parse(
        profile
            .required(format!("{prefix}_GUEST_EXEC_MODE").as_str())?
            .as_str(),
    )
    .map_err(|err| format!("{prefix}_GUEST_EXEC_MODE: {err}"))?;
    let service_manager = VmServiceManager::parse(
        profile
            .required(format!("{prefix}_SERVICE_MANAGER").as_str())?
            .as_str(),
    )
    .map_err(|err| format!("{prefix}_SERVICE_MANAGER: {err}"))?;

    Ok(Some(VmPlatformProfile {
        platform,
        remote_shell,
        guest_exec_mode,
        service_manager,
    }))
}

fn configured_live_lab_target_platform_profiles(
    profile: &LiveLabProfile,
) -> Result<Vec<(String, String, VmPlatformProfile)>, String> {
    let mut targets = Vec::new();
    for target in profile.configured_targets()? {
        let Some(platform_profile) =
            live_lab_profile_target_platform_profile(profile, target.role.as_str())?
        else {
            return Err(format!(
                "live-lab profile target {} is missing platform metadata",
                target.role
            ));
        };
        targets.push((target.role, target.target, platform_profile));
    }
    Ok(targets)
}

fn ensure_live_lab_profile_platform_metadata(profile: &LiveLabProfile) -> Result<(), String> {
    let _ = configured_live_lab_target_platform_profiles(profile)?;
    Ok(())
}

// ---------------------------------------------------------------------------
// W4.1 LiveLabStageCapability machinery
// ---------------------------------------------------------------------------

/// Per-stage host-capability tag. Each live-lab stage that depends on
/// a kernel / userland feature publishes its required capability set;
/// a target satisfies the stage only when its `target_capabilities()`
/// is a superset of the stage's requirement set.
///
/// Adding a new capability:
/// - It MUST name a feature that is observable at orchestration time
///   (i.e. derived from `VmPlatformProfile`, not from a runtime probe).
/// - Capabilities expressing security guarantees (e.g. NFT default-
///   deny enforcement) MUST follow CLAUDE.md §3 (Default-deny
///   policy is mandatory; Fail closed when trust/security state
///   is missing): a target without the capability fails the stage
///   rather than skipping it. Pure convenience capabilities (e.g.
///   NETEM kernel-impairment for test stages) skip-with-reason.
///
/// The labels listed here mirror the eight reviewed stage-set
/// dependencies the bash orchestrator (`scripts/e2e/live_linux_lab_orchestrator.sh`)
/// currently encodes implicitly via its all-or-nothing `platform=linux`
/// gate — surfacing them as typed capabilities lets W4.2+ heterogeneous
/// dispatch decide per-stage rather than per-run.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
#[allow(dead_code)]
pub enum LiveLabStageCapability {
    /// POSIX-shell remote dispatch (SSH + bash).
    PosixShell,
    /// systemd unit lifecycle management on the target host.
    Systemd,
    /// Linux bash interpreter on the target host (the orchestrator
    /// shell scripts are bash-specific; sh / zsh would not satisfy).
    LinuxBashGuestExec,
    /// `tc` / netem kernel network impairment (Linux-only kernel
    /// feature; pure convenience for impairment-test stages).
    NetemImpairment,
    /// `nftables` ingress / egress filtering (Linux-only kernel
    /// feature; security-bar capability for default-deny stages).
    NftablesFiltering,
    /// `systemd-resolved` DNS interception for the protected-mode
    /// resolver bind (Linux-only userspace; security-bar for the
    /// Linux DNS fail-closed stage).
    SystemdResolvedDns,
    /// Windows SCM service manager (lifecycle + service identity).
    WindowsServiceManager,
    /// Windows NRPT (Name Resolution Policy Table) for the
    /// protected-mode DNS path (security-bar for the W1.3 verifier
    /// + W1.4 stage).
    WindowsNrptDns,
    /// `PowerShell` SSH dispatch over the encoded-command channel.
    WindowsPowershellShell,
}

impl LiveLabStageCapability {
    #[allow(dead_code)]
    pub fn as_str(self) -> &'static str {
        match self {
            LiveLabStageCapability::PosixShell => "posix-shell",
            LiveLabStageCapability::Systemd => "systemd",
            LiveLabStageCapability::LinuxBashGuestExec => "linux-bash-guest-exec",
            LiveLabStageCapability::NetemImpairment => "netem-impairment",
            LiveLabStageCapability::NftablesFiltering => "nftables-filtering",
            LiveLabStageCapability::SystemdResolvedDns => "systemd-resolved-dns",
            LiveLabStageCapability::WindowsServiceManager => "windows-service-manager",
            LiveLabStageCapability::WindowsNrptDns => "windows-nrpt-dns",
            LiveLabStageCapability::WindowsPowershellShell => "windows-powershell-shell",
        }
    }
}

/// Capabilities published by a target's platform profile. The lookup
/// is a pure function of the profile (no runtime probe) so the
/// orchestrator can compute the per-target capability set up-front
/// before any SSH dispatch.
#[allow(dead_code)]
pub fn target_capabilities(profile: VmPlatformProfile) -> Vec<LiveLabStageCapability> {
    let mut caps = Vec::new();
    match profile.remote_shell {
        VmRemoteShell::Posix => caps.push(LiveLabStageCapability::PosixShell),
        VmRemoteShell::Powershell => caps.push(LiveLabStageCapability::WindowsPowershellShell),
        VmRemoteShell::Unsupported => {}
    }
    match profile.service_manager {
        VmServiceManager::Systemd => caps.push(LiveLabStageCapability::Systemd),
        VmServiceManager::WindowsService => {
            caps.push(LiveLabStageCapability::WindowsServiceManager);
        }
        VmServiceManager::Launchd | VmServiceManager::Unsupported => {}
    }
    if matches!(profile.guest_exec_mode, VmGuestExecMode::LinuxBash) {
        caps.push(LiveLabStageCapability::LinuxBashGuestExec);
    }
    match profile.platform {
        VmGuestPlatform::Linux => {
            // Linux kernel + userspace bring tc/netem, nftables, and
            // systemd-resolved into reach by default on the reviewed
            // RustyNet Linux distros (debian-headless-*).
            caps.push(LiveLabStageCapability::NetemImpairment);
            caps.push(LiveLabStageCapability::NftablesFiltering);
            caps.push(LiveLabStageCapability::SystemdResolvedDns);
        }
        VmGuestPlatform::Windows => {
            caps.push(LiveLabStageCapability::WindowsNrptDns);
        }
        VmGuestPlatform::Macos | VmGuestPlatform::Ios | VmGuestPlatform::Android => {}
    }
    caps
}

/// Capability set the existing Linux bash orchestrator's stage list
/// implicitly requires of every target. Today this is the strict
/// 5×Linux all-or-nothing set the `ensure_live_lab_profile_linux_only`
/// gate enforced; surfacing it as a typed list lets W4.2+ split the
/// stages so individual stages can drop dependencies they don't need
/// (e.g. a Windows-only validator stage drops `LinuxBashGuestExec`).
#[allow(dead_code)]
pub const LIVE_LAB_LINUX_ONLY_REQUIRED_CAPABILITIES: &[LiveLabStageCapability] = &[
    LiveLabStageCapability::PosixShell,
    LiveLabStageCapability::Systemd,
    LiveLabStageCapability::LinuxBashGuestExec,
    LiveLabStageCapability::NftablesFiltering,
    LiveLabStageCapability::SystemdResolvedDns,
];

/// Gate the orchestrator entry points on a typed capability list.
/// Returns the list of `(role, target, missing_capabilities)` tuples
/// for any target that does not advertise a superset of `required`.
/// Each entry point chooses how to react: today every entry point
/// rejects a non-empty result (matches the
/// `ensure_live_lab_profile_linux_only` semantics this fn replaces).
#[allow(dead_code)]
fn live_lab_targets_missing_capabilities(
    profile: &LiveLabProfile,
    required: &[LiveLabStageCapability],
) -> Result<Vec<(String, String, Vec<LiveLabStageCapability>)>, String> {
    let mut blocked = Vec::new();
    for (role, target, platform_profile) in configured_live_lab_target_platform_profiles(profile)? {
        let caps = target_capabilities(platform_profile);
        let missing: Vec<LiveLabStageCapability> = required
            .iter()
            .copied()
            .filter(|cap| !caps.contains(cap))
            .collect();
        if !missing.is_empty() {
            blocked.push((role, target, missing));
        }
    }
    Ok(blocked)
}

/// Per-blocked-target shape returned by
/// [`live_lab_targets_missing_capabilities_with_platform`]. Distinct
/// type alias (rather than an inline tuple) so the clippy
/// `type_complexity` gate stays clean. Fields: `(role, target,
/// guest_platform, missing_capabilities)`.
#[allow(dead_code)]
type BlockedTargetWithPlatform = (String, String, VmGuestPlatform, Vec<LiveLabStageCapability>);

/// Same shape as [`live_lab_targets_missing_capabilities`] but also
/// carries the target's `VmGuestPlatform` so callers can derive the
/// canonical Slice-1 `VmLabPlatform` for capability evaluation
/// without re-walking the profile. Used by
/// `ensure_live_lab_profile_capabilities` so the per-target reject
/// message can embed the stable Slice-1 reason code.
#[allow(dead_code)]
fn live_lab_targets_missing_capabilities_with_platform(
    profile: &LiveLabProfile,
    required: &[LiveLabStageCapability],
) -> Result<Vec<BlockedTargetWithPlatform>, String> {
    let mut blocked = Vec::new();
    for (role, target, platform_profile) in configured_live_lab_target_platform_profiles(profile)? {
        let caps = target_capabilities(platform_profile);
        let missing: Vec<LiveLabStageCapability> = required
            .iter()
            .copied()
            .filter(|cap| !caps.contains(cap))
            .collect();
        if !missing.is_empty() {
            blocked.push((role, target, platform_profile.platform, missing));
        }
    }
    Ok(blocked)
}

/// Capability-driven gate. Orchestrator entry points call this with
/// the per-stage-set required-capability list; a non-empty
/// `missing` list rejects with a precise per-target reason. The
/// `command_name` is included in the rejection blocker for
/// downstream diagnose-live-lab-failure ergonomics.
///
/// Slice-2 follow-up (VmLabCapabilityReportingPlan_2026-04-14.md):
/// each per-target detail now also embeds the canonical Slice-1
/// `reason_code` derived from `evaluate_vm_lab_capability` under the
/// `RunLiveLab` scope. Downstream tooling (diagnose-live-lab-failure,
/// CI grep, operator dashboards) can pattern-match on the stable
/// reason-code namespace instead of the free-form `missing=...`
/// label set; the `missing=...` set is preserved alongside for
/// per-capability remediation.
#[allow(dead_code)]
fn ensure_live_lab_profile_capabilities(
    profile: &LiveLabProfile,
    required: &[LiveLabStageCapability],
    command_name: &str,
) -> Result<(), String> {
    use crate::vm_lab::capability::{
        VmLabCapabilityContext, VmLabCapabilityScope, VmLabPlatform, VmLabSourceMode,
        evaluate_vm_lab_capability,
    };
    let blocked = live_lab_targets_missing_capabilities_with_platform(profile, required)?;
    if blocked.is_empty() {
        return Ok(());
    }
    let rendered = blocked
        .into_iter()
        .map(|(role, target, guest_platform, missing)| {
            let labels = missing
                .iter()
                .map(|cap| cap.as_str())
                .collect::<Vec<_>>()
                .join(",");
            let lab_platform = VmLabPlatform::from(guest_platform);
            let ctx = VmLabCapabilityContext {
                scope: VmLabCapabilityScope::RunLiveLab,
                platform: lab_platform,
                // The gate is invoked BEFORE any source-mode-specific
                // dispatch so the source-mode is irrelevant for the
                // canonical reason-code derivation. Use the
                // conservative `LocalHead` value (the default
                // operator-side mode) so the evaluator emits a
                // stable result regardless of how the orchestrator
                // is wired downstream.
                source_mode: VmLabSourceMode::LocalHead,
                bootstrap_phase: None,
                mixed_platform_topology: false,
            };
            let record = evaluate_vm_lab_capability(ctx);
            format!(
                "role={role} target={target} missing={labels} reason_code={}",
                record.reason_code,
            )
        })
        .collect::<Vec<_>>()
        .join("; ");
    Err(format!(
        "{command_name} requires capabilities [{}]; blocked targets: {rendered}",
        required
            .iter()
            .map(|cap| cap.as_str())
            .collect::<Vec<_>>()
            .join(",")
    ))
}

#[allow(dead_code)]
fn ensure_live_lab_profile_linux_only(
    profile: &LiveLabProfile,
    command_name: &str,
) -> Result<(), String> {
    // Delegate to the new capability-driven gate with the legacy
    // Linux-bash-orchestrator capability set. Behavior preserved:
    // any target that does not advertise the full Linux capability
    // bundle still rejects with a precise reason, just rendered via
    // the new capability vocabulary so downstream tooling can grep
    // on stable capability labels rather than the older
    // `platform=linux remote_shell=posix …` free-form string.
    ensure_live_lab_profile_capabilities(
        profile,
        LIVE_LAB_LINUX_ONLY_REQUIRED_CAPABILITIES,
        command_name,
    )
}

fn ensure_live_lab_profile_desktop_orchestrator_supported(
    profile: &LiveLabProfile,
    command_name: &str,
) -> Result<(), String> {
    let targets = configured_live_lab_target_platform_profiles(profile)?;
    if targets.is_empty() {
        return Err(format!(
            "{command_name} requires at least one configured live-lab target"
        ));
    }

    let has_linux = targets
        .iter()
        .any(|(_, _, target)| target.platform == VmGuestPlatform::Linux);
    if !has_linux {
        return Err(format!(
            "{command_name} requires at least one Linux target for the current mixed-OS live-lab orchestrator core stages"
        ));
    }

    let mut blocked = Vec::new();
    for (role, target, profile) in targets {
        let reason = match profile.platform {
            VmGuestPlatform::Linux => {
                if profile.remote_shell != VmRemoteShell::Posix
                    || profile.guest_exec_mode != VmGuestExecMode::LinuxBash
                    || profile.service_manager != VmServiceManager::Systemd
                {
                    Some(format!(
                        "linux target must use posix/linux_bash/systemd profile; got remote_shell={} guest_exec_mode={} service_manager={}",
                        profile.remote_shell.as_str(),
                        profile.guest_exec_mode.as_str(),
                        profile.service_manager.as_str()
                    ))
                } else {
                    None
                }
            }
            VmGuestPlatform::Macos => {
                if profile.remote_shell != VmRemoteShell::Posix
                    || profile.guest_exec_mode != VmGuestExecMode::MacosPosix
                    || profile.service_manager != VmServiceManager::Launchd
                {
                    Some(format!(
                        "macOS target must use posix/macos_posix/launchd profile; got remote_shell={} guest_exec_mode={} service_manager={}",
                        profile.remote_shell.as_str(),
                        profile.guest_exec_mode.as_str(),
                        profile.service_manager.as_str()
                    ))
                } else {
                    None
                }
            }
            VmGuestPlatform::Windows => {
                if profile.remote_shell != VmRemoteShell::Powershell
                    || profile.guest_exec_mode != VmGuestExecMode::WindowsPowershell
                    || profile.service_manager != VmServiceManager::WindowsService
                {
                    Some(format!(
                        "Windows target must use powershell/windows_powershell/windows_service profile; got remote_shell={} guest_exec_mode={} service_manager={}",
                        profile.remote_shell.as_str(),
                        profile.guest_exec_mode.as_str(),
                        profile.service_manager.as_str()
                    ))
                } else {
                    None
                }
            }
            VmGuestPlatform::Ios | VmGuestPlatform::Android => Some(format!(
                "{} targets are not supported by the desktop mixed-OS live-lab orchestrator",
                profile.platform.as_str()
            )),
        };
        if let Some(reason) = reason {
            blocked.push(format!(
                "role={role} target={target} platform={} reason={reason}",
                profile.platform.as_str()
            ));
        }
    }

    if blocked.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "{command_name} rejected unsupported live-lab target profile(s): {}",
            blocked.join("; ")
        ))
    }
}

fn load_live_lab_profile(path: &Path) -> Result<LiveLabProfile, String> {
    ensure_local_regular_file_path(path, "live-lab profile")?;
    let body = fs::read_to_string(path)
        .map_err(|err| format!("read live-lab profile failed ({}): {err}", path.display()))?;
    let mut values = BTreeMap::new();
    for (index, raw_line) in body.lines().enumerate() {
        let line = raw_line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        let (key, raw_value) = line.split_once('=').ok_or_else(|| {
            format!(
                "invalid live-lab profile line {} in {}: expected KEY=VALUE",
                index + 1,
                path.display()
            )
        })?;
        let key = key.trim();
        ensure_live_lab_profile_key(key)?;
        if values.contains_key(key) {
            return Err(format!(
                "duplicate live-lab profile key {} in {}",
                key,
                path.display()
            ));
        }
        let value = parse_env_value(raw_value).map_err(|err| {
            format!(
                "invalid live-lab profile value for {} in {}: {}",
                key,
                path.display(),
                err
            )
        })?;
        values.insert(key.to_owned(), value);
    }
    let profile = LiveLabProfile { values };
    ensure_ssh_target("EXIT_TARGET", profile.required("EXIT_TARGET")?.as_str())?;
    ensure_ssh_target("CLIENT_TARGET", profile.required("CLIENT_TARGET")?.as_str())?;
    let _ = profile.required("SSH_IDENTITY_FILE")?;
    Ok(profile)
}

fn resolve_live_lab_profile_targets(
    inventory_path: &Path,
    profile: &LiveLabProfile,
) -> Result<Vec<ResolvedLiveLabTarget>, String> {
    let inventory = load_inventory(inventory_path)?;
    let mut resolved = Vec::new();
    for target in profile.configured_targets()? {
        let remote_target = resolve_live_lab_profile_remote_target(inventory.as_slice(), &target)?;
        resolved.push(ResolvedLiveLabTarget {
            role: target.role.clone(),
            profile_target: target.target.clone(),
            remote_target,
        });
    }
    Ok(resolved)
}

fn resolve_live_lab_profile_remote_target(
    inventory: &[VmInventoryEntry],
    profile_target: &LiveLabProfileTarget,
) -> Result<RemoteTarget, String> {
    if let Some(utm_name) = profile_target.utm_name.as_deref() {
        let entry = inventory
            .iter()
            .find(|entry| {
                matches!(
                    entry.controller.as_ref(),
                    Some(VmController::LocalUtm {
                        utm_name: entry_utm_name,
                        ..
                    }) if entry_utm_name == utm_name
                )
            })
            .ok_or_else(|| {
                format!(
                    "live-lab profile target {} references UTM controller {} that is not present in inventory",
                    profile_target.role, utm_name
                )
            })?;
        let mut remote_target = remote_target_from_inventory_entry(entry, None);
        remote_target.label = profile_target.role.clone();
        if remote_target.ssh_user.is_none() {
            remote_target.ssh_user =
                ssh_target_user(profile_target.target.as_str()).map(str::to_string);
        }
        return Ok(remote_target);
    }

    if let Some(entry) = inventory.iter().find(|entry| {
        resolved_inventory_ssh_target(entry) == profile_target.target
            || normalized_ssh_target(
                entry.ssh_target.as_str(),
                entry.ssh_user.as_deref(),
                profile_target.role.as_str(),
            )
            .map(|candidate| candidate == profile_target.target)
            .unwrap_or(false)
    }) {
        let mut remote_target = remote_target_from_inventory_entry(entry, None);
        remote_target.label = profile_target.role.clone();
        return Ok(remote_target);
    }

    Ok(remote_target_from_raw_target(
        profile_target.role.clone(),
        profile_target.target.clone(),
    ))
}

fn ensure_live_lab_profile_key(key: &str) -> Result<(), String> {
    if key.is_empty()
        || !key
            .chars()
            .all(|ch| ch.is_ascii_uppercase() || ch.is_ascii_digit() || ch == '_')
    {
        return Err(format!("invalid live-lab profile key: {key}"));
    }
    Ok(())
}

fn validate_live_lab_source_mode(value: &str) -> Result<(), String> {
    match value {
        "working-tree" | "local-head" | "origin-main" | "ref" => Ok(()),
        _ => Err(format!(
            "unsupported live-lab profile source mode: {value} (expected working-tree|local-head|origin-main|ref)"
        )),
    }
}

fn parse_live_lab_stage_records(report_dir: &Path) -> Result<Vec<LiveLabStageRecord>, String> {
    let report_dir = if report_dir.is_absolute() {
        report_dir.to_path_buf()
    } else {
        std::env::current_dir()
            .map_err(|err| format!("resolve current directory failed: {err}"))?
            .join(report_dir)
    };
    let stages_path = report_dir.join("state/stages.tsv");
    let stages_body = fs::read_to_string(&stages_path).map_err(|err| {
        format!(
            "read live-lab stages failed ({}): {err}",
            stages_path.display()
        )
    })?;
    let mut records = Vec::new();
    for line in stages_body.lines().filter(|line| !line.trim().is_empty()) {
        let columns = line.split('\t').collect::<Vec<_>>();
        if columns.len() < 6 {
            continue;
        }
        records.push(LiveLabStageRecord {
            name: columns[0].to_owned(),
            severity: columns[1].to_owned(),
            status: columns[2].to_owned(),
            rc: columns[3].to_owned(),
            log_path: resolve_report_relative_path(columns[4], report_dir.as_path())?,
            description: columns[5].to_owned(),
        });
    }
    Ok(records)
}

fn execute_vm_lab_iteration_validation_step(
    step: &VmLabIterationValidationStep,
    timeout_secs: u64,
) -> Result<(), String> {
    let timeout = timeout_or_default(timeout_secs, DEFAULT_RUN_TIMEOUT_SECS);
    let mut command = Command::new("cargo");
    command.current_dir(workspace_root_path());
    match step {
        VmLabIterationValidationStep::FmtCheck => {
            command.args(["fmt", "--all", "--", "--check"]);
        }
        VmLabIterationValidationStep::CargoCheckPackage { package } => {
            command.args(["check", "-p", package.as_str()]);
        }
        VmLabIterationValidationStep::CargoCheckBin { package, bin } => {
            command.args(["check", "-p", package.as_str(), "--bin", bin.as_str()]);
        }
        VmLabIterationValidationStep::CargoTestPackage { package, filter } => {
            command.args(["test", "-p", package.as_str()]);
            if let Some(filter) = filter.as_deref() {
                command.arg(filter);
            }
            command.args(["--", "--nocapture"]);
        }
        VmLabIterationValidationStep::CargoTestBin {
            package,
            bin,
            filter,
        } => {
            command.args(["test", "-p", package.as_str(), "--bin", bin.as_str()]);
            if let Some(filter) = filter.as_deref() {
                command.arg(filter);
            }
            command.args(["--", "--nocapture"]);
        }
    }
    let step_label = step.label();
    let status = run_status_with_timeout_passthrough(&mut command, timeout)
        .map_err(|err| format!("validation step {step_label} failed: {err}"))?;
    ensure_success_status(status, &format!("validation step {step_label}"))
}

fn default_live_lab_iteration_profile_path() -> PathBuf {
    default_live_lab_profile_root().join(format!(
        "generated_vm_lab_iteration_{}.env",
        unique_suffix()
    ))
}

fn default_live_lab_iteration_report_dir() -> PathBuf {
    default_live_lab_report_root().join(format!("iteration_{}", unique_suffix()))
}

fn summarize_live_lab_report(
    report_dir: &Path,
    collect_failure_diagnostics: bool,
    failed_log_tail_lines: usize,
) -> Result<LiveLabStageSummary, String> {
    let report_dir = if report_dir.is_absolute() {
        report_dir.to_path_buf()
    } else {
        std::env::current_dir()
            .map_err(|err| format!("resolve current directory failed: {err}"))?
            .join(report_dir)
    };
    let stages_path = report_dir.join("state/stages.tsv");
    let failure_digest_path = report_dir.join("failure_digest.md");
    let stages_body = fs::read_to_string(&stages_path).map_err(|err| {
        format!(
            "read live-lab stages failed ({}): {err}",
            stages_path.display()
        )
    })?;
    let mut first_failed_stage = None;
    let mut key_log_path = None;
    for line in stages_body.lines().filter(|line| !line.trim().is_empty()) {
        let columns = line.split('\t').collect::<Vec<_>>();
        if columns.len() < 5 {
            continue;
        }
        if columns[2] == "fail" {
            first_failed_stage = Some(columns[0].to_owned());
            key_log_path = Some(resolve_report_relative_path(
                columns[4],
                report_dir.as_path(),
            )?);
            break;
        }
    }
    let likely_reason = key_log_path
        .as_deref()
        .map(extract_iteration_likely_reason)
        .filter(|reason| !reason.is_empty());
    let failed_log_tail = if collect_failure_diagnostics {
        key_log_path
            .as_deref()
            .map(|path| tail_log_lines(path, failed_log_tail_lines))
            .transpose()?
    } else {
        None
    };
    Ok(LiveLabStageSummary {
        overall_status: if first_failed_stage.is_some() {
            "fail".to_owned()
        } else {
            "pass".to_owned()
        },
        first_failed_stage,
        key_report_path: failure_digest_path,
        key_log_path,
        likely_reason,
        failed_log_tail,
    })
}

fn resolve_report_relative_path(value: &str, report_dir: &Path) -> Result<PathBuf, String> {
    let path = Path::new(value);
    if path.is_absolute() {
        return Ok(path.to_path_buf());
    }
    let cwd = std::env::current_dir()
        .map_err(|err| format!("resolve current directory failed: {err}"))?;
    let cwd_joined = cwd.join(path);
    if cwd_joined.exists() {
        Ok(cwd_joined)
    } else {
        Ok(report_dir.join(path))
    }
}

fn extract_iteration_likely_reason(log_path: &Path) -> String {
    let Ok(body) = fs::read_to_string(log_path) else {
        return "see full log".to_owned();
    };
    let mut candidates = Vec::new();
    for raw_line in body.lines() {
        let line = raw_line.trim();
        if line.is_empty() {
            continue;
        }
        if line.starts_with("[stage:")
            && (line.contains("] START") || line.contains("] PASS") || line.contains("] FAIL"))
        {
            continue;
        }
        if line.starts_with("[parallel:") || line.starts_with("----- ") {
            continue;
        }
        candidates.push(line.to_owned());
    }
    if candidates.is_empty() {
        return "see full log".to_owned();
    }
    for line in candidates.iter().rev() {
        let lowered = line.to_ascii_lowercase();
        if lowered.contains("error:")
            || lowered.contains("fail")
            || lowered.contains("timed out")
            || lowered.contains("timeout")
            || lowered.contains("permission denied")
            || lowered.contains("missing")
            || lowered.contains("invalid")
            || lowered.contains("mismatch")
            || lowered.contains("does not exist")
            || lowered.contains("no such")
            || lowered.contains("unreachable")
        {
            return line.clone();
        }
    }
    candidates
        .last()
        .cloned()
        .unwrap_or_else(|| "see full log".to_owned())
}

fn tail_log_lines(path: &Path, max_lines: usize) -> Result<String, String> {
    let body = fs::read_to_string(path)
        .map_err(|err| format!("read failed log tail failed ({}): {err}", path.display()))?;
    let lines = body
        .lines()
        .map(str::trim_end)
        .filter(|line| !line.is_empty())
        .collect::<Vec<_>>();
    let start = lines.len().saturating_sub(max_lines.max(1));
    Ok(lines[start..].join("\n"))
}

fn render_live_lab_iteration_summary(
    profile_output_path: &Path,
    report_dir: &Path,
    profile_result: &str,
    summary: &LiveLabStageSummary,
) -> String {
    let mut lines = vec![
        format!("profile_result={profile_result}"),
        format!("profile_path={}", profile_output_path.display()),
        format!("report_dir={}", report_dir.display()),
        format!("overall_status={}", summary.overall_status),
        format!(
            "first_failed_stage={}",
            summary.first_failed_stage.as_deref().unwrap_or("none")
        ),
        format!("key_report_path={}", summary.key_report_path.display()),
        format!(
            "key_log_path={}",
            summary
                .key_log_path
                .as_deref()
                .map_or_else(|| "none".to_owned(), |path| path.display().to_string())
        ),
    ];
    if let Some(reason) = summary.likely_reason.as_deref() {
        lines.push(format!("likely_reason={reason}"));
    }
    if let Some(tail) = summary.failed_log_tail.as_deref() {
        lines.push("diagnostic_log_tail<<EOF".to_owned());
        lines.push(tail.to_owned());
        lines.push("EOF".to_owned());
    }
    lines.join("\n")
}

fn port_status_from_probe(value: &str) -> PortStatus {
    match value {
        "open" => PortStatus::Open,
        "refused" => PortStatus::Refused,
        "timed_out" => PortStatus::TimedOut,
        "unreachable" => PortStatus::Unreachable,
        _ => PortStatus::Unknown,
    }
}

fn port_status_from_probe_error(reason: Option<&str>) -> PortStatus {
    let Some(reason) = reason else {
        return PortStatus::Unknown;
    };
    let lowered = reason.to_ascii_lowercase();
    if lowered.contains("refused") {
        PortStatus::Refused
    } else if lowered.contains("timed out") || lowered.contains("timeout") {
        PortStatus::TimedOut
    } else if lowered.contains("unreachable")
        || lowered.contains("no route to host")
        || lowered.contains("network is unreachable")
    {
        PortStatus::Unreachable
    } else {
        PortStatus::Unknown
    }
}

fn push_unique_reason_code(reason_codes: &mut Vec<String>, reason_code: &str) {
    if !reason_codes.iter().any(|existing| existing == reason_code) {
        reason_codes.push(reason_code.to_owned());
    }
}

fn windows_ssh_auth_timeout(reason: &str) -> bool {
    let lowered = reason.to_ascii_lowercase();
    lowered.contains("timed out") || lowered.contains("timeout")
}

fn known_hosts_lookup_candidates(
    authoritative_target: &str,
    live_ip: Option<&str>,
    ssh_port: u16,
) -> Vec<String> {
    let mut hosts = BTreeSet::new();
    hosts.insert(ssh_target_host(authoritative_target));
    if let Some(live_ip) = live_ip {
        hosts.insert(live_ip.to_owned());
    }
    hosts
        .into_iter()
        .map(|host| {
            if ssh_port == 22 {
                host
            } else {
                format!("[{host}]:{ssh_port}")
            }
        })
        .collect()
}

fn windows_discovery_known_hosts_state(
    authoritative_target: Option<&str>,
    live_ip: Option<&str>,
    ssh_port: u16,
    known_hosts_path: Option<&Path>,
) -> Option<ProbeState<bool>> {
    let path = known_hosts_path?;
    let Some(authoritative_target) = authoritative_target else {
        return Some(ProbeState::Missing {
            reason: "no-authoritative-ssh-target".to_owned(),
        });
    };
    let candidates = known_hosts_lookup_candidates(authoritative_target, live_ip, ssh_port);
    Some(match find_known_hosts_match(path, candidates.as_slice()) {
        Ok(Some(_)) => ProbeState::Ok { value: true },
        Ok(None) => ProbeState::Missing {
            reason: "known-hosts-entry-missing".to_owned(),
        },
        Err(err) => ProbeState::Error { reason: err },
    })
}

fn pull_windows_local_utm_guest_file_with_retry(
    utm_name: &str,
    remote_path: &str,
    local_path: &Path,
    timeout: Duration,
    label: &str,
) -> Result<(), String> {
    let retry_budget = windows_local_utm_result_pull_retry_budget(timeout);
    let started_at = Instant::now();
    let pull_timeout = windows_local_utm_result_pull_attempt_timeout(timeout);
    let mut last_error = None::<String>;
    loop {
        let remaining = retry_budget
            .checked_sub(started_at.elapsed())
            .unwrap_or_default();
        if remaining.is_zero() {
            break;
        }
        let attempt_timeout = pull_timeout.min(remaining).max(Duration::from_secs(1));
        let _ = fs::remove_file(local_path);
        match utm_pull_raw(utm_name, remote_path, local_path, attempt_timeout) {
            Ok(status) if status.success() => return Ok(()),
            Ok(_) => {
                last_error = Some(format!(
                    "{label} file pull exited unsuccessfully for {utm_name}:{remote_path}"
                ));
            }
            Err(err) => {
                last_error = Some(format!(
                    "{label} file pull failed for {utm_name}:{remote_path}: {err}"
                ));
            }
        }
        let remaining = retry_budget
            .checked_sub(started_at.elapsed())
            .unwrap_or_default();
        if remaining.is_zero() {
            break;
        }
        thread::sleep(Duration::from_secs(5).min(remaining));
    }
    Err(last_error
        .unwrap_or_else(|| format!("{label} file pull failed for {utm_name}:{remote_path}")))
}

fn windows_local_utm_result_pull_retry_budget(timeout: Duration) -> Duration {
    let capped = timeout.min(Duration::from_secs(
        WINDOWS_UTM_RESULT_PULL_RETRY_BUDGET_SECS,
    ));
    if capped.is_zero() {
        Duration::from_secs(1)
    } else {
        capped
    }
}

fn windows_local_utm_result_pull_attempt_timeout(timeout: Duration) -> Duration {
    let capped = timeout.min(Duration::from_secs(20));
    if capped < Duration::from_secs(1) {
        Duration::from_secs(1)
    } else {
        capped
    }
}

fn read_windows_local_utm_utf8_file(path: &Path, label: &str) -> Result<String, String> {
    let bytes =
        fs::read(path).map_err(|err| format!("{label} read failed ({}): {err}", path.display()))?;
    let text =
        String::from_utf8(bytes).map_err(|err| format!("{label} was not valid UTF-8: {err}"))?;
    Ok(text.trim_start_matches('\u{feff}').to_owned())
}

fn format_windows_local_utm_result_pull_failure(
    probe_label: &str,
    utm_name: &str,
    host_status: &Result<ExitStatus, String>,
    pull_error: &str,
) -> String {
    match host_status {
        Err(err) => format!("{probe_label} transport failed for {utm_name}: {err}; {pull_error}"),
        Ok(status) if !status.success() => {
            format!("{probe_label} wrapper failed for {utm_name}; {pull_error}")
        }
        Ok(_) => format!("{probe_label} result retrieval failed for {utm_name}: {pull_error}"),
    }
}

fn execute_windows_local_utm_result_file_probe<F>(
    utm_name: &str,
    probe_label: &str,
    timeout: Duration,
    remote_result_path: &str,
    build_result_script: F,
) -> Result<String, String>
where
    F: FnOnce(&str) -> Result<String, String>,
{
    let local_root = std::env::temp_dir().join(format!(
        "rustynet-vm-lab-windows-result-{}",
        unique_suffix()
    ));
    fs::create_dir_all(local_root.as_path()).map_err(|err| {
        format!(
            "create local Windows UTM result dir failed ({}): {err}",
            local_root.display()
        )
    })?;
    let local_result_path = local_root.join("result.json");
    let result_script = build_result_script(remote_result_path)?;
    let host_status = utm_exec_windows_raw(utm_name, result_script.as_str(), timeout);
    let pull_result = pull_windows_local_utm_guest_file_with_retry(
        utm_name,
        remote_result_path,
        local_result_path.as_path(),
        timeout,
        probe_label,
    );
    let output = match pull_result {
        Ok(()) => read_windows_local_utm_utf8_file(local_result_path.as_path(), probe_label),
        Err(pull_error) => Err(format_windows_local_utm_result_pull_failure(
            probe_label,
            utm_name,
            &host_status,
            pull_error.as_str(),
        )),
    };
    let _ = best_effort_remove_windows_local_utm_guest_file(
        utm_name,
        remote_result_path,
        Duration::from_secs(20),
    );
    let _ = fs::remove_dir_all(local_root.as_path());
    let output = output?;
    if output.trim().is_empty() {
        return Err(format!(
            "{probe_label} result file was empty for {utm_name}: {remote_result_path}"
        ));
    }
    Ok(output)
}

fn build_windows_ssh_readiness_result_script(remote_result_path: &str) -> Result<String, String> {
    Ok(format!(
        "Set-StrictMode -Version Latest; \
         $ErrorActionPreference = 'Stop'; \
         $ProgressPreference = 'SilentlyContinue'; \
         $resultPath = {result_path}; \
         $body = ''; \
         $probeExit = 0; \
         try {{ \
           $resultParent = Split-Path -Path $resultPath -Parent; \
           if ($resultParent -and -not (Test-Path -LiteralPath $resultParent)) {{ \
             New-Item -ItemType Directory -Path $resultParent -Force | Out-Null \
           }}; \
           if (Test-Path -LiteralPath $resultPath) {{ \
             Remove-Item -LiteralPath $resultPath -Force \
           }}; \
           $programData = [Environment]::GetFolderPath('CommonApplicationData'); \
           $sshdPath = Join-Path $env:WINDIR 'System32\\OpenSSH\\sshd.exe'; \
           $hostKeyPath = Join-Path $programData 'ssh\\ssh_host_ed25519_key.pub'; \
           $service = Get-Service -Name 'sshd' -ErrorAction SilentlyContinue; \
           $firewallRule = Get-NetFirewallRule -Name 'OpenSSH-Server-In-TCP' -ErrorAction SilentlyContinue; \
           $listenerReady = [System.Net.NetworkInformation.IPGlobalProperties]::GetIPGlobalProperties().GetActiveTcpListeners() | Where-Object {{ $_.Port -eq 22 }} | Select-Object -First 1; \
           $report = [ordered]@{{ \
             openssh_installed = ((Test-Path -LiteralPath $sshdPath) -or $null -ne $service); \
             service_running = ($null -ne $service -and $service.Status -eq 'Running'); \
             firewall_rule_enabled = ($null -ne $firewallRule -and $firewallRule.Enabled -eq 'True' -and $firewallRule.Direction -eq 'Inbound' -and $firewallRule.Action -eq 'Allow'); \
             host_key_present = ((Test-Path -LiteralPath $hostKeyPath) -and ((Get-Item -LiteralPath $hostKeyPath).Length -gt 0)); \
             listener_ready = ($null -ne $listenerReady) \
           }}; \
           $body = ($report | ConvertTo-Json -Compress) \
         }} catch {{ \
           $probeExit = 1; \
           $body = (@{{ status = 'error'; reason = ('windows-ssh-readiness-probe-exception: ' + $_.ToString().Trim()) }} | ConvertTo-Json -Compress) \
         }}; \
         $body = $body.Trim(); \
         if ([string]::IsNullOrWhiteSpace($body)) {{ \
           if ($probeExit -eq 0) {{ \
             $body = (@{{ status = 'error'; reason = 'windows-ssh-readiness-probe-produced-no-output' }} | ConvertTo-Json -Compress) \
           }} else {{ \
             $body = (@{{ status = 'error'; reason = 'windows-ssh-readiness-probe-failed-without-output' }} | ConvertTo-Json -Compress) \
           }} \
         }}; \
         Set-Content -LiteralPath $resultPath -Value $body -Encoding utf8; \
         exit $probeExit",
        result_path = powershell_quote(remote_result_path)?,
    ))
}

fn build_windows_ssh_readiness_probe_script() -> String {
    "Set-StrictMode -Version Latest; \
     $ErrorActionPreference = 'Stop'; \
     $ProgressPreference = 'SilentlyContinue'; \
     try { \
       $programData = [Environment]::GetFolderPath('CommonApplicationData'); \
       $sshdPath = Join-Path $env:WINDIR 'System32\\OpenSSH\\sshd.exe'; \
       $hostKeyPath = Join-Path $programData 'ssh\\ssh_host_ed25519_key.pub'; \
       $service = Get-Service -Name 'sshd' -ErrorAction SilentlyContinue; \
       $firewallRule = Get-NetFirewallRule -Name 'OpenSSH-Server-In-TCP' -ErrorAction SilentlyContinue; \
       $listenerReady = [System.Net.NetworkInformation.IPGlobalProperties]::GetIPGlobalProperties().GetActiveTcpListeners() | Where-Object { $_.Port -eq 22 } | Select-Object -First 1; \
       [ordered]@{ \
         openssh_installed = ((Test-Path -LiteralPath $sshdPath) -or $null -ne $service); \
         service_running = ($null -ne $service -and $service.Status -eq 'Running'); \
         firewall_rule_enabled = ($null -ne $firewallRule -and $firewallRule.Enabled -eq 'True' -and $firewallRule.Direction -eq 'Inbound' -and $firewallRule.Action -eq 'Allow'); \
         host_key_present = ((Test-Path -LiteralPath $hostKeyPath) -and ((Get-Item -LiteralPath $hostKeyPath).Length -gt 0)); \
         listener_ready = ($null -ne $listenerReady) \
       } | ConvertTo-Json -Compress \
     } catch { \
       @{ status = 'error'; reason = ('windows-ssh-readiness-probe-exception: ' + $_.ToString().Trim()) } | ConvertTo-Json -Compress; \
       exit 1 \
     }"
        .to_owned()
}

fn windows_ssh_readiness_result_path(staging_dir: Option<&str>) -> Result<String, String> {
    let file_name = format!("windows-ssh-readiness.{}.json", unique_suffix());
    if let Some(staging_dir) = staging_dir.filter(|value| !value.trim().is_empty()) {
        return windows_guest_path_join(staging_dir, file_name.as_str());
    }
    Ok(format!(r"C:\ProgramData\Rustynet\vm-lab\{file_name}"))
}

fn windows_ssh_readiness_probe_timeout(timeout: Duration) -> Duration {
    timeout.max(Duration::from_secs(30))
}

fn parse_windows_ssh_readiness_probe_output(
    output: &str,
    target_label: &str,
) -> Result<WindowsSshReadinessProbe, String> {
    let trimmed = output.trim();
    if trimmed.is_empty() {
        return Err(format!(
            "Windows SSH readiness probe produced no output for {target_label}"
        ));
    }
    let parsed: Value = serde_json::from_str(trimmed).map_err(|err| {
        format!("Windows SSH readiness probe did not emit valid JSON for {target_label}: {err}")
    })?;
    if let Some(status) = parsed.get("status").and_then(Value::as_str)
        && status != "pass"
    {
        let reason = parsed
            .get("reason")
            .and_then(Value::as_str)
            .unwrap_or("unknown");
        return Err(format!(
            "Windows SSH readiness probe reported status={status} reason={reason} for {target_label}"
        ));
    }
    serde_json::from_value(parsed).map_err(|err| {
        format!("Windows SSH readiness probe payload was not valid for {target_label}: {err}")
    })
}

fn best_effort_remove_windows_local_utm_guest_file(
    utm_name: &str,
    remote_path: &str,
    timeout: Duration,
) -> Result<(), String> {
    let cleanup_script = format!(
        "Set-StrictMode -Version Latest; $ErrorActionPreference = 'Stop'; if (Test-Path -LiteralPath {}) {{ Remove-Item -LiteralPath {} -Force -ErrorAction Stop }}",
        powershell_quote(remote_path)?,
        powershell_quote(remote_path)?,
    );
    let _ = utm_exec_windows_raw(utm_name, cleanup_script.as_str(), timeout);
    Ok(())
}

fn probe_windows_local_utm_ssh_readiness(
    utm_name: &str,
    staging_dir: Option<&str>,
    timeout: Duration,
) -> ProbeState<WindowsSshReadinessProbe> {
    let timeout = windows_ssh_readiness_probe_timeout(timeout);
    if let Some(staging_dir) = staging_dir.filter(|value| !value.trim().is_empty()) {
        let output = match execute_utm_remote_powershell_capture(
            utm_name,
            staging_dir,
            build_windows_ssh_readiness_probe_script().as_str(),
            timeout,
        ) {
            Ok((0, output)) => output,
            Ok((rc, output)) => {
                return ProbeState::Error {
                    reason: format_remote_capture_exit_error(rc, output.as_str()),
                };
            }
            Err(err) => return ProbeState::Error { reason: err },
        };
        return match parse_windows_ssh_readiness_probe_output(output.as_str(), utm_name) {
            Ok(report) => ProbeState::Ok { value: report },
            Err(err) => ProbeState::Error { reason: err },
        };
    }

    let remote_result_path = match windows_ssh_readiness_result_path(staging_dir) {
        Ok(path) => path,
        Err(err) => return ProbeState::Error { reason: err },
    };
    let output = match execute_windows_local_utm_result_file_probe(
        utm_name,
        "Windows SSH readiness probe",
        timeout,
        remote_result_path.as_str(),
        build_windows_ssh_readiness_result_script,
    ) {
        Ok(output) => output,
        Err(err) => return ProbeState::Error { reason: err },
    };
    let _ = best_effort_remove_windows_local_utm_guest_file(
        utm_name,
        remote_result_path.as_str(),
        Duration::from_secs(20),
    );
    match parse_windows_ssh_readiness_probe_output(output.as_str(), utm_name) {
        Ok(report) => ProbeState::Ok { value: report },
        Err(err) => ProbeState::Error { reason: err },
    }
}

fn push_windows_ssh_port_transport_reason(
    reason_codes: &mut Vec<String>,
    ssh_port_state: &ProbeState<PortStatus>,
) {
    match ssh_port_state {
        ProbeState::Ok {
            value: PortStatus::TimedOut | PortStatus::Unreachable,
        }
        | ProbeState::Fallback {
            value: PortStatus::TimedOut | PortStatus::Unreachable,
            ..
        }
        | ProbeState::Error { .. } => {
            push_unique_reason_code(reason_codes, "ssh-firewall-not-open");
        }
        ProbeState::Ok {
            value: PortStatus::Refused,
        }
        | ProbeState::Fallback {
            value: PortStatus::Refused,
            ..
        } => {
            push_unique_reason_code(reason_codes, "ssh-service-not-running");
            push_unique_reason_code(reason_codes, "ssh-listener-not-ready");
        }
        ProbeState::Missing { .. }
        | ProbeState::Ok {
            value: PortStatus::Unknown,
        }
        | ProbeState::Fallback {
            value: PortStatus::Unknown,
            ..
        } => {
            push_unique_reason_code(reason_codes, "ssh-listener-not-ready");
        }
        ProbeState::Ok {
            value: PortStatus::Open,
        }
        | ProbeState::Fallback {
            value: PortStatus::Open,
            ..
        } => {}
    }
}

fn build_windows_utm_reason_codes(
    process_state: &ProbeState<bool>,
    live_ip_state: &ProbeState<String>,
    ssh_port_state: &ProbeState<PortStatus>,
    ssh_auth_state: &ProbeState<String>,
    authoritative_target_present: bool,
    known_hosts_state: Option<&ProbeState<bool>>,
    windows_ssh_probe_state: Option<&ProbeState<WindowsSshReadinessProbe>>,
) -> Vec<String> {
    let powered = matches!(process_state, ProbeState::Ok { value: true });
    let networked = matches!(live_ip_state, ProbeState::Ok { .. });
    let tcp_ready = matches!(
        ssh_port_state,
        ProbeState::Ok {
            value: PortStatus::Open
        }
    );
    let auth_ready = matches!(
        ssh_auth_state,
        ProbeState::Ok { value } if value == "ok" || value == "ready"
    );
    let mut reason_codes = Vec::new();
    if !powered {
        push_unique_reason_code(&mut reason_codes, "process-not-ready");
    }
    if !networked {
        push_unique_reason_code(&mut reason_codes, "live-ip-not-authoritative");
        if powered {
            push_unique_reason_code(&mut reason_codes, "guest-agent-not-ready");
        }
    }
    if !authoritative_target_present {
        push_unique_reason_code(&mut reason_codes, "no-authoritative-ssh-target");
    }
    if let Some(ProbeState::Ok { value }) = windows_ssh_probe_state {
        if !value.openssh_installed || !value.service_running {
            push_unique_reason_code(&mut reason_codes, "ssh-service-not-running");
        }
        if !value.firewall_rule_enabled {
            push_unique_reason_code(&mut reason_codes, "ssh-firewall-not-open");
        }
        if !value.listener_ready {
            push_unique_reason_code(&mut reason_codes, "ssh-listener-not-ready");
        }
        if !value.host_key_present {
            push_unique_reason_code(&mut reason_codes, "ssh-host-key-not-ready");
        }
        if !tcp_ready
            && value.openssh_installed
            && value.service_running
            && value.firewall_rule_enabled
            && value.listener_ready
        {
            push_windows_ssh_port_transport_reason(&mut reason_codes, ssh_port_state);
        }
    } else if !tcp_ready {
        push_windows_ssh_port_transport_reason(&mut reason_codes, ssh_port_state);
    }
    if let Some(state) = known_hosts_state {
        match state {
            ProbeState::Ok { value: true } => {}
            ProbeState::Ok { value: false }
            | ProbeState::Fallback { .. }
            | ProbeState::Missing { .. }
            | ProbeState::Error { .. } => {
                if authoritative_target_present {
                    push_unique_reason_code(&mut reason_codes, "ssh-host-key-not-ready");
                }
            }
        }
    }
    if tcp_ready && authoritative_target_present && !auth_ready {
        match ssh_auth_state {
            ProbeState::Error { reason } if windows_ssh_auth_timeout(reason.as_str()) => {
                push_unique_reason_code(&mut reason_codes, "ssh-auth-timeout");
            }
            ProbeState::Fallback { .. } | ProbeState::Error { .. } => {
                push_unique_reason_code(&mut reason_codes, "ssh-auth-rejected");
            }
            ProbeState::Missing { reason }
                if reason == "no-ssh-target" || reason == "no-ssh-user" =>
            {
                push_unique_reason_code(&mut reason_codes, "no-authoritative-ssh-target");
            }
            ProbeState::Missing { .. } | ProbeState::Ok { .. } => {}
        }
    }
    reason_codes
}

struct UtmReadinessInputs<'a> {
    platform: VmGuestPlatform,
    process_state: &'a ProbeState<bool>,
    live_ip_state: &'a ProbeState<String>,
    ssh_port_state: &'a ProbeState<PortStatus>,
    ssh_auth_state: &'a ProbeState<String>,
    authoritative_target_present: bool,
    known_hosts_state: Option<&'a ProbeState<bool>>,
    windows_ssh_probe_state: Option<&'a ProbeState<WindowsSshReadinessProbe>>,
}

fn build_utm_readiness(inputs: UtmReadinessInputs<'_>) -> VmLabReadiness {
    let powered = matches!(inputs.process_state, ProbeState::Ok { value: true });
    let networked = matches!(inputs.live_ip_state, ProbeState::Ok { .. });
    let tcp_ready = matches!(
        inputs.ssh_port_state,
        ProbeState::Ok {
            value: PortStatus::Open
        }
    );
    let auth_ready = matches!(
        inputs.ssh_auth_state,
        ProbeState::Ok { value } if value == "ok" || value == "ready"
    );
    let reason_codes = if inputs.platform == VmGuestPlatform::Windows {
        build_windows_utm_reason_codes(
            inputs.process_state,
            inputs.live_ip_state,
            inputs.ssh_port_state,
            inputs.ssh_auth_state,
            inputs.authoritative_target_present,
            inputs.known_hosts_state,
            inputs.windows_ssh_probe_state,
        )
    } else {
        let mut reason_codes = Vec::new();
        if !powered {
            reason_codes.push("process-not-ready".to_owned());
        }
        if !networked {
            reason_codes.push("live-ip-not-authoritative".to_owned());
        }
        if !tcp_ready {
            reason_codes.push("ssh-tcp-not-open".to_owned());
        }
        if !auth_ready {
            reason_codes.push("ssh-auth-not-ready".to_owned());
        }
        if !inputs.authoritative_target_present {
            reason_codes.push("no-authoritative-ssh-target".to_owned());
        }
        reason_codes
    };
    let execution_ready =
        powered && networked && tcp_ready && auth_ready && inputs.authoritative_target_present;
    VmLabReadiness {
        powered,
        networked,
        tcp_ready,
        auth_ready,
        execution_ready,
        reason_codes,
    }
}

/// Pure readiness predicate for the non-Windows discover surface.
///
/// A node is execution-ready when it is powered, networked (live_ip present),
/// has an authoritative ssh target, AND ssh is reachable. ssh-reachability is
/// satisfied by EITHER the raw-TCP probe seeing the port open OR — strictly
/// stronger evidence — the real ssh-binary auth probe succeeding. The auth
/// override exists because `probe_tcp_port_status` can be blind in a
/// sandboxed / odd-routing context and report the port "closed" even though
/// the same ssh the bootstrap path uses can reach the node.
///
/// A genuinely unreachable node (auth ALSO fails) keeps `ssh_reachable=false`,
/// so the restart / fail-loud path still triggers exactly as before.
fn discover_local_utm_target_ready(
    process_present: bool,
    live_ip_authoritative: bool,
    ssh_port_open: bool,
    ssh_auth_ok: bool,
    authoritative_target_present: bool,
) -> bool {
    let ssh_reachable = ssh_port_open || ssh_auth_ok;
    process_present && live_ip_authoritative && ssh_reachable && authoritative_target_present
}

fn stage_status_from_record(record: &LiveLabStageRecord) -> VmLabStageStatus {
    match record.status.as_str() {
        "pass" => VmLabStageStatus::Pass,
        "fail" => VmLabStageStatus::Fail,
        _ => VmLabStageStatus::Skipped,
    }
}

fn command_status_from_summary(summary: &LiveLabStageSummary) -> VmLabCommandOverallStatus {
    match summary.overall_status.as_str() {
        "pass" => VmLabCommandOverallStatus::Pass,
        "pass_with_warnings" => VmLabCommandOverallStatus::Partial,
        _ => VmLabCommandOverallStatus::Fail,
    }
}

fn stage_outcomes_from_records(records: &[LiveLabStageRecord]) -> Vec<VmLabStageOutcome> {
    records
        .iter()
        .map(|record| VmLabStageOutcome {
            stage: record.name.clone(),
            status: stage_status_from_record(record),
            summary: record.description.clone(),
            artifacts: vec![record.log_path.display().to_string()],
        })
        .collect()
}

fn live_lab_matrix_stage_outcomes_from_vm_lab(
    outcomes: &[VmLabStageOutcome],
) -> Vec<LiveLabRunMatrixStageOutcome> {
    outcomes
        .iter()
        .map(|outcome| LiveLabRunMatrixStageOutcome {
            stage: outcome.stage.clone(),
            status: match outcome.status {
                VmLabStageStatus::Pass => "pass",
                VmLabStageStatus::Fail => "fail",
                // Canonical taxonomy (finding 3) — see the StageOutcome
                // converter above.
                VmLabStageStatus::Skipped => "skipped",
            }
            .to_owned(),
            artifacts: outcome.artifacts.clone(),
        })
        .collect()
}

/// Read `run_note` from `<report_dir>/run_summary.json` if present (Bucket 2:
/// so the finalize-path run-matrix row carries the note instead of dropping it —
/// the Rust `--node` path now writes run_summary.json, and bash focused wrappers
/// that write one benefit identically). Absent/unparseable/empty → None.
fn read_run_note_from_summary(report_dir: &Path) -> Option<String> {
    let body = std::fs::read_to_string(report_dir.join("run_summary.json")).ok()?;
    let val: serde_json::Value = serde_json::from_str(&body).ok()?;
    val.get("run_note")
        .and_then(serde_json::Value::as_str)
        .filter(|s| !s.is_empty())
        .map(str::to_owned)
}

fn append_live_lab_run_matrix_for_command(
    command_name: &str,
    report_dir: &Path,
    profile_path: Option<&Path>,
    inventory_path: Option<&Path>,
    outcomes: &[VmLabStageOutcome],
) -> Result<PathBuf, String> {
    let matrix_outcomes = live_lab_matrix_stage_outcomes_from_vm_lab(outcomes);
    append_live_lab_run_matrix_row(LiveLabRunMatrixAppendConfig {
        command_name,
        report_dir,
        profile_path,
        inventory_path,
        extra_stage_outcomes: matrix_outcomes.as_slice(),
        notes: read_run_note_from_summary(report_dir),
        // Focused wrappers are single-writer runs: their one row is final.
        row_role: LiveLabRunMatrixRowRole::Final,
    })
    .map(|result| result.report_row_path)
}

fn serialize_vm_lab_command_result(result: &VmLabCommandResult) -> Result<String, String> {
    serde_json::to_string_pretty(result)
        .map_err(|err| format!("serialize vm-lab command result failed: {err}"))
}

fn maybe_write_report_artifact(
    report_dir: Option<&Path>,
    filename: &str,
    contents: &str,
) -> Result<Option<PathBuf>, String> {
    let Some(report_dir) = report_dir else {
        return Ok(None);
    };
    let path = report_dir.join(filename);
    write_orchestration_artifact(path.as_path(), contents)?;
    Ok(Some(path))
}

fn report_dir_label(report_dir: Option<&Path>, fallback: &Path) -> String {
    report_dir.map_or_else(
        || fallback.display().to_string(),
        |path| path.display().to_string(),
    )
}

fn validate_live_lab_run_artifacts(report_dir: &Path) -> Result<(), String> {
    if !report_dir.is_dir() {
        return Err(format!(
            "live-lab report directory does not exist: {}",
            report_dir.display()
        ));
    }
    for artifact in [
        report_dir.join("run_summary.json"),
        report_dir.join("run_summary.md"),
        report_dir.join("state/stages.tsv"),
        report_dir.join("state/nodes.tsv"),
    ] {
        if !artifact.exists() {
            return Err(format!(
                "required live-lab artifact is missing: {}",
                artifact.display()
            ));
        }
    }

    let records = parse_live_lab_stage_records(report_dir)?;
    if records.is_empty() {
        return Err(format!(
            "live-lab report contains no stage records: {}",
            report_dir.join("state/stages.tsv").display()
        ));
    }
    for record in &records {
        if !record.log_path.exists() {
            return Err(format!(
                "stage log declared in stages.tsv is missing: {}",
                record.log_path.display()
            ));
        }
    }
    if records.iter().any(|record| record.status == "fail")
        && !report_dir.join("failure_digest.md").exists()
        && !report_dir.join("failure_digest.json").exists()
    {
        return Err(format!(
            "run contains failed stages but no failure digest exists under {}",
            report_dir.display()
        ));
    }
    Ok(())
}

fn live_lab_profile_has_full_release_gate_topology(profile: &LiveLabProfile) -> bool {
    ["ENTRY_TARGET", "AUX_TARGET", "EXTRA_TARGET"]
        .iter()
        .all(|key| {
            profile
                .optional(key)
                .is_some_and(|value| !value.trim().is_empty())
        })
}

fn full_release_gate_requested(profile: &LiveLabProfile, config: &VmLabRunLiveLabConfig) -> bool {
    !config.skip_gates
        && !config.skip_soak
        && !config.skip_cross_network
        && live_lab_profile_has_full_release_gate_topology(profile)
}

fn build_release_gate_completeness_report(
    records: &[LiveLabStageRecord],
    requested: bool,
) -> ReleaseGateCompletenessReport {
    let observed_pass_stages = records
        .iter()
        .filter(|record| record.status == "pass")
        .map(|record| record.name.clone())
        .collect::<Vec<_>>();
    let observed_pass_set = observed_pass_stages
        .iter()
        .map(String::as_str)
        .collect::<HashSet<_>>();
    let required_stages = FULL_RELEASE_GATE_REQUIRED_STAGES
        .iter()
        .map(|stage| (*stage).to_owned())
        .collect::<Vec<_>>();
    let missing_or_non_pass_stages = if requested {
        FULL_RELEASE_GATE_REQUIRED_STAGES
            .iter()
            .filter(|stage| !observed_pass_set.contains(**stage))
            .map(|stage| (*stage).to_owned())
            .collect::<Vec<_>>()
    } else {
        Vec::new()
    };
    let status = if !requested {
        "not_requested"
    } else if missing_or_non_pass_stages.is_empty() {
        "complete"
    } else {
        "incomplete"
    };
    ReleaseGateCompletenessReport {
        requested,
        status: status.to_owned(),
        required_stages,
        observed_pass_stages,
        missing_or_non_pass_stages,
    }
}

fn write_release_gate_completeness(
    report_dir: &Path,
    report: &ReleaseGateCompletenessReport,
) -> Result<(), String> {
    let path = report_dir.join(RELEASE_GATE_COMPLETENESS_RELATIVE_PATH);
    let parent = path.parent().ok_or_else(|| {
        format!(
            "release-gate completeness path has no parent: {}",
            path.display()
        )
    })?;
    fs::create_dir_all(parent).map_err(|err| {
        format!(
            "create release-gate completeness directory failed ({}): {err}",
            parent.display()
        )
    })?;
    let body = serde_json::to_vec_pretty(report)
        .map_err(|err| format!("serialize release-gate completeness failed: {err}"))?;
    fs::write(&path, body).map_err(|err| {
        format!(
            "write release-gate completeness failed ({}): {err}",
            path.display()
        )
    })
}

fn validate_live_lab_diagnostics_artifacts(diagnostics_dir: &Path) -> Result<(), String> {
    for artifact in [
        diagnostics_dir.join("diagnostics_summary.json"),
        diagnostics_dir.join("vm_lab_status.json"),
        diagnostics_dir.join("stage_forensics_summary.json"),
        diagnostics_dir.join("stage_forensics_review.md"),
    ] {
        if !artifact.exists() {
            return Err(format!(
                "required live-lab diagnostics artifact is missing: {}",
                artifact.display()
            ));
        }
    }
    Ok(())
}

fn live_lab_setup_complete(report_dir: &Path) -> Result<bool, String> {
    if !report_dir.join("state/stages.tsv").exists() {
        return Ok(false);
    }
    let records = parse_live_lab_stage_records(report_dir)?;
    Ok(records
        .iter()
        .find(|record| record.name == "validate_baseline_runtime")
        .is_some_and(|record| record.status == "pass"))
}

fn live_lab_report_has_non_setup_stage_records(report_dir: &Path) -> Result<bool, String> {
    if !report_dir.join("state/stages.tsv").exists() {
        return Ok(false);
    }
    let setup_stages = setup_stage_names().iter().copied().collect::<HashSet<_>>();
    let records = parse_live_lab_stage_records(report_dir)?;
    Ok(records
        .iter()
        .any(|record| !setup_stages.contains(record.name.as_str())))
}

pub fn execute_ops_vm_lab_check_known_hosts(
    config: VmLabCheckKnownHostsConfig,
) -> Result<String, String> {
    ensure_local_regular_file_path(config.known_hosts_path.as_path(), "known_hosts file")?;
    let inventory = load_inventory(config.inventory_path.as_path())?;
    let selected_targets = resolve_known_hosts_targets(
        inventory.as_slice(),
        config.vm_aliases.as_slice(),
        config.select_all,
        config.raw_targets.as_slice(),
    )?;
    let mut lines = Vec::new();
    let mut missing = Vec::new();
    for target in selected_targets {
        let matched = find_known_hosts_match(
            config.known_hosts_path.as_path(),
            target.host_candidates.as_slice(),
        )?;
        if let Some(candidate) = matched {
            lines.push(format!(
                "label={} status=present matched={} candidates={}",
                target.label,
                candidate,
                target.host_candidates.join(",")
            ));
        } else {
            missing.push(target.label.clone());
            lines.push(format!(
                "label={} status=missing candidates={}",
                target.label,
                target.host_candidates.join(",")
            ));
        }
    }
    if missing.is_empty() {
        Ok(lines.join("\n"))
    } else {
        Err(format!(
            "{}\nmissing pinned known_hosts entries for: {}",
            lines.join("\n"),
            missing.join(", ")
        ))
    }
}

pub fn execute_ops_vm_lab_preflight(config: VmLabPreflightConfig) -> Result<String, String> {
    if config.require_same_network {
        ensure_remote_selection_declares_single_network(
            config.inventory_path.as_path(),
            config.vm_aliases.as_slice(),
            config.select_all,
            config.raw_targets.as_slice(),
        )?;
    }
    if let Some(path) = config.known_hosts_path.as_deref() {
        execute_ops_vm_lab_check_known_hosts(VmLabCheckKnownHostsConfig {
            inventory_path: config.inventory_path.clone(),
            vm_aliases: config.vm_aliases.clone(),
            raw_targets: config.raw_targets.clone(),
            select_all: config.select_all,
            known_hosts_path: path.to_path_buf(),
        })?;
    }
    ensure_optional_local_regular_file_path(
        config.ssh_identity_file.as_deref(),
        "SSH identity file",
    )?;
    ensure_optional_local_regular_file_path(
        config.known_hosts_path.as_deref(),
        "SSH known_hosts file",
    )?;

    let targets = resolve_remote_targets(
        config.inventory_path.as_path(),
        config.vm_aliases.as_slice(),
        config.select_all,
        config.raw_targets.as_slice(),
    )?;
    let required_commands = if config.require_commands.is_empty() {
        DEFAULT_PRECHECK_COMMANDS
            .iter()
            .map(std::string::ToString::to_string)
            .collect::<Vec<_>>()
    } else {
        config.require_commands.clone()
    };
    for command_name in &required_commands {
        ensure_inventory_alias(command_name)?;
    }
    let timeout = timeout_or_default(config.timeout_secs, DEFAULT_PREFLIGHT_TIMEOUT_SECS);
    let mut results = Vec::new();
    let mut failures = 0usize;

    for target in &targets {
        let effective_user = target.ssh_user.as_deref();
        match capture_remote_shell_command_for_target(
            target,
            None,
            config.ssh_identity_file.as_deref(),
            config.known_hosts_path.as_deref(),
            build_preflight_script(
                required_commands.as_slice(),
                config.min_free_kib,
                config.require_rustynet_installed,
            )?
            .as_str(),
            timeout,
        ) {
            Ok(output) => {
                let values = parse_key_value_output(output.as_str());
                let free_kib = values
                    .get("free_kib")
                    .and_then(|value| value.parse::<u64>().ok())
                    .unwrap_or_default();
                let sudo_ok = values.get("sudo_ok").map(String::as_str) == Some("true");
                let rustynet_installed =
                    values.get("rustynet_installed").map(String::as_str) == Some("true");
                let mut missing_commands = Vec::new();
                for command_name in &required_commands {
                    let key = format!("cmd.{command_name}");
                    if values.get(key.as_str()).map(String::as_str) != Some("present") {
                        missing_commands.push(command_name.clone());
                    }
                }
                let mut problems = Vec::new();
                if !sudo_ok {
                    problems.push("sudo-n".to_owned());
                }
                if free_kib < config.min_free_kib {
                    problems.push(format!("free_kib<{min}", min = config.min_free_kib));
                }
                if config.require_rustynet_installed && !rustynet_installed {
                    problems.push("rustynet-missing".to_owned());
                }
                if !missing_commands.is_empty() {
                    problems.push(format!("missing-commands={}", missing_commands.join(",")));
                }
                if !problems.is_empty() {
                    failures += 1;
                }
                results.push(json!({
                    "label": target.label,
                    "ssh_target": target.ssh_target,
                    "ssh_user": effective_user,
                    "hostname": values.get("hostname"),
                    "os": values.get("os"),
                    "free_kib": free_kib,
                    "sudo_ok": sudo_ok,
                    "rustynet_installed": rustynet_installed,
                    "commands": required_commands.iter().map(|command_name| {
                        let key = format!("cmd.{command_name}");
                        (
                            command_name.clone(),
                            values.get(key.as_str()).cloned().unwrap_or_else(|| "missing".to_owned())
                        )
                    }).collect::<BTreeMap<_, _>>(),
                    "status": if problems.is_empty() { "pass" } else { "fail" },
                    "problems": problems,
                }));
            }
            Err(err) => {
                failures += 1;
                results.push(json!({
                    "label": target.label,
                    "ssh_target": target.ssh_target,
                    "ssh_user": effective_user,
                    "status": "fail",
                    "error": err,
                }));
            }
        }
    }

    let payload = serde_json::to_string_pretty(&json!({
        "summary": {
            "targets": targets.len(),
            "passed": targets.len().saturating_sub(failures),
            "failed": failures,
        },
        "results": results,
    }))
    .map_err(|err| format!("serialize preflight report failed: {err}"))?;
    if failures == 0 {
        Ok(payload)
    } else {
        Err(payload)
    }
}

/// Pre-orchestrate readiness check.
///
/// For each selected alias:
///   1. Resolve the SSH target IP from the inventory.
///   2. Probe TCP/<`ssh_port`> with a short timeout to confirm the VM
///      is up + SSH server is listening.
///   3. If TCP open, run a minimal identity probe over SSH (`whoami`
///      on POSIX, `whoami` via `PowerShell` on Windows) to confirm
///      authentication + the right user identity.
///   4. Record alias / `ssh_target` / platform / `port_open` / `auth_ok`
///      / `observed_user` / blocker.
///
/// Continues across aliases so the operator sees the full set of
/// blockers in one report. Returns the report JSON on success
/// (every alias ready) or wraps the same JSON in `Err` when any
/// alias has a blocker — matching the preflight subcommand's
/// pass/fail convention.
pub fn execute_ops_vm_lab_readiness_check(
    config: VmLabReadinessCheckConfig,
) -> Result<String, String> {
    ensure_optional_local_regular_file_path(
        config.ssh_identity_file.as_deref(),
        "SSH identity file",
    )?;
    ensure_optional_local_regular_file_path(
        config.known_hosts_path.as_deref(),
        "SSH known_hosts file",
    )?;
    let targets = resolve_remote_targets(
        config.inventory_path.as_path(),
        config.vm_aliases.as_slice(),
        config.select_all,
        config.raw_targets.as_slice(),
    )?;
    if targets.is_empty() {
        return Err(
            "no targets selected for readiness check; pass --vms <alias[,alias...]> or --all"
                .to_owned(),
        );
    }
    let connect_timeout = Duration::from_secs(if config.connect_timeout_secs == 0 {
        5
    } else {
        config.connect_timeout_secs
    });

    let mut results: Vec<serde_json::Value> = Vec::new();
    let mut failures = 0usize;

    for target in &targets {
        let platform = target.platform_profile.platform.as_str().to_owned();
        let ssh_user_for_probe =
            target
                .ssh_user
                .clone()
                .unwrap_or_else(|| match target.platform_profile.platform {
                    VmGuestPlatform::Windows => "Administrator".to_owned(),
                    _ => "user".to_owned(),
                });
        let mut entry = serde_json::Map::new();
        entry.insert(
            "alias".to_owned(),
            serde_json::Value::String(target.label.clone()),
        );
        entry.insert(
            "ssh_target".to_owned(),
            serde_json::Value::String(target.ssh_target.clone()),
        );
        entry.insert(
            "platform".to_owned(),
            serde_json::Value::String(platform.clone()),
        );
        entry.insert(
            "ssh_user".to_owned(),
            serde_json::Value::String(ssh_user_for_probe.clone()),
        );

        // Step 1: TCP/<port> probe.
        let port_status = match probe_tcp_port_status(
            target.ssh_target.as_str(),
            config.ssh_port,
            connect_timeout,
        ) {
            Ok((status, reason)) => (status, reason),
            Err(err) => ("invalid".to_owned(), Some(err)),
        };
        let port_open = port_status.0 == "open";
        entry.insert(
            "tcp_port_open".to_owned(),
            serde_json::Value::Bool(port_open),
        );
        if let Some(reason) = port_status.1 {
            entry.insert(
                "tcp_probe_reason".to_owned(),
                serde_json::Value::String(reason),
            );
        }
        if !port_open {
            failures += 1;
            entry.insert("ready".to_owned(), serde_json::Value::Bool(false));
            entry.insert(
                "blocker".to_owned(),
                serde_json::Value::String(format!(
                    "TCP/{} not reachable on {} (VM offline, sshd not running, or firewall)",
                    config.ssh_port, target.ssh_target
                )),
            );
            results.push(serde_json::Value::Object(entry));
            continue;
        }

        // Step 2: SSH identity probe (`whoami`).
        let identity_script = match target.platform_profile.remote_shell {
            VmRemoteShell::Posix => "whoami".to_owned(),
            VmRemoteShell::Powershell => match build_ssh_powershell_encoded_invocation("whoami") {
                Ok(script) => script,
                Err(err) => {
                    failures += 1;
                    entry.insert("ready".to_owned(), serde_json::Value::Bool(false));
                    entry.insert(
                        "blocker".to_owned(),
                        serde_json::Value::String(format!(
                            "build PS-encoded whoami invocation failed: {err}"
                        )),
                    );
                    results.push(serde_json::Value::Object(entry));
                    continue;
                }
            },
            VmRemoteShell::Unsupported => {
                failures += 1;
                entry.insert("ready".to_owned(), serde_json::Value::Bool(false));
                entry.insert(
                    "blocker".to_owned(),
                    serde_json::Value::String(format!(
                        "remote shell unsupported for platform {platform}"
                    )),
                );
                results.push(serde_json::Value::Object(entry));
                continue;
            }
        };
        match capture_remote_shell_command_for_target(
            target,
            None,
            config.ssh_identity_file.as_deref(),
            config.known_hosts_path.as_deref(),
            identity_script.as_str(),
            connect_timeout,
        ) {
            Ok(observed) => {
                let observed_trimmed = observed.trim().to_owned();
                entry.insert("auth_ok".to_owned(), serde_json::Value::Bool(true));
                entry.insert(
                    "observed_user".to_owned(),
                    serde_json::Value::String(observed_trimmed.clone()),
                );
                entry.insert("ready".to_owned(), serde_json::Value::Bool(true));
            }
            Err(err) => {
                failures += 1;
                entry.insert("auth_ok".to_owned(), serde_json::Value::Bool(false));
                entry.insert("ready".to_owned(), serde_json::Value::Bool(false));
                entry.insert(
                    "blocker".to_owned(),
                    serde_json::Value::String(format!("SSH identity probe failed: {err}")),
                );
            }
        }
        results.push(serde_json::Value::Object(entry));
    }

    let payload = serde_json::to_string_pretty(&serde_json::json!({
        "schema_version": 1,
        "summary": {
            "targets": targets.len(),
            "ready": targets.len().saturating_sub(failures),
            "blocked": failures,
        },
        "results": results,
    }))
    .map_err(|err| format!("serialize readiness report failed: {err}"))?;

    if let Some(report_dir) = config.report_dir.as_deref() {
        std::fs::create_dir_all(report_dir).map_err(|err| {
            format!(
                "create readiness-check report dir failed ({}): {err}",
                report_dir.display()
            )
        })?;
        let report_path = report_dir.join("vm_lab_readiness_check.json");
        std::fs::write(report_path.as_path(), payload.as_str()).map_err(|err| {
            format!(
                "write readiness-check report to {} failed: {err}",
                report_path.display()
            )
        })?;
    }

    if failures == 0 {
        Ok(payload)
    } else {
        Err(payload)
    }
}

pub fn execute_ops_vm_lab_status(config: VmLabStatusConfig) -> Result<String, String> {
    let targets = resolve_remote_targets(
        config.inventory_path.as_path(),
        config.vm_aliases.as_slice(),
        config.select_all,
        config.raw_targets.as_slice(),
    )?;
    let timeout = timeout_or_default(config.timeout_secs, DEFAULT_PREFLIGHT_TIMEOUT_SECS);
    ensure_optional_local_regular_file_path(
        config.ssh_identity_file.as_deref(),
        "SSH identity file",
    )?;
    ensure_optional_local_regular_file_path(
        config.known_hosts_path.as_deref(),
        "SSH known_hosts file",
    )?;
    execute_vm_lab_status_for_targets(
        targets.as_slice(),
        config.ssh_user.as_deref(),
        config.ssh_identity_file.as_deref(),
        config.known_hosts_path.as_deref(),
        timeout,
    )
}

fn execute_vm_lab_status_for_targets(
    targets: &[RemoteTarget],
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    timeout: Duration,
) -> Result<String, String> {
    let mut results = Vec::new();
    let mut failures = 0usize;
    let rustynet_status_script = privileged_rustynet_cli_script("status");
    let rustynet_netcheck_script = privileged_rustynet_cli_script("netcheck");
    let sections = [
        ("hostname", "hostname"),
        (
            "service_active",
            "if command -v systemctl >/dev/null 2>&1; then systemctl is-active rustynetd.service; else echo systemctl-unavailable; fi",
        ),
        ("rustynet_status", rustynet_status_script.as_str()),
        ("rustynet_netcheck", rustynet_netcheck_script.as_str()),
        (
            "latest_handshakes",
            "if command -v wg >/dev/null 2>&1; then if sudo -n true >/dev/null 2>&1; then sudo -n wg show all latest-handshakes 2>&1; else wg show all latest-handshakes 2>&1; fi; else echo wg-not-installed; fi",
        ),
        (
            "ip_addr",
            "if command -v ip >/dev/null 2>&1; then ip -brief addr; else echo ip-unavailable; fi",
        ),
    ];
    let capture_script = build_section_capture_script(sections.as_slice());

    for target in targets {
        let effective_user = ssh_user_override.or(target.ssh_user.as_deref());
        match capture_remote_shell_command_for_target(
            target,
            ssh_user_override,
            ssh_identity_file,
            known_hosts_path,
            capture_script.as_str(),
            timeout,
        ) {
            Ok(output) => {
                results.push(json!({
                    "label": target.label,
                    "ssh_target": target.ssh_target,
                    "ssh_user": effective_user,
                    "sections": parse_section_capture(output.as_str()),
                }));
            }
            Err(err) => {
                failures += 1;
                results.push(json!({
                    "label": target.label,
                    "ssh_target": target.ssh_target,
                    "ssh_user": effective_user,
                    "error": err,
                }));
            }
        }
    }

    let payload = serde_json::to_string_pretty(&json!({
        "summary": {
            "targets": targets.len(),
            "failed": failures,
        },
        "results": results,
    }))
    .map_err(|err| format!("serialize vm-lab status failed: {err}"))?;
    if failures == 0 {
        Ok(payload)
    } else {
        Err(payload)
    }
}

pub fn execute_ops_vm_lab_stop(config: VmLabStopConfig) -> Result<String, String> {
    let targets = resolve_start_targets(
        config.inventory_path.as_path(),
        config.vm_aliases.as_slice(),
        config.select_all,
    )?;
    let utmctl_path = config.utmctl_path;
    if !utmctl_path.is_file() {
        return Err(format!(
            "utmctl binary is not present: {}",
            utmctl_path.display()
        ));
    }
    let timeout = timeout_or_default(config.timeout_secs, DEFAULT_START_TIMEOUT_SECS);
    let mut results = Vec::new();
    for target in &targets {
        transition_local_utm_vm(
            utmctl_path.as_path(),
            target.utm_name.as_str(),
            target.bundle_path.as_path(),
            "stop",
            false,
            timeout,
        )
        .map_err(|err| format!("{} stop failed: {err}", target.alias))?;
        results.push(format!(
            "{} stopped via utm_name={} bundle_path={}",
            target.alias,
            target.utm_name,
            target.bundle_path.display()
        ));
    }
    Ok(results.join("\n"))
}

pub fn execute_ops_vm_lab_restart(config: VmLabRestartConfig) -> Result<String, String> {
    let fallback_report_dir = config
        .report_dir
        .clone()
        .or_else(|| config.inventory_path.parent().map(Path::to_path_buf))
        .unwrap_or_else(|| PathBuf::from("."));
    let report_dir = config.report_dir.as_deref();
    if let Some(service) = config.service.as_deref() {
        ensure_no_control_chars("service", service)?;
        if config.wait_ready {
            return Err(
                "--wait-ready is only supported for local UTM VM restarts, not --service restarts"
                    .to_owned(),
            );
        }
        let result = execute_ops_vm_lab_run(
            VmLabExecConfig {
                inventory_path: config.inventory_path,
                vm_aliases: config.vm_aliases,
                raw_targets: config.raw_targets,
                select_all: config.select_all,
                workdir: "/".to_owned(),
                program: "systemctl".to_owned(),
                argv: vec!["restart".to_owned(), service.to_owned()],
                ssh_user: config.ssh_user,
                ssh_identity_file: config.ssh_identity_file,
                known_hosts_path: config.known_hosts_path,
                sudo: true,
                timeout_secs: config.timeout_secs,
            },
            "restarted",
        );
        let text = match &result {
            Ok(output) => output.clone(),
            Err(err) => err.clone(),
        };
        let raw_artifact =
            maybe_write_report_artifact(report_dir, "vm_lab_restart_service.txt", text.as_str())?;
        let (rendered, overall_status) = build_vm_lab_command_result_output(
            "vm-lab-restart",
            report_dir,
            fallback_report_dir.as_path(),
            "vm_lab_restart_result.json",
            vec![stage_outcome(
                "restart_service",
                if result.is_ok() {
                    VmLabStageStatus::Pass
                } else {
                    VmLabStageStatus::Fail
                },
                if result.is_ok() {
                    format!("restarted service {service}")
                } else {
                    format!("restart service {service} failed")
                },
                raw_artifact.into_iter().collect(),
            )],
            Vec::new(),
            if result.is_ok() {
                Vec::new()
            } else {
                vec![format!(
                    "Inspect {} for the service restart failure",
                    report_dir
                        .map_or_else(
                            || fallback_report_dir.join("vm_lab_restart_service.txt"),
                            |path| path.join("vm_lab_restart_service.txt")
                        )
                        .display()
                )]
            },
        )?;
        if config.json_output {
            return match overall_status {
                VmLabCommandOverallStatus::Fail => Err(rendered),
                VmLabCommandOverallStatus::Pass | VmLabCommandOverallStatus::Partial => {
                    Ok(rendered)
                }
            };
        }
        return result;
    }

    ensure_optional_local_regular_file_path(
        config.ssh_identity_file.as_deref(),
        "SSH identity file",
    )?;
    ensure_optional_local_regular_file_path(
        config.known_hosts_path.as_deref(),
        "SSH known_hosts file",
    )?;
    let inventory_path = config.inventory_path.clone();
    let utmctl_path = config.utmctl_path.clone();
    let ready_targets = if config.wait_ready {
        Some(resolve_start_targets(
            inventory_path.as_path(),
            config.vm_aliases.as_slice(),
            config.select_all,
        )?)
    } else {
        None
    };
    let stop_result = execute_ops_vm_lab_stop(VmLabStopConfig {
        inventory_path: inventory_path.clone(),
        vm_aliases: config.vm_aliases.clone(),
        select_all: config.select_all,
        utmctl_path: utmctl_path.clone(),
        timeout_secs: config.timeout_secs,
    });
    let stop_text = match &stop_result {
        Ok(output) => output.clone(),
        Err(err) => err.clone(),
    };
    let stop_artifact =
        maybe_write_report_artifact(report_dir, "vm_lab_restart_stop.txt", stop_text.as_str())?;
    let stop_result = match stop_result {
        Ok(output) => output,
        Err(err) => {
            let (rendered, overall_status) = build_vm_lab_command_result_output(
                "vm-lab-restart",
                report_dir,
                fallback_report_dir.as_path(),
                "vm_lab_restart_result.json",
                vec![stage_outcome(
                    "stop_local_utm_vms",
                    VmLabStageStatus::Fail,
                    "failed to stop selected local UTM VMs",
                    stop_artifact.into_iter().collect(),
                )],
                Vec::new(),
                vec!["Inspect the stop artifact and UTM controller state".to_owned()],
            )?;
            return if config.json_output {
                match overall_status {
                    VmLabCommandOverallStatus::Fail => Err(rendered),
                    VmLabCommandOverallStatus::Pass | VmLabCommandOverallStatus::Partial => {
                        Ok(rendered)
                    }
                }
            } else {
                Err(err)
            };
        }
    };
    let start_result = execute_ops_vm_lab_start(VmLabStartConfig {
        inventory_path,
        vm_aliases: config.vm_aliases,
        select_all: config.select_all,
        utmctl_path: utmctl_path.clone(),
        timeout_secs: config.timeout_secs,
    });
    let start_text = match &start_result {
        Ok(output) => output.clone(),
        Err(err) => err.clone(),
    };
    let start_artifact =
        maybe_write_report_artifact(report_dir, "vm_lab_restart_start.txt", start_text.as_str())?;
    let start_result = match start_result {
        Ok(output) => output,
        Err(err) => {
            let (rendered, overall_status) = build_vm_lab_command_result_output(
                "vm-lab-restart",
                report_dir,
                fallback_report_dir.as_path(),
                "vm_lab_restart_result.json",
                vec![
                    stage_outcome(
                        "stop_local_utm_vms",
                        VmLabStageStatus::Pass,
                        "stopped selected local UTM VMs",
                        stop_artifact.into_iter().collect(),
                    ),
                    stage_outcome(
                        "start_local_utm_vms",
                        VmLabStageStatus::Fail,
                        "failed to start selected local UTM VMs",
                        start_artifact.into_iter().collect(),
                    ),
                ],
                Vec::new(),
                vec!["Inspect the start artifact and UTM controller state".to_owned()],
            )?;
            return if config.json_output {
                match overall_status {
                    VmLabCommandOverallStatus::Fail => Err(rendered),
                    VmLabCommandOverallStatus::Pass | VmLabCommandOverallStatus::Partial => {
                        Ok(rendered)
                    }
                }
            } else {
                Err(err)
            };
        }
    };
    if !config.wait_ready {
        let text = format!("{stop_result}\n{start_result}");
        let combined_artifact =
            maybe_write_report_artifact(report_dir, "vm_lab_restart.txt", text.as_str())?;
        let (rendered, overall_status) = build_vm_lab_command_result_output(
            "vm-lab-restart",
            report_dir,
            fallback_report_dir.as_path(),
            "vm_lab_restart_result.json",
            vec![
                stage_outcome(
                    "stop_local_utm_vms",
                    VmLabStageStatus::Pass,
                    "stopped selected local UTM VMs",
                    stop_artifact.into_iter().collect(),
                ),
                stage_outcome(
                    "start_local_utm_vms",
                    VmLabStageStatus::Pass,
                    "started selected local UTM VMs",
                    start_artifact
                        .into_iter()
                        .chain(combined_artifact.into_iter())
                        .collect(),
                ),
            ],
            Vec::new(),
            vec!["Run vm-lab-discover-local-utm-summary to verify readiness".to_owned()],
        )?;
        return if config.json_output {
            match overall_status {
                VmLabCommandOverallStatus::Fail => Err(rendered),
                VmLabCommandOverallStatus::Pass | VmLabCommandOverallStatus::Partial => {
                    Ok(rendered)
                }
            }
        } else {
            Ok(text)
        };
    }

    let ready_states = wait_for_local_utm_targets_ready(
        ready_targets
            .as_deref()
            .expect("wait-ready path precomputes restart targets"),
        utmctl_path.as_path(),
        config.ssh_port,
        config.ssh_identity_file.as_deref(),
        config.known_hosts_path.as_deref(),
        timeout_or_default(
            config.ready_timeout_secs,
            DEFAULT_RESTART_READY_TIMEOUT_SECS,
        ),
    );
    let ready_states = match ready_states {
        Ok(states) => states,
        Err(err) => {
            let raw_artifact = maybe_write_report_artifact(
                report_dir,
                "vm_lab_restart_wait_ready.txt",
                err.as_str(),
            )?;
            let (rendered, overall_status) = build_vm_lab_command_result_output(
                "vm-lab-restart",
                report_dir,
                fallback_report_dir.as_path(),
                "vm_lab_restart_result.json",
                vec![
                    stage_outcome(
                        "stop_local_utm_vms",
                        VmLabStageStatus::Pass,
                        "stopped selected local UTM VMs",
                        stop_artifact.into_iter().collect(),
                    ),
                    stage_outcome(
                        "start_local_utm_vms",
                        VmLabStageStatus::Pass,
                        "started selected local UTM VMs",
                        start_artifact.into_iter().collect(),
                    ),
                    stage_outcome(
                        "wait_ready",
                        VmLabStageStatus::Fail,
                        "timed out waiting for selected local UTM VMs to become execution-ready",
                        raw_artifact.into_iter().collect(),
                    ),
                ],
                Vec::new(),
                vec!["Inspect the wait-ready artifact for the last observed VM states".to_owned()],
            )?;
            return if config.json_output {
                match overall_status {
                    VmLabCommandOverallStatus::Fail => Err(rendered),
                    VmLabCommandOverallStatus::Pass | VmLabCommandOverallStatus::Partial => {
                        Ok(rendered)
                    }
                }
            } else {
                Err(err)
            };
        }
    };
    let ready_report = render_local_utm_ready_states(ready_states.as_slice());
    let ready_text_artifact = maybe_write_report_artifact(
        report_dir,
        "vm_lab_restart_ready_states.txt",
        ready_report.as_str(),
    )?;
    let ready_states_json = serde_json::to_string_pretty(&ready_states)
        .map_err(|err| format!("serialize local UTM ready states failed: {err}"))?;
    let ready_json_artifact = maybe_write_report_artifact(
        report_dir,
        "vm_lab_restart_ready_states.json",
        ready_states_json.as_str(),
    )?;
    let inventory_report = persist_local_utm_ready_states_to_inventory(
        config.inventory_path.as_path(),
        ready_states.as_slice(),
    );
    let inventory_report = match inventory_report {
        Ok(report) => report,
        Err(err) => {
            let raw_artifact = maybe_write_report_artifact(
                report_dir,
                "vm_lab_restart_inventory_update.txt",
                err.as_str(),
            )?;
            let (rendered, overall_status) = build_vm_lab_command_result_output(
                "vm-lab-restart",
                report_dir,
                fallback_report_dir.as_path(),
                "vm_lab_restart_result.json",
                vec![
                    stage_outcome(
                        "stop_local_utm_vms",
                        VmLabStageStatus::Pass,
                        "stopped selected local UTM VMs",
                        stop_artifact.into_iter().collect(),
                    ),
                    stage_outcome(
                        "start_local_utm_vms",
                        VmLabStageStatus::Pass,
                        "started selected local UTM VMs",
                        start_artifact.into_iter().collect(),
                    ),
                    stage_outcome(
                        "wait_ready",
                        VmLabStageStatus::Pass,
                        "selected local UTM VMs became execution-ready",
                        ready_text_artifact
                            .clone()
                            .into_iter()
                            .chain(ready_json_artifact.clone().into_iter())
                            .collect(),
                    ),
                    stage_outcome(
                        "update_inventory_live_ips",
                        VmLabStageStatus::Fail,
                        "failed to persist discovered live IPs into inventory",
                        raw_artifact.into_iter().collect(),
                    ),
                ],
                Vec::new(),
                vec!["Inspect the inventory update artifact and inventory JSON".to_owned()],
            )?;
            return if config.json_output {
                match overall_status {
                    VmLabCommandOverallStatus::Fail => Err(rendered),
                    VmLabCommandOverallStatus::Pass | VmLabCommandOverallStatus::Partial => {
                        Ok(rendered)
                    }
                }
            } else {
                Err(err)
            };
        }
    };
    let inventory_artifact = maybe_write_report_artifact(
        report_dir,
        "vm_lab_restart_inventory_update.txt",
        inventory_report.as_str(),
    )?;
    let text = format!("{stop_result}\n{start_result}\n{ready_report}\n{inventory_report}");
    let combined_artifact =
        maybe_write_report_artifact(report_dir, "vm_lab_restart.txt", text.as_str())?;
    let (rendered, overall_status) = build_vm_lab_command_result_output(
        "vm-lab-restart",
        report_dir,
        fallback_report_dir.as_path(),
        "vm_lab_restart_result.json",
        vec![
            stage_outcome(
                "stop_local_utm_vms",
                VmLabStageStatus::Pass,
                "stopped selected local UTM VMs",
                stop_artifact.into_iter().collect(),
            ),
            stage_outcome(
                "start_local_utm_vms",
                VmLabStageStatus::Pass,
                "started selected local UTM VMs",
                start_artifact.into_iter().collect(),
            ),
            stage_outcome(
                "wait_ready",
                VmLabStageStatus::Pass,
                "selected local UTM VMs became execution-ready",
                ready_text_artifact
                    .into_iter()
                    .chain(ready_json_artifact.into_iter())
                    .collect(),
            ),
            stage_outcome(
                "update_inventory_live_ips",
                VmLabStageStatus::Pass,
                inventory_report.clone(),
                inventory_artifact
                    .into_iter()
                    .chain(combined_artifact.into_iter())
                    .collect(),
            ),
        ],
        Vec::new(),
        Vec::new(),
    )?;
    if config.json_output {
        return match overall_status {
            VmLabCommandOverallStatus::Fail => Err(rendered),
            VmLabCommandOverallStatus::Pass | VmLabCommandOverallStatus::Partial => Ok(rendered),
        };
    }
    Ok(text)
}

pub fn execute_ops_vm_lab_collect_artifacts(
    config: VmLabCollectArtifactsConfig,
) -> Result<String, String> {
    let targets = resolve_remote_targets(
        config.inventory_path.as_path(),
        config.vm_aliases.as_slice(),
        config.select_all,
        config.raw_targets.as_slice(),
    )?;
    let timeout = timeout_or_default(config.timeout_secs, DEFAULT_COLLECT_TIMEOUT_SECS);
    ensure_optional_local_regular_file_path(
        config.ssh_identity_file.as_deref(),
        "SSH identity file",
    )?;
    ensure_optional_local_regular_file_path(
        config.known_hosts_path.as_deref(),
        "SSH known_hosts file",
    )?;
    let output_root = config.output_dir;
    fs::create_dir_all(output_root.as_path()).map_err(|err| {
        format!(
            "create artifact output dir failed ({}): {err}",
            output_root.display()
        )
    })?;
    execute_vm_lab_collect_artifacts_for_targets(
        targets.as_slice(),
        config.ssh_user.as_deref(),
        config.ssh_identity_file.as_deref(),
        config.known_hosts_path.as_deref(),
        output_root.as_path(),
        timeout,
    )
}

fn execute_vm_lab_collect_artifacts_for_targets(
    targets: &[RemoteTarget],
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    output_root: &Path,
    timeout: Duration,
) -> Result<String, String> {
    let rustynet_status_script = privileged_rustynet_cli_script("status");
    let rustynet_netcheck_script = privileged_rustynet_cli_script("netcheck");
    let sections = [
        ("hostname", "hostname"),
        ("rustynet_status", rustynet_status_script.as_str()),
        ("rustynet_netcheck", rustynet_netcheck_script.as_str()),
        (
            "service_status",
            "if command -v systemctl >/dev/null 2>&1; then systemctl status rustynetd.service --no-pager -n 80 2>&1; else echo systemctl-unavailable; fi",
        ),
        (
            "journalctl_rustynetd",
            "if command -v journalctl >/dev/null 2>&1; then if sudo -n true >/dev/null 2>&1; then sudo -n journalctl -u rustynetd.service --no-pager -n 200 2>&1; else journalctl -u rustynetd.service --no-pager -n 200 2>&1; fi; else echo journalctl-unavailable; fi",
        ),
        (
            "latest_handshakes",
            "if command -v wg >/dev/null 2>&1; then if sudo -n true >/dev/null 2>&1; then sudo -n wg show all latest-handshakes 2>&1; else wg show all latest-handshakes 2>&1; fi; else echo wg-not-installed; fi",
        ),
        (
            "ip_addr",
            "if command -v ip >/dev/null 2>&1; then ip -brief addr; else echo ip-unavailable; fi",
        ),
        (
            "ip_route",
            "if command -v ip >/dev/null 2>&1; then ip route; else echo ip-unavailable; fi",
        ),
        (
            "assignment_bundle",
            "if [ -f /var/lib/rustynet/rustynetd.assignment ]; then if sudo -n true >/dev/null 2>&1; then sudo -n cat /var/lib/rustynet/rustynetd.assignment 2>&1; else cat /var/lib/rustynet/rustynetd.assignment 2>&1; fi; else echo assignment-bundle-missing; fi",
        ),
        (
            "traversal_bundle",
            "if [ -f /var/lib/rustynet/rustynetd.traversal ]; then if sudo -n true >/dev/null 2>&1; then sudo -n cat /var/lib/rustynet/rustynetd.traversal 2>&1; else cat /var/lib/rustynet/rustynetd.traversal 2>&1; fi; else echo traversal-bundle-missing; fi",
        ),
    ];
    let capture_script = build_section_capture_script(sections.as_slice());
    let mut lines = Vec::new();
    let mut failures = Vec::new();

    for target in targets {
        let effective_user = ssh_user_override.or(target.ssh_user.as_deref());
        let target_dir = output_root.join(sanitize_label_for_path(target.label.as_str()));
        fs::create_dir_all(target_dir.as_path()).map_err(|err| {
            format!(
                "create target artifact dir failed ({}): {err}",
                target_dir.display()
            )
        })?;
        match capture_remote_shell_command_for_target(
            target,
            ssh_user_override,
            ssh_identity_file,
            known_hosts_path,
            capture_script.as_str(),
            timeout,
        ) {
            Ok(output) => {
                let sections = parse_section_capture(output.as_str());
                for (name, body) in &sections {
                    fs::write(target_dir.join(format!("{name}.txt")), body.as_bytes()).map_err(
                        |err| format!("write artifact failed ({} {}): {err}", target.label, name),
                    )?;
                }
                let metadata = json!({
                    "label": target.label,
                    "ssh_target": target.ssh_target,
                    "ssh_user": effective_user,
                    "artifacts": sections.keys().cloned().collect::<Vec<_>>(),
                });
                fs::write(
                    target_dir.join("metadata.json"),
                    serde_json::to_vec_pretty(&metadata)
                        .map_err(|err| format!("serialize metadata failed: {err}"))?,
                )
                .map_err(|err| format!("write metadata failed ({}): {err}", target.label))?;
                lines.push(format!(
                    "{} collected artifacts into {}",
                    target.label,
                    target_dir.display()
                ));
            }
            Err(err) => {
                failures.push(format!("{} ({err})", target.label));
            }
        }
    }

    if failures.is_empty() {
        Ok(lines.join("\n"))
    } else {
        Err(format!(
            "{}\nartifact collection failed for: {}",
            lines.join("\n"),
            failures.join(", ")
        ))
    }
}

pub fn execute_ops_vm_lab_write_topology(
    config: VmLabWriteTopologyConfig,
) -> Result<String, String> {
    let inventory = load_inventory(config.inventory_path.as_path())?;
    let selected =
        select_inventory_entries(&inventory, config.vm_aliases.as_slice(), config.select_all)?;
    if config.require_same_network {
        ensure_inventory_entries_share_network(selected.as_slice())?;
    }
    let topology = build_vm_lab_topology(selected.as_slice(), config.suite.as_str())?;
    let parent = config
        .output_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .ok_or_else(|| {
            format!(
                "topology output path must have a parent directory: {}",
                config.output_path.display()
            )
        })?;
    fs::create_dir_all(parent).map_err(|err| {
        format!(
            "create topology output dir failed ({}): {err}",
            parent.display()
        )
    })?;
    fs::write(
        &config.output_path,
        serde_json::to_vec_pretty(&topology)
            .map_err(|err| format!("serialize topology failed: {err}"))?,
    )
    .map_err(|err| {
        format!(
            "write topology failed ({}): {err}",
            config.output_path.display()
        )
    })?;

    Ok(format!(
        "wrote vm-lab topology={} suite={}",
        config.output_path.display(),
        normalized_suite_name(config.suite.as_str())?
    ))
}

pub fn execute_ops_vm_lab_issue_and_distribute_state(
    config: VmLabIssueDistributeStateConfig,
) -> Result<String, String> {
    let topology = load_vm_lab_topology(config.topology_path.as_path())?;
    let inventory = load_inventory(config.inventory_path.as_path())?;
    let timeout = timeout_or_default(config.timeout_secs, DEFAULT_RUN_TIMEOUT_SECS);
    ensure_optional_local_regular_file_path(
        config.ssh_identity_file.as_deref(),
        "SSH identity file",
    )?;
    ensure_optional_local_regular_file_path(
        config.known_hosts_path.as_deref(),
        "SSH known_hosts file",
    )?;
    let authority_entry = inventory
        .iter()
        .find(|entry| entry.alias == config.authority_vm)
        .cloned()
        .ok_or_else(|| {
            format!(
                "authority VM alias not found in inventory: {}",
                config.authority_vm
            )
        })?;
    let authority_target =
        remote_target_from_inventory_entry(&authority_entry, config.ssh_user.as_deref());

    let artifact_dir =
        std::env::temp_dir().join(format!("rustynet-vm-lab-state-{}", unique_suffix()));
    fs::create_dir_all(artifact_dir.as_path()).map_err(|err| {
        format!(
            "create vm-lab temporary state dir failed ({}): {err}",
            artifact_dir.display()
        )
    })?;

    let nodes_spec = build_nodes_spec(
        topology.nodes.values().collect::<Vec<_>>().as_slice(),
        inventory.as_slice(),
        timeout,
        config.ssh_user.as_deref(),
        config.ssh_identity_file.as_deref(),
        config.known_hosts_path.as_deref(),
    )?;
    let allow_spec = build_allow_spec(topology.nodes.values().collect::<Vec<_>>().as_slice());
    let assignments_spec = build_assignments_spec(&topology)?;
    let traversal_ttl_secs = 120u64;

    let assignment_env_path = artifact_dir.join("assignment.env");
    let traversal_env_path = artifact_dir.join("traversal.env");
    fs::write(
        assignment_env_path.as_path(),
        build_assignment_issue_env(
            nodes_spec.as_str(),
            allow_spec.as_str(),
            assignments_spec.as_str(),
        )?,
    )
    .map_err(|err| format!("write assignment env failed: {err}"))?;
    fs::write(
        traversal_env_path.as_path(),
        build_traversal_issue_env(nodes_spec.as_str(), allow_spec.as_str(), traversal_ttl_secs)?,
    )
    .map_err(|err| format!("write traversal env failed: {err}"))?;

    let remote_assignment_env = format!("/tmp/rn-vm-lab-assignment-{}.env", unique_suffix());
    let remote_traversal_env = format!("/tmp/rn-vm-lab-traversal-{}.env", unique_suffix());
    ensure_success_status(
        scp_to_remote_for_target(
            &authority_target,
            config.ssh_user.as_deref(),
            config.ssh_identity_file.as_deref(),
            config.known_hosts_path.as_deref(),
            assignment_env_path.as_path(),
            remote_assignment_env.as_str(),
            timeout,
        )
        .map_err(|err| format!("copy assignment env to authority failed: {err}"))?,
        "copy assignment env to authority",
    )?;
    ensure_success_status(
        scp_to_remote_for_target(
            &authority_target,
            config.ssh_user.as_deref(),
            config.ssh_identity_file.as_deref(),
            config.known_hosts_path.as_deref(),
            traversal_env_path.as_path(),
            remote_traversal_env.as_str(),
            timeout,
        )
        .map_err(|err| format!("copy traversal env to authority failed: {err}"))?,
        "copy traversal env to authority",
    )?;

    let authority_issue_script = format!(
        "set -eu; \
if sudo -n true >/dev/null 2>&1; then SUDO='sudo -n'; else SUDO=''; fi; \
$SUDO mkdir -p /run/rustynet/assignment-issue /run/rustynet/traversal-issue; \
$SUDO rustynet ops e2e-issue-assignment-bundles-from-env --env-file {assignment_env}; \
$SUDO rustynet ops e2e-issue-traversal-bundles-from-env --env-file {traversal_env}; \
$SUDO rm -f {assignment_env} {traversal_env}",
        assignment_env = shell_quote(remote_assignment_env.as_str()),
        traversal_env = shell_quote(remote_traversal_env.as_str()),
    );
    let issue_status = run_remote_shell_command_for_target(
        &authority_target,
        config.ssh_user.as_deref(),
        config.ssh_identity_file.as_deref(),
        config.known_hosts_path.as_deref(),
        authority_issue_script.as_str(),
        timeout,
    )
    .map_err(|err| format!("issue state on authority failed: {err}"))?;
    if !issue_status.success() {
        return Err(format!(
            "issue state on authority failed with status {}",
            status_code(issue_status)
        ));
    }

    let assignment_pub_local = artifact_dir.join("rn-assignment.pub");
    let traversal_pub_local = artifact_dir.join("rn-traversal.pub");
    capture_remote_file_to_local(
        &authority_target,
        config.ssh_user.as_deref(),
        config.ssh_identity_file.as_deref(),
        config.known_hosts_path.as_deref(),
        "/run/rustynet/assignment-issue/rn-assignment.pub",
        assignment_pub_local.as_path(),
        timeout,
    )?;
    capture_remote_file_to_local(
        &authority_target,
        config.ssh_user.as_deref(),
        config.ssh_identity_file.as_deref(),
        config.known_hosts_path.as_deref(),
        "/run/rustynet/traversal-issue/rn-traversal.pub",
        traversal_pub_local.as_path(),
        timeout,
    )?;

    let mut lines = vec![format!(
        "issued signed assignment/traversal state via authority={} artifacts={}",
        authority_target.label,
        artifact_dir.display()
    )];

    for node in topology.nodes.values() {
        let inventory_entry = inventory
            .iter()
            .find(|entry| entry.alias == node.alias)
            .cloned()
            .ok_or_else(|| format!("topology node missing from inventory: {}", node.alias))?;
        let target =
            remote_target_from_inventory_entry(&inventory_entry, config.ssh_user.as_deref());
        let assignment_local =
            artifact_dir.join(format!("rn-assignment-{}.assignment", node.node_id));
        let traversal_local = artifact_dir.join(format!("rn-traversal-{}.traversal", node.node_id));
        capture_remote_file_to_local(
            &authority_target,
            config.ssh_user.as_deref(),
            config.ssh_identity_file.as_deref(),
            config.known_hosts_path.as_deref(),
            format!(
                "/run/rustynet/assignment-issue/rn-assignment-{}.assignment",
                node.node_id
            )
            .as_str(),
            assignment_local.as_path(),
            timeout,
        )?;
        capture_remote_file_to_local(
            &authority_target,
            config.ssh_user.as_deref(),
            config.ssh_identity_file.as_deref(),
            config.known_hosts_path.as_deref(),
            format!(
                "/run/rustynet/traversal-issue/rn-traversal-{}.traversal",
                node.node_id
            )
            .as_str(),
            traversal_local.as_path(),
            timeout,
        )?;

        let refresh_env_path = artifact_dir.join(format!("assignment-refresh-{}.env", node.alias));
        fs::write(
            refresh_env_path.as_path(),
            build_assignment_refresh_env(
                node.node_id.as_str(),
                nodes_spec.as_str(),
                allow_spec.as_str(),
                assignment_exit_node_id(&topology, node.alias.as_str())?,
            )?,
        )
        .map_err(|err| {
            format!(
                "write assignment refresh env failed ({}): {err}",
                node.alias
            )
        })?;

        install_state_artifacts_on_target(
            &target,
            &StateArtifactInstallPaths {
                assignment_pub: assignment_pub_local.as_path(),
                assignment_bundle: assignment_local.as_path(),
                traversal_pub: traversal_pub_local.as_path(),
                traversal_bundle: traversal_local.as_path(),
                refresh_env: refresh_env_path.as_path(),
            },
            config.ssh_identity_file.as_deref(),
            config.known_hosts_path.as_deref(),
            timeout,
        )?;
        lines.push(format!(
            "{} installed assignment/traversal artifacts node_id={}",
            target.label, node.node_id
        ));
    }

    Ok(lines.join("\n"))
}

pub fn execute_ops_vm_lab_run_suite(config: VmLabRunSuiteConfig) -> Result<String, String> {
    let inventory = load_inventory(config.inventory_path.as_path())?;
    let topology = if let Some(path) = config.topology_path.as_deref() {
        load_vm_lab_topology(path)?
    } else {
        let selected =
            select_inventory_entries(&inventory, config.vm_aliases.as_slice(), config.select_all)?;
        let value = build_vm_lab_topology(selected.as_slice(), config.suite.as_str())?;
        parse_vm_lab_topology(value)?
    };
    ensure_local_regular_file_path(config.ssh_identity_file.as_path(), "SSH identity file")?;
    let suite_name = normalized_suite_name(config.suite.as_str())?;
    let report_dir = config.report_dir.unwrap_or_else(|| {
        default_artifact_root().join(format!("{}-{}", suite_name, unique_suffix()))
    });
    fs::create_dir_all(report_dir.as_path()).map_err(|err| {
        format!(
            "create suite report dir failed ({}): {err}",
            report_dir.display()
        )
    })?;

    let mut suite_command = build_suite_command(
        suite_name.as_str(),
        &topology,
        inventory.as_slice(),
        config.ssh_identity_file.as_path(),
        config.nat_profile.as_deref(),
        config.impairment_profile.as_deref(),
        report_dir.as_path(),
    )?;
    if config.dry_run {
        return Ok(suite_command.rendered);
    }

    let status = run_status_with_timeout_passthrough(
        &mut suite_command.command,
        timeout_or_default(config.timeout_secs, DEFAULT_LIVE_LAB_TIMEOUT_SECS),
    )
    .map_err(|err| format!("vm-lab suite run failed: {err}"))?;
    if !status.success() {
        return Err(format!(
            "vm-lab suite run failed with status {} command={}",
            status_code(status),
            suite_command.rendered
        ));
    }
    Ok(format!(
        "ran vm-lab suite={} report_dir={}",
        suite_name,
        report_dir.display()
    ))
}

pub fn execute_ops_vm_lab_bootstrap_phase(
    config: VmLabBootstrapPhaseConfig,
) -> Result<String, String> {
    if config.require_same_network {
        ensure_remote_selection_declares_single_network(
            config.inventory_path.as_path(),
            config.vm_aliases.as_slice(),
            config.select_all,
            config.raw_targets.as_slice(),
        )?;
    }
    let phase = bootstrap::BootstrapPhase::parse(config.phase.as_str())?;
    let timeout = timeout_or_default(config.timeout_secs, DEFAULT_RUN_TIMEOUT_SECS);
    ensure_optional_local_regular_file_path(
        config.ssh_identity_file.as_deref(),
        "SSH identity file",
    )?;
    ensure_optional_local_regular_file_path(
        config.known_hosts_path.as_deref(),
        "SSH known_hosts file",
    )?;
    let targets = resolve_remote_targets(
        config.inventory_path.as_path(),
        config.vm_aliases.as_slice(),
        config.select_all,
        config.raw_targets.as_slice(),
    )?;
    let inventory = load_inventory(config.inventory_path.as_path())?;
    let mut workdirs = BTreeMap::new();
    for target in &targets {
        let inventory_entry = inventory.iter().find(|entry| entry.alias == target.label);
        let workdir = config
            .dest_dir
            .clone()
            .or_else(|| inventory_entry.and_then(|entry| entry.rustynet_src_dir.clone()))
            .ok_or_else(|| {
                format!(
                    "bootstrap phase {} requires --dest-dir or rustynet_src_dir inventory metadata for {}",
                    phase.as_str(),
                    target.label
                )
            })?;
        workdirs.insert(target.label.clone(), workdir);
    }

    let mut lines = Vec::new();
    if matches!(
        phase,
        bootstrap::BootstrapPhase::SyncSource | bootstrap::BootstrapPhase::All
    ) {
        let sync_dest_dir = workdirs
            .values()
            .next()
            .cloned()
            .ok_or_else(|| "no targets selected for bootstrap phase".to_owned())?;
        if workdirs.values().any(|workdir| workdir != &sync_dest_dir) {
            return Err(
                "bootstrap sync-source/all requires a single destination directory across selected targets".to_owned(),
            );
        }
        let sync_source = resolve_repo_sync_source(
            config.repo_url.as_deref(),
            config.local_source_dir.as_deref(),
            config.branch.as_str(),
            config.remote.as_str(),
        )?;
        lines.extend(sync_repo_targets(
            targets.as_slice(),
            config.ssh_user.as_deref(),
            config.ssh_identity_file.as_deref(),
            config.known_hosts_path.as_deref(),
            sync_source,
            sync_dest_dir.as_str(),
            timeout,
        )?);
        if phase == bootstrap::BootstrapPhase::SyncSource {
            return Ok(lines.join("\n"));
        }
    }

    let phases = if phase == bootstrap::BootstrapPhase::All {
        vec![
            bootstrap::BootstrapPhase::BuildRelease,
            bootstrap::BootstrapPhase::SmokeServiceHost,
            bootstrap::BootstrapPhase::InstallRelease,
            bootstrap::BootstrapPhase::RestartRuntime,
            bootstrap::BootstrapPhase::VerifyRuntime,
        ]
    } else {
        vec![phase]
    };

    for target in &targets {
        let workdir = workdirs
            .get(target.label.as_str())
            .ok_or_else(|| format!("missing bootstrap workdir for {}", target.label))?;
        let effective_user = config.ssh_user.as_deref().or(target.ssh_user.as_deref());
        let context = bootstrap::BootstrapPhaseContext {
            ssh_user: effective_user,
            ssh_identity_file: config.ssh_identity_file.as_deref(),
            known_hosts_path: config.known_hosts_path.as_deref(),
            workdir: workdir.as_str(),
            repo_url: config.repo_url.as_deref(),
            branch: config.branch.as_str(),
            remote: config.remote.as_str(),
            timeout,
        };
        for phase_name in &phases {
            if *phase_name == bootstrap::BootstrapPhase::SyncSource
                && target.platform_profile.platform != VmGuestPlatform::Windows
            {
                continue;
            }
            execute_bootstrap_phase_for_target(phase_name.as_str(), target, &context)?;
            lines.push(format!(
                "{} completed bootstrap phase={} workdir={}",
                target.label,
                phase_name.as_str(),
                workdir
            ));
        }
    }

    Ok(lines.join("\n"))
}

fn resolve_start_targets(
    inventory_path: &Path,
    aliases: &[String],
    select_all: bool,
) -> Result<Vec<StartTarget>, String> {
    let inventory = load_inventory(inventory_path)?;
    let chosen = select_inventory_entries(&inventory, aliases, select_all)?;
    let mut results = Vec::new();
    for entry in chosen {
        let platform_profile = entry.platform_profile();
        let Some(controller) = entry.controller else {
            return Err(format!(
                "VM alias {} does not declare a local start controller; only local UTM-backed entries can be started here",
                entry.alias
            ));
        };
        match controller {
            VmController::LocalUtm {
                utm_name,
                bundle_path,
            } => {
                results.push(StartTarget {
                    alias: entry.alias,
                    utm_name,
                    bundle_path,
                    ssh_user: entry.ssh_user,
                    last_known_ip: entry.last_known_ip,
                    mesh_ip: entry.mesh_ip,
                    platform_profile,
                });
            }
        }
    }
    Ok(results)
}

fn wait_for_local_utm_targets_ready(
    targets: &[StartTarget],
    utmctl_path: &Path,
    ssh_port: u16,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    timeout: Duration,
) -> Result<Vec<LocalUtmReadyState>, String> {
    let started_at = Instant::now();
    let ssh_port = if ssh_port == 0 { 22 } else { ssh_port };
    let probe_timeout = Duration::from_secs(5).min(timeout);

    loop {
        let states = targets
            .iter()
            .map(|target| {
                observe_local_utm_target_ready(
                    target,
                    utmctl_path,
                    ssh_port,
                    ssh_identity_file,
                    known_hosts_path,
                    probe_timeout,
                )
            })
            .collect::<Vec<_>>();
        if states.iter().all(local_utm_ready_state_is_ready) {
            return Ok(states);
        }
        if started_at.elapsed() >= timeout {
            return Err(format!(
                "timed out waiting for restarted local UTM VMs to become ready\n{}",
                render_local_utm_ready_states(states.as_slice())
            ));
        }
        thread::sleep(Duration::from_secs(2));
    }
}

fn ssh_auth_probe_command(profile: VmPlatformProfile) -> Result<&'static str, String> {
    match profile.remote_shell {
        VmRemoteShell::Posix => Ok("true"),
        VmRemoteShell::Powershell => {
            Ok("powershell.exe -NoLogo -NoProfile -NonInteractive -Command exit 0")
        }
        VmRemoteShell::Unsupported => Err(format!(
            "vm-lab SSH readiness probing is not yet implemented for platform {}",
            profile.platform.as_str()
        )),
    }
}

fn unmatched_local_utm_advisory_target(platform: VmGuestPlatform, live_ip: &str) -> Option<String> {
    match platform {
        VmGuestPlatform::Linux => Some(rewrite_ssh_target_host("debian@", live_ip)),
        VmGuestPlatform::Macos
        | VmGuestPlatform::Windows
        | VmGuestPlatform::Ios
        | VmGuestPlatform::Android => Some(live_ip.to_owned()),
    }
}

fn observe_local_utm_target_ready(
    target: &StartTarget,
    utmctl_path: &Path,
    ssh_port: u16,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    timeout: Duration,
) -> LocalUtmReadyState {
    let process_present = local_utm_process_present_with_probes(
        utmctl_path,
        Path::new("ps"),
        target.utm_name.as_str(),
        target.bundle_path.as_path(),
        timeout,
    )
    .unwrap_or(false);
    let live_ip = resolve_local_utm_live_host_by_name(
        target.utm_name.as_str(),
        target.last_known_ip.as_deref(),
        target.mesh_ip.as_deref(),
        utmctl_path,
    );
    // SSH is only probed for Linux and macOS targets. Windows VMs may have SSH
    // firewalled or unconfigured; they are considered ready once powered + networked.
    let requires_ssh = matches!(
        target.platform_profile.platform,
        VmGuestPlatform::Linux | VmGuestPlatform::Macos
    );
    let ssh_port_status = if !requires_ssh {
        "n/a".to_owned()
    } else {
        match live_ip.as_deref() {
            Some(ip) => probe_tcp_port_status(ip, ssh_port, timeout)
                .map_or_else(|_| "unknown".to_owned(), |(status, _)| status),
            None => "unavailable".to_owned(),
        }
    };
    let ssh_auth_status = if !requires_ssh {
        "n/a".to_owned()
    } else {
        match (live_ip.as_deref(), target.ssh_user.as_deref()) {
            (None, _) => "skipped-no-live-ip".to_owned(),
            (_, None) => "skipped-no-ssh-user".to_owned(),
            // Always attempt the real ssh-binary auth probe when we have a
            // live_ip + ssh_user. The raw-TCP `probe_tcp_port_status` can be
            // blind in a sandboxed / odd-routing context and report "closed"
            // even though the same ssh the bootstrap path uses reaches the
            // node. Do NOT veto the auth probe on the raw-TCP result.
            (Some(ip), Some(ssh_user)) => match ssh_auth_probe_command(target.platform_profile) {
                Ok(probe_command) => match run_remote_shell_command(
                    ip,
                    Some(ssh_user),
                    ssh_identity_file,
                    known_hosts_path,
                    probe_command,
                    timeout,
                ) {
                    Ok(status) if status.success() => "ok".to_owned(),
                    Ok(status) => format!("failed-exit-{}", status_code(status)),
                    Err(err) => format!("error:{err}"),
                },
                Err(err) => format!("error:{err}"),
            },
        }
    };
    LocalUtmReadyState {
        alias: target.alias.clone(),
        utm_name: target.utm_name.clone(),
        process_present,
        live_ip,
        ssh_port_status,
        ssh_auth_status,
        platform: target.platform_profile.platform,
    }
}

fn local_utm_ready_state_is_ready(state: &LocalUtmReadyState) -> bool {
    if !state.process_present || state.live_ip.is_none() {
        return false;
    }
    // Windows VMs are ready once powered and networked; SSH is not required.
    match state.platform {
        VmGuestPlatform::Linux | VmGuestPlatform::Macos => {
            // ssh-reachability is satisfied by the real ssh-binary auth probe
            // succeeding ("ok"). `probe_tcp_port_status` can be blind in a
            // sandboxed / odd-routing context and report the port "closed"
            // even though the same ssh the bootstrap path uses reaches the
            // node, so a successful auth overrides a "closed" raw-TCP result.
            // ssh-auth success is strictly stronger evidence than a raw socket
            // connect; a genuinely unreachable node (auth NOT "ok") stays
            // unready, so the restart / fail-loud path still triggers.
            state.ssh_auth_status == "ok"
        }
        _ => true,
    }
}

fn render_local_utm_ready_states(states: &[LocalUtmReadyState]) -> String {
    states
        .iter()
        .map(|state| {
            format!(
                "{} ready process_present={} live_ip={} ssh_port_status={} ssh_auth_status={}",
                state.alias,
                state.process_present,
                state.live_ip.as_deref().unwrap_or("unavailable"),
                state.ssh_port_status,
                state.ssh_auth_status
            )
        })
        .collect::<Vec<_>>()
        .join("\n")
}

fn persist_local_utm_ready_states_to_inventory(
    inventory_path: &Path,
    states: &[LocalUtmReadyState],
) -> Result<String, String> {
    let original = fs::read_to_string(inventory_path).map_err(|err| {
        format!(
            "read vm inventory for live IP update failed ({}): {err}",
            inventory_path.display()
        )
    })?;
    let mut document: Value = serde_json::from_str(original.as_str()).map_err(|err| {
        format!(
            "parse vm inventory for live IP update failed ({}): {err}",
            inventory_path.display()
        )
    })?;
    let object = document.as_object_mut().ok_or_else(|| {
        format!(
            "vm inventory root must be an object: {}",
            inventory_path.display()
        )
    })?;
    let entries = object
        .get_mut("entries")
        .and_then(Value::as_array_mut)
        .ok_or_else(|| {
            format!(
                "vm inventory is missing entries array: {}",
                inventory_path.display()
            )
        })?;

    let updates = states
        .iter()
        .filter_map(|state| {
            state
                .live_ip
                .as_ref()
                .map(|live_ip| (state.alias.as_str(), live_ip.as_str()))
        })
        .collect::<BTreeMap<_, _>>();
    if updates.is_empty() {
        return Ok(format!(
            "inventory not updated because no authoritative live IPs were observed in {}",
            inventory_path.display()
        ));
    }

    let mut updated_aliases = Vec::new();
    let mut missing_aliases = Vec::new();
    for (alias, live_ip) in &updates {
        let Some(entry_value) = entries.iter_mut().find(|entry| {
            entry
                .as_object()
                .and_then(|object| object.get("alias"))
                .and_then(Value::as_str)
                == Some(*alias)
        }) else {
            missing_aliases.push((*alias).to_owned());
            continue;
        };
        let entry = entry_value.as_object_mut().ok_or_else(|| {
            format!(
                "vm inventory entry for alias {} must be an object: {}",
                alias,
                inventory_path.display()
            )
        })?;
        let current_ssh_target = required_string_field(entry, "ssh_target")?;
        let new_ssh_target = rewrite_ssh_target_host(current_ssh_target.as_str(), live_ip);
        ensure_ssh_target("ssh_target", new_ssh_target.as_str())?;
        ensure_no_control_chars("last_known_ip", live_ip)?;
        entry.insert(
            "ssh_target".to_owned(),
            Value::String(new_ssh_target.clone()),
        );
        entry.insert(
            "last_known_ip".to_owned(),
            Value::String((*live_ip).to_owned()),
        );
        if let Some(existing_live_ips) = entry.get_mut("live_ips") {
            let mut ordered = vec![(*live_ip).to_owned()];
            if let Some(values) = existing_live_ips.as_array() {
                for value in values.iter().filter_map(Value::as_str) {
                    if !ordered.iter().any(|existing| existing == value) {
                        ordered.push(value.to_owned());
                    }
                }
            }
            *existing_live_ips =
                Value::Array(ordered.into_iter().map(Value::String).collect::<Vec<_>>());
        }
        updated_aliases.push(format!(
            "{alias} ssh_target={new_ssh_target} last_known_ip={live_ip}"
        ));
    }
    if !missing_aliases.is_empty() {
        return Err(format!(
            "cannot update vm inventory {}; aliases not found: {}",
            inventory_path.display(),
            missing_aliases.join(", ")
        ));
    }

    let rendered = serde_json::to_string_pretty(&document)
        .map_err(|err| format!("serialize updated vm inventory failed: {err}"))?;
    write_text_file_atomically(inventory_path, rendered.as_str())?;
    load_inventory(inventory_path)?;
    Ok(format!(
        "updated inventory live IPs in {}: {}",
        inventory_path.display(),
        updated_aliases.join("; ")
    ))
}

fn write_text_file_atomically(path: &Path, contents: &str) -> Result<(), String> {
    let parent = path.parent().ok_or_else(|| {
        format!(
            "cannot atomically write file without parent directory: {}",
            path.display()
        )
    })?;
    fs::create_dir_all(parent).map_err(|err| {
        format!(
            "create parent directory for atomic write failed ({}): {err}",
            parent.display()
        )
    })?;
    let temp_path = parent.join(format!(
        ".{}.{}.tmp",
        path.file_name()
            .and_then(|value| value.to_str())
            .unwrap_or("inventory"),
        unique_suffix()
    ));
    let normalized_contents = if contents.ends_with('\n') {
        contents.to_owned()
    } else {
        format!("{contents}\n")
    };
    fs::write(temp_path.as_path(), normalized_contents.as_bytes()).map_err(|err| {
        format!(
            "write temporary file for atomic write failed ({}): {err}",
            temp_path.display()
        )
    })?;
    fs::rename(temp_path.as_path(), path).map_err(|err| {
        let _ = fs::remove_file(temp_path.as_path());
        format!(
            "replace file during atomic write failed ({} -> {}): {err}",
            temp_path.display(),
            path.display()
        )
    })
}

fn resolve_remote_targets(
    inventory_path: &Path,
    aliases: &[String],
    select_all: bool,
    raw_targets: &[String],
) -> Result<Vec<RemoteTarget>, String> {
    let mut resolved = Vec::new();
    let mut seen = HashSet::new();

    if select_all || !aliases.is_empty() {
        let inventory = load_inventory(inventory_path)?;
        for entry in select_inventory_entries(&inventory, aliases, select_all)? {
            let key = format!(
                "{}|{}",
                entry.ssh_user.as_deref().unwrap_or(""),
                entry.ssh_target
            );
            if seen.insert(key) {
                resolved.push(remote_target_from_inventory_entry(&entry, None));
            }
        }
    }

    for raw_target in raw_targets {
        ensure_ssh_target("target", raw_target)?;
        let key = format!("|{raw_target}");
        if seen.insert(key) {
            resolved.push(remote_target_from_raw_target(
                raw_target.clone(),
                raw_target.clone(),
            ));
        }
    }

    if resolved.is_empty() {
        return Err("specify at least one inventory alias/--all or explicit --target".to_owned());
    }

    Ok(resolved)
}

fn resolve_role_target(
    inventory_path: &Path,
    role_label: &str,
    alias: Option<&str>,
    raw_target: Option<&str>,
) -> Result<RoleTarget, String> {
    match (alias, raw_target) {
        (Some(_), Some(_)) => Err(format!(
            "{role_label} target must use either --{role_label}-vm or --{role_label}-target, not both"
        )),
        (None, None) => Err(format!(
            "{role_label} target is required; specify --{role_label}-vm or --{role_label}-target"
        )),
        (Some(alias), None) => {
            resolve_role_target_from_inventory(inventory_path, role_label, alias)
        }
        (None, Some(raw_target)) => resolve_role_target_from_raw(role_label, raw_target),
    }
}

fn resolve_optional_role_target(
    inventory_path: &Path,
    role_label: &str,
    alias: Option<&str>,
    raw_target: Option<&str>,
) -> Result<Option<RoleTarget>, String> {
    match (alias, raw_target) {
        (None, None) => Ok(None),
        _ => resolve_role_target(inventory_path, role_label, alias, raw_target).map(Some),
    }
}

fn resolve_role_target_from_inventory(
    inventory_path: &Path,
    role_label: &str,
    alias: &str,
) -> Result<RoleTarget, String> {
    ensure_inventory_alias(alias)?;
    let inventory = load_inventory(inventory_path)?;
    let entry = inventory
        .into_iter()
        .find(|entry| entry.alias == alias)
        .ok_or_else(|| format!("unknown VM alias for {role_label} target: {alias}"))?;
    let resolved_target = resolved_inventory_ssh_target(&entry);
    let normalized_target = normalized_ssh_target(
        resolved_target.as_str(),
        entry.ssh_user.as_deref(),
        role_label,
    )?;
    let platform_profile = entry.platform_profile();
    let utm_name = entry
        .controller
        .as_ref()
        .map(|VmController::LocalUtm { utm_name, .. }| utm_name.clone());
    Ok(RoleTarget {
        label: entry.alias,
        normalized_target,
        network_group: entry.network_group,
        utm_name,
        platform_profile,
        rustynet_src_dir: entry.rustynet_src_dir.clone().or_else(|| {
            Some(default_rustynet_src_dir_for_profile(
                platform_profile,
                entry.ssh_user.as_deref(),
            ))
        }),
    })
}

fn resolve_role_target_from_raw(role_label: &str, raw_target: &str) -> Result<RoleTarget, String> {
    ensure_ssh_target(role_label, raw_target)?;
    if !raw_target.contains('@') {
        return Err(format!(
            "{role_label} raw target must include an explicit SSH user (user@host): {raw_target}"
        ));
    }
    let platform_profile = default_platform_profile(VmGuestPlatform::Linux);
    let ssh_user = ssh_target_user(raw_target).map(str::to_string);
    Ok(RoleTarget {
        label: raw_target.to_owned(),
        normalized_target: raw_target.to_owned(),
        network_group: None,
        utm_name: None,
        platform_profile,
        rustynet_src_dir: Some(default_rustynet_src_dir_for_profile(
            platform_profile,
            ssh_user.as_deref(),
        )),
    })
}

fn normalized_ssh_target(
    ssh_target: &str,
    ssh_user: Option<&str>,
    label: &str,
) -> Result<String, String> {
    ensure_ssh_target(label, ssh_target)?;
    if ssh_target.contains('@') {
        return Ok(ssh_target.to_owned());
    }
    let ssh_user = ssh_user.ok_or_else(|| {
        format!(
            "{label} target requires ssh_user metadata because ssh_target lacks user@host form: {ssh_target}"
        )
    })?;
    ensure_ssh_user(ssh_user)?;
    Ok(format!("{ssh_user}@{ssh_target}"))
}

fn remote_target_from_inventory_entry(
    entry: &VmInventoryEntry,
    ssh_user_override: Option<&str>,
) -> RemoteTarget {
    let platform_profile = entry.platform_profile();
    let ssh_user = ssh_user_override
        .map(ToString::to_string)
        .or_else(|| entry.ssh_user.clone());
    RemoteTarget {
        label: entry.alias.clone(),
        ssh_target: resolved_inventory_ssh_target(entry),
        ssh_user: ssh_user.clone(),
        controller: entry.controller.clone(),
        platform_profile,
        rustynet_src_dir: entry.rustynet_src_dir.clone().or_else(|| {
            Some(default_rustynet_src_dir_for_profile(
                platform_profile,
                ssh_user.as_deref(),
            ))
        }),
        remote_temp_dir: entry
            .remote_temp_dir
            .clone()
            .or_else(|| Some(default_remote_temp_dir_for_profile(platform_profile))),
        utm_staging_dir: entry
            .utm_staging_dir
            .clone()
            .or_else(|| default_utm_staging_dir_for_profile(platform_profile, ssh_user.as_deref())),
    }
}

fn remote_target_from_raw_target(label: String, ssh_target: String) -> RemoteTarget {
    let platform_profile = default_platform_profile(VmGuestPlatform::Linux);
    let ssh_user = ssh_target_user(ssh_target.as_str()).map(str::to_string);
    RemoteTarget {
        label,
        ssh_target,
        ssh_user: ssh_user.clone(),
        controller: None,
        platform_profile,
        rustynet_src_dir: Some(default_rustynet_src_dir_for_profile(
            platform_profile,
            ssh_user.as_deref(),
        )),
        remote_temp_dir: Some(default_remote_temp_dir_for_profile(platform_profile)),
        utm_staging_dir: default_utm_staging_dir_for_profile(platform_profile, ssh_user.as_deref()),
    }
}

fn remote_target_from_start_target(target: &StartTarget) -> RemoteTarget {
    RemoteTarget {
        label: target.alias.clone(),
        ssh_target: target
            .last_known_ip
            .clone()
            .or_else(|| target.mesh_ip.clone())
            .unwrap_or_else(|| target.utm_name.clone()),
        ssh_user: target.ssh_user.clone(),
        controller: Some(VmController::LocalUtm {
            utm_name: target.utm_name.clone(),
            bundle_path: target.bundle_path.clone(),
        }),
        platform_profile: target.platform_profile,
        rustynet_src_dir: None,
        remote_temp_dir: None,
        utm_staging_dir: default_utm_staging_dir_for_profile(
            target.platform_profile,
            target.ssh_user.as_deref(),
        ),
    }
}

fn resolved_inventory_ssh_target(entry: &VmInventoryEntry) -> String {
    resolved_inventory_ssh_target_with_utmctl(entry, default_utmctl_path().as_path())
}

fn resolved_inventory_ssh_target_with_utmctl(
    entry: &VmInventoryEntry,
    utmctl_path: &Path,
) -> String {
    resolve_local_utm_live_host(entry, utmctl_path).map_or_else(
        || entry.ssh_target.clone(),
        |host| rewrite_ssh_target_host(entry.ssh_target.as_str(), host.as_str()),
    )
}

fn resolve_local_utm_live_host(entry: &VmInventoryEntry, utmctl_path: &Path) -> Option<String> {
    let utm_name = match entry.controller.as_ref()? {
        VmController::LocalUtm { utm_name, .. } => utm_name,
    };
    resolve_local_utm_live_host_by_name(
        utm_name.as_str(),
        entry.last_known_ip.as_deref(),
        entry.mesh_ip.as_deref(),
        utmctl_path,
    )
}

fn resolve_local_utm_live_host_by_name(
    utm_name: &str,
    last_known_ip: Option<&str>,
    mesh_ip: Option<&str>,
    utmctl_path: &Path,
) -> Option<String> {
    if !utmctl_path.is_file() {
        return None;
    }
    let mut command = Command::new(utmctl_path);
    command.arg("ip-address").arg(utm_name);
    let output = run_output_with_timeout(
        &mut command,
        Duration::from_secs(DEFAULT_UTM_IP_DISCOVERY_TIMEOUT_SECS),
    )
    .ok()?;
    if !output.status.success() {
        return None;
    }
    let stdout = String::from_utf8(output.stdout).ok()?;
    select_live_ssh_host_from_utm_output(stdout.as_str(), last_known_ip, mesh_ip)
}

fn matches_local_utm_inventory_entry(
    entry: &VmInventoryEntry,
    bundle_path: &Path,
    utm_name: &str,
) -> bool {
    let Some(VmController::LocalUtm {
        utm_name: inventory_utm_name,
        bundle_path: inventory_bundle_path,
    }) = entry.controller.as_ref()
    else {
        return false;
    };
    if inventory_utm_name == utm_name {
        return true;
    }
    match (
        fs::canonicalize(bundle_path),
        fs::canonicalize(inventory_bundle_path.as_path()),
    ) {
        (Ok(observed), Ok(expected)) => observed == expected,
        _ => false,
    }
}

fn probe_tcp_port_status(
    ip: &str,
    port: u16,
    timeout: Duration,
) -> Result<(String, Option<String>), String> {
    let parsed_ip = ip
        .trim()
        .parse::<IpAddr>()
        .map_err(|err| format!("invalid SSH probe IP {ip:?}: {err}"))?;
    let socket_addr = SocketAddr::new(parsed_ip, port);
    match TcpStream::connect_timeout(&socket_addr, timeout) {
        Ok(_) => Ok(("open".to_owned(), None)),
        Err(primary_err) => {
            // On macOS some process contexts (e.g. sandboxed app descendants) cannot reach
            // bridged-network VMs with an unbound socket because the route lookup returns
            // EHOSTUNREACH before the ARP-cloned host route is consulted.  Retrying with
            // the socket explicitly bound to the source IP that the kernel would select for
            // this destination (discovered via a zero-cost UDP connect that sends no bytes)
            // forces the correct interface-scoped path.
            //
            // Also handles 192.168.64.0/24 (UTM shared-network bridge100) where the same
            // scoping issue was first observed.
            use socket2::{Domain, SockAddr, Socket, Type};
            let source_ip_for_bind: Option<IpAddr> = if let IpAddr::V4(v4) = parsed_ip {
                let octets = v4.octets();
                if octets[0] == 192 && octets[1] == 168 && octets[2] == 64 {
                    // Legacy: UTM shared network — bind to the bridge100 gateway.
                    "192.168.64.1".parse().ok()
                } else {
                    // General case: probe the source IP the kernel would select for
                    // this destination via a UDP connect (no packets sent).
                    std::net::UdpSocket::bind("0.0.0.0:0")
                        .and_then(|u| {
                            u.connect(SocketAddr::new(IpAddr::V4(v4), port))?;
                            u.local_addr()
                        })
                        .ok()
                        .map(|a| a.ip())
                        .filter(|src| *src != IpAddr::V4(std::net::Ipv4Addr::UNSPECIFIED))
                }
            } else {
                None
            };
            if let (Some(src), Ok(sock)) = (
                source_ip_for_bind,
                Socket::new(Domain::IPV4, Type::STREAM, None),
            ) {
                let bind: SocketAddr = SocketAddr::new(src, 0);
                if sock.bind(&SockAddr::from(bind)).is_ok()
                    && sock
                        .connect_timeout(&SockAddr::from(socket_addr), timeout)
                        .is_ok()
                {
                    return Ok(("open".to_owned(), None));
                }
            }
            // Third fallback: on macOS the UDP connect trick can also fail (EHOSTUNREACH) when
            // running as a subprocess of a sandboxed app whose network extension intercepts
            // outgoing UDP.  Enumerate local interface addresses directly via getifaddrs and
            // pick the first IPv4 address on the same /24 as the target — this is the address
            // that *would* be selected for the destination if routing were not blocked — then
            // bind the TCP socket explicitly before connecting.
            if let IpAddr::V4(v4_target) = parsed_ip {
                let target_prefix = {
                    let o = v4_target.octets();
                    [o[0], o[1], o[2]]
                };
                let ifaddr_src: Option<IpAddr> =
                    nix::ifaddrs::getifaddrs().ok().and_then(|addrs| {
                        addrs
                            .filter_map(|ia| ia.address)
                            .filter_map(|sa| {
                                let v4 = sa.as_sockaddr_in()?.ip();
                                let o = v4.octets();
                                if [o[0], o[1], o[2]] == target_prefix && v4 != v4_target {
                                    Some(IpAddr::V4(v4))
                                } else {
                                    None
                                }
                            })
                            .next()
                    });
                if let (Some(src), Ok(sock)) =
                    (ifaddr_src, Socket::new(Domain::IPV4, Type::STREAM, None))
                {
                    let bind: SocketAddr = SocketAddr::new(src, 0);
                    if sock.bind(&SockAddr::from(bind)).is_ok()
                        && sock
                            .connect_timeout(&SockAddr::from(socket_addr), timeout)
                            .is_ok()
                    {
                        return Ok(("open".to_owned(), None));
                    }
                }
            }
            Ok(("closed".to_owned(), Some(format!("{primary_err}"))))
        }
    }
}

/// Hard deadline for the recursive UTM-bundle scan. The scan normally
/// completes in milliseconds; macOS TCC consent mediation can park `open()`
/// on another app's container indefinitely when the process context lacks
/// approval (observed under unattended agent runs), so the scan must never
/// be allowed to block a run forever.
const UTM_BUNDLE_SCAN_TIMEOUT_SECS: u64 = 20;

/// Run the UTM bundle scan — including the root existence check, which is
/// also subject to TCC mediation — on a worker thread with a hard deadline.
///
/// On deadline the worker is abandoned (it holds no locks or shared state and
/// parks harmlessly in the kernel) and an error is returned so the caller can
/// degrade to inventory-recorded bundle paths instead of hanging.
fn discover_local_utm_bundle_paths_bounded(
    root: PathBuf,
    timeout: Duration,
) -> Result<Vec<PathBuf>, String> {
    let (sender, receiver) = std::sync::mpsc::channel();
    std::thread::Builder::new()
        .name("utm-bundle-scan".to_owned())
        .spawn(move || {
            let result = if root.is_dir() {
                discover_local_utm_bundle_paths(root.as_path())
            } else {
                Err(format!(
                    "UTM documents root must be an existing directory: {}",
                    root.display()
                ))
            };
            // A send error only means the receiver gave up at the deadline.
            let _ = sender.send(result);
        })
        .map_err(|err| format!("spawn UTM bundle scan thread failed: {err}"))?;
    match receiver.recv_timeout(timeout) {
        Ok(result) => result,
        Err(std::sync::mpsc::RecvTimeoutError::Timeout) => Err(format!(
            "UTM bundle scan did not finish within {}s — on macOS this usually means \
             privacy (TCC) consent for the UTM container is missing for this process \
             context, which parks filesystem access indefinitely",
            timeout.as_secs()
        )),
        Err(std::sync::mpsc::RecvTimeoutError::Disconnected) => {
            Err("UTM bundle scan thread exited without producing a result".to_owned())
        }
    }
}

fn discover_local_utm_bundle_paths(root: &Path) -> Result<Vec<PathBuf>, String> {
    let mut bundles = Vec::new();
    discover_local_utm_bundle_paths_recursive(root, &mut bundles)?;
    bundles.sort();
    bundles.dedup();
    Ok(bundles)
}

fn discover_local_utm_bundle_paths_recursive(
    current: &Path,
    bundles: &mut Vec<PathBuf>,
) -> Result<(), String> {
    let mut entries = fs::read_dir(current)
        .map_err(|err| {
            format!(
                "read UTM documents directory failed ({}): {err}",
                current.display()
            )
        })?
        .filter_map(Result::ok)
        .collect::<Vec<_>>();
    entries.sort_by_key(std::fs::DirEntry::file_name);
    for entry in entries {
        let path = entry.path();
        let file_type = entry
            .file_type()
            .map_err(|err| format!("read file type failed ({}): {err}", path.display()))?;
        if file_type.is_symlink() {
            continue;
        }
        if file_type.is_dir() {
            if path.extension().and_then(|value| value.to_str()) == Some("utm") {
                bundles.push(fs::canonicalize(path.as_path()).map_err(|err| {
                    format!("canonicalize UTM bundle failed ({}): {err}", path.display())
                })?);
            } else {
                discover_local_utm_bundle_paths_recursive(path.as_path(), bundles)?;
            }
        }
    }
    Ok(())
}

fn select_live_ssh_host_from_utm_output(
    output: &str,
    last_known_ip: Option<&str>,
    mesh_ip: Option<&str>,
) -> Option<String> {
    let candidates = output
        .lines()
        .filter_map(|line| line.trim().parse::<IpAddr>().ok())
        .collect::<Vec<_>>();
    select_preferred_live_ssh_ip(candidates.as_slice(), last_known_ip, mesh_ip)
        .map(|ip| ip.to_string())
}

fn select_preferred_live_ssh_ip(
    candidates: &[IpAddr],
    last_known_ip: Option<&str>,
    mesh_ip: Option<&str>,
) -> Option<IpAddr> {
    let last_known_ip = last_known_ip.and_then(|value| value.parse::<IpAddr>().ok());
    let mesh_ip = mesh_ip.and_then(|value| value.parse::<IpAddr>().ok());

    let viable: Vec<IpAddr> = candidates
        .iter()
        .copied()
        .filter(|c| is_viable_live_ssh_ip(*c))
        .filter(|c| Some(*c) != mesh_ip)
        .collect();

    // If no IPv4 candidate survives (only IPv6 secondary/tunnel addresses like
    // SLAAC ULA from bridge100 or a stale WireGuard interface), include
    // last_known_ip as a fallback to avoid selecting a non-SSH-accessible IPv6.
    let has_ipv4 = viable.iter().any(IpAddr::is_ipv4);
    let mut all_candidates = viable;
    if !has_ipv4
        && let Some(lk) = last_known_ip
        && lk.is_ipv4()
        && is_viable_live_ssh_ip(lk)
        && Some(lk) != mesh_ip
    {
        all_candidates.push(lk);
    }

    all_candidates
        .iter()
        .copied()
        .max_by_key(|c| live_ssh_ip_score(*c, last_known_ip))
}

fn is_viable_live_ssh_ip(candidate: IpAddr) -> bool {
    match candidate {
        IpAddr::V4(addr) => {
            !(addr.is_unspecified()
                || addr.is_loopback()
                || addr.is_multicast()
                || addr.is_link_local())
        }
        IpAddr::V6(addr) => {
            !(addr.is_unspecified()
                || addr.is_loopback()
                || addr.is_multicast()
                || addr.is_unicast_link_local())
        }
    }
}

fn live_ssh_ip_score(candidate: IpAddr, last_known_ip: Option<IpAddr>) -> i32 {
    let mut score = 0;
    if Some(candidate) == last_known_ip {
        score += 100;
    }
    if let Some(last_known_ip) = last_known_ip
        && std::mem::discriminant(&candidate) == std::mem::discriminant(&last_known_ip)
    {
        score += 40;
    }
    match candidate {
        IpAddr::V4(addr) => {
            score += 30;
            if addr.is_private() {
                score += 20;
            }
            if ipv4_is_shared_address_space(addr) {
                score -= 10;
            }
        }
        IpAddr::V6(addr) => {
            if !addr.is_unique_local() {
                score += 5;
            }
        }
    }
    score
}

fn ipv4_is_shared_address_space(addr: std::net::Ipv4Addr) -> bool {
    let octets = addr.octets();
    octets[0] == 100 && (octets[1] & 0b1100_0000) == 0b0100_0000
}

fn rewrite_ssh_target_host(ssh_target: &str, new_host: &str) -> String {
    let formatted_host = if new_host.contains(':') {
        format!("[{new_host}]")
    } else {
        new_host.to_owned()
    };
    match ssh_target.rsplit_once('@') {
        Some((user, _)) => format!("{user}@{formatted_host}"),
        None => formatted_host,
    }
}

fn literal_ip_host_from_ssh_target(ssh_target: &str) -> Option<String> {
    let host = ssh_target_host(ssh_target);
    host.parse::<IpAddr>().ok().map(|_| host)
}

fn select_inventory_entries(
    inventory: &[VmInventoryEntry],
    aliases: &[String],
    select_all: bool,
) -> Result<Vec<VmInventoryEntry>, String> {
    let requested = if select_all {
        inventory
            .iter()
            .filter(|entry| entry.include_in_all.unwrap_or(true))
            .map(|entry| entry.alias.clone())
            .collect::<Vec<_>>()
    } else {
        aliases.to_vec()
    };
    if requested.is_empty() {
        return Err("specify at least one --vm alias or use --all".to_owned());
    }
    let mut selected = Vec::new();
    let mut seen_aliases = HashSet::new();
    for alias in requested {
        if !seen_aliases.insert(alias.clone()) {
            continue;
        }
        let entry = inventory
            .iter()
            .find(|candidate| candidate.alias == alias)
            .cloned()
            .ok_or_else(|| format!("unknown VM alias: {alias}"))?;
        selected.push(entry);
    }
    Ok(selected)
}

fn ensure_remote_selection_declares_single_network(
    inventory_path: &Path,
    aliases: &[String],
    select_all: bool,
    raw_targets: &[String],
) -> Result<String, String> {
    if !raw_targets.is_empty() {
        return Err(
            "require-same-network only supports inventory-backed targets; raw --target values do not declare network metadata".to_owned(),
        );
    }
    let inventory = load_inventory(inventory_path)?;
    let selected = select_inventory_entries(&inventory, aliases, select_all)?;
    ensure_inventory_entries_share_network(selected.as_slice())
}

fn ensure_inventory_entries_share_network(entries: &[VmInventoryEntry]) -> Result<String, String> {
    let mut chosen_group: Option<String> = None;
    for entry in entries {
        let group = entry.network_group.as_deref().ok_or_else(|| {
            format!(
                "VM alias {} is missing network_group metadata required for same-network validation",
                entry.alias
            )
        })?;
        match chosen_group.as_deref() {
            None => chosen_group = Some(group.to_owned()),
            Some(existing) if existing == group => {}
            Some(existing) => {
                return Err(format!(
                    "selected VMs span multiple network groups: {} is on {} but expected {}",
                    entry.alias, group, existing
                ));
            }
        }
    }
    chosen_group.ok_or_else(|| "no inventory-backed targets were selected".to_owned())
}

fn ensure_role_targets_share_network(targets: &[Option<RoleTarget>]) -> Result<String, String> {
    let mut chosen_group: Option<String> = None;
    for target in targets {
        let Some(target) = target.as_ref() else {
            continue;
        };
        let group = target.network_group.as_deref().ok_or_else(|| {
            format!(
                "target {} is missing inventory-backed network_group metadata required for same-network validation",
                target.label
            )
        })?;
        match chosen_group.as_deref() {
            None => chosen_group = Some(group.to_owned()),
            Some(existing) if existing == group => {}
            Some(existing) => {
                return Err(format!(
                    "selected role targets span multiple network groups: {} is on {} but expected {}",
                    target.label, group, existing
                ));
            }
        }
    }
    chosen_group
        .ok_or_else(|| "same-network validation requires at least one resolved target".to_owned())
}

fn load_inventory(path: &Path) -> Result<Vec<VmInventoryEntry>, String> {
    let body = fs::read_to_string(path)
        .map_err(|err| format!("read vm inventory failed ({}): {err}", path.display()))?;
    let value = serde_json::from_str::<Value>(body.as_str())
        .map_err(|err| format!("parse vm inventory failed ({}): {err}", path.display()))?;
    let object = value
        .as_object()
        .ok_or_else(|| format!("vm inventory must be a JSON object: {}", path.display()))?;
    let version = object
        .get("version")
        .and_then(Value::as_u64)
        .ok_or_else(|| {
            format!(
                "vm inventory is missing numeric version: {}",
                path.display()
            )
        })?;
    if version != 1 {
        return Err(format!(
            "unsupported vm inventory version {} in {}",
            version,
            path.display()
        ));
    }
    let entries = object
        .get("entries")
        .and_then(Value::as_array)
        .ok_or_else(|| format!("vm inventory is missing entries array: {}", path.display()))?;
    if entries.is_empty() {
        return Err(format!("vm inventory has no entries: {}", path.display()));
    }

    let mut parsed = Vec::with_capacity(entries.len());
    let mut seen_aliases = HashSet::new();
    for entry in entries {
        let parsed_entry = parse_inventory_entry(entry)?;
        if !seen_aliases.insert(parsed_entry.alias.clone()) {
            return Err(format!(
                "vm inventory contains duplicate alias: {}",
                parsed_entry.alias
            ));
        }
        parsed.push(parsed_entry);
    }
    Ok(parsed)
}

fn parse_inventory_entry(value: &Value) -> Result<VmInventoryEntry, String> {
    let object = value
        .as_object()
        .ok_or_else(|| "vm inventory entry must be an object".to_owned())?;
    let alias = required_string_field(object, "alias")?;
    ensure_inventory_alias(alias.as_str())?;
    let ssh_target = required_string_field(object, "ssh_target")?;
    ensure_ssh_target("ssh_target", ssh_target.as_str())?;
    let ssh_user = optional_string_field(object, "ssh_user")?;
    if let Some(user) = ssh_user.as_deref() {
        ensure_ssh_user(user)?;
    }
    let ssh_password = optional_string_field(object, "ssh_password")?;
    if let Some(value) = ssh_password.as_deref() {
        ensure_no_control_chars("ssh_password", value)?;
    }
    let include_in_all = optional_bool_field(object, "include_in_all")?;
    let os = optional_string_field(object, "os")?;
    if let Some(value) = os.as_deref() {
        ensure_no_control_chars("os", value)?;
    }
    let last_known_ip = optional_string_field(object, "last_known_ip")?;
    if let Some(value) = last_known_ip.as_deref() {
        ensure_no_control_chars("last_known_ip", value)?;
    }
    let parent_device = optional_string_field(object, "parent_device")?;
    if let Some(value) = parent_device.as_deref() {
        ensure_no_control_chars("parent_device", value)?;
    }
    let last_known_network = optional_string_field(object, "last_known_network")?;
    if let Some(value) = last_known_network.as_deref() {
        ensure_no_control_chars("last_known_network", value)?;
    }
    let network_group = optional_string_field(object, "network_group")?;
    if let Some(value) = network_group.as_deref() {
        ensure_no_control_chars("network_group", value)?;
    }
    let node_id = optional_string_field(object, "node_id")?;
    if let Some(value) = node_id.as_deref() {
        ensure_inventory_alias(value)?;
    }
    let lab_role = optional_string_field(object, "lab_role")?;
    if let Some(value) = lab_role.as_deref() {
        ensure_inventory_alias(value)?;
    }
    let mesh_ip = optional_string_field(object, "mesh_ip")?;
    if let Some(value) = mesh_ip.as_deref() {
        ensure_no_control_chars("mesh_ip", value)?;
    }
    let exit_capable = optional_bool_field(object, "exit_capable")?;
    let relay_capable = optional_bool_field(object, "relay_capable")?;
    let remote_temp_dir = optional_string_field(object, "remote_temp_dir")?;
    if let Some(value) = remote_temp_dir.as_deref() {
        ensure_no_control_chars("remote_temp_dir", value)?;
    }
    let utm_staging_dir = optional_string_field(object, "utm_staging_dir")?;
    if let Some(value) = utm_staging_dir.as_deref() {
        ensure_no_control_chars("utm_staging_dir", value)?;
    }
    let rustynet_src_dir = optional_string_field(object, "rustynet_src_dir")?;
    if let Some(value) = rustynet_src_dir.as_deref() {
        ensure_no_control_chars("rustynet_src_dir", value)?;
    }
    let platform = match optional_string_field(object, "platform")? {
        Some(value) => {
            Some(VmGuestPlatform::parse(value.as_str()).map_err(|err| format!("platform: {err}"))?)
        }
        None => None,
    };
    let remote_shell = match optional_string_field(object, "remote_shell")? {
        Some(value) => Some(
            VmRemoteShell::parse(value.as_str()).map_err(|err| format!("remote_shell: {err}"))?,
        ),
        None => None,
    };
    let guest_exec_mode = match optional_string_field(object, "guest_exec_mode")? {
        Some(value) => Some(
            VmGuestExecMode::parse(value.as_str())
                .map_err(|err| format!("guest_exec_mode: {err}"))?,
        ),
        None => None,
    };
    let service_manager = match optional_string_field(object, "service_manager")? {
        Some(value) => Some(
            VmServiceManager::parse(value.as_str())
                .map_err(|err| format!("service_manager: {err}"))?,
        ),
        None => None,
    };
    let controller = match object.get("controller") {
        None | Some(Value::Null) => None,
        Some(value) => Some(parse_controller(value)?),
    };
    Ok(VmInventoryEntry {
        alias,
        ssh_target,
        ssh_user,
        ssh_password,
        include_in_all,
        os,
        last_known_ip,
        parent_device,
        last_known_network,
        network_group,
        node_id,
        lab_role,
        mesh_ip,
        exit_capable,
        relay_capable,
        remote_temp_dir,
        utm_staging_dir,
        rustynet_src_dir,
        platform,
        remote_shell,
        guest_exec_mode,
        service_manager,
        controller,
    })
}

fn parse_controller(value: &Value) -> Result<VmController, String> {
    let object = value
        .as_object()
        .ok_or_else(|| "vm controller must be an object".to_owned())?;
    let controller_type = required_string_field(object, "type")?;
    match controller_type.as_str() {
        "local_utm" => {
            let utm_name = required_string_field(object, "utm_name")?;
            ensure_no_control_chars("utm_name", utm_name.as_str())?;
            let bundle_path_raw = required_string_field(object, "bundle_path")?;
            let bundle_path = PathBuf::from(bundle_path_raw.as_str());
            if !bundle_path.is_absolute() {
                return Err(format!(
                    "local_utm bundle_path must be absolute: {}",
                    bundle_path.display()
                ));
            }
            Ok(VmController::LocalUtm {
                utm_name,
                bundle_path,
            })
        }
        _ => Err(format!("unsupported vm controller type: {controller_type}")),
    }
}

fn required_string_field(
    object: &serde_json::Map<String, Value>,
    key: &str,
) -> Result<String, String> {
    object
        .get(key)
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToString::to_string)
        .ok_or_else(|| format!("vm inventory entry is missing string field: {key}"))
}

fn optional_string_field(
    object: &serde_json::Map<String, Value>,
    key: &str,
) -> Result<Option<String>, String> {
    match object.get(key) {
        None | Some(Value::Null) => Ok(None),
        Some(Value::String(value)) => {
            let trimmed = value.trim();
            if trimmed.is_empty() {
                Ok(None)
            } else {
                Ok(Some(trimmed.to_owned()))
            }
        }
        _ => Err(format!(
            "vm inventory field must be a string when present: {key}"
        )),
    }
}

fn optional_bool_field(
    object: &serde_json::Map<String, Value>,
    key: &str,
) -> Result<Option<bool>, String> {
    match object.get(key) {
        None | Some(Value::Null) => Ok(None),
        Some(Value::Bool(value)) => Ok(Some(*value)),
        _ => Err(format!(
            "vm inventory field must be a boolean when present: {key}"
        )),
    }
}

fn ensure_inventory_alias(value: &str) -> Result<(), String> {
    if value.is_empty() {
        return Err("vm alias must not be empty".to_owned());
    }
    let allowed = |ch: char| ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_' | '.');
    if !value.chars().all(allowed) {
        return Err(format!("vm alias contains unsupported characters: {value}"));
    }
    Ok(())
}

fn ensure_ssh_target(label: &str, value: &str) -> Result<(), String> {
    if value.is_empty() {
        return Err(format!("{label} must not be empty"));
    }
    if value.chars().any(char::is_whitespace) {
        return Err(format!("{label} must not contain whitespace: {value}"));
    }
    ensure_no_control_chars(label, value)
}

fn ensure_ssh_user(value: &str) -> Result<(), String> {
    if value.is_empty() {
        return Err("SSH user must not be empty".to_owned());
    }
    if value.chars().any(char::is_whitespace) {
        return Err(format!("SSH user must not contain whitespace: {value}"));
    }
    ensure_no_control_chars("SSH user", value)
}

fn build_repo_sync_script(
    repo_url: &str,
    dest_dir: &str,
    branch: &str,
    remote: &str,
) -> Result<String, String> {
    ensure_no_control_chars("repo URL", repo_url)?;
    ensure_no_control_chars("destination directory", dest_dir)?;
    ensure_no_control_chars("branch", branch)?;
    ensure_no_control_chars("remote", remote)?;
    let parent = Path::new(dest_dir)
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .ok_or_else(|| format!("destination directory must have a parent: {dest_dir}"))?;
    let parent = parent
        .to_str()
        .ok_or_else(|| format!("destination directory parent is not valid UTF-8: {dest_dir}"))?;
    let dest_git_dir = format!("{dest_dir}/.git");
    Ok(format!(
        "set -eu; mkdir -p {parent}; \
if [ -e {dest_dir} ] && [ ! -d {dest_dir} ]; then \
printf 'destination path exists but is not a directory: %s\\n' {dest_dir} >&2; \
exit 1; \
fi; \
if [ -d {dest_dir} ] && [ ! -d {dest_git_dir} ]; then \
backup_path={dest_dir}.prep.$(date -u +%Y%m%dT%H%M%S).$$; \
mv -- {dest_dir} \"$backup_path\"; \
fi; \
if [ -d {dest_git_dir} ]; then \
git -C {dest_dir} remote set-url {remote} {repo_url}; \
git -C {dest_dir} fetch --prune {remote}; \
else \
git clone --origin {remote} --branch {branch} -- {repo_url} {dest_dir}; \
fi; \
git -C {dest_dir} checkout --force {branch}; \
git -C {dest_dir} reset --hard {remote}/{branch}",
        parent = shell_quote(parent),
        dest_git_dir = shell_quote(dest_git_dir.as_str()),
        dest_dir = shell_quote(dest_dir),
        remote = shell_quote(remote),
        repo_url = shell_quote(repo_url),
        branch = shell_quote(branch),
    ))
}

fn build_windows_repo_sync_script(
    repo_url: &str,
    dest_dir: &str,
    branch: &str,
    remote: &str,
) -> Result<String, String> {
    ensure_no_control_chars("repo URL", repo_url)?;
    ensure_no_control_chars("destination directory", dest_dir)?;
    ensure_no_control_chars("branch", branch)?;
    ensure_no_control_chars("remote", remote)?;
    Ok(format!(
        "Set-StrictMode -Version Latest; \
         $ErrorActionPreference = 'Stop'; \
         $dest = {dest}; \
         $parent = Split-Path -Parent $dest; \
         if ($parent -and -not (Test-Path -LiteralPath $parent)) {{ New-Item -ItemType Directory -Force -Path $parent | Out-Null }}; \
         if (-not (Test-Path -LiteralPath $dest)) {{ git clone --origin {remote_name} --branch {branch_name} --single-branch {repo} $dest | Out-Null }} \
         elseif (Test-Path -LiteralPath (Join-Path $dest '.git')) {{ \
             git -C $dest remote set-url {remote_name} {repo}; \
             git -C $dest fetch {remote_name} {branch_name} --prune; \
             git -C $dest checkout -B {branch_name} FETCH_HEAD; \
             git -C $dest reset --hard FETCH_HEAD; \
             git -C $dest clean -fdx \
         }} else {{ throw \"destination exists but is not a git repository: $dest\" }}",
        dest = powershell_quote(dest_dir)?,
        remote_name = powershell_quote(remote)?,
        branch_name = powershell_quote(branch)?,
        repo = powershell_quote(repo_url)?,
    ))
}

fn build_repo_sync_script_for_target(
    target: &RemoteTarget,
    repo_url: &str,
    dest_dir: &str,
    branch: &str,
    remote: &str,
) -> Result<String, String> {
    match repo_sync_dispatch_kind_for_target(target, RepoSyncMode::Git)? {
        RepoSyncDispatchKind::PosixGit => {
            build_repo_sync_script(repo_url, dest_dir, branch, remote)
        }
        RepoSyncDispatchKind::WindowsPowershellGit => {
            build_windows_repo_sync_script(repo_url, dest_dir, branch, remote)
        }
        other => Err(format!(
            "repo sync dispatch mismatch for {}: {other:?}",
            target.label
        )),
    }
}

fn build_local_source_extract_script(
    dest_dir: &str,
    remote_archive_path: &str,
) -> Result<String, String> {
    ensure_no_control_chars("destination directory", dest_dir)?;
    ensure_no_control_chars("remote archive path", remote_archive_path)?;
    let parent = Path::new(dest_dir)
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .ok_or_else(|| format!("destination directory must have a parent: {dest_dir}"))?;
    let parent = parent
        .to_str()
        .ok_or_else(|| format!("destination directory parent is not valid UTF-8: {dest_dir}"))?;
    let cleanup_targets = posix_local_source_generated_cleanup_targets(dest_dir);
    let backup_glob = posix_local_source_backup_glob(dest_dir)?;
    Ok(format!(
        "set -eu; mkdir -p {parent}; \
if [ -e {dest_dir} ] && [ ! -d {dest_dir} ]; then \
printf 'destination path exists but is not a directory: %s\\n' {dest_dir} >&2; \
rm -f -- {remote_archive}; \
exit 1; \
fi; \
backup_path=; \
if [ -d {dest_dir} ]; then \
rm -rf -- {cleanup_targets}; \
fi; \
if [ -d {parent} ]; then \
find {parent} -maxdepth 1 -type d -name {backup_glob} -exec rm -rf -- {{}} +; \
fi; \
if [ -d {dest_dir} ]; then \
backup_path={dest_dir}.prep.$(date -u +%Y%m%dT%H%M%S).$$; \
mv -- {dest_dir} \"$backup_path\"; \
fi; \
mkdir -p {dest_dir}; \
tar -xf {remote_archive} -C {dest_dir}; \
if [ -n \"${{backup_path:-}}\" ]; then rm -rf -- \"$backup_path\"; fi; \
rm -f -- {remote_archive}",
        parent = shell_quote(parent),
        dest_dir = shell_quote(dest_dir),
        remote_archive = shell_quote(remote_archive_path),
        cleanup_targets = cleanup_targets,
        backup_glob = shell_quote(backup_glob.as_str()),
    ))
}

fn build_local_source_presync_cleanup_script(dest_dir: &str) -> Result<String, String> {
    ensure_no_control_chars("destination directory", dest_dir)?;
    let parent = Path::new(dest_dir)
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .ok_or_else(|| format!("destination directory must have a parent: {dest_dir}"))?;
    let parent = parent
        .to_str()
        .ok_or_else(|| format!("destination directory parent is not valid UTF-8: {dest_dir}"))?;
    let cleanup_targets = posix_local_source_generated_cleanup_targets(dest_dir);
    let backup_glob = posix_local_source_backup_glob(dest_dir)?;
    Ok(format!(
        "set -eu; \
if [ -d {dest_dir} ]; then rm -rf -- {cleanup_targets}; fi; \
if [ -d {parent} ]; then find {parent} -maxdepth 1 -type d -name {backup_glob} -exec rm -rf -- {{}} +; fi; \
if [ -n \"${{HOME:-}}\" ]; then rm -f -- \"$HOME\"/.rn-vm-lab-source-*.tar 2>/dev/null || true; fi",
        dest_dir = shell_quote(dest_dir),
        parent = shell_quote(parent),
        cleanup_targets = cleanup_targets,
        backup_glob = shell_quote(backup_glob.as_str()),
    ))
}

fn posix_local_source_generated_cleanup_targets(dest_dir: &str) -> String {
    let base = dest_dir.trim_end_matches('/');
    LOCAL_SOURCE_GENERATED_TOP_LEVEL_DIRS
        .iter()
        .map(|name| shell_quote(format!("{base}/{name}").as_str()))
        .collect::<Vec<_>>()
        .join(" ")
}

fn posix_local_source_backup_glob(dest_dir: &str) -> Result<String, String> {
    Path::new(dest_dir)
        .file_name()
        .and_then(|name| name.to_str())
        .filter(|name| !name.is_empty())
        .map(|name| format!("{name}.prep.*"))
        .ok_or_else(|| {
            format!("destination directory must have a final path component: {dest_dir}")
        })
}

fn build_windows_local_source_extract_script(
    dest_dir: &str,
    remote_archive_path: &str,
) -> Result<String, String> {
    ensure_no_control_chars("destination directory", dest_dir)?;
    ensure_no_control_chars("remote archive path", remote_archive_path)?;
    Ok(format!(
        "Set-StrictMode -Version Latest; \
         $ErrorActionPreference = 'Stop'; \
         $ProgressPreference = 'SilentlyContinue'; \
         $dest = {dest}; \
         $archive = {archive}; \
         $parent = Split-Path -Parent $dest; \
         $staging = Join-Path $parent ('rn-vm-lab-source-' + [guid]::NewGuid().ToString('N')); \
         $currentScriptPath = ''; \
         if ($PSCommandPath) {{ \
           try {{ $currentScriptPath = (Resolve-Path -LiteralPath $PSCommandPath -ErrorAction Stop).Path }} catch {{ $currentScriptPath = $PSCommandPath }} \
         }}; \
         if ($parent -and -not (Test-Path -LiteralPath $parent)) {{ New-Item -ItemType Directory -Force -Path $parent | Out-Null }}; \
         if (-not (Test-Path -LiteralPath $archive)) {{ throw ('Windows local source archive is missing: {{0}}' -f $archive) }}; \
         if (Test-Path -LiteralPath $staging) {{ Remove-Item -LiteralPath $staging -Recurse -Force }}; \
         try {{ \
           if (-not (Test-Path -LiteralPath $dest)) {{ New-Item -ItemType Directory -Force -Path $dest | Out-Null }}; \
           {generated_cleanup} \
           Expand-Archive -LiteralPath $archive -DestinationPath $staging -Force; \
           $stagedEntries = @(Get-ChildItem -LiteralPath $staging -Force -ErrorAction SilentlyContinue); \
           if ($stagedEntries.Count -eq 0) {{ throw ('Windows local source archive extracted no files: {{0}}' -f $archive) }}; \
           foreach ($junk in @(Get-ChildItem -LiteralPath $dest -Recurse -Force -ErrorAction SilentlyContinue | Where-Object {{ $_.Name -like '._*' -or $_.Name -eq '.DS_Store' }})) {{ \
             try {{ [System.IO.File]::Delete('\\\\?\\' + $junk.FullName) }} catch {{ }} \
           }}; \
           foreach ($existing in @(Get-ChildItem -LiteralPath $dest -Force -ErrorAction SilentlyContinue)) {{ \
             $existingPath = $existing.FullName; \
             if ($currentScriptPath -and $existingPath.Equals($currentScriptPath, [System.StringComparison]::OrdinalIgnoreCase)) {{ continue }}; \
             if ($existing.Name -like 'utm_*.ps1') {{ continue }}; \
             Remove-Item -LiteralPath $existingPath -Recurse -Force \
           }}; \
           foreach ($entry in $stagedEntries) {{ \
             Move-Item -LiteralPath $entry.FullName -Destination $dest -Force \
           }}; \
         }} catch {{ \
           $detail = if ($_.Exception -and $_.Exception.Message) {{ $_.Exception.Message.Trim() }} else {{ ($_ | Out-String).Trim() }}; \
           if (-not $detail) {{ $detail = 'windows-local-source-extract-failed' }}; \
           Write-Output ('windows-local-source-extract-error=' + $detail); \
           throw \
         }} finally {{ \
           if (Test-Path -LiteralPath $archive) {{ Remove-Item -LiteralPath $archive -Force -ErrorAction SilentlyContinue }}; \
           if (Test-Path -LiteralPath $staging) {{ Remove-Item -LiteralPath $staging -Recurse -Force -ErrorAction SilentlyContinue }} \
        }};",
        dest = powershell_quote(dest_dir)?,
        archive = powershell_quote(remote_archive_path)?,
        generated_cleanup = windows_local_source_generated_cleanup_snippet(),
    ))
}

fn build_windows_local_source_presync_cleanup_script(
    dest_dir: &str,
    archive_root: &str,
) -> Result<String, String> {
    ensure_no_control_chars("destination directory", dest_dir)?;
    ensure_no_control_chars("Windows local source archive root", archive_root)?;
    Ok(format!(
        "Set-StrictMode -Version Latest; \
         $ErrorActionPreference = 'Stop'; \
         $ProgressPreference = 'SilentlyContinue'; \
         $dest = {dest}; \
         $archiveRoot = {archive_root}; \
         $parent = Split-Path -Parent $dest; \
         if ($parent -and -not (Test-Path -LiteralPath $parent)) {{ New-Item -ItemType Directory -Force -Path $parent | Out-Null }}; \
         if (-not (Test-Path -LiteralPath $dest)) {{ New-Item -ItemType Directory -Force -Path $dest | Out-Null }}; \
         if (-not (Test-Path -LiteralPath $archiveRoot)) {{ New-Item -ItemType Directory -Force -Path $archiveRoot | Out-Null }}; \
         {generated_cleanup} \
         if (Test-Path -LiteralPath $archiveRoot) {{ \
           foreach ($archiveJunk in @(Get-ChildItem -LiteralPath $archiveRoot -Force -ErrorAction SilentlyContinue | Where-Object {{ $_.Name.StartsWith('rn-vm-lab-source-', [System.StringComparison]::Ordinal) }})) {{ \
             Remove-Item -LiteralPath $archiveJunk.FullName -Recurse -Force -ErrorAction SilentlyContinue \
           }} \
         }}",
        dest = powershell_quote(dest_dir)?,
        archive_root = powershell_quote(archive_root)?,
        generated_cleanup = windows_local_source_generated_cleanup_snippet(),
    ))
}

fn windows_local_source_generated_cleanup_snippet() -> &'static str {
    "foreach ($generatedChild in @('target', 'target-livelab', 'artifacts', '.git', 'state')) { \
       $generatedPath = Join-Path $dest $generatedChild; \
       if (Test-Path -LiteralPath $generatedPath) { Remove-Item -LiteralPath $generatedPath -Recurse -Force -ErrorAction SilentlyContinue } \
     }; \
     if ($parent -and (Test-Path -LiteralPath $parent)) { \
       $prepPrefix = (Split-Path -Leaf $dest) + '.prep.'; \
       foreach ($staleDir in @(Get-ChildItem -LiteralPath $parent -Directory -Force -ErrorAction SilentlyContinue | Where-Object { $_.Name.StartsWith($prepPrefix, [System.StringComparison]::Ordinal) -or $_.Name.StartsWith('rn-vm-lab-source-', [System.StringComparison]::Ordinal) })) { \
         Remove-Item -LiteralPath $staleDir.FullName -Recurse -Force -ErrorAction SilentlyContinue \
       } \
     };"
}

fn build_windows_local_source_extract_result_script(
    dest_dir: &str,
    remote_archive_path: &str,
    remote_result_path: &str,
) -> Result<String, String> {
    ensure_no_control_chars("destination directory", dest_dir)?;
    ensure_no_control_chars("remote archive path", remote_archive_path)?;
    ensure_no_control_chars("Windows extract result path", remote_result_path)?;
    Ok(format!(
        "Set-StrictMode -Version Latest; \
         $ErrorActionPreference = 'Stop'; \
         $ProgressPreference = 'SilentlyContinue'; \
         $dest = {dest}; \
         $archive = {archive}; \
         $resultPath = {result_path}; \
         $resultParent = Split-Path -Path $resultPath -Parent; \
         if ($resultParent -and -not (Test-Path -LiteralPath $resultParent)) {{ New-Item -ItemType Directory -Force -Path $resultParent | Out-Null }}; \
         if (Test-Path -LiteralPath $resultPath) {{ Remove-Item -LiteralPath $resultPath -Force -ErrorAction SilentlyContinue }}; \
         $parent = Split-Path -Parent $dest; \
         $staging = Join-Path $parent ('rn-vm-lab-source-' + [guid]::NewGuid().ToString('N')); \
         $currentScriptPath = ''; \
         if ($PSCommandPath) {{ \
           try {{ $currentScriptPath = (Resolve-Path -LiteralPath $PSCommandPath -ErrorAction Stop).Path }} catch {{ $currentScriptPath = $PSCommandPath }} \
         }}; \
         if ($parent -and -not (Test-Path -LiteralPath $parent)) {{ New-Item -ItemType Directory -Force -Path $parent | Out-Null }}; \
         $report = $null; \
         try {{ \
           if (-not (Test-Path -LiteralPath $archive)) {{ throw ('Windows local source archive is missing: {{0}}' -f $archive) }}; \
           if (Test-Path -LiteralPath $staging) {{ Remove-Item -LiteralPath $staging -Recurse -Force }}; \
           if (-not (Test-Path -LiteralPath $dest)) {{ New-Item -ItemType Directory -Force -Path $dest | Out-Null }}; \
           {generated_cleanup} \
           Expand-Archive -LiteralPath $archive -DestinationPath $staging -Force; \
           $stagedEntries = @(Get-ChildItem -LiteralPath $staging -Force -ErrorAction SilentlyContinue); \
           if ($stagedEntries.Count -eq 0) {{ throw ('Windows local source archive extracted no files: {{0}}' -f $archive) }}; \
           foreach ($junk in @(Get-ChildItem -LiteralPath $dest -Recurse -Force -ErrorAction SilentlyContinue | Where-Object {{ $_.Name -like '._*' -or $_.Name -eq '.DS_Store' }})) {{ \
             try {{ [System.IO.File]::Delete('\\\\?\\' + $junk.FullName) }} catch {{ }} \
           }}; \
           foreach ($existing in @(Get-ChildItem -LiteralPath $dest -Force -ErrorAction SilentlyContinue)) {{ \
             $existingPath = $existing.FullName; \
             if ($currentScriptPath -and $existingPath.Equals($currentScriptPath, [System.StringComparison]::OrdinalIgnoreCase)) {{ continue }}; \
             if ($existing.Name -like 'utm_*.ps1') {{ continue }}; \
             Remove-Item -LiteralPath $existingPath -Recurse -Force \
           }}; \
           foreach ($entry in $stagedEntries) {{ \
             Move-Item -LiteralPath $entry.FullName -Destination $dest -Force \
           }}; \
           $report = [ordered]@{{ status = 'pass'; dest = $dest }} \
         }} catch {{ \
           $detail = if ($_.Exception -and $_.Exception.Message) {{ $_.Exception.Message.Trim() }} else {{ ($_ | Out-String).Trim() }}; \
           if (-not $detail) {{ $detail = 'windows-local-source-extract-failed' }}; \
           $report = [ordered]@{{ status = 'fail'; reason = $detail; dest = $dest }} \
         }} finally {{ \
           if (Test-Path -LiteralPath $archive) {{ Remove-Item -LiteralPath $archive -Force -ErrorAction SilentlyContinue }}; \
           if (Test-Path -LiteralPath $staging) {{ Remove-Item -LiteralPath $staging -Recurse -Force -ErrorAction SilentlyContinue }} \
         }}; \
         $report | ConvertTo-Json -Compress | Set-Content -LiteralPath $resultPath -Encoding UTF8; \
         if ($report.status -ne 'pass') {{ exit 1 }}",
        dest = powershell_quote(dest_dir)?,
        archive = powershell_quote(remote_archive_path)?,
        result_path = powershell_quote(remote_result_path)?,
        generated_cleanup = windows_local_source_generated_cleanup_snippet(),
    ))
}

fn prepare_local_source_archive(
    source_dir: &Path,
    timeout: Duration,
) -> Result<LocalSourceArchive, String> {
    ensure_local_directory_path(source_dir, "local source dir")?;
    let archive_path =
        std::env::temp_dir().join(format!("rustynet-vm-lab-source-{}.tar", unique_suffix()));
    let extras = prepare_local_source_bundle_extras(source_dir, timeout)?;
    if let Err(git_err) =
        write_git_worktree_archive(source_dir, archive_path.as_path(), timeout, extras.as_ref())
        && let Err(raw_err) =
            write_raw_directory_archive(source_dir, archive_path.as_path(), extras.as_ref())
    {
        let _ = fs::remove_file(archive_path.as_path());
        return Err(format!(
            "local source archive failed via git-managed path ({git_err}); raw directory fallback also failed ({raw_err})"
        ));
    }
    Ok(LocalSourceArchive { path: archive_path })
}

/// macOS metadata sidecars (AppleDouble `._*`, Finder `.DS_Store`) must never
/// ship in source archives. AppleDouble names include POSIX-only forms such as
/// `._.` (trailing dot) that Win32 path normalization cannot address once they
/// land on NTFS, permanently bricking extraction cleanup on Windows guests.
fn is_macos_metadata_artifact_name(name: &str) -> bool {
    name == ".DS_Store" || name.starts_with("._")
}

fn path_contains_macos_metadata_artifact(path: &Path) -> bool {
    path.components().any(|component| {
        matches!(
            component,
            std::path::Component::Normal(name)
                if name.to_str().is_some_and(is_macos_metadata_artifact_name)
        )
    })
}

fn prepare_local_source_zip_archive(
    source_dir: &Path,
    timeout: Duration,
) -> Result<LocalSourceArchive, String> {
    ensure_local_directory_path(source_dir, "local source dir")?;
    let archive_path =
        std::env::temp_dir().join(format!("rustynet-vm-lab-source-{}.zip", unique_suffix()));
    let extras = prepare_local_source_bundle_extras(source_dir, timeout)?;
    if let Err(git_err) =
        write_git_worktree_zip_archive(source_dir, archive_path.as_path(), timeout, extras.as_ref())
        && let Err(raw_err) =
            write_raw_directory_zip_archive(source_dir, archive_path.as_path(), extras.as_ref())
    {
        let _ = fs::remove_file(archive_path.as_path());
        return Err(format!(
            "local ZIP source archive failed via git-managed path ({git_err}); raw directory fallback also failed ({raw_err})"
        ));
    }
    Ok(LocalSourceArchive { path: archive_path })
}

fn write_raw_directory_archive(
    source_dir: &Path,
    archive_path: &Path,
    extras: Option<&LocalSourceBundleExtras>,
) -> Result<(), String> {
    let file = fs::File::create(archive_path).map_err(|err| {
        format!(
            "create raw local source archive failed ({}): {err}",
            archive_path.display()
        )
    })?;
    let mut archive = Builder::new(file);
    let mut included = 0usize;
    append_raw_local_source_tree(&mut archive, source_dir, source_dir, &mut included)?;
    append_local_source_bundle_extras(&mut archive, extras, &mut included)?;
    if included == 0 {
        let _ = fs::remove_file(archive_path);
        return Err(format!(
            "local source dir did not yield any syncable files: {}",
            source_dir.display()
        ));
    }
    archive.finish().map_err(|err| {
        format!(
            "finalize raw local source archive failed ({}): {err}",
            archive_path.display()
        )
    })
}

fn write_raw_directory_zip_archive(
    source_dir: &Path,
    archive_path: &Path,
    extras: Option<&LocalSourceBundleExtras>,
) -> Result<(), String> {
    let file = fs::File::create(archive_path).map_err(|err| {
        format!(
            "create raw local ZIP source archive failed ({}): {err}",
            archive_path.display()
        )
    })?;
    let mut zip = ZipWriter::new(file);
    let options = SimpleFileOptions::default()
        .compression_method(CompressionMethod::Deflated)
        .unix_permissions(0o644);
    let mut included = 0usize;
    append_raw_local_source_tree_to_zip(&mut zip, &options, source_dir, source_dir, &mut included)?;
    append_local_source_bundle_extras_to_zip(&mut zip, &options, extras, &mut included)?;
    if included == 0 {
        let _ = fs::remove_file(archive_path);
        return Err(format!(
            "local source dir did not yield any syncable files for ZIP archive: {}",
            source_dir.display()
        ));
    }
    zip.finish().map_err(|err| {
        format!(
            "finalize raw local ZIP source archive failed ({}): {err}",
            archive_path.display()
        )
    })?;
    Ok(())
}

fn write_git_worktree_archive(
    source_dir: &Path,
    archive_path: &Path,
    timeout: Duration,
    extras: Option<&LocalSourceBundleExtras>,
) -> Result<(), String> {
    let mut list_command = Command::new("git");
    list_command.arg("-C").arg(source_dir).args([
        "ls-files",
        "-z",
        "--cached",
        "--others",
        "--exclude-standard",
    ]);
    let output = run_output_with_timeout(&mut list_command, timeout)?;
    if !output.status.success() {
        return Err(format!(
            "collect local source file list failed with status {}",
            status_code(output.status)
        ));
    }

    let mut archive = Builder::new(fs::File::create(archive_path).map_err(|err| {
        format!(
            "create local source archive failed ({}): {err}",
            archive_path.display()
        )
    })?);
    let mut included = 0usize;
    let mut seen = HashSet::new();
    for raw_path in output.stdout.split(|byte| *byte == 0) {
        if raw_path.is_empty() {
            continue;
        }
        let relative = std::str::from_utf8(raw_path)
            .map_err(|err| format!("local source file list contained non-utf8 path: {err}"))?;
        if relative.is_empty() || !seen.insert(relative.to_owned()) {
            continue;
        }
        let relative_path = Path::new(relative);
        if should_skip_local_source_path(relative_path) {
            continue;
        }
        let absolute_path = source_dir.join(relative_path);
        if !absolute_path.exists() {
            continue;
        }
        archive
            .append_path_with_name(absolute_path.as_path(), relative_path)
            .map_err(|err| {
                format!(
                    "append local source path failed ({}): {err}",
                    relative_path.display()
                )
            })?;
        included += 1;
    }
    append_local_source_bundle_extras(&mut archive, extras, &mut included)?;
    if included == 0 {
        return Err(format!(
            "local source dir did not yield any syncable files: {}",
            source_dir.display()
        ));
    }
    archive.finish().map_err(|err| {
        format!(
            "finalize local source archive failed ({}): {err}",
            archive_path.display()
        )
    })
}

fn write_git_worktree_zip_archive(
    source_dir: &Path,
    archive_path: &Path,
    timeout: Duration,
    extras: Option<&LocalSourceBundleExtras>,
) -> Result<(), String> {
    let mut list_command = Command::new("git");
    list_command.arg("-C").arg(source_dir).args([
        "ls-files",
        "-z",
        "--cached",
        "--others",
        "--exclude-standard",
    ]);
    let output = run_output_with_timeout(&mut list_command, timeout)?;
    if !output.status.success() {
        return Err(format!(
            "collect local ZIP source file list failed with status {}",
            status_code(output.status)
        ));
    }

    let file = fs::File::create(archive_path).map_err(|err| {
        format!(
            "create local ZIP source archive failed ({}): {err}",
            archive_path.display()
        )
    })?;
    let mut zip = ZipWriter::new(file);
    let options = SimpleFileOptions::default()
        .compression_method(CompressionMethod::Deflated)
        .unix_permissions(0o644);
    let mut included = 0usize;
    let mut seen = HashSet::new();
    for raw_path in output.stdout.split(|byte| *byte == 0) {
        if raw_path.is_empty() {
            continue;
        }
        let relative = std::str::from_utf8(raw_path)
            .map_err(|err| format!("local source file list contained non-utf8 path: {err}"))?;
        if relative.is_empty() || !seen.insert(relative.to_owned()) {
            continue;
        }
        let relative_path = Path::new(relative);
        if should_skip_local_source_path(relative_path) {
            continue;
        }
        let absolute_path = source_dir.join(relative_path);
        if !absolute_path.is_file() {
            continue;
        }
        append_file_to_zip(
            &mut zip,
            &options,
            absolute_path.as_path(),
            relative_path,
            &mut included,
        )?;
    }
    append_local_source_bundle_extras_to_zip(&mut zip, &options, extras, &mut included)?;
    if included == 0 {
        return Err(format!(
            "local source dir did not yield any syncable files for ZIP archive: {}",
            source_dir.display()
        ));
    }
    zip.finish().map_err(|err| {
        format!(
            "finalize local ZIP source archive failed ({}): {err}",
            archive_path.display()
        )
    })?;
    Ok(())
}

fn prepare_local_source_bundle_extras(
    source_dir: &Path,
    timeout: Duration,
) -> Result<Option<LocalSourceBundleExtras>, String> {
    let manifest_path = source_dir.join("Cargo.toml");
    if !manifest_path.is_file() {
        return Ok(None);
    }
    let manifest_path = fs::canonicalize(manifest_path.as_path()).map_err(|err| {
        format!(
            "canonicalize local source manifest failed ({}): {err}",
            manifest_path.display()
        )
    })?;

    let temp_root =
        std::env::temp_dir().join(format!("rustynet-vm-lab-bundle-{}", unique_suffix()));
    fs::create_dir_all(temp_root.as_path()).map_err(|err| {
        format!(
            "create local source bundle dir failed ({}): {err}",
            temp_root.display()
        )
    })?;
    let vendor_dir = temp_root.join("vendor");
    let mut command = Command::new("cargo");
    command
        .current_dir(temp_root.as_path())
        .arg("vendor")
        .arg("--locked")
        .arg("--offline")
        .arg("--versioned-dirs")
        .arg("--manifest-path")
        .arg(manifest_path.as_os_str())
        .arg("vendor");
    let output = run_output_with_timeout(&mut command, timeout)?;
    if !output.status.success() {
        let stderr = String::from_utf8_lossy(output.stderr.as_slice())
            .trim()
            .to_owned();
        if stderr.contains("--offline was specified")
            || stderr.contains("failed to download")
            || stderr.contains("failed to sync")
        {
            let _ = fs::remove_dir_all(temp_root.as_path());
            return Ok(None);
        }
        let _ = fs::remove_dir_all(temp_root.as_path());
        return Err(format!(
            "prepare vendored cargo dependencies failed with status {}{}",
            status_code(output.status),
            if stderr.is_empty() {
                String::new()
            } else {
                format!(": {stderr}")
            }
        ));
    }

    let cargo_config_dir = temp_root.join(".cargo");
    fs::create_dir_all(cargo_config_dir.as_path()).map_err(|err| {
        format!(
            "create vendored cargo config dir failed ({}): {err}",
            cargo_config_dir.display()
        )
    })?;
    let cargo_config_path = cargo_config_dir.join("config.toml");
    let vendor_stdout = String::from_utf8(output.stdout)
        .map_err(|err| format!("vendored cargo config was not valid UTF-8: {err}"))?;
    fs::write(
        cargo_config_path.as_path(),
        build_vendored_cargo_config(vendor_stdout.as_str()).as_bytes(),
    )
    .map_err(|err| {
        format!(
            "write vendored cargo config failed ({}): {err}",
            cargo_config_path.display()
        )
    })?;

    Ok(Some(LocalSourceBundleExtras {
        temp_root,
        vendor_dir: Some(vendor_dir),
        cargo_config_path: Some(cargo_config_path),
    }))
}

fn build_vendored_cargo_config(vendor_stdout: &str) -> String {
    let mut config = vendor_stdout.trim().to_owned();
    if !config.ends_with('\n') {
        config.push('\n');
    }
    config.push_str("\n[net]\noffline = true\n");
    config
}

fn append_local_source_bundle_extras(
    archive: &mut Builder<fs::File>,
    extras: Option<&LocalSourceBundleExtras>,
    included: &mut usize,
) -> Result<(), String> {
    let Some(extras) = extras else {
        return Ok(());
    };
    if let Some(vendor_dir) = extras.vendor_dir.as_deref() {
        append_directory_tree_to_archive(archive, vendor_dir, Path::new("vendor"), included)?;
    }
    if let Some(cargo_config_path) = extras.cargo_config_path.as_deref() {
        archive
            .append_path_with_name(cargo_config_path, Path::new(".cargo/config.toml"))
            .map_err(|err| {
                format!(
                    "append vendored cargo config failed ({}): {err}",
                    cargo_config_path.display()
                )
            })?;
        *included += 1;
    }
    Ok(())
}

fn append_local_source_bundle_extras_to_zip(
    zip: &mut ZipWriter<fs::File>,
    options: &SimpleFileOptions,
    extras: Option<&LocalSourceBundleExtras>,
    included: &mut usize,
) -> Result<(), String> {
    let Some(extras) = extras else {
        return Ok(());
    };
    if let Some(vendor_dir) = extras.vendor_dir.as_deref() {
        append_directory_tree_to_zip(zip, options, vendor_dir, Path::new("vendor"), included)?;
    }
    if let Some(cargo_config_path) = extras.cargo_config_path.as_deref() {
        append_file_to_zip(
            zip,
            options,
            cargo_config_path,
            Path::new(".cargo/config.toml"),
            included,
        )?;
    }
    Ok(())
}

fn append_raw_local_source_tree(
    archive: &mut Builder<fs::File>,
    source_root: &Path,
    current_dir: &Path,
    included: &mut usize,
) -> Result<(), String> {
    let entries = fs::read_dir(current_dir).map_err(|err| {
        format!(
            "read local source dir failed ({}): {err}",
            current_dir.display()
        )
    })?;
    for entry in entries {
        let entry = entry.map_err(|err| {
            format!(
                "read local source dir entry failed ({}): {err}",
                current_dir.display()
            )
        })?;
        let path = entry.path();
        let relative = path.strip_prefix(source_root).map_err(|err| {
            format!(
                "strip local source prefix failed ({}): {err}",
                path.display()
            )
        })?;
        if should_skip_local_source_path(relative) {
            continue;
        }
        let file_type = entry.file_type().map_err(|err| {
            format!(
                "read local source entry type failed ({}): {err}",
                path.display()
            )
        })?;
        if file_type.is_dir() {
            append_raw_local_source_tree(archive, source_root, path.as_path(), included)?;
            continue;
        }
        archive
            .append_path_with_name(path.as_path(), relative)
            .map_err(|err| {
                format!(
                    "append raw local source path failed ({}): {err}",
                    relative.display()
                )
            })?;
        *included += 1;
    }
    Ok(())
}

fn append_raw_local_source_tree_to_zip(
    zip: &mut ZipWriter<fs::File>,
    options: &SimpleFileOptions,
    source_root: &Path,
    current_dir: &Path,
    included: &mut usize,
) -> Result<(), String> {
    let entries = fs::read_dir(current_dir).map_err(|err| {
        format!(
            "read local ZIP source dir failed ({}): {err}",
            current_dir.display()
        )
    })?;
    for entry in entries {
        let entry = entry.map_err(|err| {
            format!(
                "read local ZIP source dir entry failed ({}): {err}",
                current_dir.display()
            )
        })?;
        let path = entry.path();
        let relative = path.strip_prefix(source_root).map_err(|err| {
            format!(
                "strip local ZIP source prefix failed ({}): {err}",
                path.display()
            )
        })?;
        if should_skip_local_source_path(relative) {
            continue;
        }
        let file_type = entry.file_type().map_err(|err| {
            format!(
                "read local ZIP source entry type failed ({}): {err}",
                path.display()
            )
        })?;
        if file_type.is_dir() {
            append_raw_local_source_tree_to_zip(
                zip,
                options,
                source_root,
                path.as_path(),
                included,
            )?;
            continue;
        }
        append_file_to_zip(zip, options, path.as_path(), relative, included)?;
    }
    Ok(())
}

fn append_directory_tree_to_archive(
    archive: &mut Builder<fs::File>,
    source_root: &Path,
    archive_root: &Path,
    included: &mut usize,
) -> Result<(), String> {
    let entries = fs::read_dir(source_root).map_err(|err| {
        format!(
            "read archive source dir failed ({}): {err}",
            source_root.display()
        )
    })?;
    for entry in entries {
        let entry = entry.map_err(|err| {
            format!(
                "read archive source dir entry failed ({}): {err}",
                source_root.display()
            )
        })?;
        let path = entry.path();
        if is_macos_metadata_artifact_name(entry.file_name().to_string_lossy().as_ref()) {
            continue;
        }
        let archive_path = archive_root.join(entry.file_name());
        let file_type = entry.file_type().map_err(|err| {
            format!(
                "read archive source entry type failed ({}): {err}",
                path.display()
            )
        })?;
        if file_type.is_dir() {
            append_directory_tree_to_archive(
                archive,
                path.as_path(),
                archive_path.as_path(),
                included,
            )?;
            continue;
        }
        archive
            .append_path_with_name(path.as_path(), archive_path.as_path())
            .map_err(|err| {
                format!(
                    "append archive source path failed ({}): {err}",
                    archive_path.display()
                )
            })?;
        *included += 1;
    }
    Ok(())
}

fn append_directory_tree_to_zip(
    zip: &mut ZipWriter<fs::File>,
    options: &SimpleFileOptions,
    source_root: &Path,
    archive_root: &Path,
    included: &mut usize,
) -> Result<(), String> {
    let entries = fs::read_dir(source_root).map_err(|err| {
        format!(
            "read ZIP archive source dir failed ({}): {err}",
            source_root.display()
        )
    })?;
    for entry in entries {
        let entry = entry.map_err(|err| {
            format!(
                "read ZIP archive source dir entry failed ({}): {err}",
                source_root.display()
            )
        })?;
        let path = entry.path();
        if is_macos_metadata_artifact_name(entry.file_name().to_string_lossy().as_ref()) {
            continue;
        }
        let archive_path = archive_root.join(entry.file_name());
        let file_type = entry.file_type().map_err(|err| {
            format!(
                "read ZIP archive source entry type failed ({}): {err}",
                path.display()
            )
        })?;
        if file_type.is_dir() {
            append_directory_tree_to_zip(
                zip,
                options,
                path.as_path(),
                archive_path.as_path(),
                included,
            )?;
            continue;
        }
        append_file_to_zip(
            zip,
            options,
            path.as_path(),
            archive_path.as_path(),
            included,
        )?;
    }
    Ok(())
}

fn append_file_to_zip(
    zip: &mut ZipWriter<fs::File>,
    options: &SimpleFileOptions,
    source_path: &Path,
    archive_path: &Path,
    included: &mut usize,
) -> Result<(), String> {
    let name = archive_path
        .to_str()
        .ok_or_else(|| {
            format!(
                "path is not valid UTF-8 for ZIP archive: {}",
                archive_path.display()
            )
        })?
        .replace('\\', "/");
    zip.start_file(name, *options).map_err(|err| {
        format!(
            "start ZIP file entry failed ({}): {err}",
            archive_path.display()
        )
    })?;
    let mut input = fs::File::open(source_path).map_err(|err| {
        format!(
            "open ZIP source file failed ({}): {err}",
            source_path.display()
        )
    })?;
    std::io::copy(&mut input, zip)
        .map_err(|err| format!("write ZIP entry failed ({}): {err}", archive_path.display()))?;
    *included += 1;
    Ok(())
}

fn should_skip_local_source_path(relative: &Path) -> bool {
    if path_contains_macos_metadata_artifact(relative) {
        return true;
    }
    let first = relative.components().next();
    matches!(
        first,
        Some(std::path::Component::Normal(name))
            if name
                .to_str()
                .is_some_and(|value| LOCAL_SOURCE_ARCHIVE_EXCLUDED_TOP_LEVEL_DIRS.contains(&value))
    )
}

fn sync_local_source_archive_to_target(
    archive_path: &Path,
    target: &RemoteTarget,
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    dest_dir: &str,
    timeout: Duration,
) -> Result<(), String> {
    ensure_local_regular_file_path(archive_path, "local source archive")?;
    if target.platform_profile.platform == VmGuestPlatform::Windows {
        // Stage the archive under windows_orchestration_root so the SSH
        // user can SCP it AND the SYSTEM-context utmctl can read the
        // companion .result.json that the extract wrapper writes.  The
        // legacy vm-lab path was unreachable from utmctl on UTM Windows
        // guests (state-tree hardening strips the SYSTEM ACE) and was
        // wedging the result-file pull retry loop.
        let archive_root = windows_orchestration_root(target);
        let archive_root = archive_root.trim_end_matches(['\\', '/']);
        let cleanup_script =
            build_windows_local_source_presync_cleanup_script(dest_dir, archive_root)?;
        let cleanup_status = run_remote_shell_command_for_target(
            target,
            ssh_user_override,
            ssh_identity_file,
            known_hosts_path,
            cleanup_script.as_str(),
            timeout,
        )?;
        ensure_success_status(
            cleanup_status,
            "cleanup stale Windows local source artifacts before archive copy",
        )?;
        let remote_archive = format!(r"{archive_root}\rn-vm-lab-source-{}.zip", unique_suffix());
        ensure_success_status(
            scp_to_remote_for_target(
                target,
                ssh_user_override,
                ssh_identity_file,
                known_hosts_path,
                archive_path,
                remote_archive.as_str(),
                timeout,
            )?,
            "copy local ZIP source archive to Windows remote",
        )?;
        if remote_target_local_utm(target).is_some() {
            let (utm_name, _) = remote_target_local_utm(target).expect("validated local UTM");
            let remote_result_path = format!(r"{remote_archive}.result.json");
            let output = execute_windows_local_utm_result_file_probe(
                utm_name,
                "Windows local source extract",
                timeout,
                remote_result_path.as_str(),
                |remote_result_path| {
                    build_windows_local_source_extract_result_script(
                        dest_dir,
                        remote_archive.as_str(),
                        remote_result_path,
                    )
                },
            )?;
            let parsed: serde_json::Value =
                serde_json::from_str(output.as_str()).map_err(|err| {
                    format!("Windows local source extract returned invalid JSON: {err}")
                })?;
            let status = parsed
                .get("status")
                .and_then(|value| value.as_str())
                .unwrap_or("fail");
            if status == "pass" {
                return Ok(());
            }
            let reason = parsed
                .get("reason")
                .and_then(|value| value.as_str())
                .unwrap_or("windows-local-source-extract-failed");
            return Err(format!(
                "extract local ZIP source archive on Windows remote failed: {reason}"
            ));
        }
        let extract_script =
            build_windows_local_source_extract_script(dest_dir, remote_archive.as_str())?;
        let status = run_remote_shell_command_for_target(
            target,
            ssh_user_override,
            ssh_identity_file,
            known_hosts_path,
            extract_script.as_str(),
            timeout,
        )?;
        return ensure_success_status(status, "extract local ZIP source archive on Windows remote");
    }
    let cleanup_script = build_local_source_presync_cleanup_script(dest_dir)?;
    let cleanup_status = run_remote_shell_command_for_target(
        target,
        ssh_user_override,
        ssh_identity_file,
        known_hosts_path,
        cleanup_script.as_str(),
        timeout,
    )?;
    ensure_success_status(
        cleanup_status,
        "cleanup stale local source artifacts before archive copy",
    )?;
    // These guest images accept SFTP writes into the SSH user's home directory
    // reliably, while absolute /tmp uploads are rejected on some hosts.
    let remote_archive = if remote_target_local_utm(target).is_some() {
        let ssh_user = remote_target_effective_user(target, ssh_user_override)?;
        format!(
            "{}/.rn-vm-lab-source-{}.tar",
            remote_target_home(ssh_user.as_str()),
            unique_suffix()
        )
    } else {
        format!(".rn-vm-lab-source-{}.tar", unique_suffix())
    };
    ensure_success_status(
        scp_to_remote_for_target(
            target,
            ssh_user_override,
            ssh_identity_file,
            known_hosts_path,
            archive_path,
            remote_archive.as_str(),
            timeout,
        )?,
        "copy local source archive to remote",
    )?;
    let extract_script = build_local_source_extract_script(dest_dir, remote_archive.as_str())?;
    let status = run_remote_shell_command_for_target(
        target,
        ssh_user_override,
        ssh_identity_file,
        known_hosts_path,
        extract_script.as_str(),
        timeout,
    )?;
    ensure_success_status(status, "extract local source archive on remote")
}

fn build_remote_argv_script(
    workdir: &str,
    program: &str,
    argv: &[String],
    sudo: bool,
) -> Result<String, String> {
    ensure_no_control_chars("workdir", workdir)?;
    ensure_no_control_chars("program", program)?;
    let mut command = String::new();
    if sudo {
        command.push_str("sudo -n -- ");
    } else {
        command.push_str("exec ");
    }
    command.push_str(shell_quote(program).as_str());
    for arg in argv {
        ensure_no_control_chars("command arg", arg.as_str())?;
        command.push(' ');
        command.push_str(shell_quote(arg.as_str()).as_str());
    }
    if sudo {
        command = format!("exec {command}");
    }
    Ok(format!("set -eu; cd {}; {}", shell_quote(workdir), command))
}

fn ensure_optional_local_regular_file_path(path: Option<&Path>, label: &str) -> Result<(), String> {
    if let Some(path) = path {
        ensure_local_regular_file_path(path, label)?;
    }
    Ok(())
}

fn append_ssh_transport_options(
    command: &mut Command,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
) -> Result<(), String> {
    ensure_optional_local_regular_file_path(ssh_identity_file, "SSH identity file")?;
    ensure_optional_local_regular_file_path(known_hosts_path, "SSH known_hosts file")?;
    if let Some(path) = ssh_identity_file {
        command.arg("-i").arg(path);
    }
    if let Some(path) = known_hosts_path {
        command
            .arg("-o")
            .arg(format!("UserKnownHostsFile={}", path.display()));
    }
    Ok(())
}

fn remote_target_local_utm(target: &RemoteTarget) -> Option<(&str, &Path)> {
    match target.controller.as_ref() {
        Some(VmController::LocalUtm {
            utm_name,
            bundle_path,
        }) => Some((utm_name.as_str(), bundle_path.as_path())),
        None => None,
    }
}

fn remote_target_effective_user(
    target: &RemoteTarget,
    ssh_user_override: Option<&str>,
) -> Result<String, String> {
    if let Some(ssh_user) = ssh_user_override {
        ensure_ssh_user(ssh_user)?;
        return Ok(ssh_user.to_owned());
    }
    if let Some(ssh_user) = target.ssh_user.as_deref() {
        ensure_ssh_user(ssh_user)?;
        return Ok(ssh_user.to_owned());
    }
    if let Some(ssh_user) = ssh_target_user(target.ssh_target.as_str()) {
        ensure_ssh_user(ssh_user)?;
        return Ok(ssh_user.to_owned());
    }
    Err(format!(
        "UTM-backed target {} requires an explicit ssh_user or user@host SSH target",
        target.label
    ))
}

fn remote_target_home(ssh_user: &str) -> String {
    if ssh_user == "root" {
        "/root".to_owned()
    } else {
        format!("/home/{ssh_user}")
    }
}

fn utmctl_binary_path() -> Result<PathBuf, String> {
    let path = default_utmctl_path();
    if !path.is_file() {
        return Err(format!("utmctl binary is not present: {}", path.display()));
    }
    Ok(path)
}

fn utm_push_raw(
    utm_name: &str,
    src: &Path,
    dst: &str,
    timeout: Duration,
) -> Result<ExitStatus, String> {
    ensure_local_regular_file_path(src, "UTM push source file")?;
    ensure_no_control_chars("UTM push destination path", dst)?;
    let utmctl_path = utmctl_binary_path()?;
    let stdin = fs::File::open(src)
        .map_err(|err| format!("open UTM push source failed ({}): {err}", src.display()))?;
    let mut command = Command::new(utmctl_path);
    command.arg("file").arg("push").arg(utm_name).arg(dst);
    command.stdin(Stdio::from(stdin));
    command.stdout(Stdio::null());
    command.stderr(Stdio::piped());
    // Use _preserve to avoid run_output_with_timeout overriding our stdin setup.
    let output = run_output_with_timeout_preserve(&mut command, timeout)?;
    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_owned();
    if !stderr.is_empty() {
        return Err(format!(
            "UTM file push reported error for {utm_name}:{dst}: {stderr}"
        ));
    }
    Ok(output.status)
}

fn utm_pull_raw(
    utm_name: &str,
    src: &str,
    dst: &Path,
    timeout: Duration,
) -> Result<ExitStatus, String> {
    ensure_no_control_chars("UTM pull source path", src)?;
    let utmctl_path = utmctl_binary_path()?;
    let parent = dst.parent().filter(|path| !path.as_os_str().is_empty());
    if let Some(parent) = parent {
        fs::create_dir_all(parent).map_err(|err| {
            format!(
                "create UTM pull destination dir failed ({}): {err}",
                parent.display()
            )
        })?;
    }
    let mut command = Command::new(utmctl_path);
    command.arg("file").arg("pull").arg(utm_name).arg(src);
    let output = run_output_with_timeout(&mut command, timeout)?;
    fs::write(dst, &output.stdout).map_err(|err| {
        format!(
            "write UTM pull destination failed ({}): {err}",
            dst.display()
        )
    })?;
    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_owned();
    if !stderr.is_empty() {
        let _ = fs::remove_file(dst);
        return Err(format!(
            "UTM file pull reported error for {utm_name}:{src}: {stderr}"
        ));
    }
    Ok(output.status)
}

fn utm_exec_root_raw(
    utm_name: &str,
    command_script: &str,
    timeout: Duration,
) -> Result<ExitStatus, String> {
    ensure_no_control_chars("UTM exec command", command_script)?;
    let utmctl_path = utmctl_binary_path()?;
    let mut command = Command::new(utmctl_path);
    command.arg("exec").arg(utm_name);
    // Use a single `--cmd` followed by bare positional args. The Linux
    // QEMU guest agent delivers subsequent `--cmd` tokens as literal argv
    // elements to the executed binary (i.e. bash receives "--cmd" as an
    // unknown option and exits 2). Passing a single `--cmd /bin/bash`
    // then bare positionals keeps the argv clean on both Linux QEMU and
    // the Windows UTM guest-agent path. The collapsing issue observed for
    // the Windows powershell.exe path in livelab4/5 was specific to the
    // Windows guest agent and does not affect Linux; the Windows exec path
    // uses `utm_exec_windows_raw`/`append_utmctl_windows_exec_command`
    // instead of this function.
    command
        .arg("--cmd")
        .arg("/bin/bash")
        .arg("-lc")
        .arg(command_script);
    run_status_with_timeout(&mut command, timeout)
}

/// Ensure a directory exists on the Windows guest before any
/// `utm_push_raw` to a path inside it. utmctl file push does NOT create
/// intermediate directories — pushing to a missing path returns
/// `OSStatus -2700` ("The system cannot find the path specified.").
///
/// Idempotent: `New-Item -Force` on an existing directory is a no-op.
fn ensure_utm_windows_dir(
    utm_name: &str,
    remote_dir: &str,
    timeout: Duration,
) -> Result<(), String> {
    ensure_no_control_chars("UTM Windows dir", remote_dir)?;
    let quoted = powershell_quote(remote_dir)?;
    let script = format!(
        "Set-StrictMode -Version Latest; \
         $ErrorActionPreference = 'Stop'; \
         New-Item -ItemType Directory -Force -Path {quoted} | Out-Null"
    );
    let status = utm_exec_windows_raw(utm_name, script.as_str(), timeout)?;
    if !status.success() {
        return Err(format!(
            "UTM Windows mkdir for {utm_name}:{remote_dir} exited with status {}",
            status_code(status)
        ));
    }
    Ok(())
}

fn utm_cleanup_exec_files(
    utm_name: &str,
    remote_script: &str,
    remote_wrapper: &str,
    remote_output: &str,
    remote_rc: &str,
) {
    let cleanup = format!(
        "rm -f {} {} {} {}",
        shell_quote(remote_script),
        shell_quote(remote_wrapper),
        shell_quote(remote_output),
        shell_quote(remote_rc),
    );
    let _ = utm_exec_root_raw(utm_name, cleanup.as_str(), Duration::from_secs(20));
}

fn execute_utm_remote_script_as_user(
    utm_name: &str,
    ssh_user: &str,
    home: &str,
    remote_script: &str,
    timeout: Duration,
) -> Result<(i32, String), String> {
    ensure_ssh_user(ssh_user)?;
    ensure_no_control_chars("UTM exec home", home)?;
    if remote_script.chars().any(|ch| ch == '\0') {
        return Err("UTM remote script contains unsupported NUL byte".to_owned());
    }

    let temp_root = std::env::temp_dir().join(format!("rustynet-vm-lab-utm-{}", unique_suffix()));
    fs::create_dir_all(temp_root.as_path()).map_err(|err| {
        format!(
            "create local UTM helper dir failed ({}): {err}",
            temp_root.display()
        )
    })?;
    let local_script = temp_root.join("command.sh");
    let local_wrapper = temp_root.join("wrapper.sh");
    let local_output = temp_root.join("output.txt");
    let local_rc = temp_root.join("rc.txt");
    fs::write(
        local_script.as_path(),
        format!("#!/usr/bin/env bash\nset -euo pipefail\n{remote_script}\n").as_bytes(),
    )
    .map_err(|err| {
        let _ = fs::remove_dir_all(temp_root.as_path());
        format!(
            "write local UTM command script failed ({}): {err}",
            local_script.display()
        )
    })?;
    fs::write(
        local_wrapper.as_path(),
        br#"#!/usr/bin/env bash
set -euo pipefail

if [[ $# -ne 5 ]]; then
  echo "usage: rn-utm-wrapper.sh <user> <home> <command-script> <output-path> <rc-path>" >&2
  exit 2
fi

user="$1"
home="$2"
command_script="$3"
output_path="$4"
rc_path="$5"
rc=0

if [[ "$user" == "root" ]]; then
  chmod 700 "$command_script"
  if /usr/bin/env HOME="$home" USER=root LOGNAME=root PATH=/usr/local/bin:/usr/bin:/bin:/usr/sbin:/sbin \
    /bin/bash "$command_script" >"$output_path" 2>&1
  then
    rc=0
  else
    rc=$?
  fi
else
  chmod 755 "$command_script"
  if runuser -u "$user" -- env HOME="$home" USER="$user" LOGNAME="$user" PATH=/usr/local/bin:/usr/bin:/bin:/usr/sbin:/sbin \
    /bin/bash "$command_script" >"$output_path" 2>&1
  then
    rc=0
  else
    rc=$?
  fi
fi

printf '%s\n' "$rc" > "$rc_path"
sync "$output_path" "$rc_path" >/dev/null 2>&1 || sync >/dev/null 2>&1 || true
exit 0
"#,
    )
    .map_err(|err| {
        let _ = fs::remove_dir_all(temp_root.as_path());
        format!(
            "write local UTM wrapper script failed ({}): {err}",
            local_wrapper.display()
        )
    })?;

    let remote_base = format!("/var/tmp/rn-utm-exec.{}", unique_suffix());
    let remote_command_path = format!("{remote_base}.sh");
    let remote_wrapper_path = format!("{remote_base}.wrapper.sh");
    let remote_output_path = format!("{remote_base}.out");
    let remote_rc_path = format!("{remote_base}.rc");

    let push_timeout = timeout.min(Duration::from_secs(60));
    for (path, destination, label) in [
        (
            local_script.as_path(),
            remote_command_path.as_str(),
            "command",
        ),
        (
            local_wrapper.as_path(),
            remote_wrapper_path.as_str(),
            "wrapper",
        ),
    ] {
        let status = utm_push_raw(utm_name, path, destination, push_timeout).map_err(|err| {
            let _ = fs::remove_dir_all(temp_root.as_path());
            format!("UTM push {label} script failed: {err}")
        })?;
        if !status.success() {
            let _ = fs::remove_dir_all(temp_root.as_path());
            return Err(format!(
                "UTM push {label} script failed with status {}",
                status_code(status)
            ));
        }
    }

    let host_status = {
        let utmctl_path = utmctl_binary_path()?;
        let mut command = Command::new(utmctl_path);
        command.arg("exec").arg(utm_name);
        // Explicit `--cmd` per arg (matches utmctl's documented syntax,
        // never collapses positional args). See utm_exec_root_raw above
        // for the same fix on the bash-utmctl path.
        for arg in [
            "/bin/bash",
            remote_wrapper_path.as_str(),
            ssh_user,
            home,
            remote_command_path.as_str(),
            remote_output_path.as_str(),
            remote_rc_path.as_str(),
        ] {
            command.arg("--cmd").arg(arg);
        }
        run_status_with_timeout(&mut command, timeout + Duration::from_secs(30))?
    };
    if !host_status.success() {
        utm_cleanup_exec_files(
            utm_name,
            remote_command_path.as_str(),
            remote_wrapper_path.as_str(),
            remote_output_path.as_str(),
            remote_rc_path.as_str(),
        );
        let _ = fs::remove_dir_all(temp_root.as_path());
        return Err(format!(
            "UTM exec wrapper failed with status {}",
            status_code(host_status)
        ));
    }

    let max_rc_attempts = timeout.as_secs().max(10);
    let mut rc = None;
    for attempt in 1..=max_rc_attempts {
        let rc_status = utm_pull_raw(
            utm_name,
            remote_rc_path.as_str(),
            local_rc.as_path(),
            push_timeout,
        )?;
        if rc_status.success()
            && let Ok(rc_text) = fs::read_to_string(local_rc.as_path())
            && let Ok(parsed_rc) = rc_text.trim().parse::<i32>()
        {
            rc = Some(parsed_rc);
            break;
        }
        if attempt < max_rc_attempts {
            thread::sleep(Duration::from_secs(1));
        }
    }
    let rc = if let Some(rc) = rc {
        rc
    } else {
        utm_cleanup_exec_files(
            utm_name,
            remote_command_path.as_str(),
            remote_wrapper_path.as_str(),
            remote_output_path.as_str(),
            remote_rc_path.as_str(),
        );
        let _ = fs::remove_dir_all(temp_root.as_path());
        return Err(format!(
            "parse local UTM exit-code failed ({}): cannot parse integer from empty string",
            local_rc.display()
        ));
    };
    let output_status = utm_pull_raw(
        utm_name,
        remote_output_path.as_str(),
        local_output.as_path(),
        push_timeout,
    )?;
    if !output_status.success() {
        utm_cleanup_exec_files(
            utm_name,
            remote_command_path.as_str(),
            remote_wrapper_path.as_str(),
            remote_output_path.as_str(),
            remote_rc_path.as_str(),
        );
        let _ = fs::remove_dir_all(temp_root.as_path());
        return Err(format!(
            "UTM exec output pull failed with status {}",
            status_code(output_status)
        ));
    }

    let output_bytes = fs::read(local_output.as_path()).map_err(|err| {
        utm_cleanup_exec_files(
            utm_name,
            remote_command_path.as_str(),
            remote_wrapper_path.as_str(),
            remote_output_path.as_str(),
            remote_rc_path.as_str(),
        );
        let _ = fs::remove_dir_all(temp_root.as_path());
        format!(
            "read local UTM output file failed ({}): {err}",
            local_output.display()
        )
    })?;
    let output = String::from_utf8(output_bytes).map_err(|err| {
        utm_cleanup_exec_files(
            utm_name,
            remote_command_path.as_str(),
            remote_wrapper_path.as_str(),
            remote_output_path.as_str(),
            remote_rc_path.as_str(),
        );
        let _ = fs::remove_dir_all(temp_root.as_path());
        format!("UTM remote output was not valid UTF-8: {err}")
    })?;

    utm_cleanup_exec_files(
        utm_name,
        remote_command_path.as_str(),
        remote_wrapper_path.as_str(),
        remote_output_path.as_str(),
        remote_rc_path.as_str(),
    );
    let _ = fs::remove_dir_all(temp_root.as_path());
    Ok((rc, output))
}

fn synthetic_exit_status(code: i32) -> ExitStatus {
    let normalized = code.clamp(0, 255);
    ExitStatus::from_raw(normalized << 8)
}

fn fallback_remote_shell_command_to_ssh(
    target: &RemoteTarget,
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    remote_script: &str,
    timeout: Duration,
    utm_error: &str,
) -> Result<ExitStatus, String> {
    let ssh_script = remote_script_for_ssh_transport(target, remote_script)?;
    run_remote_shell_command(
        target.ssh_target.as_str(),
        ssh_user_override.or(target.ssh_user.as_deref()),
        ssh_identity_file,
        known_hosts_path,
        ssh_script.as_str(),
        timeout,
    )
    .map_err(|ssh_err| {
        format!(
            "UTM transport failed for {} ({utm_error}); SSH fallback failed: {ssh_err}",
            target.label
        )
    })
}

fn fallback_capture_remote_shell_command_to_ssh(
    target: &RemoteTarget,
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    remote_script: &str,
    timeout: Duration,
    utm_error: &str,
) -> Result<String, String> {
    let ssh_script = remote_script_for_ssh_transport(target, remote_script)?;
    capture_remote_shell_command(
        target.ssh_target.as_str(),
        ssh_user_override.or(target.ssh_user.as_deref()),
        ssh_identity_file,
        known_hosts_path,
        ssh_script.as_str(),
        timeout,
    )
    .map_err(|ssh_err| {
        format!(
            "UTM transport failed for {} ({utm_error}); SSH fallback failed: {ssh_err}",
            target.label
        )
    })
}

fn fallback_scp_to_remote(
    context: &RemoteFallbackContext<'_>,
    src: &Path,
    dst: &str,
    utm_error: &str,
) -> Result<ExitStatus, String> {
    scp_to_remote(
        src,
        context.target.ssh_target.as_str(),
        context
            .ssh_user_override
            .or(context.target.ssh_user.as_deref()),
        context.ssh_identity_file,
        context.known_hosts_path,
        dst,
        context.timeout,
    )
    .map_err(|ssh_err| {
        format!(
            "UTM transport failed for {} ({utm_error}); SSH fallback failed: {ssh_err}",
            context.target.label
        )
    })
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum RemoteTransportPhase {
    AccessEstablishment,
    PostBootstrap,
}

/// Return the utmctl staging directory for a Windows UTM target.
///
/// The staging directory is a SYSTEM-writable location that the QEMU
/// guest agent can read and write via `utmctl file push`/`utmctl file
/// pull`. It MUST live outside the runtime state tree
/// (`C:\ProgramData\Rustynet\`) because that tree is hardened with
/// `icacls /grant:r <user>:(OI)(CI)(F) /T`, which strips the SYSTEM
/// ACE and therefore breaks utmctl file operations.
///
/// Falls back to the platform default when the target does not carry an
/// explicit value, but never returns `remote_temp_dir` because that
/// path lives inside the hardened tree.
fn remote_target_windows_utm_staging_dir(target: &RemoteTarget) -> Result<String, String> {
    if let Some(dir) = target.utm_staging_dir.as_deref() {
        return Ok(dir.to_owned());
    }
    default_utm_staging_dir_for_profile(target.platform_profile, target.ssh_user.as_deref())
        .ok_or_else(|| {
            format!(
                "no UTM staging directory configured for Windows target {}",
                target.label
            )
        })
}

fn ssh_fallback_allowed_for_target(target: &RemoteTarget, phase: RemoteTransportPhase) -> bool {
    !(target.platform_profile.platform == VmGuestPlatform::Windows
        && phase == RemoteTransportPhase::AccessEstablishment)
}

fn windows_local_utm_transport_allowed_for_phase(phase: RemoteTransportPhase) -> bool {
    phase == RemoteTransportPhase::AccessEstablishment
}

fn format_windows_access_establishment_transport_error(
    target_label: &str,
    operation: &str,
    cause: &str,
) -> String {
    format!("Windows access establishment {operation} failed for {target_label}: {cause}")
}

fn run_remote_shell_command_for_target_with_phase(
    target: &RemoteTarget,
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    remote_script: &str,
    timeout: Duration,
    phase: RemoteTransportPhase,
) -> Result<ExitStatus, String> {
    if let Some((utm_name, _)) = remote_target_local_utm(target)
        && (target.platform_profile.platform != VmGuestPlatform::Windows
            || windows_local_utm_transport_allowed_for_phase(phase))
    {
        return match target.platform_profile.platform {
            VmGuestPlatform::Linux => {
                let ssh_user = remote_target_effective_user(target, ssh_user_override)?;
                let home = remote_target_home(ssh_user.as_str());
                let (rc, _) = match execute_utm_remote_script_as_user(
                    utm_name,
                    ssh_user.as_str(),
                    home.as_str(),
                    remote_script,
                    timeout,
                ) {
                    Ok(result) => result,
                    Err(err) => {
                        return fallback_remote_shell_command_to_ssh(
                            target,
                            ssh_user_override,
                            ssh_identity_file,
                            known_hosts_path,
                            remote_script,
                            timeout,
                            err.as_str(),
                        );
                    }
                };
                Ok(synthetic_exit_status(rc))
            }
            VmGuestPlatform::Windows => {
                // Primary path: utmctl exec + result-file (network-independent;
                // survives WireGuard interface up/down mid-orchestration).
                // SSH fallback is allowed only after access establishment.
                let staging_dir = remote_target_windows_utm_staging_dir(target)?;
                match execute_utm_remote_powershell_capture(
                    utm_name,
                    staging_dir.as_str(),
                    remote_script,
                    timeout,
                ) {
                    Ok((rc, _output)) => Ok(synthetic_exit_status(rc)),
                    Err(utm_err) => {
                        if ssh_fallback_allowed_for_target(target, phase) {
                            fallback_remote_shell_command_to_ssh(
                                target,
                                ssh_user_override,
                                ssh_identity_file,
                                known_hosts_path,
                                remote_script,
                                timeout,
                                utm_err.as_str(),
                            )
                        } else {
                            Err(format_windows_access_establishment_transport_error(
                                target.label.as_str(),
                                "UTM Windows exec",
                                utm_err.as_str(),
                            ))
                        }
                    }
                }
            }
            VmGuestPlatform::Macos => fallback_remote_shell_command_to_ssh(
                target,
                ssh_user_override,
                ssh_identity_file,
                known_hosts_path,
                remote_script,
                timeout,
                "local UTM guest exec is not yet implemented for macOS targets",
            ),
            VmGuestPlatform::Ios | VmGuestPlatform::Android => Err(format!(
                "local UTM guest exec is not supported for platform {} ({})",
                target.platform_profile.platform.as_str(),
                target.label
            )),
        };
    }
    let ssh_script = remote_script_for_ssh_transport(target, remote_script)?;
    run_remote_shell_command(
        target.ssh_target.as_str(),
        ssh_user_override.or(target.ssh_user.as_deref()),
        ssh_identity_file,
        known_hosts_path,
        ssh_script.as_str(),
        timeout,
    )
}

fn run_remote_shell_command_for_target(
    target: &RemoteTarget,
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    remote_script: &str,
    timeout: Duration,
) -> Result<ExitStatus, String> {
    run_remote_shell_command_for_target_with_phase(
        target,
        ssh_user_override,
        ssh_identity_file,
        known_hosts_path,
        remote_script,
        timeout,
        RemoteTransportPhase::PostBootstrap,
    )
}

fn capture_remote_shell_command_for_target_with_phase(
    target: &RemoteTarget,
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    remote_script: &str,
    timeout: Duration,
    phase: RemoteTransportPhase,
) -> Result<String, String> {
    if let Some((utm_name, _)) = remote_target_local_utm(target)
        && (target.platform_profile.platform != VmGuestPlatform::Windows
            || windows_local_utm_transport_allowed_for_phase(phase))
    {
        return match target.platform_profile.platform {
            VmGuestPlatform::Linux => {
                let ssh_user = remote_target_effective_user(target, ssh_user_override)?;
                let home = remote_target_home(ssh_user.as_str());
                let (rc, output) = match execute_utm_remote_script_as_user(
                    utm_name,
                    ssh_user.as_str(),
                    home.as_str(),
                    remote_script,
                    timeout,
                ) {
                    Ok(result) => result,
                    Err(err) => {
                        return fallback_capture_remote_shell_command_to_ssh(
                            target,
                            ssh_user_override,
                            ssh_identity_file,
                            known_hosts_path,
                            remote_script,
                            timeout,
                            err.as_str(),
                        );
                    }
                };
                if rc != 0 {
                    let trimmed = output.trim();
                    return if trimmed.is_empty() {
                        Err(format!("remote command exited with status {rc}"))
                    } else {
                        Err(format!("remote command exited with status {rc}: {trimmed}"))
                    };
                }
                Ok(output)
            }
            VmGuestPlatform::Windows => {
                let staging_dir = remote_target_windows_utm_staging_dir(target)?;
                let utm_result = execute_utm_remote_powershell_capture(
                    utm_name,
                    staging_dir.as_str(),
                    remote_script,
                    timeout,
                );
                match utm_result {
                    Ok((rc, output)) => {
                        if rc != 0 {
                            Err(format_remote_capture_exit_error(rc, output.as_str()))
                        } else {
                            Ok(output)
                        }
                    }
                    Err(utm_err) => {
                        if ssh_fallback_allowed_for_target(target, phase) {
                            fallback_capture_remote_shell_command_to_ssh(
                                target,
                                ssh_user_override,
                                ssh_identity_file,
                                known_hosts_path,
                                remote_script,
                                timeout,
                                utm_err.as_str(),
                            )
                        } else {
                            Err(format_windows_access_establishment_transport_error(
                                target.label.as_str(),
                                "UTM Windows capture",
                                utm_err.as_str(),
                            ))
                        }
                    }
                }
            }
            VmGuestPlatform::Macos => fallback_capture_remote_shell_command_to_ssh(
                target,
                ssh_user_override,
                ssh_identity_file,
                known_hosts_path,
                remote_script,
                timeout,
                "local UTM guest exec is not yet implemented for macOS targets",
            ),
            VmGuestPlatform::Ios | VmGuestPlatform::Android => Err(format!(
                "local UTM guest exec is not supported for platform {} ({})",
                target.platform_profile.platform.as_str(),
                target.label
            )),
        };
    }
    let ssh_script = remote_script_for_ssh_transport(target, remote_script)?;
    capture_remote_shell_command(
        target.ssh_target.as_str(),
        ssh_user_override.or(target.ssh_user.as_deref()),
        ssh_identity_file,
        known_hosts_path,
        ssh_script.as_str(),
        timeout,
    )
}

fn capture_remote_shell_command_for_target(
    target: &RemoteTarget,
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    remote_script: &str,
    timeout: Duration,
) -> Result<String, String> {
    capture_remote_shell_command_for_target_with_phase(
        target,
        ssh_user_override,
        ssh_identity_file,
        known_hosts_path,
        remote_script,
        timeout,
        RemoteTransportPhase::PostBootstrap,
    )
}

/// Substring the OpenSSH client prints when the server refuses to open a new
/// session channel on an otherwise-successful (TCP+auth) connection — the
/// remote script never ran. Distinct from an auth failure or the remote
/// command's own non-zero exit.
const SSH_CHANNEL_OPEN_REJECTED_MARKER: &str = "exec request failed on channel";

fn scp_to_remote_for_target_with_phase(
    context: &RemoteFallbackContext<'_>,
    src: &Path,
    dst: &str,
    phase: RemoteTransportPhase,
) -> Result<ExitStatus, String> {
    let dst = remote_copy_destination_for_target(context.target, dst);
    if let Some((utm_name, _)) = remote_target_local_utm(context.target) {
        return match context.target.platform_profile.platform {
            VmGuestPlatform::Linux => {
                let ssh_user =
                    remote_target_effective_user(context.target, context.ssh_user_override)?;
                let status = match utm_push_raw(utm_name, src, dst.as_str(), context.timeout) {
                    Ok(status) if status.success() => status,
                    Ok(status) => {
                        return fallback_scp_to_remote(
                            context,
                            src,
                            dst.as_str(),
                            format!("UTM push failed with status {}", status_code(status)).as_str(),
                        );
                    }
                    Err(err) => {
                        return fallback_scp_to_remote(context, src, dst.as_str(), err.as_str());
                    }
                };
                if ssh_user != "root" {
                    let chown_status = utm_exec_root_raw(
                        utm_name,
                        format!(
                            "chown {}:{} {}",
                            shell_quote(ssh_user.as_str()),
                            shell_quote(ssh_user.as_str()),
                            shell_quote(dst.as_str()),
                        )
                        .as_str(),
                        Duration::from_secs(20),
                    )?;
                    if !chown_status.success() {
                        return Ok(chown_status);
                    }
                }
                Ok(status)
            }
            VmGuestPlatform::Windows => {
                // Windows UTM staging strategy:
                //
                // - `windows_helper_script_remote_path` and
                //   `windows_orchestration_root` route helper paths under
                //   `utm_staging_dir` (typically
                //   C:\Users\<windows>\rustynet-utm-stage), which both the
                //   SSH user and the SYSTEM-level guest agent can read+write.
                // - During access establishment, SSH may be down by
                //   definition, so use utmctl push for helper/support files
                //   under staging. Do not fall back to SCP here: SSH is the
                //   thing being established, and fallback would hide the
                //   broken layer.
                // - Post-bootstrap paths keep using SCP so ordinary Windows
                //   targets and SSH-only lab paths exercise the same operator
                //   transport after access has been proven.
                //
                // During access establishment, use `utmctl exec` to mkdir
                // the staging directory before UTM push. Post-bootstrap SCP
                // avoids UTM exec entirely; if the directory is missing, the
                // SSH/SCP error is the authoritative transport failure.
                if phase == RemoteTransportPhase::AccessEstablishment
                    && let Some(staging_dir) = context.target.utm_staging_dir.as_deref()
                {
                    let parent = windows_guest_parent_dir(dst.as_str()).unwrap_or_default();
                    let needs_mkdir =
                        parent.is_empty() || windows_path_is_within(parent.as_str(), staging_dir);
                    if needs_mkdir {
                        let mkdir_target = if parent.is_empty() {
                            staging_dir.to_owned()
                        } else {
                            parent
                        };
                        if let Err(err) = ensure_utm_windows_dir(
                            utm_name,
                            mkdir_target.as_str(),
                            context.timeout.min(Duration::from_secs(30)),
                        ) {
                            return Err(format!(
                                "UTM Windows staging mkdir failed for {} ({}): {err}",
                                context.target.label, mkdir_target
                            ));
                        }
                    }
                }
                if phase == RemoteTransportPhase::AccessEstablishment {
                    match utm_push_raw(utm_name, src, dst.as_str(), context.timeout) {
                        Ok(status) if status.success() => return Ok(status),
                        Ok(status) => {
                            return Err(format_windows_access_establishment_transport_error(
                                context.target.label.as_str(),
                                "UTM Windows file push",
                                format!("UTM push failed with status {}", status_code(status))
                                    .as_str(),
                            ));
                        }
                        Err(err) => {
                            return Err(format_windows_access_establishment_transport_error(
                                context.target.label.as_str(),
                                "UTM Windows file push",
                                err.as_str(),
                            ));
                        }
                    }
                }
                fallback_scp_to_remote(
                    context,
                    src,
                    dst.as_str(),
                    "Windows UTM SCP path uses staging directory directly",
                )
            }
            VmGuestPlatform::Macos => fallback_scp_to_remote(
                context,
                src,
                dst.as_str(),
                "local UTM file push is not yet implemented for macOS targets",
            ),
            VmGuestPlatform::Ios | VmGuestPlatform::Android => Err(format!(
                "local UTM file copy is not supported for platform {} ({})",
                context.target.platform_profile.platform.as_str(),
                context.target.label
            )),
        };
    }
    let ssh_user = context
        .ssh_user_override
        .or(context.target.ssh_user.as_deref());
    scp_to_remote(
        src,
        context.target.ssh_target.as_str(),
        ssh_user,
        context.ssh_identity_file,
        context.known_hosts_path,
        dst.as_str(),
        context.timeout,
    )
}

fn scp_to_remote_for_target(
    target: &RemoteTarget,
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    src: &Path,
    dst: &str,
    timeout: Duration,
) -> Result<ExitStatus, String> {
    let context = RemoteFallbackContext {
        target,
        ssh_user_override,
        ssh_identity_file,
        known_hosts_path,
        timeout,
    };
    scp_to_remote_for_target_with_phase(&context, src, dst, RemoteTransportPhase::PostBootstrap)
}

fn run_remote_shell_command(
    target: &str,
    ssh_user: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    remote_script: &str,
    timeout: Duration,
) -> Result<ExitStatus, String> {
    validate_target_user_combination(target, ssh_user)?;
    let mut command = Command::new("ssh");
    command.args([
        "-n",
        "-o",
        "LogLevel=ERROR",
        "-o",
        "BatchMode=yes",
        "-o",
        "StrictHostKeyChecking=yes",
        "-o",
        "ConnectTimeout=15",
        "-o",
        "ServerAliveInterval=20",
        "-o",
        "ServerAliveCountMax=3",
        "-o",
        "IdentitiesOnly=yes",
    ]);
    append_ssh_transport_options(&mut command, ssh_identity_file, known_hosts_path)?;
    if let Some(ssh_user) = ssh_user {
        command.arg("-l").arg(ssh_user);
    }
    command.arg("--").arg(target).arg(remote_script);
    run_status_with_timeout(&mut command, timeout)
}

fn capture_remote_shell_command(
    target: &str,
    ssh_user: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    remote_script: &str,
    timeout: Duration,
) -> Result<String, String> {
    validate_target_user_combination(target, ssh_user)?;
    let mut command = Command::new("ssh");
    command.args([
        "-n",
        "-o",
        "LogLevel=ERROR",
        "-o",
        "BatchMode=yes",
        "-o",
        "StrictHostKeyChecking=yes",
        "-o",
        "ConnectTimeout=15",
        "-o",
        "ServerAliveInterval=20",
        "-o",
        "ServerAliveCountMax=3",
        "-o",
        "IdentitiesOnly=yes",
    ]);
    append_ssh_transport_options(&mut command, ssh_identity_file, known_hosts_path)?;
    if let Some(ssh_user) = ssh_user {
        command.arg("-l").arg(ssh_user);
    }
    command.arg("--").arg(target).arg(remote_script);
    let output = run_output_with_timeout(&mut command, timeout)?;
    if !output.status.success() {
        let stderr_snippet = String::from_utf8_lossy(&output.stderr);
        let stdout_snippet = String::from_utf8_lossy(&output.stdout);
        let combined = format!("{}{}", stdout_snippet.trim(), stderr_snippet.trim());
        let trimmed = combined.trim();
        if trimmed.is_empty() {
            return Err(format!(
                "remote command exited with status {}",
                status_code(output.status)
            ));
        }
        return Err(format!(
            "remote command exited with status {}: {}",
            status_code(output.status),
            trimmed
        ));
    }
    String::from_utf8(output.stdout)
        .map_err(|err| format!("remote output was not valid UTF-8: {err}"))
}

fn scp_to_remote(
    src: &Path,
    target: &str,
    ssh_user: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    dst: &str,
    timeout: Duration,
) -> Result<ExitStatus, String> {
    validate_target_user_combination(target, ssh_user)?;
    ensure_no_control_chars("remote destination path", dst)?;
    let mut command = Command::new("scp");
    command.args([
        "-q",
        "-o",
        "LogLevel=ERROR",
        "-o",
        "BatchMode=yes",
        "-o",
        "StrictHostKeyChecking=yes",
        "-o",
        "ConnectTimeout=15",
        "-o",
        "IdentitiesOnly=yes",
    ]);
    append_ssh_transport_options(&mut command, ssh_identity_file, known_hosts_path)?;
    if let Some(ssh_user) = ssh_user {
        command.arg("-o").arg(format!("User={ssh_user}"));
    }
    command
        .arg("--")
        .arg(src.as_os_str())
        .arg(format!("{target}:{dst}"));
    // Capture stderr.  The previous implementation routed it to /dev/null
    // via run_status_with_timeout, which made every scp failure look like
    // a silent multi-second hang to the orchestrator.  Surfacing the last
    // few stderr lines on non-zero exit makes auth, host-key, and
    // connection-reset failures self-diagnosing.
    let output = run_output_with_timeout(&mut command, timeout)?;
    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        let tail = stderr
            .lines()
            .rev()
            .take(8)
            .collect::<Vec<_>>()
            .into_iter()
            .rev()
            .collect::<Vec<_>>()
            .join(" | ");
        return Err(format!(
            "scp to {target}:{dst} failed with status {}: {}",
            status_code(output.status),
            if tail.is_empty() {
                "(no stderr)"
            } else {
                tail.as_str()
            }
        ));
    }
    Ok(output.status)
}

fn scp_from_remote(
    target: &RemoteTarget,
    ssh_user: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    src: &str,
    dst: &Path,
    timeout: Duration,
) -> Result<ExitStatus, String> {
    validate_target_user_combination(target.ssh_target.as_str(), ssh_user)?;
    ensure_no_control_chars("remote source path", src)?;
    let mut command = Command::new("scp");
    command.args([
        "-q",
        "-o",
        "LogLevel=ERROR",
        "-o",
        "BatchMode=yes",
        "-o",
        "StrictHostKeyChecking=yes",
        "-o",
        "ConnectTimeout=15",
        "-o",
        "IdentitiesOnly=yes",
    ]);
    append_ssh_transport_options(&mut command, ssh_identity_file, known_hosts_path)?;
    if let Some(ssh_user) = ssh_user {
        command.arg("-o").arg(format!("User={ssh_user}"));
    }
    if let Some(parent) = dst.parent().filter(|path| !path.as_os_str().is_empty()) {
        fs::create_dir_all(parent).map_err(|err| {
            format!(
                "create remote scp destination dir failed ({}): {err}",
                parent.display()
            )
        })?;
    }
    command
        .arg("--")
        .arg(format!(
            "{}:{}",
            target.ssh_target,
            remote_copy_source_for_target(target, src)
        ))
        .arg(dst.as_os_str());
    run_status_with_timeout(&mut command, timeout)
}

fn run_status_with_timeout(command: &mut Command, timeout: Duration) -> Result<ExitStatus, String> {
    command.stdin(Stdio::null());
    command.stdout(Stdio::null());
    command.stderr(Stdio::null());
    run_status_with_timeout_preserve(command, timeout)
}

fn run_status_with_timeout_preserve(
    command: &mut Command,
    timeout: Duration,
) -> Result<ExitStatus, String> {
    let mut child = command
        .spawn()
        .map_err(|err| format!("spawn failed: {err}"))?;
    let started_at = Instant::now();
    loop {
        if let Some(status) = child
            .try_wait()
            .map_err(|err| format!("wait failed: {err}"))?
        {
            return Ok(status);
        }
        if started_at.elapsed() >= timeout {
            let _ = child.kill();
            let _ = child.wait();
            return Err(format!("timed out after {} seconds", timeout.as_secs()));
        }
        thread::sleep(Duration::from_millis(POLL_INTERVAL_MILLIS));
    }
}

fn run_output_with_timeout(
    command: &mut Command,
    timeout: Duration,
) -> Result<std::process::Output, String> {
    command.stdin(Stdio::null());
    command.stdout(Stdio::piped());
    command.stderr(Stdio::piped());
    run_output_with_timeout_preserve(command, timeout)
}

fn run_output_with_timeout_preserve(
    command: &mut Command,
    timeout: Duration,
) -> Result<std::process::Output, String> {
    let mut child = command
        .spawn()
        .map_err(|err| format!("spawn failed: {err}"))?;
    let started_at = Instant::now();
    loop {
        if child
            .try_wait()
            .map_err(|err| format!("wait failed: {err}"))?
            .is_some()
        {
            return child
                .wait_with_output()
                .map_err(|err| format!("collect output failed: {err}"));
        }
        if started_at.elapsed() >= timeout {
            let _ = child.kill();
            let _ = child.wait();
            return Err(format!("timed out after {} seconds", timeout.as_secs()));
        }
        thread::sleep(Duration::from_millis(POLL_INTERVAL_MILLIS));
    }
}

fn run_status_with_timeout_passthrough(
    command: &mut Command,
    timeout: Duration,
) -> Result<ExitStatus, String> {
    let mut child = command
        .spawn()
        .map_err(|err| format!("spawn failed: {err}"))?;
    let started_at = Instant::now();
    loop {
        if let Some(status) = child
            .try_wait()
            .map_err(|err| format!("wait failed: {err}"))?
        {
            return Ok(status);
        }
        if started_at.elapsed() >= timeout {
            let _ = child.kill();
            let _ = child.wait();
            return Err(format!("timed out after {} seconds", timeout.as_secs()));
        }
        thread::sleep(Duration::from_millis(POLL_INTERVAL_MILLIS));
    }
}

fn transition_local_utm_vm(
    utmctl_path: &Path,
    utm_name: &str,
    bundle_path: &Path,
    action: &str,
    expected_process_present: bool,
    timeout: Duration,
) -> Result<(), String> {
    transition_local_utm_vm_with_process_probe(
        utmctl_path,
        Path::new("ps"),
        utm_name,
        bundle_path,
        action,
        expected_process_present,
        timeout,
    )
}

fn transition_local_utm_vm_with_process_probe(
    utmctl_path: &Path,
    ps_path: &Path,
    utm_name: &str,
    bundle_path: &Path,
    action: &str,
    expected_process_present: bool,
    timeout: Duration,
) -> Result<(), String> {
    let observed = local_utm_process_present_with_probes(
        utmctl_path,
        ps_path,
        utm_name,
        bundle_path,
        timeout,
    )?;
    if observed == expected_process_present {
        return Ok(());
    }

    let mut command = Command::new(utmctl_path);
    command.arg(action).arg(utm_name);
    let status = match run_status_with_timeout(&mut command, timeout) {
        Ok(status) => status,
        Err(err) => {
            match wait_for_local_utm_process_state_with_probes(
                utmctl_path,
                ps_path,
                utm_name,
                bundle_path,
                expected_process_present,
                transition_reconciliation_timeout(timeout),
            ) {
                Ok(()) => return Ok(()),
                Err(probe_err) => {
                    return Err(format!(
                        "{err}; follow-up process-state probe failed: {probe_err}"
                    ));
                }
            }
        }
    };
    if !status.success() {
        match wait_for_local_utm_process_state_with_probes(
            utmctl_path,
            ps_path,
            utm_name,
            bundle_path,
            expected_process_present,
            transition_reconciliation_timeout(timeout),
        ) {
            Ok(()) => return Ok(()),
            Err(probe_err) => {
                return Err(format!(
                    "{action} exited with status {}; follow-up process-state probe failed: {probe_err}",
                    status_code(status)
                ));
            }
        }
    }
    wait_for_local_utm_process_state_with_probes(
        utmctl_path,
        ps_path,
        utm_name,
        bundle_path,
        expected_process_present,
        timeout,
    )
}

fn wait_for_local_utm_process_state_with_probes(
    utmctl_path: &Path,
    ps_path: &Path,
    utm_name: &str,
    bundle_path: &Path,
    expected_present: bool,
    timeout: Duration,
) -> Result<(), String> {
    let started_at = Instant::now();
    loop {
        let observed = local_utm_process_present_with_probes(
            utmctl_path,
            ps_path,
            utm_name,
            bundle_path,
            timeout,
        )?;
        if observed == expected_present {
            return Ok(());
        }
        if started_at.elapsed() >= timeout {
            return Err(format!(
                "timed out waiting for local UTM process presence={} for {}",
                expected_present,
                bundle_path.display()
            ));
        }
        thread::sleep(Duration::from_millis(POLL_INTERVAL_MILLIS));
    }
}

fn local_utm_process_present_with_probes(
    utmctl_path: &Path,
    ps_path: &Path,
    utm_name: &str,
    bundle_path: &Path,
    timeout: Duration,
) -> Result<bool, String> {
    match local_utm_process_present_with_utmctl_list(utmctl_path, utm_name, timeout) {
        Ok(Some(present)) => return Ok(present),
        Ok(None) => {}
        Err(utmctl_err) => {
            return local_utm_process_present_with_ps(ps_path, bundle_path, timeout).map_err(
                |ps_err| {
                    format!(
                        "utmctl process probe failed: {utmctl_err}; ps process probe failed: {ps_err}"
                    )
                },
            );
        }
    }
    local_utm_process_present_with_ps(ps_path, bundle_path, timeout)
}

fn local_utm_process_present_with_utmctl_list(
    utmctl_path: &Path,
    utm_name: &str,
    timeout: Duration,
) -> Result<Option<bool>, String> {
    if !utmctl_path.is_file() {
        return Ok(None);
    }
    let mut command = Command::new(utmctl_path);
    command.arg("list");
    let output = run_output_with_timeout(&mut command, timeout)?;
    if !output.status.success() {
        return Ok(None);
    }
    let stdout = String::from_utf8(output.stdout)
        .map_err(|err| format!("utmctl list returned non-UTF-8 output: {err}"))?;
    Ok(parse_local_utm_list_started_status(
        stdout.as_str(),
        utm_name,
    ))
}

fn local_utm_process_present_with_ps(
    ps_path: &Path,
    bundle_path: &Path,
    timeout: Duration,
) -> Result<bool, String> {
    let mut command = Command::new(ps_path);
    command.args(["axww", "-o", "command"]);
    let output = run_output_with_timeout(&mut command, timeout)?;
    if !output.status.success() {
        return Err(format!(
            "ps exited with status {}",
            status_code(output.status)
        ));
    }
    let ps_output = String::from_utf8(output.stdout)
        .map_err(|err| format!("ps returned non-UTF-8 output: {err}"))?;
    Ok(local_utm_process_present_in_ps_output(
        ps_output.as_str(),
        bundle_path,
    ))
}

fn local_utm_process_present_in_ps_output(ps_output: &str, bundle_path: &Path) -> bool {
    let needle = bundle_path.display().to_string();
    ps_output
        .lines()
        .any(|line| line.contains("QEMULauncher") && line.contains(needle.as_str()))
}

fn parse_local_utm_list_started_status(list_output: &str, utm_name: &str) -> Option<bool> {
    list_output.lines().find_map(|line| {
        let trimmed = line.trim();
        if trimmed.is_empty() || trimmed.starts_with("UUID") {
            return None;
        }

        let mut parts = trimmed.split_whitespace();
        let _uuid = parts.next()?;
        let status = parts.next()?;
        let name_start = trimmed.find(status)? + status.len();
        let name = trimmed[name_start..].trim();
        if name != utm_name {
            return None;
        }

        // "stopping" means a graceful-shutdown was requested but the QEMU process is still
        // alive and the guest is still reachable. Treat it as present so a VM undergoing a
        // clean shutdown is not incorrectly flagged as powered-off and needlessly restarted.
        Some(status == "started" || status == "stopping")
    })
}

fn transition_reconciliation_timeout(_timeout: Duration) -> Duration {
    Duration::from_secs(15)
}

fn timeout_or_default(value: u64, default_secs: u64) -> Duration {
    let secs = if value == 0 { default_secs } else { value };
    Duration::from_secs(secs)
}

fn status_code(status: ExitStatus) -> i32 {
    match status.code() {
        Some(code) => code,
        None => {
            #[cfg(unix)]
            {
                use std::os::unix::process::ExitStatusExt;

                match status.signal() {
                    Some(signal) => 128 + signal,
                    None => 1,
                }
            }
            #[cfg(not(unix))]
            {
                1
            }
        }
    }
}

fn ensure_success_status(status: ExitStatus, label: &str) -> Result<(), String> {
    if status.success() {
        Ok(())
    } else {
        Err(format!(
            "{label} failed with status {}",
            status_code(status)
        ))
    }
}

fn ensure_no_control_chars(label: &str, value: &str) -> Result<(), String> {
    if value.trim().is_empty() {
        return Err(format!("{label} must not be empty"));
    }
    if value
        .chars()
        .any(|ch| ch == '\0' || ch == '\n' || ch == '\r')
    {
        return Err(format!("{label} contains unsupported control characters"));
    }
    Ok(())
}

fn ensure_local_regular_file_path(path: &Path, label: &str) -> Result<(), String> {
    let metadata = fs::metadata(path)
        .map_err(|err| format!("{label} metadata read failed ({}): {err}", path.display()))?;
    if !metadata.is_file() {
        return Err(format!(
            "{label} must be a regular file: {}",
            path.display()
        ));
    }
    Ok(())
}

fn ensure_local_directory_path(path: &Path, label: &str) -> Result<(), String> {
    let metadata = fs::metadata(path)
        .map_err(|err| format!("{label} metadata read failed ({}): {err}", path.display()))?;
    if !metadata.is_dir() {
        return Err(format!("{label} must be a directory: {}", path.display()));
    }
    Ok(())
}

fn shell_quote(value: &str) -> String {
    let mut out = String::from("'");
    for ch in value.chars() {
        if ch == '\'' {
            out.push_str("'\\''");
        } else {
            out.push(ch);
        }
    }
    out.push('\'');
    out
}

fn powershell_quote(value: &str) -> Result<String, String> {
    ensure_no_control_chars("PowerShell literal", value)?;
    Ok(format!("'{}'", value.replace('\'', "''")))
}

fn encode_powershell_command(script: &str) -> Result<String, String> {
    if script.chars().any(|ch| ch == '\0') {
        return Err("PowerShell script contains unsupported NUL byte".to_owned());
    }
    let mut bytes = Vec::with_capacity(script.len() * 2);
    for unit in script.encode_utf16() {
        bytes.extend_from_slice(&unit.to_le_bytes());
    }
    Ok(BASE64_STANDARD.encode(bytes))
}

fn build_ssh_powershell_encoded_invocation(script: &str) -> Result<String, String> {
    let encoded = encode_powershell_command(script)?;
    Ok(format!(
        "powershell.exe -NoLogo -NoProfile -NonInteractive -ExecutionPolicy Bypass -EncodedCommand {encoded}"
    ))
}

fn build_remote_argv_powershell_script(
    workdir: &str,
    program: &str,
    argv: &[String],
) -> Result<String, String> {
    ensure_no_control_chars("workdir", workdir)?;
    ensure_no_control_chars("program", program)?;
    let mut script = String::new();
    script.push_str("Set-StrictMode -Version Latest; ");
    script.push_str("$ErrorActionPreference = 'Stop'; ");
    script.push_str(format!("Set-Location -LiteralPath {}; ", powershell_quote(workdir)?).as_str());
    script.push_str(format!("& {}", powershell_quote(program)?).as_str());
    for arg in argv {
        ensure_no_control_chars("command arg", arg.as_str())?;
        script.push(' ');
        script.push_str(powershell_quote(arg.as_str())?.as_str());
    }
    script.push_str("; $lastExitCode = Get-Variable -Name LASTEXITCODE -ErrorAction SilentlyContinue; if ($null -ne $lastExitCode -and [int]$lastExitCode.Value -ne 0) { exit [int]$lastExitCode.Value }");
    Ok(script)
}

fn build_remote_argv_script_for_target(
    target: &RemoteTarget,
    workdir: &str,
    program: &str,
    argv: &[String],
    sudo: bool,
) -> Result<String, String> {
    match target.platform_profile.remote_shell {
        VmRemoteShell::Posix => build_remote_argv_script(workdir, program, argv, sudo),
        VmRemoteShell::Powershell => {
            if sudo {
                return Err(format!(
                    "sudo is not supported for Windows targets: {}",
                    target.label
                ));
            }
            build_remote_argv_powershell_script(workdir, program, argv)
        }
        VmRemoteShell::Unsupported => Err(format!(
            "vm-lab remote shell is not yet implemented for platform {} ({})",
            target.platform_profile.platform.as_str(),
            target.label
        )),
    }
}

fn remote_script_for_ssh_transport(
    target: &RemoteTarget,
    remote_script: &str,
) -> Result<String, String> {
    match target.platform_profile.remote_shell {
        VmRemoteShell::Posix => Ok(remote_script.to_owned()),
        VmRemoteShell::Powershell => build_ssh_powershell_encoded_invocation(remote_script),
        VmRemoteShell::Unsupported => Err(format!(
            "SSH transport is not yet implemented for platform {} ({})",
            target.platform_profile.platform.as_str(),
            target.label
        )),
    }
}

fn remote_copy_destination_for_target(target: &RemoteTarget, dst: &str) -> String {
    match target.platform_profile.platform {
        VmGuestPlatform::Linux
        | VmGuestPlatform::Macos
        | VmGuestPlatform::Ios
        | VmGuestPlatform::Android => dst.to_owned(),
        VmGuestPlatform::Windows => dst.replace('\\', "/"),
    }
}

fn remote_copy_source_for_target(target: &RemoteTarget, src: &str) -> String {
    match target.platform_profile.platform {
        VmGuestPlatform::Linux
        | VmGuestPlatform::Macos
        | VmGuestPlatform::Ios
        | VmGuestPlatform::Android => src.to_owned(),
        VmGuestPlatform::Windows => src.replace('\\', "/"),
    }
}

fn windows_guest_path_join(root: &str, file_name: &str) -> Result<String, String> {
    ensure_no_control_chars("Windows guest root", root)?;
    ensure_no_control_chars("Windows guest file name", file_name)?;
    let trimmed = root.trim_end_matches(['\\', '/']);
    Ok(format!(r"{trimmed}\{file_name}"))
}

/// Strip the trailing path component from a Windows guest path. Returns
/// an empty string when the path has no parent (single component or empty).
/// Tolerates both `\` and `/` separators.
fn windows_guest_parent_dir(path: &str) -> Option<String> {
    let last = path.rfind(['\\', '/']).filter(|idx| *idx > 0)?;
    Some(path[..last].to_string())
}

/// True when `path` lies at or below `root`, treating both `\` and `/` as
/// path separators and ignoring case (Windows file systems are typically
/// case-insensitive).
fn windows_path_is_within(path: &str, root: &str) -> bool {
    fn normalize(value: &str) -> String {
        value
            .replace('/', "\\")
            .trim_end_matches('\\')
            .to_ascii_lowercase()
    }
    let path_norm = normalize(path);
    let root_norm = normalize(root);
    if root_norm.is_empty() {
        return false;
    }
    if path_norm == root_norm {
        return true;
    }
    let prefix = format!("{root_norm}\\");
    path_norm.starts_with(prefix.as_str())
}

/// Single source of truth for "where does Windows orchestration scratch go?"
///
/// For Windows local-UTM targets, returns `utm_staging_dir` so that both
/// halves of the transport share one directory:
/// - SCP staging (runs as the SSH user `windows`) can write there because
///   `C:\Users\windows\...` inherits `windows:F`.
/// - `utmctl exec` (runs as `NT AUTHORITY\SYSTEM`) can read+write there
///   because the same path inherits `SYSTEM:F`.
///
/// For non-UTM Windows targets and other platforms, returns
/// `remote_temp_dir`. That preserves vm-lab semantics for SSH-only
/// Windows hosts (lab-LAN, future cloud) where the SYSTEM ACL clash
/// does not apply.
fn windows_orchestration_root(target: &RemoteTarget) -> String {
    if target.platform_profile.platform == VmGuestPlatform::Windows
        && remote_target_local_utm(target).is_some()
        && let Some(staging) = target.utm_staging_dir.as_deref()
    {
        return staging.to_owned();
    }
    target
        .remote_temp_dir
        .clone()
        .unwrap_or_else(|| default_remote_temp_dir_for_profile(target.platform_profile))
}

fn windows_helper_script_remote_path(
    target: &RemoteTarget,
    file_name: &str,
) -> Result<String, String> {
    let remote_root = windows_orchestration_root(target);
    windows_guest_path_join(remote_root.as_str(), file_name)
}

fn utm_exec_windows_raw(
    utm_name: &str,
    powershell_script: &str,
    timeout: Duration,
) -> Result<ExitStatus, String> {
    ensure_no_control_chars("UTM exec command", powershell_script)?;
    // Prepend $ProgressPreference suppression so PowerShell's "Preparing
    // modules for first use" progress record (and any other progress
    // record) does not get serialized to stderr as a CLIXML envelope.
    // Observed on a freshly-booted Windows guest: the first powershell
    // -EncodedCommand under utmctl exec emits "#< CLIXML ...<Progress
    // .../>...</Objs>" on stderr even when the command itself runs fine
    // and exits 0.  Without suppression we treat that benign noise as a
    // hard failure.
    let wrapped_script = format!(
        "$ProgressPreference = 'SilentlyContinue'; $VerbosePreference = 'SilentlyContinue'; $InformationPreference = 'SilentlyContinue'; {powershell_script}"
    );
    let encoded = encode_powershell_command(wrapped_script.as_str())?;
    let utmctl_path = utmctl_binary_path()?;
    let mut command = Command::new(utmctl_path);
    command.arg("exec").arg(utm_name);
    append_utmctl_windows_exec_command(
        &mut command,
        &[
            // UTM Windows guest exec accepts absolute Windows paths when
            // the separators are forward slashes. Backslash separators can
            // be misparsed by the guest agent and leak literal `--cmd`
            // tokens into PowerShell.
            "C:/Windows/System32/WindowsPowerShell/v1.0/powershell.exe",
            "-NoLogo",
            "-NoProfile",
            "-NonInteractive",
            "-OutputFormat",
            "Text",
            "-ExecutionPolicy",
            "Bypass",
            "-EncodedCommand",
            encoded.as_str(),
        ],
    );
    // Retry up to 3 times: rapid back-to-back utmctl exec calls intermittently
    // return exit 1 with empty stderr on macOS when the UTM guest agent is still
    // processing the previous command's Apple Event.  This is not a script error
    // (PowerShell exit codes are not forwarded by utmctl) — it is a host-side
    // transient.  Sleep briefly and retry; keep the last attempt's result.
    const UTMCTL_EXEC_RETRIES: u32 = 3;
    const UTMCTL_EXEC_RETRY_SLEEP_MS: u64 = 600;
    let mut last_output = None;
    for attempt in 0..=UTMCTL_EXEC_RETRIES {
        let output = run_output_with_timeout(&mut command, timeout)?;
        let stderr_raw = String::from_utf8_lossy(&output.stderr);
        // Strip CLIXML envelopes from the stderr stream defensively even
        // after the preference suppression above: nested PowerShell calls
        // (like the build-release wrapper invoking another powershell.exe
        // -EncodedCommand) can re-emit them.  CLIXML payloads start with
        // "#< CLIXML" and continue as XML; everything around them (real
        // utmctl host errors like "OSStatus error -2700" / "Access is
        // denied") is what we actually care about.
        let stderr_filtered = strip_powershell_clixml_noise(stderr_raw.as_ref())
            .trim()
            .to_owned();
        if !stderr_filtered.is_empty() {
            return Err(format!(
                "UTM Windows exec reported error for {utm_name}: {stderr_filtered}"
            ));
        }
        if output.status.success() || attempt == UTMCTL_EXEC_RETRIES {
            last_output = Some(output);
            break;
        }
        // exit non-zero + empty stderr = UTM agent transient; retry after brief sleep
        thread::sleep(Duration::from_millis(UTMCTL_EXEC_RETRY_SLEEP_MS));
    }
    Ok(last_output
        .expect("retry loop always sets last_output")
        .status)
}

fn append_utmctl_windows_exec_command(command: &mut Command, args: &[&str]) {
    // `utmctl exec <vm> --cmd <cmd> ...` accepts one variadic `--cmd`
    // option. On the Windows guest-agent path used by the live lab,
    // repeating `--cmd` for every argv element can return host success
    // while the guest command never runs, leaving no result file for the
    // orchestrator to pull. Keep the boundary argv-only by passing every
    // element as a separate `Command` arg after a single `--cmd`.
    command.arg("--cmd");
    for arg in args {
        command.arg(arg);
    }
}

/// Remove `PowerShell` CLIXML serialization payloads from a stderr buffer.
///
/// `PowerShell`, when invoked as a child process with `-OutputFormat Text`,
/// still emits its non-stdout streams (Progress, Verbose, Information,
/// sometimes Error and Warning records) as a CLIXML envelope on stderr
/// the first time the host runspace initializes after a cold boot or a
/// module-cache invalidation.  Setting `$ProgressPreference =
/// 'SilentlyContinue'` reduces it but does not eliminate it, because the
/// CLIXML emitter is per-runspace and the OUTER runspace activates
/// before our wrapper script runs.
///
/// The CLIXML payload always begins with the literal `#< CLIXML` marker
/// followed by an XML envelope.  This helper drops that marker and any
/// XML-like lines, returning whatever else is left.  Real utmctl host
/// failures (Apple Events errors, `OSStatus` codes, "Access is denied"
/// from the guest agent) are plain text and pass through untouched.
fn strip_powershell_clixml_noise(stderr: &str) -> String {
    let mut kept = Vec::new();
    let mut in_clixml = false;
    for line in stderr.lines() {
        let trimmed = line.trim_start();
        if trimmed.starts_with("#< CLIXML") {
            in_clixml = true;
            continue;
        }
        if in_clixml {
            // CLIXML payload is XML; once we hit the closing </Objs> we
            // exit the block.  Any line that is empty or starts with '<'
            // is treated as part of the envelope.
            if trimmed.starts_with("</Objs>") {
                in_clixml = false;
                continue;
            }
            if trimmed.is_empty() || trimmed.starts_with('<') {
                continue;
            }
            // Defensive: a non-XML, non-empty line inside what we
            // thought was a CLIXML block means the envelope ended
            // unexpectedly.  Keep this line and exit the block.
            in_clixml = false;
            kept.push(line);
            continue;
        }
        kept.push(line);
    }
    kept.join("\n")
}

fn format_remote_capture_exit_error(rc: i32, output: &str) -> String {
    let trimmed = output.trim();
    if trimmed.is_empty() {
        format!("remote command exited with status {rc}")
    } else {
        format!("remote command exited with status {rc}: {trimmed}")
    }
}

/// Build a `PowerShell` wrapper script that runs `powershell_script` and
/// writes its captured output and exit code to two files in the staging
/// directory. utmctl exec exposes only the guest exit code (no stdout
/// or stderr capture), so we redirect the inner script's combined
/// streams to a file the host can `utm_pull` afterwards.
fn build_utm_windows_result_file_wrapper_script(
    powershell_script: &str,
    remote_output_path: &str,
    remote_rc_path: &str,
) -> Result<String, String> {
    let encoded_body = encode_powershell_command(powershell_script)?;
    Ok(format!(
        "Set-StrictMode -Version Latest; \
         $ErrorActionPreference = 'Stop'; \
         $ProgressPreference = 'SilentlyContinue'; \
         $outputPath = {output_path}; \
         $rcPath = {rc_path}; \
         foreach ($path in @($outputPath, $rcPath)) {{ \
           $parent = Split-Path -Path $path -Parent; \
           if ($parent -and -not (Test-Path -LiteralPath $parent)) {{ \
             New-Item -ItemType Directory -Path $parent -Force | Out-Null \
           }}; \
           if (Test-Path -LiteralPath $path) {{ \
             Remove-Item -LiteralPath $path -Force -ErrorAction SilentlyContinue \
           }} \
         }}; \
         $rc = 0; \
         $captured = ''; \
         $psExe = Join-Path $env:WINDIR 'System32\\WindowsPowerShell\\v1.0\\powershell.exe'; \
         if (-not (Test-Path -LiteralPath $psExe)) {{ $psExe = 'powershell.exe' }}; \
         try {{ \
           $captured = (& $psExe -NoLogo -NoProfile -NonInteractive -OutputFormat Text -ExecutionPolicy Bypass -EncodedCommand {encoded_body} *>&1 | Out-String); \
           $rcVar = Get-Variable -Name LASTEXITCODE -ErrorAction SilentlyContinue; \
           if ($null -ne $rcVar -and $null -ne $rcVar.Value) {{ \
             $rcRaw = $rcVar.Value; \
             if ($rcRaw -is [System.Management.Automation.PSVariable]) {{ $rcRaw = $rcRaw.Value }}; \
             if ($null -ne $rcRaw -and [string]$rcRaw -match '^-?[0-9]+$') {{ \
               $rc = [int]$rcRaw \
             }} \
           }} elseif (-not $?) {{ \
             $rc = 1 \
           }} \
         }} catch {{ \
           $captured = ($_ | Out-String); \
           $rc = 1 \
         }}; \
         if ($null -eq $captured) {{ $captured = '' }}; \
         Set-Content -LiteralPath $outputPath -Value ([string]$captured) -Encoding utf8; \
         Set-Content -LiteralPath $rcPath -Value ([string]$rc) -Encoding ascii; \
         exit 0",
        encoded_body = powershell_quote(encoded_body.as_str())?,
        output_path = powershell_quote(remote_output_path)?,
        rc_path = powershell_quote(remote_rc_path)?,
    ))
}

/// Execute a `PowerShell` script on a Windows UTM guest via the guest agent
/// (network-independent) and return its (`exit_code`, `captured_output`).
///
/// Mechanism:
/// 1. Wrap the script so it writes output and rc to two files in
///    `staging_dir` (which must be SYSTEM-writable; see
///    [`default_utm_staging_dir_for_profile`]).
/// 2. `utmctl exec` the wrapper (one round-trip; runs as SYSTEM in-guest).
/// 3. `utmctl file pull` the rc and output files back.
/// 4. Best-effort remove the remote files.
///
/// This survives mid-orchestration network changes (e.g. `WireGuard`
/// interface coming up and reordering routes) because it never touches
/// SSH. It is the primary control channel for Windows UTM guests; SSH
/// is the fallback when utmctl itself errors.
fn execute_utm_remote_powershell_capture(
    utm_name: &str,
    staging_dir: &str,
    powershell_script: &str,
    timeout: Duration,
) -> Result<(i32, String), String> {
    if powershell_script.chars().any(|ch| ch == '\0') {
        return Err("UTM remote PowerShell script contains unsupported NUL byte".to_owned());
    }
    ensure_no_control_chars("UTM Windows staging dir", staging_dir)?;

    // Make sure the staging directory exists before the wrapper runs.
    // The wrapper itself also creates output-file parents defensively,
    // but pulling from a missing dir would still fail.
    ensure_utm_windows_dir(utm_name, staging_dir, timeout.min(Duration::from_secs(30)))?;

    let local_root =
        std::env::temp_dir().join(format!("rustynet-vm-lab-windows-exec-{}", unique_suffix()));
    fs::create_dir_all(local_root.as_path()).map_err(|err| {
        format!(
            "create local Windows UTM exec dir failed ({}): {err}",
            local_root.display()
        )
    })?;
    let local_output_path = local_root.join("output.txt");
    let local_rc_path = local_root.join("rc.txt");
    let separator = if staging_dir.ends_with('\\') {
        ""
    } else {
        "\\"
    };
    let unique = unique_suffix();
    let remote_output_path = format!("{staging_dir}{separator}rn-utm-exec.{unique}.out");
    let remote_rc_path = format!("{staging_dir}{separator}rn-utm-exec.{unique}.rc");

    let cleanup = |reason_root: &Path| {
        let _ = best_effort_remove_windows_local_utm_guest_file(
            utm_name,
            remote_output_path.as_str(),
            Duration::from_secs(20),
        );
        let _ = best_effort_remove_windows_local_utm_guest_file(
            utm_name,
            remote_rc_path.as_str(),
            Duration::from_secs(20),
        );
        let _ = fs::remove_dir_all(reason_root);
    };

    let wrapped_script = match build_utm_windows_result_file_wrapper_script(
        powershell_script,
        remote_output_path.as_str(),
        remote_rc_path.as_str(),
    ) {
        Ok(script) => script,
        Err(err) => {
            cleanup(local_root.as_path());
            return Err(err);
        }
    };

    let host_status = utm_exec_windows_raw(utm_name, wrapped_script.as_str(), timeout);
    if let Err(host_err) = host_status.as_ref() {
        cleanup(local_root.as_path());
        return Err(format!(
            "UTM Windows exec failed for {utm_name} before result file could be written: {host_err}"
        ));
    }

    let rc_pull = pull_windows_local_utm_guest_file_with_retry(
        utm_name,
        remote_rc_path.as_str(),
        local_rc_path.as_path(),
        timeout,
        "UTM Windows rc",
    );
    if let Err(pull_error) = rc_pull {
        let pull_failure_msg = format_windows_local_utm_result_pull_failure(
            "UTM Windows PowerShell capture",
            utm_name,
            &host_status,
            pull_error.as_str(),
        );
        cleanup(local_root.as_path());
        return Err(pull_failure_msg);
    }

    let rc_text = match read_windows_local_utm_utf8_file(local_rc_path.as_path(), "UTM Windows rc")
    {
        Ok(text) => text,
        Err(err) => {
            cleanup(local_root.as_path());
            return Err(err);
        }
    };
    let rc = match rc_text.trim().parse::<i32>() {
        Ok(rc) => rc,
        Err(_) => {
            let trimmed = rc_text.trim().to_owned();
            cleanup(local_root.as_path());
            return Err(format!(
                "UTM Windows rc was not a valid integer for {utm_name}: {trimmed}"
            ));
        }
    };

    let output_pull = pull_windows_local_utm_guest_file_with_retry(
        utm_name,
        remote_output_path.as_str(),
        local_output_path.as_path(),
        timeout,
        "UTM Windows output",
    );
    if let Err(pull_error) = output_pull {
        let pull_failure_msg = format_windows_local_utm_result_pull_failure(
            "UTM Windows PowerShell capture",
            utm_name,
            &host_status,
            pull_error.as_str(),
        );
        cleanup(local_root.as_path());
        return Err(pull_failure_msg);
    }

    let output =
        match read_windows_local_utm_utf8_file(local_output_path.as_path(), "UTM Windows output") {
            Ok(text) => text,
            Err(err) => {
                cleanup(local_root.as_path());
                return Err(err);
            }
        };

    cleanup(local_root.as_path());
    Ok((rc, output))
}

fn stage_windows_helper_script_from_path(
    context: &RemoteFallbackContext<'_>,
    local_path: &Path,
    remote_file_name: &str,
) -> Result<String, String> {
    let phase = if windows_local_utm_execution_authority(context.target, false).is_some() {
        RemoteTransportPhase::AccessEstablishment
    } else {
        RemoteTransportPhase::PostBootstrap
    };
    stage_windows_helper_script_from_path_with_phase(context, local_path, remote_file_name, phase)
}

fn stage_windows_helper_script_from_path_with_phase(
    context: &RemoteFallbackContext<'_>,
    local_path: &Path,
    remote_file_name: &str,
    phase: RemoteTransportPhase,
) -> Result<String, String> {
    ensure_local_regular_file_path(local_path, "Windows helper script")?;
    let remote_path = windows_helper_script_remote_path(context.target, remote_file_name)?;
    let status =
        scp_to_remote_for_target_with_phase(context, local_path, remote_path.as_str(), phase)?;
    if !status.success() {
        return Err(format!(
            "stage Windows helper script failed with status {} ({})",
            status_code(status),
            local_path.display()
        ));
    }
    Ok(remote_path)
}

fn stage_windows_helper_script(
    context: &RemoteFallbackContext<'_>,
    helper_file_name: &str,
    remote_file_name: &str,
) -> Result<String, String> {
    let local_path = windows_helper_script_local_path(helper_file_name);
    stage_windows_helper_script_from_path(context, local_path.as_path(), remote_file_name)
}

fn stage_windows_helper_support_files(
    context: &RemoteFallbackContext<'_>,
    helper_file_name: &str,
) -> Result<(), String> {
    let phase = if windows_local_utm_execution_authority(context.target, false).is_some() {
        RemoteTransportPhase::AccessEstablishment
    } else {
        RemoteTransportPhase::PostBootstrap
    };
    stage_windows_helper_support_files_with_phase(context, helper_file_name, phase)
}

fn stage_windows_helper_support_files_with_phase(
    context: &RemoteFallbackContext<'_>,
    helper_file_name: &str,
    phase: RemoteTransportPhase,
) -> Result<(), String> {
    if helper_file_name != WINDOWS_BOOTSTRAP_HELPER_FILE
        && helper_file_name != WINDOWS_ENABLE_ACCESS_HELPER_FILE
    {
        return Ok(());
    }
    if helper_file_name == WINDOWS_ENABLE_ACCESS_HELPER_FILE {
        let local_path = windows_bootstrap_helper_script_local_path();
        stage_windows_helper_script_from_path_with_phase(
            context,
            local_path.as_path(),
            WINDOWS_BOOTSTRAP_HELPER_FILE,
            phase,
        )?;
    }
    for support_file_name in [
        WINDOWS_BOOTSTRAP_WINGET_CONFIG_FILE,
        WINDOWS_BOOTSTRAP_VSCONFIG_FILE,
        WINDOWS_SERVICE_INSTALL_HELPER_FILE,
        WINDOWS_SERVICE_UNINSTALL_HELPER_FILE,
        WINDOWS_RELAY_SERVICE_INSTALL_HELPER_FILE,
        WINDOWS_RELAY_SERVICE_UNINSTALL_HELPER_FILE,
        WINDOWS_VERIFY_HELPER_FILE,
        WINDOWS_COLLECT_DIAGNOSTICS_HELPER_FILE,
    ] {
        let local_path = windows_helper_script_local_path(support_file_name);
        stage_windows_helper_script_from_path_with_phase(
            context,
            local_path.as_path(),
            support_file_name,
            phase,
        )?;
    }
    Ok(())
}

fn build_windows_helper_invocation_script(
    remote_path: &str,
    args: &[String],
) -> Result<String, String> {
    let helper_command = build_windows_helper_command(remote_path, args)?;
    // Pre-seed $LASTEXITCODE: it is only defined after an external .exe runs, and
    // a helper .ps1 that returns via Start-Process / falling off the end never
    // sets it. Under Set-StrictMode -Version Latest the later raw [string]$LASTEXITCODE
    // read would then throw "cannot be retrieved because it has not been set",
    // discarding the helper's own JSON verdict. Seeding 0 = "no native failure";
    // any native command the helper runs overwrites it. Mirrors the result-file
    // sibling (build_windows_result_file_helper_invocation_script).
    let mut script = format!(
        "Set-StrictMode -Version Latest; $ErrorActionPreference = 'Stop'; $LASTEXITCODE = 0; {helper_command}"
    );
    script.push_str("; if (-not $?) { throw 'Windows helper invocation failed' }; $_helperExitCodeParsed = 0; if ([int]::TryParse([string]$LASTEXITCODE, [ref]$_helperExitCodeParsed) -and $_helperExitCodeParsed -ne 0) { throw (\"Windows helper invocation failed with exit code {0}\" -f $_helperExitCodeParsed) }");
    Ok(script)
}

fn build_windows_result_file_helper_invocation_script(
    remote_path: &str,
    args: &[String],
    remote_result_path: &str,
    helper_label: &str,
) -> Result<String, String> {
    let mut helper_args = args.to_vec();
    let has_result_path = helper_args
        .windows(2)
        .any(|pair| pair[0] == "-OutputPath" || pair[0] == "-ResultPath");
    if !has_result_path {
        helper_args.push("-OutputPath".to_owned());
        helper_args.push(remote_result_path.to_owned());
    }
    let helper_command = build_windows_helper_command(remote_path, helper_args.as_slice())?;
    let encoded_helper = encode_powershell_command(helper_command.as_str())?;
    let encoded_helper_literal = powershell_quote(encoded_helper.as_str())?;
    ensure_no_control_chars("Windows result helper label", helper_label)?;
    Ok(format!(
        "Set-StrictMode -Version Latest; \
         $ErrorActionPreference = 'Stop'; \
         $resultPath = {result_path}; \
         $resultParent = Split-Path -Path $resultPath -Parent; \
         if ($resultParent -and -not (Test-Path -LiteralPath $resultParent)) {{ \
           New-Item -ItemType Directory -Path $resultParent -Force | Out-Null \
         }}; \
         if (Test-Path -LiteralPath $resultPath) {{ \
           Remove-Item -LiteralPath $resultPath -Force \
         }}; \
         $helperExit = 0; \
         $captured = ''; \
         $failureMessage = ''; \
         $LASTEXITCODE = 0; \
         $encodedHelper = {encoded_helper}; \
         try {{ \
           $decodedHelper = [System.Text.Encoding]::Unicode.GetString([System.Convert]::FromBase64String($encodedHelper)); \
           $helperBlock = [ScriptBlock]::Create($decodedHelper); \
           $captured = (& $helperBlock *>&1 | Out-String); \
           $_exitCodeParsed = 0; \
           if ([int]::TryParse([string]$LASTEXITCODE, [ref]$_exitCodeParsed)) {{ \
             $helperExit = $_exitCodeParsed \
           }} elseif (-not $?) {{ \
             $helperExit = 1 \
           }} \
         }} catch {{ \
           $failureMessage = if ($_.Exception -and $_.Exception.Message) {{ $_.Exception.Message.Trim() }} else {{ ($_ | Out-String).Trim() }}; \
           $helperExit = 1 \
         }}; \
         if ([string]::IsNullOrWhiteSpace($failureMessage) -and -not [string]::IsNullOrWhiteSpace($captured)) {{ \
           $failureMessage = $captured.Trim() \
         }}; \
         if (-not (Test-Path -LiteralPath $resultPath)) {{ \
           if ([string]::IsNullOrWhiteSpace($failureMessage)) {{ \
             $failureMessage = ('{helper_label} did not write result file: {{0}}' -f $resultPath) \
           }}; \
           ([ordered]@{{ \
             status = 'fail'; \
             reason = $failureMessage; \
             backend_label = ''; \
             notes = @('helper-wrapper-fallback'); \
             service_status = 'missing'; \
             start_error = $failureMessage; \
             host_surface_validated = $false; \
             cleanup_status = 'failed'; \
             openssh_installed = $false; \
             service_running = $false; \
             firewall_rule_enabled = $false; \
             authorized_keys_applied = $false; \
             host_key_present = $false; \
             listener_ready = $false; \
             default_shell_configured = $false; \
             host_key = '' \
           }} | ConvertTo-Json -Compress) | Set-Content -LiteralPath $resultPath -Encoding UTF8 \
         }}; \
         $body = Get-Content -Raw -LiteralPath $resultPath -Encoding UTF8; \
         if ([string]::IsNullOrWhiteSpace($body)) {{ \
           $failureMessage = ('{helper_label} wrote empty result file: {{0}}' -f $resultPath); \
           ([ordered]@{{ \
             status = 'fail'; \
             reason = $failureMessage; \
             backend_label = ''; \
             notes = @('helper-wrapper-empty-result'); \
             service_status = 'missing'; \
             start_error = $failureMessage; \
             host_surface_validated = $false; \
             cleanup_status = 'failed'; \
             openssh_installed = $false; \
             service_running = $false; \
             firewall_rule_enabled = $false; \
             authorized_keys_applied = $false; \
             host_key_present = $false; \
             listener_ready = $false; \
             default_shell_configured = $false; \
             host_key = '' \
           }} | ConvertTo-Json -Compress) | Set-Content -LiteralPath $resultPath -Encoding UTF8 \
         }}; \
         exit $helperExit",
        result_path = powershell_quote(remote_result_path)?,
        encoded_helper = encoded_helper_literal,
        helper_label = helper_label,
    ))
}

fn build_windows_access_bootstrap_result_script(
    remote_path: &str,
    args: &[String],
    remote_result_path: &str,
) -> Result<String, String> {
    build_windows_result_file_helper_invocation_script(
        remote_path,
        args,
        remote_result_path,
        "Windows access bootstrap helper",
    )
}

struct WindowsHelperInvocation<'a> {
    helper_file_name: &'a str,
    remote_file_name: &'a str,
    args: &'a [String],
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum WindowsLocalUtmExecutionAuthority {
    StatusProbeResultFile,
    CaptureOutput,
}

fn windows_local_utm_execution_authority(
    target: &RemoteTarget,
    capture_output_required: bool,
) -> Option<WindowsLocalUtmExecutionAuthority> {
    if remote_target_local_utm(target).is_none()
        || target.platform_profile.platform != VmGuestPlatform::Windows
    {
        return None;
    }
    Some(if capture_output_required {
        WindowsLocalUtmExecutionAuthority::CaptureOutput
    } else {
        WindowsLocalUtmExecutionAuthority::StatusProbeResultFile
    })
}

fn build_windows_helper_command(remote_path: &str, args: &[String]) -> Result<String, String> {
    let mut command = format!("& {}", powershell_quote(remote_path)?);
    for arg in args {
        ensure_no_control_chars("Windows helper arg", arg.as_str())?;
        command.push(' ');
        if arg.starts_with('-')
            && arg
                .chars()
                .skip(1)
                .all(|ch| ch.is_ascii_alphanumeric() || ch == '-')
        {
            command.push_str(arg.as_str());
        } else {
            command.push_str(powershell_quote(arg.as_str())?.as_str());
        }
    }
    Ok(command)
}

fn capture_windows_helper_script_output_for_target_with_phase(
    context: &RemoteFallbackContext<'_>,
    helper_file_name: &str,
    remote_file_name: &str,
    args: &[String],
    phase: RemoteTransportPhase,
) -> Result<String, String> {
    let local_path = windows_helper_script_local_path(helper_file_name);
    capture_windows_helper_script_output_from_path_with_phase(
        context,
        local_path.as_path(),
        remote_file_name,
        args,
        phase,
    )
}

fn capture_windows_helper_script_output_from_path(
    context: &RemoteFallbackContext<'_>,
    local_path: &Path,
    remote_file_name: &str,
    args: &[String],
) -> Result<String, String> {
    let phase = if windows_local_utm_execution_authority(context.target, false).is_some() {
        RemoteTransportPhase::AccessEstablishment
    } else {
        RemoteTransportPhase::PostBootstrap
    };
    capture_windows_helper_script_output_from_path_with_phase(
        context,
        local_path,
        remote_file_name,
        args,
        phase,
    )
}

fn capture_windows_helper_script_output_from_path_with_phase(
    context: &RemoteFallbackContext<'_>,
    local_path: &Path,
    remote_file_name: &str,
    args: &[String],
    phase: RemoteTransportPhase,
) -> Result<String, String> {
    let remote_path = stage_windows_helper_script_from_path_with_phase(
        context,
        local_path,
        remote_file_name,
        phase,
    )?;
    let script = build_windows_helper_invocation_script(remote_path.as_str(), args)?;
    capture_remote_shell_command_for_target_with_phase(
        context.target,
        context.ssh_user_override,
        context.ssh_identity_file,
        context.known_hosts_path,
        script.as_str(),
        context.timeout,
        phase,
    )
}

fn build_windows_access_bootstrap_args(
    automation_public_key: Option<&str>,
    result_path: Option<&str>,
) -> Result<Vec<String>, String> {
    let mut args = vec!["-Phase".to_owned(), "prepare-transport".to_owned()];
    if let Some(public_key) = automation_public_key {
        ensure_no_control_chars("automation public key", public_key)?;
        args.push("-AutomationPublicKey".to_owned());
        args.push(public_key.to_owned());
    }
    if let Some(result_path) = result_path {
        ensure_no_control_chars("Windows access bootstrap result path", result_path)?;
        args.push("-ResultPath".to_owned());
        args.push(result_path.to_owned());
    }
    Ok(args)
}

fn invoke_windows_helper_script_for_target(
    context: &RemoteFallbackContext<'_>,
    invocation: WindowsHelperInvocation<'_>,
) -> Result<ExitStatus, String> {
    let phase = if windows_local_utm_execution_authority(context.target, false).is_some() {
        RemoteTransportPhase::AccessEstablishment
    } else {
        RemoteTransportPhase::PostBootstrap
    };
    stage_windows_helper_support_files(context, invocation.helper_file_name)?;
    let local_path = match invocation.helper_file_name {
        WINDOWS_BOOTSTRAP_HELPER_FILE => windows_bootstrap_helper_script_local_path(),
        WINDOWS_SERVICE_INSTALL_HELPER_FILE => windows_service_install_helper_script_local_path(),
        WINDOWS_SERVICE_UNINSTALL_HELPER_FILE => {
            windows_service_uninstall_helper_script_local_path()
        }
        WINDOWS_RELAY_SERVICE_INSTALL_HELPER_FILE => {
            windows_relay_service_install_helper_script_local_path()
        }
        WINDOWS_RELAY_SERVICE_UNINSTALL_HELPER_FILE => {
            windows_relay_service_uninstall_helper_script_local_path()
        }
        WINDOWS_VERIFY_HELPER_FILE => windows_verify_helper_script_local_path(),
        WINDOWS_COLLECT_DIAGNOSTICS_HELPER_FILE => windows_diagnostics_helper_script_local_path(),
        WINDOWS_SERVICE_HOST_SMOKE_HELPER_FILE => {
            windows_service_host_smoke_helper_script_local_path()
        }
        _ => windows_helper_script_local_path(invocation.helper_file_name),
    };
    let remote_path = stage_windows_helper_script(
        context,
        local_path
            .file_name()
            .and_then(|value| value.to_str())
            .unwrap_or(invocation.helper_file_name),
        invocation.remote_file_name,
    )?;
    let script = build_windows_helper_invocation_script(remote_path.as_str(), invocation.args)?;
    run_remote_shell_command_for_target_with_phase(
        context.target,
        context.ssh_user_override,
        context.ssh_identity_file,
        context.known_hosts_path,
        script.as_str(),
        context.timeout,
        phase,
    )
}

fn render_known_hosts_line(host: &str, port: u16, public_key_line: &str) -> Result<String, String> {
    ensure_no_control_chars("known_hosts host", host)?;
    ensure_no_control_chars("known_hosts key", public_key_line)?;
    let mut parts = public_key_line.split_whitespace();
    let key_type = parts
        .next()
        .ok_or_else(|| "Windows SSH host key line is missing key type".to_owned())?;
    let key_data = parts
        .next()
        .ok_or_else(|| "Windows SSH host key line is missing key payload".to_owned())?;
    let host_field = if port == 22 {
        host.to_owned()
    } else {
        format!("[{host}]:{port}")
    };
    Ok(format!("{host_field} {key_type} {key_data}"))
}

fn append_known_hosts_entry(path: &Path, rendered_line: &str) -> Result<(), String> {
    ensure_no_control_chars("known_hosts entry", rendered_line)?;
    let mut existing = if path.exists() {
        fs::read_to_string(path)
            .map_err(|err| format!("read known_hosts file failed ({}): {err}", path.display()))?
    } else {
        String::new()
    };
    if existing
        .lines()
        .any(|line| line.trim() == rendered_line.trim())
    {
        return Ok(());
    }
    if !existing.is_empty() && !existing.ends_with('\n') {
        existing.push('\n');
    }
    existing.push_str(rendered_line.trim_end());
    existing.push('\n');
    write_text_file_atomically(path, existing.as_str())
}

#[derive(Debug, Deserialize)]
struct WindowsAccessBootstrapReport {
    openssh_installed: bool,
    service_running: bool,
    firewall_rule_enabled: bool,
    authorized_keys_applied: bool,
    host_key_present: bool,
    listener_ready: bool,
    default_shell_configured: bool,
    status: String,
    reason: String,
    #[serde(default)]
    host_key: String,
}

fn parse_windows_access_bootstrap_output(
    output: &str,
    target_label: &str,
) -> Result<WindowsAccessBootstrapReport, String> {
    let trimmed = output.trim();
    if trimmed.is_empty() {
        return Err(format!(
            "Windows access bootstrap helper produced no output for {target_label}"
        ));
    }
    let report: WindowsAccessBootstrapReport = serde_json::from_str(trimmed).map_err(|err| {
        format!("Windows access bootstrap helper did not emit valid JSON for {target_label}: {err}")
    })?;
    if report.status != "pass" {
        return Err(format!(
            "Windows access bootstrap helper reported status={} reason={} authorized_keys_applied={} for {}",
            report.status, report.reason, report.authorized_keys_applied, target_label
        ));
    }
    for (field_name, value) in [
        ("openssh_installed", report.openssh_installed),
        ("service_running", report.service_running),
        ("firewall_rule_enabled", report.firewall_rule_enabled),
        ("host_key_present", report.host_key_present),
        ("listener_ready", report.listener_ready),
        ("default_shell_configured", report.default_shell_configured),
    ] {
        if !value {
            return Err(format!(
                "Windows access bootstrap helper reported status=pass but {field_name}=false for {target_label}"
            ));
        }
    }
    if report.host_key.trim().is_empty() {
        return Err(format!(
            "Windows access bootstrap helper reported status=pass but host_key was empty for {target_label}"
        ));
    }
    Ok(report)
}

fn bootstrap_windows_access_for_target(
    target: &RemoteTarget,
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    automation_public_key: Option<&str>,
    ssh_port: u16,
    timeout: Duration,
) -> Result<String, String> {
    if target.platform_profile.platform != VmGuestPlatform::Windows {
        return Err(format!(
            "Windows access bootstrap requested for non-Windows target: {}",
            target.label
        ));
    }
    let context = RemoteFallbackContext {
        target,
        ssh_user_override,
        ssh_identity_file,
        known_hosts_path,
        timeout,
    };
    let report_output = match windows_local_utm_execution_authority(target, false) {
        Some(WindowsLocalUtmExecutionAuthority::StatusProbeResultFile) => {
            let (utm_name, _) = remote_target_local_utm(target).ok_or_else(|| {
                format!(
                    "Windows access bootstrap probe requested local UTM mode for non-UTM target {}",
                    target.label
                )
            })?;
            let local_path = windows_bootstrap_helper_script_local_path();
            stage_windows_helper_support_files(&context, WINDOWS_BOOTSTRAP_HELPER_FILE)?;
            // Use a unique per-run remote name so a Defender file lock on the
            // previously-executed copy does not block the UTM push (OSStatus
            // -2700 / "file in use").  The result file already uses this
            // pattern; apply it to the script itself for the same reason.
            let remote_bootstrap_name =
                format!("Bootstrap-RustyNetWindows.{}.ps1", unique_suffix());
            let remote_path = stage_windows_helper_script_from_path_with_phase(
                &context,
                local_path.as_path(),
                remote_bootstrap_name.as_str(),
                RemoteTransportPhase::AccessEstablishment,
            )?;
            let remote_result_name = format!(
                "{}.result.{}.json",
                sanitize_label_for_path(WINDOWS_BOOTSTRAP_HELPER_FILE),
                unique_suffix()
            );
            let remote_result_path =
                windows_helper_script_remote_path(context.target, remote_result_name.as_str())?;
            let args = build_windows_access_bootstrap_args(
                automation_public_key,
                Some(&remote_result_path),
            )?;
            // Cap the UTM probe timeout so we can fall back to SSH in a
            // reasonable time when the UTM file pull is broken on this guest.
            // The exec step blocks until the script completes; give it up to
            // 6 minutes (covering slower first-time OpenSSH installs), then
            // allow equal time for pull retries before giving up on the UTM
            // path entirely.
            let utm_probe_timeout = context.timeout.min(Duration::from_secs(360));
            let report_output = execute_windows_local_utm_result_file_probe(
                utm_name,
                "Windows access bootstrap probe",
                utm_probe_timeout,
                remote_result_path.as_str(),
                |remote_result_path| {
                    build_windows_access_bootstrap_result_script(
                        remote_path.as_str(),
                        args.as_slice(),
                        remote_result_path,
                    )
                },
            );
            let _ = best_effort_remove_windows_local_utm_guest_file(
                utm_name,
                remote_result_path.as_str(),
                Duration::from_secs(20),
            );
            report_output.map_err(|utm_err| {
                format_windows_access_establishment_transport_error(
                    target.label.as_str(),
                    "UTM Windows access bootstrap probe",
                    utm_err.as_str(),
                )
            })?
        }
        _ => {
            let args = build_windows_access_bootstrap_args(automation_public_key, None)?;
            capture_windows_helper_script_output_from_path(
                &context,
                windows_bootstrap_helper_script_local_path().as_path(),
                WINDOWS_BOOTSTRAP_HELPER_FILE,
                args.as_slice(),
            )?
        }
    };
    let report =
        parse_windows_access_bootstrap_output(report_output.as_str(), target.label.as_str())?;
    let host_key_line = report.host_key.trim();

    if let Some(path) = known_hosts_path {
        let host = ssh_target_host(target.ssh_target.as_str());
        let rendered = render_known_hosts_line(host.as_str(), ssh_port, host_key_line)?;
        append_known_hosts_entry(path, rendered.as_str())?;
    }

    Ok(host_key_line.to_owned())
}

fn summarize_ssh_probe_streams(stdout: &[u8], stderr: &[u8]) -> String {
    let stderr_text = String::from_utf8_lossy(stderr).trim().to_owned();
    if !stderr_text.is_empty() {
        return stderr_text;
    }
    let stdout_text = String::from_utf8_lossy(stdout).trim().to_owned();
    if !stdout_text.is_empty() {
        return stdout_text;
    }
    String::new()
}

fn classify_windows_ssh_access_probe_failure(detail: &str, status: Option<ExitStatus>) -> String {
    let normalized_detail = detail.trim();
    let lowered = normalized_detail.to_ascii_lowercase();
    let status_detail = status.map(status_code);
    let fallback_detail = status_detail.map_or_else(
        || "remote command failed".to_owned(),
        |code| format!("remote command exited with status {code}"),
    );
    let rendered_detail = if normalized_detail.is_empty() {
        fallback_detail
    } else {
        normalized_detail.to_owned()
    };
    if lowered.contains("host key verification failed")
        || lowered.contains("remote host identification has changed")
        || lowered.contains("offending key")
        || lowered.contains("no matching host key")
    {
        format!("ssh-host-key-not-ready: {rendered_detail}")
    } else if lowered.contains("permission denied")
        || lowered.contains("publickey")
        || lowered.contains("authentication failed")
        || lowered.contains("access denied")
    {
        format!("ssh-auth-rejected: {rendered_detail}")
    } else if lowered.contains("connection refused") {
        format!("ssh-listener-not-ready: {rendered_detail}")
    } else if lowered.contains("could not resolve hostname")
        || lowered.contains("name or service not known")
        || lowered.contains("temporary failure in name resolution")
        || lowered.contains("no address associated with hostname")
    {
        format!("no-authoritative-ssh-target: {rendered_detail}")
    } else if lowered.contains("timed out")
        || lowered.contains("timeout")
        || lowered.contains("no route to host")
        || lowered.contains("network is unreachable")
        || lowered.contains("unreachable")
    {
        format!("ssh-firewall-not-open: {rendered_detail}")
    } else {
        format!("ssh-auth-rejected: {rendered_detail}")
    }
}

fn prove_windows_ssh_access_for_target(
    target: &RemoteTarget,
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    timeout: Duration,
) -> Result<(), String> {
    let ssh_target = target.ssh_target.as_str();
    let ssh_user = ssh_user_override.or(target.ssh_user.as_deref());
    if ssh_user.is_none() {
        return Err("no-authoritative-ssh-target: no Windows ssh_user is configured".to_owned());
    }
    validate_target_user_combination(ssh_target, ssh_user)?;
    let probe_command = ssh_auth_probe_command(target.platform_profile)?;
    let ssh_script = remote_script_for_ssh_transport(target, probe_command)?;
    let mut command = Command::new("ssh");
    command.args([
        "-n",
        "-o",
        "LogLevel=ERROR",
        "-o",
        "BatchMode=yes",
        "-o",
        "StrictHostKeyChecking=yes",
        "-o",
        "ConnectTimeout=15",
        "-o",
        "ServerAliveInterval=20",
        "-o",
        "ServerAliveCountMax=3",
        "-o",
        "IdentitiesOnly=yes",
    ]);
    append_ssh_transport_options(&mut command, ssh_identity_file, known_hosts_path)?;
    if let Some(ssh_user) = ssh_user {
        command.arg("-l").arg(ssh_user);
    }
    command.arg("--").arg(ssh_target).arg(ssh_script);
    let output = run_output_with_timeout(&mut command, timeout)
        .map_err(|err| classify_windows_ssh_access_probe_failure(err.as_str(), None))?;
    if output.status.success() {
        return Ok(());
    }
    let detail = summarize_ssh_probe_streams(output.stdout.as_slice(), output.stderr.as_slice());
    Err(classify_windows_ssh_access_probe_failure(
        detail.as_str(),
        Some(output.status),
    ))
}

fn ensure_windows_runtime_access_ready_for_target(
    target: &RemoteTarget,
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    timeout: Duration,
) -> Result<(), String> {
    if target.platform_profile.platform != VmGuestPlatform::Windows {
        return Err(format!(
            "Windows runtime access proof requested for non-Windows target: {}",
            target.label
        ));
    }
    match prove_windows_ssh_access_for_target(
        target,
        ssh_user_override,
        ssh_identity_file,
        known_hosts_path,
        timeout,
    ) {
        Ok(()) => return Ok(()),
        Err(first_ssh_err) if remote_target_local_utm(target).is_none() => {
            return Err(format!("ssh-access-not-ready: {first_ssh_err}"));
        }
        Err(_) => {}
    }
    if remote_target_local_utm(target).is_some() {
        bootstrap_windows_access_for_target(
            target,
            ssh_user_override,
            ssh_identity_file,
            known_hosts_path,
            None,
            22,
            timeout,
        )
        .map_err(|err| format!("access-bootstrap-not-ready: {err}"))?;
    }
    prove_windows_ssh_access_for_target(
        target,
        ssh_user_override,
        ssh_identity_file,
        known_hosts_path,
        timeout,
    )
    .map_err(|err| format!("ssh-access-not-ready: {err}"))
}

fn validate_target_user_combination(target: &str, ssh_user: Option<&str>) -> Result<(), String> {
    if ssh_user.is_some() && target.contains('@') {
        return Err(format!(
            "explicit SSH user override cannot be combined with user@host target: {target}"
        ));
    }
    Ok(())
}

fn unique_suffix() -> u128 {
    let now = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_nanos();
    let counter = u128::from(UNIQUE_COUNTER.fetch_add(1, Ordering::Relaxed));
    (now << 16) ^ counter
}

fn sanitize_label_for_path(value: &str) -> String {
    let mut out = String::with_capacity(value.len());
    for ch in value.chars() {
        if ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_' | '.') {
            out.push(ch);
        } else {
            out.push('_');
        }
    }
    if out.is_empty() {
        "target".to_owned()
    } else {
        out
    }
}

fn ssh_target_host(value: &str) -> String {
    let without_user = value.rsplit_once('@').map_or(value, |(_, host)| host);
    without_user
        .strip_prefix('[')
        .and_then(|host| host.strip_suffix(']'))
        .unwrap_or(without_user)
        .to_owned()
}

fn ssh_target_user(value: &str) -> Option<&str> {
    value.rsplit_once('@').map(|(user, _)| user)
}

fn resolve_known_hosts_targets(
    inventory: &[VmInventoryEntry],
    aliases: &[String],
    select_all: bool,
    raw_targets: &[String],
) -> Result<Vec<KnownHostsTarget>, String> {
    let mut results = Vec::new();
    let mut seen = HashSet::new();
    if select_all || !aliases.is_empty() {
        for entry in select_inventory_entries(inventory, aliases, select_all)? {
            let mut candidates = Vec::new();
            let live_host = ssh_target_host(resolved_inventory_ssh_target(&entry).as_str());
            if !live_host.is_empty() {
                candidates.push(live_host);
            }
            let inventory_host = ssh_target_host(entry.ssh_target.as_str());
            if !inventory_host.is_empty()
                && !candidates
                    .iter()
                    .any(|candidate| candidate == &inventory_host)
            {
                candidates.push(inventory_host);
            }
            if let Some(last_known_ip) = entry.last_known_ip.as_deref()
                && !candidates
                    .iter()
                    .any(|candidate| candidate == last_known_ip)
            {
                candidates.push(last_known_ip.to_owned());
            }
            if seen.insert(entry.alias.clone()) {
                results.push(KnownHostsTarget {
                    label: entry.alias,
                    host_candidates: candidates,
                });
            }
        }
    }
    for raw_target in raw_targets {
        ensure_ssh_target("target", raw_target)?;
        let label = raw_target.clone();
        if seen.insert(label.clone()) {
            results.push(KnownHostsTarget {
                label,
                host_candidates: vec![ssh_target_host(raw_target)],
            });
        }
    }
    if results.is_empty() {
        return Err("specify at least one inventory alias/--all or explicit --target".to_owned());
    }
    Ok(results)
}

fn find_known_hosts_match(path: &Path, candidates: &[String]) -> Result<Option<String>, String> {
    for candidate in candidates {
        let status = Command::new("ssh-keygen")
            .arg("-F")
            .arg(candidate)
            .arg("-f")
            .arg(path)
            .stdin(Stdio::null())
            .stdout(Stdio::null())
            .stderr(Stdio::null())
            .status()
            .map_err(|err| format!("ssh-keygen lookup failed for {candidate}: {err}"))?;
        if status.success() {
            return Ok(Some(candidate.clone()));
        }
    }
    Ok(None)
}

fn build_preflight_script(
    required_commands: &[String],
    _min_free_kib: u64,
    require_rustynet_installed: bool,
) -> Result<String, String> {
    let mut script = String::from(
        "set -eu; \
printf 'hostname=%s\\n' \"$(hostname)\"; \
printf 'os=%s\\n' \"$(uname -srm)\"; \
printf 'free_kib=%s\\n' \"$(df -Pk / | awk 'NR==2 {print $4}')\"; \
if sudo -n true >/dev/null 2>&1; then printf 'sudo_ok=true\\n'; else printf 'sudo_ok=false\\n'; fi; ",
    );
    if require_rustynet_installed {
        script.push_str(
            "if command -v rustynet >/dev/null 2>&1; then printf 'rustynet_installed=true\\n'; else printf 'rustynet_installed=false\\n'; fi; ",
        );
    } else {
        script.push_str("printf 'rustynet_installed=skipped\\n'; ");
    }
    for command_name in required_commands {
        ensure_inventory_alias(command_name)?;
        let _ = write!(
            script,
            "if command -v {cmd} >/dev/null 2>&1; then printf 'cmd.{cmd}=present\\n'; else printf 'cmd.{cmd}=missing\\n'; fi; ",
            cmd = shell_quote(command_name)
        );
    }
    Ok(script)
}

fn privileged_rustynet_cli_script(subcommand: &str) -> String {
    format!(
        "if command -v rustynet >/dev/null 2>&1; then if sudo -n true >/dev/null 2>&1; then sudo -n env RUSTYNET_DAEMON_SOCKET=/run/rustynet/rustynetd.sock rustynet {subcommand} 2>&1; else RUSTYNET_DAEMON_SOCKET=/run/rustynet/rustynetd.sock rustynet {subcommand} 2>&1; fi; else echo rustynet-not-installed; fi"
    )
}

fn parse_key_value_output(output: &str) -> BTreeMap<String, String> {
    let mut values = BTreeMap::new();
    for line in output.lines() {
        if let Some((key, value)) = line.split_once('=') {
            values.insert(key.trim().to_owned(), value.trim().to_owned());
        }
    }
    values
}

fn build_section_capture_script(sections: &[(&str, &str)]) -> String {
    let mut script = String::from("set +e; ");
    for (name, body) in sections {
        let _ = write!(
            script,
            "printf '%s\\n' '__VM_LAB_SECTION__{name}'; {{ {body}; }} 2>&1 || true; printf '%s\\n' '__VM_LAB_SECTION_END__'; "
        );
    }
    script
}

fn parse_section_capture(output: &str) -> BTreeMap<String, String> {
    let mut sections = BTreeMap::new();
    let mut current_name: Option<String> = None;
    let mut current_body = String::new();
    for line in output.lines() {
        if let Some(name) = line.strip_prefix("__VM_LAB_SECTION__") {
            current_name = Some(name.to_owned());
            current_body.clear();
            continue;
        }
        if line == "__VM_LAB_SECTION_END__" {
            if let Some(name) = current_name.take() {
                sections.insert(name, current_body.trim_end().to_owned());
            }
            current_body.clear();
            continue;
        }
        if current_name.is_some() {
            current_body.push_str(line);
            current_body.push('\n');
        }
    }
    sections
}

fn normalized_suite_name(value: &str) -> Result<String, String> {
    let normalized = value.trim().to_ascii_lowercase().replace('_', "-");
    match normalized.as_str() {
        "direct-remote-exit" | "relay-remote-exit" | "failback-roaming" | "full-live-lab" => {
            Ok(normalized)
        }
        _ => Err(format!(
            "unsupported vm-lab suite: {value} (expected direct-remote-exit|relay-remote-exit|failback-roaming|full-live-lab)"
        )),
    }
}

fn build_vm_lab_topology(entries: &[VmInventoryEntry], suite: &str) -> Result<Value, String> {
    let suite_name = normalized_suite_name(suite)?;
    let mut roles = BTreeMap::new();
    let mut nodes = Vec::new();
    for entry in entries {
        let resolved_target = resolved_inventory_ssh_target(entry);
        let normalized_target = normalized_ssh_target(
            resolved_target.as_str(),
            entry.ssh_user.as_deref(),
            entry.alias.as_str(),
        )?;
        let node_id = entry.node_id.clone().ok_or_else(|| {
            format!(
                "inventory entry {} is missing node_id required for topology generation",
                entry.alias
            )
        })?;
        let lab_role = entry.lab_role.clone().ok_or_else(|| {
            format!(
                "inventory entry {} is missing lab_role required for topology generation",
                entry.alias
            )
        })?;
        let network_id = entry
            .network_group
            .clone()
            .or_else(|| entry.last_known_network.clone())
            .ok_or_else(|| {
                format!(
                    "inventory entry {} is missing network_group/last_known_network required for topology generation",
                    entry.alias
                )
            })?;
        if roles
            .insert(lab_role.clone(), entry.alias.clone())
            .is_some()
        {
            return Err(format!(
                "multiple selected entries declare lab_role={lab_role}; topology roles must be unique"
            ));
        }
        nodes.push(json!({
            "alias": entry.alias,
            "normalized_target": normalized_target,
            "node_id": node_id,
            "lab_role": lab_role,
            "network_id": network_id,
            "mesh_ip": entry.mesh_ip,
            "last_known_ip": literal_ip_host_from_ssh_target(normalized_target.as_str())
                .or_else(|| entry.last_known_ip.clone()),
            "exit_capable": entry.exit_capable.unwrap_or(false),
            "relay_capable": entry.relay_capable.unwrap_or(false),
            "rustynet_src_dir": entry.rustynet_src_dir,
        }));
    }

    let topology = json!({
        "version": 1,
        "generated_at_unix": SystemTime::now().duration_since(UNIX_EPOCH).unwrap_or_default().as_secs(),
        "suite": suite_name,
        "roles": roles,
        "nodes": nodes,
    });
    let parsed = parse_vm_lab_topology(topology.clone())?;
    validate_vm_lab_topology(&parsed)?;
    Ok(topology)
}

fn load_vm_lab_topology(path: &Path) -> Result<VmLabTopology, String> {
    let body = fs::read_to_string(path)
        .map_err(|err| format!("read vm-lab topology failed ({}): {err}", path.display()))?;
    let value = serde_json::from_str::<Value>(body.as_str())
        .map_err(|err| format!("parse vm-lab topology failed ({}): {err}", path.display()))?;
    let topology = parse_vm_lab_topology(value)?;
    validate_vm_lab_topology(&topology)?;
    Ok(topology)
}

fn parse_vm_lab_topology(value: Value) -> Result<VmLabTopology, String> {
    let object = value
        .as_object()
        .ok_or_else(|| "vm-lab topology must be a JSON object".to_owned())?;
    let version = object
        .get("version")
        .and_then(Value::as_u64)
        .ok_or_else(|| "vm-lab topology is missing numeric version".to_owned())?;
    if version != 1 {
        return Err(format!("unsupported vm-lab topology version: {version}"));
    }
    let suite = object
        .get("suite")
        .and_then(Value::as_str)
        .ok_or_else(|| "vm-lab topology is missing suite".to_owned())?
        .to_owned();
    let suite = normalized_suite_name(suite.as_str())?;
    let roles_object = object
        .get("roles")
        .and_then(Value::as_object)
        .ok_or_else(|| "vm-lab topology is missing roles object".to_owned())?;
    let mut roles = BTreeMap::new();
    for (key, value) in roles_object {
        let alias = value
            .as_str()
            .ok_or_else(|| format!("vm-lab topology role {key} must be a string alias"))?;
        roles.insert(key.clone(), alias.to_owned());
    }
    let node_array = object
        .get("nodes")
        .and_then(Value::as_array)
        .ok_or_else(|| "vm-lab topology is missing nodes array".to_owned())?;
    let mut nodes = BTreeMap::new();
    for node_value in node_array {
        let node_object = node_value
            .as_object()
            .ok_or_else(|| "vm-lab topology node must be an object".to_owned())?;
        let alias = required_string_field(node_object, "alias")?;
        let normalized_target = required_string_field(node_object, "normalized_target")?;
        let node_id = required_string_field(node_object, "node_id")?;
        let lab_role = required_string_field(node_object, "lab_role")?;
        let network_id = required_string_field(node_object, "network_id")?;
        let mesh_ip = optional_string_field(node_object, "mesh_ip")?;
        let last_known_ip = optional_string_field(node_object, "last_known_ip")?;
        let exit_capable = optional_bool_field(node_object, "exit_capable")?.unwrap_or(false);
        let relay_capable = optional_bool_field(node_object, "relay_capable")?.unwrap_or(false);
        let rustynet_src_dir = optional_string_field(node_object, "rustynet_src_dir")?;
        nodes.insert(
            alias.clone(),
            VmLabTopologyNode {
                alias,
                normalized_target,
                node_id,
                lab_role,
                network_id,
                mesh_ip,
                last_known_ip,
                exit_capable,
                relay_capable,
                rustynet_src_dir,
            },
        );
    }
    Ok(VmLabTopology {
        suite,
        roles,
        nodes,
    })
}

fn validate_vm_lab_topology(topology: &VmLabTopology) -> Result<(), String> {
    match topology.suite.as_str() {
        "direct-remote-exit" => {
            let client = topology_role_node(topology, &["client"])?;
            let exit = topology_role_node(topology, &["exit"])?;
            ensure_distinct_topology_networks([client, exit].as_slice())?;
        }
        "relay-remote-exit" | "failback-roaming" => {
            let client = topology_role_node(topology, &["client"])?;
            let exit = topology_role_node(topology, &["exit"])?;
            let relay = topology_role_node(topology, &["relay", "entry"])?;
            ensure_distinct_topology_networks([client, exit, relay].as_slice())?;
        }
        "full-live-lab" => {
            let _ = topology_role_node(topology, &["client"])?;
            let _ = topology_role_node(topology, &["exit"])?;
            let _ = topology_role_node(topology, &["entry", "relay"])?;
            let _ = topology_role_node(topology, &["aux"])?;
        }
        _ => {}
    }
    Ok(())
}

fn topology_role_node<'a>(
    topology: &'a VmLabTopology,
    role_candidates: &[&str],
) -> Result<&'a VmLabTopologyNode, String> {
    for role in role_candidates {
        if let Some(alias) = topology.roles.get(*role) {
            return topology.nodes.get(alias).ok_or_else(|| {
                format!("vm-lab topology role {role} points to missing alias {alias}")
            });
        }
    }
    Err(format!(
        "vm-lab topology is missing required role; expected one of {}",
        role_candidates.join(", ")
    ))
}

fn topology_optional_role_node<'a>(
    topology: &'a VmLabTopology,
    role_candidates: &[&str],
) -> Result<Option<&'a VmLabTopologyNode>, String> {
    for role in role_candidates {
        if let Some(alias) = topology.roles.get(*role) {
            return topology.nodes.get(alias).map(Some).ok_or_else(|| {
                format!("vm-lab topology role {role} points to missing alias {alias}")
            });
        }
    }
    Ok(None)
}

fn ensure_distinct_topology_networks(nodes: &[&VmLabTopologyNode]) -> Result<(), String> {
    let mut seen = HashSet::new();
    for node in nodes {
        if !seen.insert(node.network_id.clone()) {
            return Err(format!(
                "suite {} requires distinct network_id values but duplicate network {} was found",
                nodes.first().map_or("cross-network", |_| "cross-network"),
                node.network_id
            ));
        }
    }
    Ok(())
}

fn build_nodes_spec(
    nodes: &[&VmLabTopologyNode],
    inventory: &[VmInventoryEntry],
    timeout: Duration,
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
) -> Result<String, String> {
    let mut parts = Vec::new();
    for node in nodes {
        let inventory_entry = inventory
            .iter()
            .find(|entry| entry.alias == node.alias)
            .cloned()
            .ok_or_else(|| format!("topology alias missing from inventory: {}", node.alias))?;
        let target = remote_target_from_inventory_entry(&inventory_entry, ssh_user_override);
        let pubkey_hex = collect_public_key_hex_for_target(
            &target,
            ssh_identity_file,
            known_hosts_path,
            timeout,
        )?;
        let underlay_ip = literal_ip_host_from_ssh_target(node.normalized_target.as_str())
            .or_else(|| node.last_known_ip.clone())
            .ok_or_else(|| {
                format!(
                    "node {} is missing last_known_ip and its SSH target is not a literal IP; cannot build authoritative NODES_SPEC endpoint",
                    node.alias
                )
            })?;
        parts.push(format!(
            "{}|{}:51820|{}",
            node.node_id, underlay_ip, pubkey_hex
        ));
    }
    Ok(parts.join(";"))
}

fn collect_public_key_hex_for_target(
    target: &RemoteTarget,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    timeout: Duration,
) -> Result<String, String> {
    let output = capture_remote_shell_command_for_target(
        target,
        None,
        ssh_identity_file,
        known_hosts_path,
        "set -eu; if sudo -n true >/dev/null 2>&1; then sudo -n cat /var/lib/rustynet/keys/wireguard.pub; else cat /var/lib/rustynet/keys/wireguard.pub; fi",
        timeout,
    )
    .map_err(|err| format!("collect pubkey failed for {}: {err}", target.label))?;
    decode_wireguard_pubkey_to_hex(output.trim())
        .map_err(|err| format!("decode pubkey failed for {}: {err}", target.label))
}

fn decode_wireguard_pubkey_to_hex(value: &str) -> Result<String, String> {
    let decoded = BASE64_STANDARD
        .decode(value.as_bytes())
        .map_err(|err| format!("base64 decode failed: {err}"))?;
    if decoded.len() != 32 {
        return Err(format!(
            "expected 32-byte WireGuard public key, got {} bytes",
            decoded.len()
        ));
    }
    let mut out = String::with_capacity(decoded.len() * 2);
    for byte in decoded {
        let _ = write!(out, "{byte:02x}");
    }
    Ok(out)
}

fn build_allow_spec(nodes: &[&VmLabTopologyNode]) -> String {
    let mut pairs = Vec::new();
    for source in nodes {
        for target in nodes {
            if source.node_id != target.node_id {
                pairs.push(format!("{}|{}", source.node_id, target.node_id));
            }
        }
    }
    pairs.join(";")
}

fn build_assignments_spec(topology: &VmLabTopology) -> Result<String, String> {
    let mut assignments = Vec::new();
    for node in topology.nodes.values() {
        let upstream = assignment_exit_node_id(topology, node.alias.as_str())?;
        assignments.push(format!(
            "{}|{}",
            node.node_id,
            upstream.as_deref().unwrap_or("-")
        ));
    }
    Ok(assignments.join(";"))
}

fn assignment_exit_node_id(
    topology: &VmLabTopology,
    alias: &str,
) -> Result<Option<String>, String> {
    let node = topology
        .nodes
        .get(alias)
        .ok_or_else(|| format!("vm-lab topology alias not found: {alias}"))?;
    let exit = topology_optional_role_node(topology, &["exit"])?;
    let relay = topology_optional_role_node(topology, &["relay", "entry"])?;
    match node.lab_role.as_str() {
        "exit" => Ok(None),
        "relay" | "entry" => Ok(exit.map(|node| node.node_id.clone())),
        "client" | "aux" | "extra" | "fifth_client" | "probe" => Ok(relay
            .map(|node| node.node_id.clone())
            .or_else(|| exit.map(|node| node.node_id.clone()))),
        _ => Ok(exit.map(|node| node.node_id.clone())),
    }
}

fn build_assignment_issue_env(
    nodes_spec: &str,
    allow_spec: &str,
    assignments_spec: &str,
) -> Result<String, String> {
    let lines = [
        format_env_assignment("NODES_SPEC", nodes_spec)?,
        format_env_assignment("ALLOW_SPEC", allow_spec)?,
        format_env_assignment("ASSIGNMENTS_SPEC", assignments_spec)?,
        String::new(),
    ];
    Ok(lines.join("\n"))
}

fn build_traversal_issue_env(
    nodes_spec: &str,
    allow_spec: &str,
    traversal_ttl_secs: u64,
) -> Result<String, String> {
    let lines = [
        format_env_assignment("NODES_SPEC", nodes_spec)?,
        format_env_assignment("ALLOW_SPEC", allow_spec)?,
        format_env_assignment(
            "TRAVERSAL_TTL_SECS",
            traversal_ttl_secs.to_string().as_str(),
        )?,
        String::new(),
    ];
    Ok(lines.join("\n"))
}

fn build_assignment_refresh_env(
    target_node_id: &str,
    nodes_spec: &str,
    allow_spec: &str,
    exit_node_id: Option<String>,
) -> Result<String, String> {
    let mut lines = vec![
        format_env_assignment("RUSTYNET_ASSIGNMENT_TARGET_NODE_ID", target_node_id)?,
        format_env_assignment("RUSTYNET_ASSIGNMENT_NODES", nodes_spec)?,
        format_env_assignment("RUSTYNET_ASSIGNMENT_ALLOW", allow_spec)?,
        format_env_assignment(
            "RUSTYNET_ASSIGNMENT_SIGNING_SECRET",
            "/etc/rustynet/assignment.signing.secret",
        )?,
        format_env_assignment(
            "RUSTYNET_ASSIGNMENT_SIGNING_SECRET_PASSPHRASE_FILE",
            "/run/credentials/rustynetd-assignment-refresh.service/signing_key_passphrase",
        )?,
        format_env_assignment("RUSTYNET_ASSIGNMENT_TTL_SECS", "300")?,
        format_env_assignment("RUSTYNET_ASSIGNMENT_MIN_REMAINING_SECS", "180")?,
    ];
    if let Some(exit_node_id) = exit_node_id {
        lines.push(format_env_assignment(
            "RUSTYNET_ASSIGNMENT_EXIT_NODE_ID",
            exit_node_id.as_str(),
        )?);
    }
    lines.push(String::new());
    Ok(lines.join("\n"))
}

fn capture_remote_file_to_local(
    target: &RemoteTarget,
    ssh_user_override: Option<&str>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    remote_path: &str,
    local_path: &Path,
    timeout: Duration,
) -> Result<(), String> {
    let output = capture_remote_shell_command_for_target(
        target,
        ssh_user_override,
        ssh_identity_file,
        known_hosts_path,
        format!(
            "set -eu; if sudo -n true >/dev/null 2>&1; then sudo -n cat {}; else cat {}; fi",
            shell_quote(remote_path),
            shell_quote(remote_path)
        )
        .as_str(),
        timeout,
    )?;
    fs::write(local_path, output.as_bytes()).map_err(|err| {
        format!(
            "write local capture failed ({}): {err}",
            local_path.display()
        )
    })
}

fn install_state_artifacts_on_target(
    target: &RemoteTarget,
    paths: &StateArtifactInstallPaths<'_>,
    ssh_identity_file: Option<&Path>,
    known_hosts_path: Option<&Path>,
    timeout: Duration,
) -> Result<(), String> {
    ensure_success_status(
        scp_to_remote_for_target(
            target,
            None,
            ssh_identity_file,
            known_hosts_path,
            paths.assignment_pub,
            "/tmp/rn-assignment.pub",
            timeout,
        )?,
        "copy assignment verifier to remote",
    )?;
    ensure_success_status(
        scp_to_remote_for_target(
            target,
            None,
            ssh_identity_file,
            known_hosts_path,
            paths.assignment_bundle,
            "/tmp/rn-assignment.bundle",
            timeout,
        )?,
        "copy assignment bundle to remote",
    )?;
    ensure_success_status(
        scp_to_remote_for_target(
            target,
            None,
            ssh_identity_file,
            known_hosts_path,
            paths.traversal_pub,
            "/tmp/rn-traversal.pub",
            timeout,
        )?,
        "copy traversal verifier to remote",
    )?;
    ensure_success_status(
        scp_to_remote_for_target(
            target,
            None,
            ssh_identity_file,
            known_hosts_path,
            paths.traversal_bundle,
            "/tmp/rn-traversal.bundle",
            timeout,
        )?,
        "copy traversal bundle to remote",
    )?;
    ensure_success_status(
        scp_to_remote_for_target(
            target,
            None,
            ssh_identity_file,
            known_hosts_path,
            paths.refresh_env,
            "/tmp/rn-assignment-refresh.env",
            timeout,
        )?,
        "copy assignment refresh env to remote",
    )?;
    let install_script = "set -eu; \
if sudo -n true >/dev/null 2>&1; then SUDO='sudo -n'; else SUDO=''; fi; \
$SUDO install -m 0644 -o root -g root /tmp/rn-assignment.pub /etc/rustynet/assignment.pub; \
$SUDO install -m 0640 -o root -g rustynetd /tmp/rn-assignment.bundle /var/lib/rustynet/rustynetd.assignment; \
$SUDO rm -f /var/lib/rustynet/rustynetd.assignment.watermark; \
$SUDO install -m 0644 -o root -g root /tmp/rn-traversal.pub /etc/rustynet/traversal.pub; \
$SUDO install -m 0640 -o root -g rustynetd /tmp/rn-traversal.bundle /var/lib/rustynet/rustynetd.traversal; \
$SUDO rm -f /var/lib/rustynet/rustynetd.traversal.watermark; \
$SUDO install -m 0600 -o root -g root /tmp/rn-assignment-refresh.env /etc/rustynet/assignment-refresh.env; \
$SUDO rm -f /tmp/rn-assignment.pub /tmp/rn-assignment.bundle /tmp/rn-traversal.pub /tmp/rn-traversal.bundle /tmp/rn-assignment-refresh.env";
    let status = run_remote_shell_command_for_target(
        target,
        None,
        ssh_identity_file,
        known_hosts_path,
        install_script,
        timeout,
    )
    .map_err(|err| format!("install state artifacts failed for {}: {err}", target.label))?;
    if !status.success() {
        return Err(format!(
            "install state artifacts failed for {} with status {}",
            target.label,
            status_code(status)
        ));
    }
    Ok(())
}

fn suite_topology_nodes<'a>(
    topology: &'a VmLabTopology,
    suite: &str,
) -> Result<Vec<&'a VmLabTopologyNode>, String> {
    match suite {
        "direct-remote-exit" => Ok(vec![
            topology_role_node(topology, &["client"])?,
            topology_role_node(topology, &["exit"])?,
        ]),
        "relay-remote-exit" | "failback-roaming" => Ok(vec![
            topology_role_node(topology, &["client"])?,
            topology_role_node(topology, &["exit"])?,
            topology_role_node(topology, &["relay", "entry"])?,
        ]),
        "full-live-lab" => {
            let mut nodes = vec![
                topology_role_node(topology, &["exit"])?,
                topology_role_node(topology, &["client"])?,
                topology_role_node(topology, &["entry", "relay"])?,
                topology_role_node(topology, &["aux"])?,
            ];
            if let Some(extra) = topology_optional_role_node(topology, &["extra"])? {
                nodes.push(extra);
            }
            if let Some(fifth_client) = topology_optional_role_node(topology, &["fifth_client"])? {
                nodes.push(fifth_client);
            }
            Ok(nodes)
        }
        _ => Err(format!("unsupported vm-lab suite: {suite}")),
    }
}

fn ensure_suite_topology_linux_only(
    suite: &str,
    topology: &VmLabTopology,
    inventory: &[VmInventoryEntry],
) -> Result<(), String> {
    let nodes = suite_topology_nodes(topology, suite)?;
    let mut blocked = Vec::new();
    for node in nodes {
        let inventory_entry = inventory
            .iter()
            .find(|entry| entry.alias == node.alias)
            .ok_or_else(|| {
                format!(
                    "vm-lab topology alias {} is missing from inventory; cannot verify suite platform compatibility",
                    node.alias
                )
            })?;
        let platform_profile = inventory_entry.platform_profile();
        if platform_profile.platform != VmGuestPlatform::Linux {
            blocked.push(format!(
                "role={} alias={} target={} platform={} remote_shell={} guest_exec_mode={} service_manager={}",
                node.lab_role,
                node.alias,
                node.normalized_target,
                platform_profile.platform.as_str(),
                platform_profile.remote_shell.as_str(),
                platform_profile.guest_exec_mode.as_str(),
                platform_profile.service_manager.as_str(),
            ));
        }
    }
    if blocked.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "vm-lab suite {} is not yet supported for Windows targets in the Linux live-lab shell orchestrator; blocked targets: {}",
            suite,
            blocked.join("; ")
        ))
    }
}

fn build_suite_command(
    suite: &str,
    topology: &VmLabTopology,
    inventory: &[VmInventoryEntry],
    ssh_identity_file: &Path,
    nat_profile: Option<&str>,
    impairment_profile: Option<&str>,
    report_dir: &Path,
) -> Result<SuiteCommand, String> {
    let nat_profile = nat_profile.unwrap_or("baseline_lan");
    let impairment_profile = impairment_profile.unwrap_or("none");
    ensure_suite_topology_linux_only(suite, topology, inventory)?;
    let mut command = Command::new("bash");
    let rendered = match suite {
        "direct-remote-exit" => {
            let script = default_cross_network_direct_script_path();
            let client = topology_role_node(topology, &["client"])?;
            let exit = topology_role_node(topology, &["exit"])?;
            let report_path = report_dir.join("cross_network_direct_remote_exit_report.json");
            let log_path = report_dir.join("cross_network_direct_remote_exit.log");
            command
                .arg(script.as_path())
                .arg("--ssh-identity-file")
                .arg(ssh_identity_file)
                .arg("--client-host")
                .arg(client.normalized_target.as_str())
                .arg("--exit-host")
                .arg(exit.normalized_target.as_str())
                .arg("--client-node-id")
                .arg(client.node_id.as_str())
                .arg("--exit-node-id")
                .arg(exit.node_id.as_str())
                .arg("--client-network-id")
                .arg(client.network_id.as_str())
                .arg("--exit-network-id")
                .arg(exit.network_id.as_str())
                .arg("--nat-profile")
                .arg(nat_profile)
                .arg("--impairment-profile")
                .arg(impairment_profile)
                .arg("--report-path")
                .arg(report_path.as_path())
                .arg("--log-path")
                .arg(log_path.as_path());
            render_command_for_display(&command)
        }
        "relay-remote-exit" => {
            let script = default_cross_network_relay_script_path();
            let client = topology_role_node(topology, &["client"])?;
            let exit = topology_role_node(topology, &["exit"])?;
            let relay = topology_role_node(topology, &["relay", "entry"])?;
            let report_path = report_dir.join("cross_network_relay_remote_exit_report.json");
            let log_path = report_dir.join("cross_network_relay_remote_exit.log");
            command
                .arg(script.as_path())
                .arg("--ssh-identity-file")
                .arg(ssh_identity_file)
                .arg("--client-host")
                .arg(client.normalized_target.as_str())
                .arg("--exit-host")
                .arg(exit.normalized_target.as_str())
                .arg("--relay-host")
                .arg(relay.normalized_target.as_str())
                .arg("--client-node-id")
                .arg(client.node_id.as_str())
                .arg("--exit-node-id")
                .arg(exit.node_id.as_str())
                .arg("--relay-node-id")
                .arg(relay.node_id.as_str())
                .arg("--client-network-id")
                .arg(client.network_id.as_str())
                .arg("--exit-network-id")
                .arg(exit.network_id.as_str())
                .arg("--relay-network-id")
                .arg(relay.network_id.as_str())
                .arg("--nat-profile")
                .arg(nat_profile)
                .arg("--impairment-profile")
                .arg(impairment_profile)
                .arg("--report-path")
                .arg(report_path.as_path())
                .arg("--log-path")
                .arg(log_path.as_path());
            render_command_for_display(&command)
        }
        "failback-roaming" => {
            let script = default_cross_network_failback_script_path();
            let client = topology_role_node(topology, &["client"])?;
            let exit = topology_role_node(topology, &["exit"])?;
            let relay = topology_role_node(topology, &["relay", "entry"])?;
            let report_path = report_dir.join("cross_network_failback_roaming_report.json");
            let log_path = report_dir.join("cross_network_failback_roaming.log");
            command
                .arg(script.as_path())
                .arg("--ssh-identity-file")
                .arg(ssh_identity_file)
                .arg("--client-host")
                .arg(client.normalized_target.as_str())
                .arg("--exit-host")
                .arg(exit.normalized_target.as_str())
                .arg("--relay-host")
                .arg(relay.normalized_target.as_str())
                .arg("--client-node-id")
                .arg(client.node_id.as_str())
                .arg("--exit-node-id")
                .arg(exit.node_id.as_str())
                .arg("--relay-node-id")
                .arg(relay.node_id.as_str())
                .arg("--client-network-id")
                .arg(client.network_id.as_str())
                .arg("--exit-network-id")
                .arg(exit.network_id.as_str())
                .arg("--relay-network-id")
                .arg(relay.network_id.as_str())
                .arg("--nat-profile")
                .arg(nat_profile)
                .arg("--impairment-profile")
                .arg(impairment_profile)
                .arg("--report-path")
                .arg(report_path.as_path())
                .arg("--log-path")
                .arg(log_path.as_path());
            render_command_for_display(&command)
        }
        "full-live-lab" => {
            let script = default_live_lab_orchestrator_path();
            let exit = topology_role_node(topology, &["exit"])?;
            let client = topology_role_node(topology, &["client"])?;
            let entry = topology_role_node(topology, &["entry", "relay"])?;
            let aux = topology_role_node(topology, &["aux"])?;
            let extra = topology_optional_role_node(topology, &["extra"])?;
            let fifth_client = topology_optional_role_node(topology, &["fifth_client"])?;
            let profile_path = report_dir.join("vm_lab_live_lab.env");
            let mut lines = vec![
                format_env_assignment("EXIT_TARGET", exit.normalized_target.as_str())?,
                format_env_assignment("CLIENT_TARGET", client.normalized_target.as_str())?,
                format_env_assignment("ENTRY_TARGET", entry.normalized_target.as_str())?,
                format_env_assignment("AUX_TARGET", aux.normalized_target.as_str())?,
                format_env_assignment(
                    "SSH_IDENTITY_FILE",
                    ssh_identity_file.display().to_string().as_str(),
                )?,
            ];
            if let Some(extra) = extra {
                lines.push(format_env_assignment(
                    "EXTRA_TARGET",
                    extra.normalized_target.as_str(),
                )?);
            }
            if let Some(fifth_client) = fifth_client {
                lines.push(format_env_assignment(
                    "FIFTH_CLIENT_TARGET",
                    fifth_client.normalized_target.as_str(),
                )?);
            }
            lines.push(format_env_assignment("SOURCE_MODE", "local-head")?);
            lines.push(format_env_assignment(
                "REPORT_DIR",
                report_dir.display().to_string().as_str(),
            )?);
            lines.push(String::new());
            fs::write(profile_path.as_path(), lines.join("\n")).map_err(|err| {
                format!(
                    "write full live-lab profile failed ({}): {err}",
                    profile_path.display()
                )
            })?;
            command
                .arg(script.as_path())
                .arg("--profile")
                .arg(profile_path.as_path());
            render_command_for_display(&command)
        }
        _ => return Err(format!("unsupported vm-lab suite command: {suite}")),
    };
    Ok(SuiteCommand { command, rendered })
}

fn render_command_for_display(command: &Command) -> String {
    let mut rendered = String::new();
    rendered.push_str(command.get_program().to_string_lossy().as_ref());
    for arg in command.get_args() {
        rendered.push(' ');
        rendered.push_str(shell_quote(arg.to_string_lossy().as_ref()).as_str());
    }
    rendered
}

fn execute_legacy_posix_bootstrap_phase_for_target(
    phase: bootstrap::BootstrapPhase,
    target: &RemoteTarget,
    context: &bootstrap::BootstrapPhaseContext<'_>,
) -> Result<(), String> {
    if target.platform_profile.platform != VmGuestPlatform::Linux {
        return Err(format!(
            "legacy POSIX bootstrap executor only supports Linux targets: {}",
            target.label
        ));
    }
    match phase {
        bootstrap::BootstrapPhase::SyncSource => {
            let repo_url = context.repo_url.ok_or_else(|| {
                format!(
                    "bootstrap phase {} requires --repo-url for {}",
                    phase.as_str(),
                    target.label
                )
            })?;
            let status = run_remote_shell_command_for_target(
                target,
                context.ssh_user,
                context.ssh_identity_file,
                context.known_hosts_path,
                build_repo_sync_script(repo_url, context.workdir, context.branch, context.remote)?
                    .as_str(),
                context.timeout,
            )
            .map_err(|err| format!("{} failed for {}: {err}", phase.as_str(), target.label))?;
            if !status.success() {
                return Err(format!(
                    "{} failed for {} with status {}",
                    phase.as_str(),
                    target.label,
                    status_code(status)
                ));
            }
        }
        bootstrap::BootstrapPhase::BuildRelease => {
            let tmpdir = format!("{}/.tmp", context.workdir);
            let status = run_remote_shell_command_for_target(
                target,
                context.ssh_user,
                context.ssh_identity_file,
                context.known_hosts_path,
                format!(
                    "set -eu; cd {workdir}; mkdir -p {tmpdir}; \
toolchain_name=''; \
if command -v rustup >/dev/null 2>&1; then \
  toolchain_name=\"$(rustup toolchain list 2>/dev/null | awk 'NR==1 {{ print $1; exit }}' | sed 's/ (default)$//')\"; \
fi; \
cargo_bin='cargo'; \
toolchain_bin=''; \
if [ -n \"$toolchain_name\" ] && [ -d \"$HOME/.rustup/toolchains/$toolchain_name/bin\" ]; then \
  toolchain_bin=\"$HOME/.rustup/toolchains/$toolchain_name/bin\"; \
  cargo_bin=\"$toolchain_bin/cargo\"; \
fi; \
if [ -n \"$toolchain_bin\" ]; then \
  export PATH=\"$toolchain_bin:$PATH\"; \
  export RUSTC=\"$toolchain_bin/rustc\"; \
fi; \
TMPDIR={tmpdir} RUSTUP_SKIP_UPDATE_CHECK=yes exec \"$cargo_bin\" build --locked --release -p rustynetd -p rustynet-cli",
                    workdir = shell_quote(context.workdir),
                    tmpdir = shell_quote(tmpdir.as_str()),
                )
                .as_str(),
                context.timeout,
            )
            .map_err(|err| format!("{} failed for {}: {err}", phase.as_str(), target.label))?;
            if !status.success() {
                return Err(format!(
                    "{} failed for {} with status {}",
                    phase.as_str(),
                    target.label,
                    status_code(status)
                ));
            }
        }
        bootstrap::BootstrapPhase::SmokeServiceHost
        | bootstrap::BootstrapPhase::TunnelSmoke
        | bootstrap::BootstrapPhase::KillswitchSmoke
        | bootstrap::BootstrapPhase::DnsSmoke
        | bootstrap::BootstrapPhase::Ipv6Smoke => {
            return Err(format!(
                "bootstrap phase {} is currently Windows-only: {}",
                phase.as_str(),
                target.label
            ));
        }
        bootstrap::BootstrapPhase::InstallRelease => {
            let script = format!(
                "set -eu; cd {workdir}; \
if sudo -n true >/dev/null 2>&1; then SUDO='sudo -n'; else SUDO=''; fi; \
$SUDO install -m 0755 target/release/rustynetd /usr/local/bin/rustynetd; \
$SUDO install -m 0755 target/release/rustynet-cli /usr/local/bin/rustynet",
                workdir = shell_quote(context.workdir),
            );
            let status = run_remote_shell_command_for_target(
                target,
                context.ssh_user,
                context.ssh_identity_file,
                context.known_hosts_path,
                script.as_str(),
                context.timeout,
            )
            .map_err(|err| format!("{} failed for {}: {err}", phase.as_str(), target.label))?;
            if !status.success() {
                return Err(format!(
                    "{} failed for {} with status {}",
                    phase.as_str(),
                    target.label,
                    status_code(status)
                ));
            }
        }
        bootstrap::BootstrapPhase::RestartRuntime => {
            let status = run_remote_shell_command_for_target(
                target,
                context.ssh_user,
                context.ssh_identity_file,
                context.known_hosts_path,
                "set -eu; if sudo -n true >/dev/null 2>&1; then sudo -n systemctl restart rustynetd.service; else systemctl restart rustynetd.service; fi",
                context.timeout,
            )
            .map_err(|err| format!("{} failed for {}: {err}", phase.as_str(), target.label))?;
            if !status.success() {
                return Err(format!(
                    "{} failed for {} with status {}",
                    phase.as_str(),
                    target.label,
                    status_code(status)
                ));
            }
        }
        bootstrap::BootstrapPhase::VerifyRuntime => {
            let status_script = privileged_rustynet_cli_script("status");
            let netcheck_script = privileged_rustynet_cli_script("netcheck");
            let status = run_remote_shell_command_for_target(
                target,
                context.ssh_user,
                context.ssh_identity_file,
                context.known_hosts_path,
                format!("set -eu; {status_script} >/dev/null; {netcheck_script} >/dev/null")
                    .as_str(),
                context.timeout,
            )
            .map_err(|err| format!("{} failed for {}: {err}", phase.as_str(), target.label))?;
            if !status.success() {
                return Err(format!(
                    "{} failed for {} with status {}",
                    phase.as_str(),
                    target.label,
                    status_code(status)
                ));
            }
        }
        bootstrap::BootstrapPhase::All => {
            execute_legacy_posix_bootstrap_phase_for_target(
                bootstrap::BootstrapPhase::SyncSource,
                target,
                context,
            )?;
            execute_legacy_posix_bootstrap_phase_for_target(
                bootstrap::BootstrapPhase::BuildRelease,
                target,
                context,
            )?;
            execute_legacy_posix_bootstrap_phase_for_target(
                bootstrap::BootstrapPhase::InstallRelease,
                target,
                context,
            )?;
            execute_legacy_posix_bootstrap_phase_for_target(
                bootstrap::BootstrapPhase::RestartRuntime,
                target,
                context,
            )?;
            execute_legacy_posix_bootstrap_phase_for_target(
                bootstrap::BootstrapPhase::VerifyRuntime,
                target,
                context,
            )?;
        }
    }
    Ok(())
}

fn execute_bootstrap_phase_for_target(
    phase: &str,
    target: &RemoteTarget,
    context: &bootstrap::BootstrapPhaseContext<'_>,
) -> Result<(), String> {
    bootstrap::execute_bootstrap_phase_for_target(phase, target, context)
}

