    #[test]
    fn macos_membership_capabilities_grants_anchor_for_exit() {
        // Regression: a regular macOS exit assumes the Admin primary role, which
        // the daemon requires the `anchor` capability for. The grant MUST include
        // `anchor` (else `role set admin` fails closed) and `exit_server`.
        let exit = super::macos_membership_capabilities(true, false);
        assert!(
            exit.split(',').any(|c| c == "anchor"),
            "exit grant must include anchor (Admin role requirement): {exit}"
        );
        assert!(
            exit.split(',').any(|c| c == "exit_server"),
            "exit grant must include exit_server: {exit}"
        );

        // Anchor election and the client default are unchanged.
        assert_eq!(
            super::macos_membership_capabilities(false, true),
            "client,anchor.bundle_pull,anchor.port_mapping_authoritative"
        );
        assert_eq!(super::macos_membership_capabilities(false, false), "client");
        // Exit election takes precedence over anchor election.
        assert_eq!(
            super::macos_membership_capabilities(true, true),
            "client,anchor,exit_server"
        );
    }

    #[test]
    fn augment_dns_zone_env_for_macos_appends_node_and_allow() {
        // Realistic Linux issuer env (quoted, ;-delimited nodes / allow pairs).
        let env = "NODES_SPEC=\"exit-1|192.168.0.200:51820|aabb|anchor,exit_server||||anchor,exit_server;client-1|192.168.0.201:51820|ccdd|client,relay_host||||client,relay_host\"\n\
             ALLOW_SPEC=\"client-1|exit-1;exit-1|client-1\"\n\
             DNS_ZONE_NAME=\"rustynet\"\n";
        let out = super::augment_dns_zone_env_for_macos(
            env,
            "macos-client-1",
            "192.168.0.210:51820",
            "eeff",
            "exit-1",
        )
        .expect("augmentation should succeed");
        // The macOS node is appended inside the NODES_SPEC quotes.
        assert!(
            out.contains(";macos-client-1|192.168.0.210:51820|eeff|client||||client\""),
            "NODES_SPEC must gain the macOS entry inside the quotes: {out}"
        );
        // Bidirectional allow to the exit so the macOS bundle carries exit-1's record.
        assert!(
            out.contains(";macos-client-1|exit-1;exit-1|macos-client-1\""),
            "ALLOW_SPEC must gain the macOS<->exit allow pair: {out}"
        );
        // Unrelated lines are preserved verbatim.
        assert!(out.contains("DNS_ZONE_NAME=\"rustynet\"\n"));
        // The original Linux entries are untouched.
        assert!(out.contains("exit-1|192.168.0.200:51820|aabb|anchor,exit_server"));
    }

    #[test]
    fn augment_dns_zone_env_for_macos_fails_loud_on_bad_input() {
        let env = "NODES_SPEC=\"exit-1|x|y|client\"\nALLOW_SPEC=\"exit-1|exit-1\"\n";
        // A delimiter in any field would corrupt the spec grammar — reject it.
        assert!(
            super::augment_dns_zone_env_for_macos(
                env,
                "macos-client-1;rm -rf",
                "192.168.0.210:51820",
                "eeff",
                "exit-1"
            )
            .is_err()
        );
        // Missing NODES_SPEC line -> fail loud rather than silently issue nothing.
        assert!(
            super::augment_dns_zone_env_for_macos(
                "ALLOW_SPEC=\"exit-1|exit-1\"\n",
                "macos-client-1",
                "192.168.0.210:51820",
                "eeff",
                "exit-1"
            )
            .is_err()
        );
    }

    #[test]
    fn macos_peer_list_mesh_join_rejects_empty_output() {
        // No output at all: daemon may have exited before printing — fail closed.
        assert!(!macos_peer_list_indicates_mesh_join(""));
        assert!(!macos_peer_list_indicates_mesh_join("   \n  \n"));
    }

    #[test]
    fn macos_peer_list_mesh_join_rejects_daemon_socket_failure() {
        // The exact soft-pass that slipped through before: a down daemon prints
        // a non-empty unreachable diagnostic. This MUST NOT be treated as joined.
        assert!(!macos_peer_list_indicates_mesh_join(
            "daemon unreachable: inspect daemon socket failed \
             (/private/var/run/rustynet/rustynetd.sock): No such file or directory"
        ));
    }

    #[test]
    fn macos_peer_list_mesh_join_rejects_daemon_error_response() {
        // IPC reached the daemon but it answered not-ok.
        assert!(!macos_peer_list_indicates_mesh_join(
            "daemon error: trust state unavailable"
        ));
    }

    #[test]
    fn macos_peer_list_mesh_join_rejects_live_but_unmeshed_daemon() {
        // Daemon answered but printed no status line / no membership — not joined.
        assert!(!macos_peer_list_indicates_mesh_join("peers:\n  (no peers)"));
    }

    #[test]
    fn macos_peer_list_mesh_join_rejects_zero_membership() {
        // Daemon up (status line present) but has loaded no active membership.
        assert!(!macos_peer_list_indicates_mesh_join(
            "peers:\n  node_id=macos-client-1 node_role=client state=Bootstrapping \
             encrypted_key_store=true membership_epoch=0 membership_active_nodes=0"
        ));
    }

    #[test]
    fn macos_peer_list_mesh_join_rejects_membership_of_only_self() {
        // Sees only itself (1) — has not joined a mesh with any peer.
        assert!(!macos_peer_list_indicates_mesh_join(
            "peers:\n  node_id=macos-client-1 node_role=client state=DataplaneApplied \
             encrypted_key_store=true membership_epoch=3 membership_active_nodes=1"
        ));
    }

    #[test]
    fn macos_peer_list_mesh_join_accepts_joined_node_status_line() {
        // The real shape: peer-list reflects the local node status line with an
        // active membership view of the full mesh. This is the only PASS shape.
        assert!(macos_peer_list_indicates_mesh_join(
            "peers:\n  node_id=macos-client-1 node_role=client state=DataplaneApplied \
             generation=1 encrypted_key_store=true membership_epoch=16 \
             membership_active_nodes=7"
        ));
    }

    #[test]
    fn parse_membership_active_nodes_reads_count_and_handles_absence() {
        assert_eq!(
            parse_membership_active_nodes(
                "node_id=macos-client-1 state=DataplaneApplied membership_active_nodes=7"
            ),
            Some(7)
        );
        assert_eq!(
            parse_membership_active_nodes("membership_active_nodes=0"),
            Some(0)
        );
        // Absent field (daemon-down diagnostic) -> None, treated as not-joined.
        assert_eq!(
            parse_membership_active_nodes(
                "daemon unreachable: inspect daemon socket failed: No such file or directory"
            ),
            None
        );
    }

    fn write_temp_inventory(body: &str) -> PathBuf {
        let unique = super::unique_suffix();
        let dir = std::env::temp_dir().join(format!("rustynet-vm-lab-{unique}.dir"));
        fs::create_dir_all(&dir).expect("temp dir should exist");
        let path = dir.join("inventory.json");
        fs::write(&path, body).expect("inventory should be written");
        path
    }

    fn cleanup_temp_inventory(path: &Path) {
        if let Some(parent) = path.parent() {
            let _ = fs::remove_dir_all(parent);
        }
    }

    fn resolve_platform_remote_target(platform: &str) -> (PathBuf, super::RemoteTarget) {
        let (alias, ssh_target, ssh_user, remote_temp_dir) = match platform {
            "linux" => ("linux-utm-1", "debian@192.168.64.10", "debian", "/var/tmp"),
            "windows" => (
                "windows-utm-1",
                "192.168.64.20",
                "Administrator",
                r"C:\ProgramData\Rustynet\vm-lab",
            ),
            "macos" => (
                "macos-utm-1",
                "macos@192.168.64.30",
                "macos",
                "/private/var/tmp",
            ),
            "ios" => (
                "ios-sim-1",
                "ios@192.168.64.40",
                "mobile",
                "/var/mobile/tmp",
            ),
            "android" => (
                "android-emulator-1",
                "android@192.168.64.50",
                "shell",
                "/data/local/tmp",
            ),
            other => panic!("unsupported test platform: {other}"),
        };
        let remote_temp_dir = remote_temp_dir.replace('\\', "\\\\");
        let path = write_temp_inventory(&format!(
            r#"{{
  "version": 1,
  "entries": [
    {{
      "alias": "{alias}",
      "ssh_target": "{ssh_target}",
      "ssh_user": "{ssh_user}",
      "platform": "{platform}",
      "remote_temp_dir": "{remote_temp_dir}",
      "controller": {{
        "type": "local_utm",
        "utm_name": "{alias}",
        "bundle_path": "/tmp/{alias}.utm"
      }}
    }}
  ]
}}"#,
        ));
        let raw_targets: Vec<String> = Vec::new();
        let target = resolve_remote_targets(
            path.as_path(),
            &[alias.to_owned()],
            false,
            raw_targets.as_slice(),
        )
        .expect("target should resolve")
        .into_iter()
        .next()
        .expect("resolved target should exist");
        (path, target)
    }

    fn resolve_windows_remote_target() -> (PathBuf, super::RemoteTarget) {
        resolve_platform_remote_target("windows")
    }

    fn write_temp_executable(body: &str) -> PathBuf {
        let unique = super::unique_suffix();
        let dir = std::env::temp_dir().join(format!("rustynet-vm-lab-bin-{unique}.dir"));
        fs::create_dir_all(&dir).expect("temp executable dir should exist");
        let path = dir.join("mock-bin.sh");
        fs::write(&path, body).expect("temp executable should be written");
        let mut permissions = fs::metadata(&path)
            .expect("temp executable metadata should read")
            .permissions();
        permissions.set_mode(0o755);
        fs::set_permissions(&path, permissions).expect("temp executable should be chmodded");
        // On macOS, first execve() of a new binary from a temp path triggers a ~26s
        // Gatekeeper/trustd check. Run it once now so the cache is warm before the
        // script is used inside timing-sensitive code that has a 30s subprocess timeout.
        #[cfg(target_os = "macos")]
        {
            let _ = std::process::Command::new(&path)
                .arg("--_noop_prime_cache")
                .stdin(std::process::Stdio::null())
                .stdout(std::process::Stdio::null())
                .stderr(std::process::Stdio::null())
                .status();
        }
        path
    }

    // On macOS, first execve() of a new binary from a temp path triggers a ~26-50s
    // security check by trustd, which exceeds the 30s per-operation timeout used
    // inside transition_local_utm_vm_with_process_probe. Call this after writing any
    // executable test script and before passing the path to timing-sensitive code.
    fn prime_executable_if_macos(_path: &Path) {
        #[cfg(target_os = "macos")]
        {
            let _ = std::process::Command::new(_path)
                .arg("--_noop_prime_cache")
                .stdin(std::process::Stdio::null())
                .stdout(std::process::Stdio::null())
                .stderr(std::process::Stdio::null())
                .status();
        }
    }

    fn write_temp_report_dir() -> PathBuf {
        let unique = super::unique_suffix();
        let dir = std::env::temp_dir().join(format!("rustynet-live-lab-report-{unique}.dir"));
        fs::create_dir_all(dir.join("state")).expect("state dir should exist");
        fs::create_dir_all(dir.join("logs")).expect("logs dir should exist");
        dir
    }

    fn write_temp_live_lab_profile(body: &str) -> PathBuf {
        let unique = super::unique_suffix();
        let dir = std::env::temp_dir().join(format!("rustynet-live-lab-profile-{unique}.dir"));
        fs::create_dir_all(&dir).expect("temp dir should exist");
        let identity = dir.join("id_ed25519");
        fs::write(&identity, "dummy-key").expect("identity file should write");
        let known_hosts = dir.join("known_hosts");
        fs::write(&known_hosts, "example ssh-ed25519 AAAA\n").expect("known hosts should write");
        let profile_path = dir.join("profile.env");
        let rendered = body
            .replace("$IDENTITY_FILE", identity.display().to_string().as_str())
            .replace(
                "$KNOWN_HOSTS_FILE",
                known_hosts.display().to_string().as_str(),
            );
        let rendered = append_default_live_lab_platform_metadata(rendered.as_str());
        fs::write(&profile_path, rendered).expect("profile should write");
        profile_path
    }

    fn append_default_live_lab_platform_metadata(rendered: &str) -> String {
        let mut rendered = rendered.to_owned();
        for role in ["EXIT", "CLIENT", "ENTRY", "AUX", "EXTRA", "FIFTH_CLIENT"] {
            let target_key = format!("{role}_TARGET=");
            let platform_key = format!("{role}_PLATFORM=");
            if rendered.contains(target_key.as_str()) && !rendered.contains(platform_key.as_str()) {
                rendered.push_str(&format!(
                    "\n{role}_PLATFORM=\"linux\"\n{role}_REMOTE_SHELL=\"posix\"\n{role}_GUEST_EXEC_MODE=\"linux_bash\"\n{role}_SERVICE_MANAGER=\"systemd\"\n{role}_RUSTYNET_SRC_DIR=\"/home/debian/Rustynet\"\n"
                ));
            }
        }
        rendered
    }

    fn write_temp_stage_rows(report_dir: &Path, rows: &[(&str, &str)]) {
        let mut rendered = String::new();
        for (index, (name, status)) in rows.iter().enumerate() {
            let log_path = report_dir.join("logs").join(format!("{name}.log"));
            fs::write(&log_path, format!("{name} {status}\n")).expect("stage log should write");
            rendered.push_str(&format!(
                "{name}\thard\t{status}\t{}\t{}\t{name} stage\t2026-04-12T00:00:{index:02}Z\t2026-04-12T00:00:{end:02}Z\n",
                if *status == "pass" { 0 } else { 1 },
                log_path.display(),
                end = index + 1,
            ));
        }
        fs::write(report_dir.join("state/stages.tsv"), rendered).expect("stages should write");
    }

    fn cleanup_temp_path(path: &Path) {
        if let Some(parent) = path.parent() {
            let _ = fs::remove_dir_all(parent);
        }
    }

    fn build_test_setup_manifest(
        report_dir: &Path,
        profile_path: &Path,
        script_path: &Path,
        inventory_path: Option<&Path>,
    ) -> super::LiveLabSetupManifest {
        super::build_setup_manifest(&super::LiveLabSetupManifestInput {
            report_dir: report_dir.to_path_buf(),
            profile_path: profile_path.to_path_buf(),
            script_path: script_path.to_path_buf(),
            inventory_path: inventory_path.map(Path::to_path_buf),
            source_mode: "local-head".to_owned(),
            repo_ref: Some("HEAD".to_owned()),
            require_same_network: Some(true),
            dry_run: false,
            max_parallel_node_workers: None,
        })
        .expect("manifest should build")
    }

    fn write_setup_only_report_state(report_dir: &Path, manifest: &super::LiveLabSetupManifest) {
        super::write_setup_manifest(report_dir, manifest).expect("manifest should write");
        let state =
            super::initial_report_state(report_dir, manifest).expect("report state should build");
        super::write_report_state(report_dir, &state).expect("report state should write");
        write_temp_stage_rows(report_dir, &[("validate_baseline_runtime", "pass")]);
        super::update_report_state_setup_complete(report_dir)
            .expect("setup-complete state should write");
    }

