    #[test]
    fn rust_native_cli_stage_ids_match_plan_builder() {
        let cli_ids = super::rust_native_orchestration_stage_ids();
        let plan_ids: Vec<_> = super::orchestrator::plan::PlanBuilder::new()
            .build()
            .iter()
            .map(|stage| stage.id())
            .collect();

        assert_eq!(cli_ids, plan_ids);
        // Canonical stage count — must track PlanBuilder::build(). Bump this in
        // lockstep with plan.rs's `build_returns_N_stages` whenever a stage is
        // added/removed (the `cli_ids == plan_ids` assert above already proves
        // the CLI builder and the plan builder stay in sync; this guards the
        // absolute size). 24 = the 18 baseline + cross-OS relay_validation +
        // anchor_validation + admin_issue + blind_exit + deploy_relay_service +
        // security_audit_validation + dns_failclosed_validation +
        // runtime_acls_validation.
        assert_eq!(cli_ids.len(), 27);
        assert_eq!(
            cli_ids.last(),
            Some(&super::orchestrator::stage::StageId::Cleanup)
        );
    }

    #[test]
    fn rust_native_setup_only_plan_stops_after_validate_baseline_without_cleanup() {
        let ids = super::rust_native_orchestration_stage_ids_for_mode(true, false);
        assert_eq!(ids, super::rust_native_setup_stage_ids());
        assert_eq!(
            ids.last(),
            Some(&super::orchestrator::stage::StageId::ValidateBaselineRuntime)
        );
        assert!(!ids.contains(&super::orchestrator::stage::StageId::Cleanup));
    }

    #[test]
    fn rust_native_run_only_plan_keeps_setup_dependencies_and_live_suite_without_cleanup() {
        let ids = super::rust_native_orchestration_stage_ids_for_mode(false, true);
        for setup_id in super::rust_native_setup_stage_ids() {
            assert!(
                ids.contains(&setup_id),
                "run-only plan must retain {setup_id:?} so it can be injected Passed"
            );
        }
        for live_id in super::orchestrator::plan::PlanBuilder::LIVE_SUITE_STAGES {
            assert!(
                ids.contains(&live_id),
                "run-only plan must execute live stage {live_id:?}"
            );
        }
        assert!(!ids.contains(&super::orchestrator::stage::StageId::Cleanup));
    }

