    #[test]
    fn execute_ops_vm_lab_discover_local_utm_marks_windows_unmatched_without_debian_guess() {
        let unique = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .expect("clock should be valid")
            .as_nanos();
        let root = std::env::temp_dir().join(format!("rustynet-vm-lab-utm-root-{unique}.dir"));
        let bundle = root.join("nested").join("windows-utm-1.utm");
        fs::create_dir_all(&bundle).expect("bundle should exist");

        let inventory_body = r#"{{
  "version": 1,
  "entries": [
    {{
      "alias": "other-linux-vm",
      "ssh_target": "other-linux-host",
      "ssh_user": "debian",
      "platform": "linux"
    }}
  ]
}}"#
        .to_owned();
        let inventory = write_temp_inventory(inventory_body.as_str());

        let utmctl = write_temp_executable(
            "#!/bin/sh\nif [ \"$1\" = \"ip-address\" ] && [ \"$2\" = \"windows-utm-1\" ]; then\n  printf '192.168.64.20\\n100.64.0.1\\n'\n  exit 0\nfi\nexit 1\n",
        );

        let report = execute_ops_vm_lab_discover_local_utm(VmLabDiscoverLocalUtmConfig {
            inventory_path: Some(inventory.clone()),
            utm_documents_root: Some(root.clone()),
            utmctl_path: Some(utmctl.clone()),
            ssh_identity_file: None,
            known_hosts_path: None,
            ssh_port: 65_534,
            timeout_secs: 30,
            update_inventory_live_ips: false,
            report_dir: None,
        })
        .expect("discovery report should be produced");
        let parsed: serde_json::Value =
            serde_json::from_str(report.as_str()).expect("discovery report should parse as JSON");
        assert_eq!(
            parsed["entries"][0]["ssh_target_source"].as_str(),
            Some("platform-aware-unmatched-windows")
        );
        assert_eq!(
            parsed["entries"][0]["advisory_ssh_target"].as_str(),
            Some("192.168.64.20")
        );
        assert_eq!(parsed["entries"][0]["ssh_user"].as_str(), None);
        assert!(
            !parsed["entries"][0]["ssh_target"]
                .as_str()
                .unwrap_or("")
                .contains("debian@")
        );
        assert!(
            parsed["entries"][0]["notes"]
                .as_array()
                .expect("notes should be an array")
                .iter()
                .any(|note| note.as_str()
                    == Some("windows-utm-discovered-without-inventory-no-linux-user-assumed"))
        );

        cleanup_temp_inventory(inventory.as_path());
        let _ = fs::remove_dir_all(&root);
        let _ = fs::remove_dir_all(
            utmctl
                .parent()
                .expect("temp executable parent should exist"),
        );
    }

    #[test]
    fn selected_local_utm_readiness_tracks_unready_aliases_with_reasons() {
        let report = json!({
            "entries": [
                {
                    "alias": "exit-vm",
                    "readiness": {
                        "powered": true,
                        "networked": true,
                        "tcp_ready": true,
                        "auth_ready": true,
                        "execution_ready": true,
                        "reason_codes": []
                    }
                },
                {
                    "alias": "client-vm",
                    "readiness": {
                        "powered": true,
                        "networked": true,
                        "tcp_ready": true,
                        "auth_ready": false,
                        "execution_ready": false,
                        "reason_codes": ["ssh-auth-rejected"]
                    }
                }
            ]
        });
        let aliases = vec!["exit-vm".to_owned(), "client-vm".to_owned()];
        let summary = selected_local_utm_readiness_from_report(
            serde_json::to_string(&report)
                .expect("discovery report should serialize")
                .as_str(),
            aliases.as_slice(),
        )
        .expect("selected readiness should parse");
        assert_eq!(summary.ready_aliases, vec!["exit-vm".to_owned()]);
        assert_eq!(summary.unready_entries.len(), 1);
        assert_eq!(summary.unready_entries[0].alias, "client-vm");
        assert_eq!(
            summary.unready_entries[0].reason_codes,
            vec!["ssh-auth-rejected".to_owned()]
        );
    }

    #[test]
    fn decide_restart_unready_all_ready_short_circuits() {
        // No unready aliases: never restart, regardless of the other flags.
        assert_eq!(
            decide_restart_unready(true, false, false),
            RestartUnreadyDecision::AllReady
        );
        assert_eq!(
            decide_restart_unready(true, true, true),
            RestartUnreadyDecision::AllReady
        );
    }

    #[test]
    fn decide_restart_unready_default_restarts_when_unready() {
        // Historical default: unready + no opt-outs => destructive restart gate.
        assert_eq!(
            decide_restart_unready(false, false, false),
            RestartUnreadyDecision::Restart
        );
    }

    #[test]
    fn decide_restart_unready_dry_run_skips_without_restart() {
        assert_eq!(
            decide_restart_unready(false, true, false),
            RestartUnreadyDecision::DryRunSkip
        );
    }

    #[test]
    fn decide_restart_unready_trust_inventory_skips_restart() {
        // --trust-inventory-ready must skip the restart gate even though the
        // (possibly blind) probe reported unready nodes — bootstrap is then the
        // source of truth instead of a destructive restart-all.
        assert_eq!(
            decide_restart_unready(false, false, true),
            RestartUnreadyDecision::TrustInventorySkip
        );
    }

    #[test]
    fn decide_restart_unready_trust_inventory_wins_over_dry_run() {
        // When both are set, trust-inventory wins: we never reboot, dry-run or not.
        assert_eq!(
            decide_restart_unready(false, true, true),
            RestartUnreadyDecision::TrustInventorySkip
        );
    }

