    #[test]
    fn run_linux_daemon_validators_for_aliases_dry_run_prefixes_stage_names_per_alias() {
        let temp = tempfile::TempDir::new().expect("tempdir");
        let report_dir = temp.path().to_path_buf();
        let inventory = temp.path().join("inventory.json");
        std::fs::write(inventory.as_path(), r#"{"version":1,"entries":[]}"#)
            .expect("write inventory");
        let identity = temp.path().join("id_ed25519");
        std::fs::write(identity.as_path(), b"fake-key").expect("write key");
        let aliases = vec!["debian-utm-1".to_owned(), "debian-utm-2".to_owned()];
        let outcomes = super::run_linux_daemon_validators_for_aliases(
            aliases.as_slice(),
            None,
            inventory.as_path(),
            identity.as_path(),
            None,
            report_dir.as_path(),
            true,
        );
        let expected_stages = [
            "validate_linux_runtime_acls",
            "validate_linux_key_custody",
            "validate_linux_service_hardening",
            "validate_linux_authenticode",
            "validate_linux_privileged_helper_allowlist",
            "validate_linux_membership_signature_forgery",
            "validate_linux_membership_revoke_applies",
            "validate_linux_revoked_peer_denied_e2e",
            "validate_linux_blind_exit_reversal_denied",
            "validate_linux_blind_exit_dataplane",
            "validate_linux_gossip_revoked_readmit",
            "validate_linux_enrollment_replay",
            "validate_linux_hello_limiter_flood",
            "validate_linux_policy_default_deny",
            "validate_linux_dns_failclosed",
            "validate_linux_exit_nat_lifecycle",
            "validate_linux_ipv6_leak",
            "validate_linux_exit_demotion_residue",
            "validate_linux_exit_dns_failclosed",
            "validate_linux_relay_service_lifecycle",
            "validate_linux_anchor_bundle_pull",
            "validate_linux_membership_genesis",
            "validate_linux_mesh_status",
            "validate_linux_relay_forwards_frame",
        ];
        assert_eq!(outcomes.len(), expected_stages.len() * aliases.len());
        for alias in &aliases {
            for expected_stage in expected_stages {
                assert!(
                    outcomes
                        .iter()
                        .any(|outcome| outcome.stage == format!("{alias}::{expected_stage}")),
                    "missing dry-run stage {alias}::{expected_stage}",
                );
            }
        }
        for outcome in &outcomes {
            assert!(
                outcome.stage.contains("::"),
                "stage name must be prefixed with alias::: {}",
                outcome.stage
            );
            assert!(
                outcome.stage.starts_with("debian-utm-1::")
                    || outcome.stage.starts_with("debian-utm-2::"),
                "stage prefix must match one of the aliases: {}",
                outcome.stage
            );
        }
        // Per-alias log subdirs created.
        let validate_root = report_dir.join("validate_linux_daemon_state");
        assert!(validate_root.join("debian-utm-1").is_dir());
        assert!(validate_root.join("debian-utm-2").is_dir());
    }

